window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-029.json"] = [{"name":"休恩亭鸟","english_name":"Huon Bowerbird","scientific_name":"Amblyornis germanus","overview":"休恩亭鸟（英文名：Huon Bowerbird，学名：Amblyornis germanus），是雀形目园丁鸟科褐色园丁鸟属的鸟类。主要分布在澳新界的休恩半岛山区（新几内亚东北部）。","appearance":"具体描述未提供，通常园丁鸟科的鸟类具有独特的外形和色彩，休恩亭鸟亦不例外，其特征需参考专业文献以获取详细信息。","habits":"生活在休恩半岛的山区，具体的栖息环境、食物来源和活动习性需要参照详细的生态学研究。","identification":"与同属的其他园丁鸟种类相比，休恩亭鸟在外观上可能有明显的区别，特别是在羽毛颜色和装饰性建筑的风格上。","distribution":"休恩亭鸟主要分布在新几内亚东北部的休恩半岛山区。","other":"现为冠园丁鸟亚种。"},{"name":"金亭鸟","english_name":"Golden Bowerbird","scientific_name":"Prionodura newtoniana","appearance":"雄性金亭鸟长约25厘米，体重62至86克，拥有橄榄绿色头部、下巴和上体，全身泛着深金色光泽，头部中央有小冠羽，颈背和胸部为纯正的深金色，翅膀上覆羽带有黄色调，尾羽基部橄榄棕色，其余部分深黄色。雌鸟体长23厘米，重62至96克，比雄鸟体型更圆润，尾巴较短，上体橄榄褐色，下体淡灰绿色，喉咙和胸部颜色偏淡，侧胸和胁部略带褐色。雌雄幼鸟外观类似雌鸟，但下体颜色更深，飞行羽颜色较淡，虹膜深棕色，喙和腿蓝灰色。","call":"雄性金亭鸟的鸣叫包括一种持续1至2秒的脉动咔嗒声，这种声音具有地域差异性，通常在9月至12月期间达到顶峰。此外，它们还会发出尖叫、嘶吼、斥责声、口哨音或混杂的叫声，以及高精度模仿其他鸟类的声音和机械声。","habits":"金亭鸟栖息于海拔350至1530米的上层雨林地带，偏好地形平坦、斜坡温和、山脊附近的环境，树木覆盖率通常超过70%，不在山顶或受干扰的森林中筑巢。它们以果实为主食，尤其是藤本植物的果实，偶尔食用昆虫和蜘蛛。雄鸟会将果实藏在巢穴附近以备后用。","breeding":"繁殖季节从9月至次年2月，筑巢和产卵高峰期在11月至12月，雏鸟孵化期为12月至1月，整个繁殖季持续约4个月。雄性金亭鸟装饰大型简单型的树桩巢，雌鸟独自筑巢并照顾后代。巢由死叶和叶骨架构成，内衬细嫩的藤蔓，建于树干或裂缝中，离地面高度可达5米。每窝产卵1至3枚，多为2枚，间隔天数产下。孵化期21至23天，雏鸟17至20天后离巢。","identification":"金亭鸟是最小的园丁鸟种类，雄鸟的鲜艳黄色腹部和头部特征明显，而雌鸟则是橄榄褐色和灰绿色的对比，易于与其他园丁鸟区分开来。","protection":"IUCN：NT（近危）","distribution":"金亭鸟的分布局限于澳大利亚东北部的昆士兰州，具体从约克角半岛东南部到帕卢马山脉一带的山地雨林。","other":"金亭鸟的寿命可达30年，雄鸟至少在获得成年羽毛前5至6年处于学习和社会适应阶段，期间会模仿成熟雄鸟的行为。"},{"name":"辉亭鸟","english_name":"Masked Bowerbird","scientific_name":"Sericulus aureus","overview":"辉亭鸟（英文名：Masked Bowerbird，学名：Sericulus aureus），是雀形目园丁鸟科辉亭鸟属的鸟类。色彩斑斓的园丁鸟，雄鸟拥有火焰橙色与金色黄色的羽毛，身长约25厘米，头部、颈侧和肩部光泽深橙，面部黑色面具鲜明，雌鸟背部橄榄棕色，腹部黄色或金色。广泛分布于新几内亚雨林，从鸟头半岛山区至新几内亚中东部，是当地特有种，曾被误认为天堂鸟。","appearance":"雄性辉亭鸟头部、颈侧、肩部及颈部上方呈深橙色，带有纯白色高光，对比明显的黑色面部面具、下巴和喉咙。颈部上部羽毛长而丝状，肩部逐渐融合橙色，背部、臀部和大部分尾上覆羽全为深黄色。翅膀主要为深黄色，翼上的黑色斑点位于腕关节上方，延伸至小翼羽和初级飞羽。雌鸟体型较小，尾巴略长，上部橄榄棕色，下部橙黄至金黄色，胸部有明显鳞片状暗边。","call":"辉亭鸟发出偶尔微弱的“ksh”音，以及刺耳的嘶哑声，繁殖期间伴有奇特的嗡嗡声。","habits":"栖息于海拔850至1400米的山地和中高山森林，偶尔降至500米，偏好在树冠层觅食水果和昆虫，单独或小群体活动，冬季可能形成较大群体。清晨时会在开阔处停歇。","breeding":"繁殖期在新几内亚的Vogelkop地区（Tamrau山脉和Arfak山脉）为8月至11月，雄鸟建造并装饰地面型‘大道’型鸟巢，用蓝色和紫色果实、黑色真菌、蜗牛壳和黄铜色叶子等装饰。求偶行为尚不明确。","identification":"雄性辉亭鸟与金树八哥相似，但后者背部和腹部为黑色。雌性辉亭鸟与雄鸟的颜色差异显著，可通过背部橄榄棕色与腹部橙黄至金黄色的区别辨认。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的鸟头半岛山区和Neck（新几内亚西北部）至新几内亚中东部，包括Vogelkop山脉、Wandammen山脉、Weyland山脉、Oranje山脉以及北海岸山脉（Torricelli山脉、Prince Alexander山脉）向东接近Sepik河。","other":"辉亭鸟是第一个由自然学家描述的园丁鸟物种，因其雄鸟绚丽的羽毛一度被认为是天堂鸟。"},{"name":"火红辉亭鸟","english_name":"Flame Bowerbird","scientific_name":"Sericulus ardens","overview":"火红辉亭鸟（英文名：Flame Bowerbird，学名：Sericulus ardens），是雀形目园丁鸟科辉亭鸟属的鸟类。以鲜艳夺目的色彩著称。雄鸟拥有深红色的头部至肩部，如同头巾般覆盖，黄色的身体，黑色的翼缘和尾羽，以及独特的黄色喉线。雌鸟橄榄褐色上身，橙黄色下身，喉部带有黄色线条。分布于新几内亚中南部的低地和山脚森林。","appearance":"雄鸟体长约25.5厘米，体重约120至140克；雌鸟稍轻，体重介于127至168克。雄鸟具有火焰般的鲜红色头部至肩部，深黄色的下巴和喉咙，橙色的颈羽和背部逐渐融入深黄色，翼上部主要是亮丽的黄色，尾羽黑色而边缘带黄。雌鸟上身橄榄褐色，下身橙黄色，喉部有明显的黄色线条，眼睛暗褐色。幼鸟冠部银灰色，面部、喙基和喉咙呈亮肉粉色，下体羽毛柔软，白色中带有微弱的黄色调。","call":"发出尖锐的下降式尖叫'kwiiiiiiuuu!'和粗糙的嘶哑声。","habits":"栖息于低地和山脚雨林，包括高大的次生林和平原稀树草原下的斑块。通常单独或成小群觅食，偶尔与其他果实食鸟共同活动。以水果和昆虫为食。","breeding":"繁殖季节在分布区东部主要为5月至7月，在Nomad河附近和8月至11月接近Strickland河。雄鸟建造并装饰‘大道型’亭子，用以吸引雌鸟。巢穴和野外繁殖的其他方面信息未知；在圈养条件下，一窝产1枚蛋，孵化期21至22天，幼鸟离巢期21至23天。","identification":"与辉亭鸟相似，但体型略小，尾部较短，面部无黑色面罩，喙更细长，颜色较淡。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚中南部，从Wataikwa河至Mimika河和Noord河上游至Endrich河东至Fly河上游，Strickland河和Nomad河，以及Ludesa Mission（Mt Bosavi）附近；亦见于Tarara至Morehead地区和Merauke内陆。","other":"在Wataikwa河区域和Fly河流域较为常见。当地人有时会用雄鸟的干燥皮肤作为装饰品。"},{"name":"贝氏辉亭鸟","english_name":"Fire-maned Bowerbird","scientific_name":"Sericulus bakeri","overview":"贝氏辉亭鸟（英文名：Fire-maned Bowerbird，学名：Sericulus bakeri），是雀形目园丁鸟科辉亭鸟属的鸟类。以独特的橙色头冠和深黑带黄翼斑闻名，主要分布在新几内亚东北部的阿德尔伯特山脉森林中。","appearance":"雄鸟拥有光泽的深黑羽毛，头部至背部覆盖着鲜艳的橙色火焰状羽冠，翅膀基部呈现深黄色，形成醒目的翼斑。雌鸟则呈橄榄棕色，腹部带有斑纹。雄鸟体重约178至183克，雌鸟164至184克，体长约27厘米。","call":"雄鸟发出响亮而刺耳的声音，类似电击器发出的噪声。雌鸟会发出‘k-zzz k-zzz’或‘tk-sss tk-sss’的响亮叫声。","habits":"栖息于海拔1200至1450米的山地森林，偶尔下降至900米。以果实为主食，包括无花果和浆果，也捕食节肢动物如蚂蚁。通常单独或成对出现，有时会在小群体中看到更多雌鸟样貌的个体。","breeding":"繁殖季节可能为2月，雌鸟独自筑巢，雄鸟建立装饰性的大道型亭子吸引伴侣。巢由雌鸟单独建造，位于小树蕨的树冠上。","identification":"雄鸟与雌鸟在外观上有明显差异，雄鸟的火焰状羽冠和黄翼斑是辨识关键。","protection":"IUCN：NT（近危）","distribution":"分布于新几内亚东北部的阿德尔伯特山脉。","other":"曾被认为是近危物种，直到2009年仍被列为易危。"},{"name":"黄头辉亭鸟","english_name":"Regent Bowerbird","scientific_name":"Sericulus chrysocephalus","overview":"黄头辉亭鸟（英文名：Regent Bowerbird，学名：Sericulus chrysocephalus），是雀形目园丁鸟科辉亭鸟属的鸟类。体长约25厘米，具有明显的雌雄异型。雄鸟鸟以黑色为主，头顶、颈背和翼部闪耀着金色光辉，拥有黄色喙和眼环，黑色脚。雌鸟呈褐色，带有白色或浅棕色斑纹，灰喙，黑色脚和冠。该鸟种以英国的摄政王命名。","appearance":"雄性黄头辉亭鸟的前额、头顶、颈背和上背部呈现出亮丽的深黄色，有时前额处会呈现较暗的火焰红。头部和全身其余部分以及整个下体为纯黑色，包括眼上的狭窄弧线。两根最外侧的初级飞羽和所有上翼覆羽为哑光黑，其余初级飞羽大部为金黄色，尖端和前缘有宽窄不一的黑色。次级飞羽（无黑色前缘）尖端逐渐变小至内侧羽毛，内侧次级飞羽和大部分三级飞羽全为黄色。雌鸟平均比雄鸟重，体型更大，但喙长相似；羽毛颜色差异显著，头部为暗淡的脏白色到灰色，细条纹、斑点和污渍明显，与暗烟黑色的冠形成对比。上体颜色各异，橄榄棕色，背部有斑点的米色，下体为脏白色到奶油色，宽幅的暗烟黑色羽毛沿喉部中央延伸，下体有宽幅的黑褐色条纹。幼鸟刚离巢时，翅膀羽毛发育良好，头顶、颈背和背部保留绒毛，随后被类似雌雄亚成体的柔软松散羽毛所取代。","call":"远离求偶场时，黄头辉亭鸟是家族中最少鸣叫的成员；在求偶时会发出典型的刺耳磨擦声和连续的亚鸣声，模仿其他鸟类。","habits":"栖息于澳大利亚东部的亚热带雨林、相关的硬叶林和更开阔的生境，包括农田和城市花园，海拔从海平面至900米，随地域不同而变化。传统求偶场分散于适宜的山脊生境中，倾向于在雨林平坦或坡度较小的地方，周围有藤蔓灌木丛提供隐蔽和保护。冬季可能局部向低海拔迁移；雌鸟外观的个体比成年雄鸟早3-4周进行迁移。以果实为主食，辅以花（芽、花瓣、花蜜）、种子、叶片和节肢动物（主要是昆虫）；幼鸟的食物包括水果和昆虫，如蝉、毛虫、蚱蜢和甲虫，蝉占饮食的显著部分。主要在树冠上层觅食，通过扫食和捕猎获取节肢动物。常与其他园丁鸟和食果鸟类共同觅食，积极驱赶其他物种离开果树；雌鸟在觅食树上占据主导地位；有时与缎蓝园丁鸟和斑噪钟鹊形成混群觅食。","breeding":"繁殖季节为9月至翌年2月，产卵高峰期在11月至12月，幼鸟离巢时间为2月末至3月初，繁殖周期约3-4个月。雄鸟建造并装饰小型通道式求偶场吸引雌鸟；雌鸟独自筑巢和照料巢穴。非领地性，除了雄鸟保卫求偶场外，雄鸟可能在同一地点至少三个季节内维持同一求偶场；24个传统求偶场在昆士兰州萨拉巴山脉的平均最近邻距离为195米。求偶场由稀疏脆弱的枝条构成，长度和宽度分别为23厘米和20厘米，通道宽8厘米高18厘米，44个通道的平均偏离南北方向38度；雄鸟每天仅花费约3%的时间在求偶场。求偶装饰品（最多约30件）包括绿叶、淡色花朵和花瓣、种子、果实、蜗牛壳、蝉幼虫外骨骼和人造蓝色物品；\"涂鸦\"求偶场和偷盗装饰品的现象普遍存在；求偶场结构往往寿命短暂（十天或更短），因竞争对手破坏或主人发现对手找到它而重建，新的求偶场在相同地点下方的另一片灌木丛中只需3-4小时即可建成。雌鸟在森林树冠上层被雄鸟的鲜艳羽毛吸引，然后被引导至求偶场；雄鸟的求偶展示包括三个元素：入口求偶展示、外围求偶展示和通道求偶展示；展示姿态包括振翅、张口、颈背展示姿势，雄鸟还会向雌鸟发起短暂的垂直\"飞行\"，所有动作都旨在展示和增强羽毛色彩。巢穴为脆弱的浅盘状，由松散放置的枝条构成，蛋窝衬里为细枝条，偶尔夹杂几片叶子，隐藏在密集的植被中，高度2-31米，位于藤本植物簇、寄生植物（桑寄生科）或其他植物中；四个活跃巢穴与最近活跃求偶场的平均距离为266米（最近距离20米）。每窝产卵1-3枚，多数为2枚，在圈养条件下每隔一天产一枚；圈养状态下，失败后会在新巢中产下一窝替代卵；孵化期约17-21天，幼鸟期17天。萨拉巴山脉七巢的总体成功率约为43%。雌鸟最早在第三年开始繁殖，更常见的是在第四年。已知雄鸟最长存活记录至少23年。","identification":"黄头辉亭鸟雄鸟与雌鸟在外形上有显著区别。雄鸟以醒目的金色头部和翼部以及黑色身体为特征，而雌鸟呈褐色，带有白色或浅棕色斑纹。与其他园丁鸟相比，黄头辉亭鸟的雄鸟在求偶展示中更多依赖于其鲜艳的羽毛而非声音。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从昆士兰中部东部至新南威尔士州中部东部（澳大利亚东部）。","other":"已知罕见的自然间属杂交种为Rawnsley's bowerbird，是黄头辉亭鸟与缎蓝园丁鸟的杂交后代。"},{"name":"缎蓝园丁鸟","english_name":"Satin Bowerbird","scientific_name":"Ptilonorhynchus violaceus","overview":"缎蓝园丁鸟（英文名：Satin Bowerbird，学名：Ptilonorhynchus violaceus），是雀形目园丁鸟科园丁鸟属的鸟类。体型略似鸽子的中型鸣禽，体长32.5厘米，羽毛光泽亮丽。雄鸟拥有蓝黑色的羽毛，如同绸缎般泛着蓝光，配以紫色的眼睛，而雌鸟则呈现黄绿色。以独特的筑巢行为和艺术性装饰闻名，主要分布在澳大利亚东部。","appearance":"雄性缎蓝园丁鸟全身覆盖着光泽的蓝黑色羽毛，羽毛质地犹如绸缎，眼色为紫色，喙部呈白色或浅黄绿带蓝晕，腿部颜色变化不定。雌鸟及幼鸟主要为灰绿或棕色，翅膀和尾上覆羽为肉桂棕色，腹部带有绿色，下颌至胸上部有白色条纹或斑点，眼睛为深蓝色。幼鸟的头部为柔软的棕橄榄色，上体为棕色，下体为淡色，胸部边缘为暗灰棕色，其余部位有宽阔的楔形和精细边缘的相同颜色，赋予其鳞片状外观。","call":"缎蓝园丁鸟声音响亮且多样，包括尖叫声、嘶嘶声和吼叫声。","habits":"缎蓝园丁鸟栖息于雨林和湿润的桉树林中，常见于澳大利亚东部。它们以果实为主食，辅以少量花朵、叶子、种子和昆虫。它们在所有层次上觅食，常单独或与家族成员及其它食果鸟种一起觅食。冬季时，它们会结成多达200只的大群，前往牧场觅食草芽、多汁的白三叶草叶片和草本植物，也会访问花园和果园吃蔬菜、软果和花蜜。","breeding":"繁殖季为8月至次年1月，雌鸟独自建造巢穴，通常位于树或灌木上，距地面2至40米之间，平均高度为15米。雄鸟通过建立装饰精美的巢穴吸引雌鸟，巢穴由两排向外弯曲的平行棍棒构成，中央有一条通道，周围装饰着蓝色的羽毛、花瓣、果实和昆虫外骨骼等。雌鸟产卵1至3枚，大多为2枚，每两天产一枚，孵化期为21至22天。雌鸟负责孵化和喂养幼鸟，幼鸟约在17至21天后离巢。","identification":"雄性缎蓝园丁鸟与雌鸟和幼鸟的差异显著，雄鸟全身蓝黑，雌鸟和幼鸟则为黄绿或棕色。与绿猫鸟和斑点猫鸟相比，缎蓝园丁鸟的雌鸟有明显的蓝色眼睛。","protection":"IUCN：LC（无危）","distribution":"缎蓝园丁鸟广泛分布于澳大利亚东部，从昆士兰南部至维多利亚，另有孤立群体在北昆士兰的湿热热带地区。","other":"雄性缎蓝园丁鸟会破坏和窃取同类的巢穴装饰物，而这种行为与巢穴的质量无关，却与雄鸟的攻击性相关。"},{"name":"西大亭鸟","english_name":"Western Bowerbird","scientific_name":"Chlamydera guttata","overview":"西大亭鸟（英文名：Western Bowerbird，学名：Chlamydera guttata），是雀形目园丁鸟科大亭鸟属的鸟类。以暗褐色为主色调，斑点明显，体羽带温暖棕色调的园丁鸟，头部和颈部有红棕色至淡黄色斑纹，背部黑色边缘明显，拥有一顶小型粉红色的颈背冠羽。分布于澳大利亚中部和西澳大利亚州的皮尔巴拉地区，偶尔在人类居住区的花园和城市公园中出现。","appearance":"体长约28厘米，雄鸟体重128-142克，雌鸟体重122-148克。雄鸟指名亚种具有红棕色头颈，羽毛边缘黑色，露出基部，大部分冠羽带有银白色光泽和羽毛尖端；大而可竖起的丝状颈背冠羽颜色从浅到亮粉红色不等；上体包括翅膀和尾巴，颜色从深棕色到黑色不等，翼和尾部较浅，有明显的陶土色圆形羽毛斑点；翅膀和尾羽的细边缘呈淡黄色；下巴、喉咙、耳羽和上胸部分黑色或深棕色，有明显的陶土色斑点；其余下体呈脏黄色，胸部较暗，腹部中央偏黄；侧胸和两肋从中心颜色渐变为更加丰富的陶土色；尾下覆羽呈淡陶土色，宽幅橄榄棕色条纹；虹膜深棕色；喙黑色；腿橄榄棕色。雌鸟羽毛与雄鸟相似，但缺乏冠羽（或随年龄增长获得较小的冠羽），尾巴平均略长。幼鸟未详细描述；未成熟雄鸟缺乏冠羽，背部斑点更奶油色，尾巴平均比成年雄鸟稍长；亚成年雄鸟拥有比成年雄鸟小的冠羽，尾巴平均比成年雄鸟稍长。卡特里亚种（Carteri）比指名亚种体型更小，尤其是在翅膀上，拥有较短的颈背冠羽，羽毛色彩更丰富，更红棕色。","call":"对其声音了解不多。雄鸟的筑巢招引歌曲由重复的响亮而刺耳的嘟噜声组成，可能还包括模仿；模仿也被用于其他场合，例如当潜在的捕食者出现时。据说其曲目与斑大亭鸟相似，但记录描述很少。","habits":"栖息于河岸林地、岩石山脉和峡谷中的灌木丛，以及有水源的“断裂地带”。访问人类居住区周围的花园。居民性，但会根据果实可用性和降雨量进行局部游荡。主要以果实为食，尤其是岩榕树（Ficus platypoda）的果实，花朵、花蕾、花蜜、种子；也吃动物，主要是昆虫。在树木和灌木中觅食，有时在地上。通常是单独活动，成对或以不超过六只的小群体活动；偶尔形成约15只的大群。","breeding":"繁殖季节延长，7月至次年3月，产卵期7月至12月，在北西角（卡特里亚种）繁殖期为8月至9月，幼鸟和离巢雏鸟期为9月至10月；展示季节几乎全年，高峰为8月至12月。雄鸟多配偶制，好色，建立并装饰大道型园地；雌鸟独自筑巢和照顾巢穴。非领地性，除了雄鸟保卫园地位置；传统园地位置相距约2公里，根据可用的合适灌木建造。在前一个园地的地点重建新园地，几个废弃园地经常在活跃园地1米范围内，或在附近重新定位；园地大型，有宽阔的大道，底部由树枝构成，其余部分由草茎构成，与斑大亭鸟类似；西澳大利亚州（哈默斯利山脉和巴勒山脉之间）四个园地的平均尺寸为外部长度36厘米，宽度16厘米，大道高度23厘米，平台延伸超出园地墙端48厘米，似乎对大道方向没有特别偏好；园地装饰（可达1600件或更多）包括骨片、蜗牛壳、鹅卵石、绿色果实和其他物品（包括人造物品）；已记录园地“涂漆”，园地破坏和装饰品盗窃可能也发生。求偶知之甚少，但姿态包括颈部展示，类似于斑大亭鸟和黄头辉亭鸟。巢是一个浅碗状基础，由枯枝和干藤蔓须构成，浅蛋窝衬垫由更细的树枝、藤蔓须、刺柏（Casuarina）针叶、金合欢（Acacia）叶状小枝和/或干燥的草茎构成，通常位于低树或灌木中，距离地面2-6米；两个巢与最近的活跃园地平均距离354米。一窝蛋1-2枚，多数为2枚；关于孵化和雏鸟期没有信息。","identification":"与斑大亭鸟非常相似，但总体颜色更深，下体中心区域更亮更黄，头顶有更强的银色光泽。雌鸟与雄鸟羽毛相似，但缺乏或拥有较小的颈背冠羽，尾巴平均较长。卡特里亚种与指名亚种相比，体型更小，颈背冠羽更短，羽毛颜色更丰富，更红棕色。","protection":"IUCN：LC（无危）；在澳大利亚，被列为\"近危\"。","distribution":"分布于澳大利亚西部和中部，特别是在皮尔巴拉地区和澳大利亚中部。在北西角（卡特里亚种）的种群最近估计稳定在大约2000只繁殖个体，占地约500平方公里。","other":"有时因干旱条件而受到不利影响；一个围绕粘土洼地的种群离开了它，以及一个未完成的巢，因为水蒸发了。许多个体因习惯食用花园里的水果和蔬菜而被杀死。"},{"name":"大亭鸟","english_name":"Great Bowerbird","scientific_name":"Chlamydera nuchalis","overview":"大亭鸟（英文名：Great Bowerbird，学名：Chlamydera nuchalis），是雀形目园丁鸟科大亭鸟属的鸟类。广泛分布于澳大利亚北部。以其独特的粉色颈冠和壮观的筑巢仪式而闻名。","appearance":"大亭鸟体型较大，约35厘米长，体重介于153至265克之间。雄性大亭鸟全身呈灰褐色，背部带有白色斑点，最显著的是其可竖立的粉红色颈冠。雌鸟体型较小，可能缺少粉色颈冠。幼鸟的羽毛上有着明显的淡色斑点，亚成鸟的颈冠尚未发育完全，胸腹部条纹明显。","call":"雄性大亭鸟的鸣叫包括响亮的刺耳音符、爆炸性的嘶嘶声、咯咯声和喋喋不休的声音，还有模仿其他鸟类和人类制造声音的能力。","habits":"栖息于桉树森林、河岸森林、红树林边缘和雨林边缘，常见于接近水源的地带。它们以果实、花朵、花蜜、绿色蔬菜、昆虫、种子和食物残渣为食，偶尔会形成小群落觅食。","breeding":"繁殖季节主要集中在秋季至春季，雄鸟会建造装饰精美的亭状巢穴吸引雌鸟，雌鸟独自筑巢并照料后代。巢穴通常位于离地面2至9米高的树上。","identification":"与其他园丁鸟相比，大亭鸟的体型更大，雄鸟的粉红色颈冠是其显著特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚北部，包括从布鲁姆周边地区横跨至开普约克半岛，南至芒特艾萨。","other":"大亭鸟有时会在农作物区造成损害，尤其是在冬季群聚攻击软果和绿叶作物时，可能会被人们猎杀。"},{"name":"斑大亭鸟","english_name":"Spotted Bowerbird","scientific_name":"Chlamydera maculata","overview":"斑大亭鸟（英文名：Spotted Bowerbird，学名：Chlamydera maculata），是雀形目园丁鸟科大亭鸟属的鸟类。生活在澳大利亚东部内陆干燥林地的中等体型、色彩斑斓的园丁鸟。以建造装饰性的鸟亭和复杂的模仿叫声而闻名，虽然在当地常见，但其总体数量被认为正在减少。斑大亭鸟还有‘大型褶边大亭鸟’、‘卷心菜鸟’或‘模仿鸟’等别称。","appearance":"斑大亭鸟长约29厘米，体重介于125至162克之间。头部呈暖褐色，带有灰色条纹，前额的羽毛边缘呈黑色，中央有几根细长的银白色尖端羽毛。颈后有一簇粉红色丝状的羽毛，下方是一块独立的棕色斑块。背部和翅膀覆羽及尾巴为黑褐色，末端或次末端有广泛的琥珀色至陶土色斑点。下体颜色较浅，从淡黄色到奶油色，带有灰色斑纹和条纹，腹部下方有淡淡的黄绿色。虹膜深棕色，喙黑色，腿橄榄棕色。雌雄相似，但雌鸟的冠羽可能不明显或完全不存在。幼鸟头部中央的羽毛有厚重的淡色条纹，亚成年雄鸟与成年雌鸟相似，但主翼羽有更大的淡色尖端，尾羽更尖，若冠羽存在，则比成年的要小。","call":"斑大亭鸟发出响亮刺耳的叫声，包括嘶嘶声和尖叫。它们能模仿多种声音，包括其他鸟类的叫声和人类制造的声音。在面临威胁时，雄鸟和雌鸟会模仿猛禽的叫声。","habits":"斑大亭鸟栖息于干燥的开阔硬叶林地，偏好有密集灌木丛的环境，如桉树和白千层树主导的区域，也常出现在果园、公园和乡村住宅的花园中。它们以水果、花和种子为主食，也会捕食节肢动物。通常单独或小群觅食，但在非繁殖季节会形成10至30只的小群。","breeding":"繁殖期从7月持续至次年3月，产卵高峰在10月至2月。雄鸟建造装饰性的鸟亭吸引雌鸟，雌鸟独自筑巢并照料后代。巢由枯枝和细枝构成，建于树上或灌木丛中，距离地面平均6米。每窝通常产一枚卵，卵呈卵圆形，淡灰绿色，带有深棕色和黑色的蠕虫状斑纹。","identification":"斑大亭鸟与西大亭鸟相比，颜色更深，分布范围更偏东。辨识要点包括其独特的粉色颈后羽毛和鸟亭的装饰风格。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚昆士兰州（约克角半岛除外）和新南威尔士州（澳大利亚东部和东南部）。","other":"斑大亭鸟的寿命至少可达11至13年，它们的鸟亭装饰物数量和种类与雄鸟的交配成功有关。"},{"name":"黄胸大亭鸟","english_name":"Yellow-breasted Bowerbird","scientific_name":"Chlamydera lauterbachi","overview":"黄胸大亭鸟（英文名：Yellow-breasted Bowerbird，学名：Chlamydera lauterbachi），是雀形目园丁鸟科大亭鸟属的鸟类。中等体型的园丁鸟，约27厘米长。其上体呈橄榄褐色，腹部黄色，具铜色冠羽，眼睛深棕色，喙黑色，口部粉橙色。两性外观相似，但雌鸟色彩略淡。广泛分布于新几内亚的森林边缘、草地和低山地带。","appearance":"成年雄性黄胸大亭鸟头部呈橄榄黄色，具丝光玫瑰色冠羽，侧面和颈部羽毛明显条纹状，上体橄榄褐色，背部有细小的淡色羽毛轴和淡黄橄榄色边缘，形成鳞片状外观。翼覆羽和飞羽暗褐色，尾羽类似飞羽，但外侧尾羽基部更黄。下巴至胸部灰色至淡黄色，其余下体黄色。雌鸟与雄鸟相似，但颜色较暗淡。幼鸟上身和下体更条纹状，腹部柔软灰白色，中央腹部淡黄色。亚成年雄鸟可能有少量到大部分红色羽毛侵入冠羽。","call":"成年雄鸟的叫声独特，包括尖锐的“chilp chilp chilp”声和嘶哑的、摩擦的、嗡嗡的声音，以及模仿环境声音的能力，但在野外记录到的鸟类模仿较为罕见。","habits":"黄胸大亭鸟通常单独或以小群出现，主要栖息于新几内亚的森林边缘、草地和低山地带。它们的食物包括水果和昆虫，如毛虫和甲虫。它们并不固守领地，除了保卫筑巢地点。","breeding":"繁殖季节几乎全年都有，除了五月。雄鸟会建造和装饰复杂的四壁亭子，吸引雌鸟；而雌鸟独自建巢和照顾后代。巢为浅杯状，由细枝、藤蔓须、干草和树皮构成，建在离地面1-4米的高度，通常位于树、灌木、小树或草丛中。","identification":"与赤胸园丁鸟相比，黄胸大亭鸟具有黄色而非肉色的腹部，以及无条纹的冠羽。雄鸟头部颜色和条纹是主要的识别特征。","protection":"IUCN：LC（无危）","distribution":"黄胸大亭鸟分布于澳新界，从中西部至新几内亚东北部。"},{"name":"浅黄胸大亭鸟","english_name":"Fawn-breasted Bowerbird","scientific_name":"Chlamydera cerviniventris","overview":"浅黄胸大亭鸟（英文名：Fawn-breasted Bowerbird，学名：Chlamydera cerviniventris），是雀形目园丁鸟科大亭鸟属的鸟类。体长约32厘米，羽毛呈灰褐色，点缀以白色斑点，嘴黑色，虹膜深棕色，下体橙色偏黄。两性相似，雌鸟略小于雄鸟。广泛分布于新几内亚和澳大利亚北部的约克角半岛，栖息于热带森林、红树林、稀树草原和森林边缘。","appearance":"成鸟体长约29厘米，体重介于117至182克。上体橄榄褐色，冠部稍淡且灰，背部可见脏白至淡黄色的条纹和斑点；额部、眼周、面部侧面和颈部有不规则的灰白条纹；翅膀和尾巴颜色类似上体，初级飞羽、次级飞羽和三级飞羽边缘呈淡黄色；下巴、喉咙和胸部淡黄色，边缘灰褐产生条纹效果；下体干净的淡肉桂色；飞羽下侧淡棕灰色。幼鸟特征未详述，亚成鸟与成鸟相似，但有更圆的初级飞羽外缘，头部斑点更多，背部斑点更红棕色。","call":"雄鸟发出多种粗糙音调的鸣唱，包括模仿其他鸟类的声音。","habits":"栖息于低地到山地森林、桉树-茶树林地、稀树草原、草地、公园、花园和柚木种植园，海拔高度从海平面至1700米。主要以果实和昆虫为食，包括毛虫和甲虫。单独或成对，有时形成小群活动。","breeding":"全年繁殖，在新几内亚高峰月份因地区而异，在澳大利亚为9月至12月，筑巢主要在11月。雄鸟建造装饰华丽的U形鸟巢，雌鸟独自筑巢。巢由细枝和藤蔓构成，内衬干草，建于树、灌木或红树林中，离地面高达10米。每季雄鸟在同一地点重建新巢。每次产卵一枚，孵化期未知，雏鸟在巢中停留21天。","identification":"与其他大亭鸟属物种相比，两性外观相同，可通过大小和缺乏粉色头冠来区分于较大的大亭鸟。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚（包括特兰斯弗莱地区、东北海岸、东南部）、约克角半岛东北部以及澳大利亚昆士兰州东北部。"},{"name":"白喉短嘴旋木雀","english_name":"White-throated Treecreeper","scientific_name":"Cormobates leucophaea","overview":"白喉短嘴旋木雀（英文名：White-throated Treecreeper，学名：Cormobates leucophaea），是雀形目短嘴旋木雀科白喉短嘴旋木雀属的鸟类。小型的澳大利亚旋木雀，主要分布在澳新界的东部森林地带。与北半球的旋木雀并无亲缘关系，体长约15厘米，以深灰棕色为主，具有显著的白色喉咙和胸部。","appearance":"白喉短嘴旋木雀体长14至16.5厘米，重17克（minor亚种）到22克（指名亚种）。雄鸟指名亚种上部呈深棕色，具细长的白色眼纹，额头有灰色斑点，眼圈破碎而微白；背部和尾巴颜色一致，后者带有黑色亚端带；翅膀上有宽阔的对比鲜明的红棕色横杠；喉咙纯白，逐渐变为中央下胸和腹部的黄白色；两侧和侧腹为灰棕色，饰有黑色边缘的奶油色条纹；尾下覆羽为奶油色，带有断续的黑色条纹；眼睛深棕色；喙黑色至灰黑色，下颚基部通常为淡灰色或奶油色；腿为深灰色至黑色。雌鸟脸颊处有锈橙色斑点。幼鸟背部有黑色边缘的暗白色羽毛轴纹，上胸有时有细小的灰色斑点，下腹部和尾下覆羽有强烈的肉桂棕色色调。","call":"其典型的领地叫声是由两性发出的一系列穿透性的笛音，起初快速重复，随后缓慢下降，持续时间可达5分钟；单个音符也可用于接触。雄鸟还会发出连续的上扬音符序列，带有轻微的渐强，以及柔和的颤音。雌鸟偶尔会发出一系列下降和减速的音符；在孵卵期间，会发出柔和的声音，类似摩尔斯电码。","habits":"白喉短嘴旋木雀主要以成虫和幼虫昆虫为食，特别是蚂蚁，也会吃蜘蛛；偶尔食用金合欢或桉树的树液，罕见地摄取花蜜。它们在树木和灌木的树皮上觅食，偶尔在枯木上，但在地面上很少见；觅食高度取决于可用植被的高度，大多在树干上（高达88%），以及树枝和细枝上。在干旱硬叶林中，偏好粗糙树皮的桉树，如弦叶桉和铁木，而在光滑树皮的桉树上花费的时间较少。","breeding":"繁殖季节从8月至次年1月；通常是单窝繁殖。社会上是一夫一妻制，通常以一对形式繁殖；个别个体（无论性别）可能同时与两个异性维持配偶关系。巢由雌鸟单独建造，需时7至15天，为杯状结构，由树皮纤维、草和苔藓组成，内部铺垫更细的树皮、毛发和羽毛，置于树洞内，入口通过树干上的孔或树枝侧面的裂缝；巢高1至25米，平均7米。每窝产2至3枚蛋，罕见情况下产4枚，蛋壳为哑光白色，带有少量深红棕色到紫黑色的圆形斑点，主要集中在较大的一端。","identification":"白喉短嘴旋木雀与红眉短嘴旋木雀的区别在于头部和背部颜色相同，红眉短嘴旋木雀的头部与棕色背部形成对比。此外，它的翼下有明显的浅色横杠。","protection":"IUCN：LC（无危）","distribution":"白喉短嘴旋木雀广泛分布于澳大利亚东部，从南澳大利亚的Gulf St Vincent，经维多利亚州，到新南威尔士州东部和昆士兰州东南部，北部分布区从Mount Spec延伸至Cooktown。","other":"白喉短嘴旋木雀在澳大利亚受到《国家公园和野生动物法》（1974年）的保护。"},{"name":"短嘴旋木雀","english_name":"Papuan Treecreeper","scientific_name":"Cormobates placens","overview":"短嘴旋木雀（英文名：Papuan Treecreeper，学名：Cormobates placens），是雀形目短嘴旋木雀科白喉短嘴旋木雀属的鸟类。新几内亚高山区特有种。曾被认为是白喉短嘴旋木雀的一个亚种。体长约14.5厘米，体重介于12至19.5克之间。","appearance":"雄性短嘴旋木雀的头部呈暗棕色，有模糊的淡褐色条纹；背部至臀部为暗橄榄褐色，翅膀较深，带有锈色条纹，尾巴橄榄色到灰色，有黑色斑点，腹部颜色由灰白色渐变为赭黄色，两侧有暗褐色条纹。雌鸟有明显的锈橙色颊斑，腹部条纹更大。幼鸟类似成年个体，但腹部的斑点更重。不同亚种在羽毛色彩上有所差异。","call":"发出一系列柔和的5至10个笛音或钟音似的音符，音调缓慢上升，最后一个音符持续时间较长；还有一种逐渐下降的颤音，类似于栗胸杜鹃的叫声，以及微弱的鼻音三连音，‘chu chee chu’。","habits":"栖息于海拔1250米至2600米的低至高山雨林，甚至可达雪山西部高达3000米的亚高山森林。以昆虫为食，通常单独活动，偶尔成对或家庭群出现。以独特的跳跃式攀爬树干的方式觅食，然后飞降至较低水平，随即再次开始攀爬。","breeding":"关于繁殖的信息尚不清楚。","identification":"与其它旋木雀相比，短嘴旋木雀是新几内亚唯一的旋木雀物种，其最显著的区别在于其行为模式，而与之行为相似的sitellas体型明显较小且背部有条纹。","protection":"IUCN：LC（无危）；尽管观察稀少，但据估计在某些地区可能较为常见。由于其栖息地集中在较高海拔，远离伐木和刀耕火种农业的低地，因此物种安全受到威胁的可能性较低。生态学和生物学知识贫乏，需进一步研究。","distribution":"主要分布在新几内亚的山区，包括从1250米至2600米的低至高山雨林，以及雪山西部高达3000米的亚高山森林。"},{"name":"红眉短嘴旋木雀","english_name":"Red-browed Treecreeper","scientific_name":"Climacteris erythrops","overview":"红眉短嘴旋木雀（英文名：Red-browed Treecreeper，学名：Climacteris erythrops），是雀形目短嘴旋木雀科短嘴旋木雀属的鸟类。澳大利亚东南部特有种。体长约15-16厘米，以灰褐色为主调，具有醒目的锈红色眉纹和淡色喉胸。分布于从昆士兰东南部至维多利亚东部的成熟桉树林和山地森林。","appearance":"雄性红眉短嘴旋木雀头部、颈背和臀部为暗灰色，上体其余部分为深棕色；具有宽广的红橙色眉纹、颊区及眼下方区域。上翼为黑褐色，次级飞羽基部有灰色条纹，尾上覆羽为灰色，尾羽有黑色亚端带。下体为淡白色喉部，上胸部棕色，下胸部及两胁为暗棕色，带有显著的黑边白色条纹，腹部为奶油色，尾下覆羽为浅黄色，有断续的黑色横斑。雌鸟与雄鸟的主要区别在于眉纹、颊区及眼下方区域为暗红栗色，上胸部有红栗色和淡白色条纹。幼鸟头部为均匀灰色，缺乏成年鸟的红褐色眼区，下体无或仅有少量标记。","call":"叫声比白眉短嘴旋木雀更为沙哑和昆虫般。","habits":"栖息于非常湿润的桉树森林，主要以蚂蚁为食，亦食用蜘蛛、甲虫、各种昆虫及它们的幼虫。常在树干、枝条和细枝上觅食，偶尔在地面或倒木上活动，活动高度多样，从地面至树冠层均有其身影。","breeding":"繁殖季节为8月底至次年1月，有时会育有两窝。社会上实行一夫一妻制，通常由一对配偶繁殖，或形成包含一个每性别的繁殖者和一两个助手（通常是雄鸟）的互助群体。巢由雌鸟主要建造，雄鸟辅助，置于树洞底部，入口通过树干上的孔或裂缝，或折断树枝的开口。孵化期约18天，雏鸟期25天，幼鸟离巢后至少依赖60天。","identification":"与白眉短嘴旋木雀相比，红眉短嘴旋木雀的头部颜色更偏向灰色，背部颜色更深，眉纹为锈红色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东南部沿海和高地森林，从昆士兰东南部南至维多利亚（东至墨尔本稍西）。"},{"name":"白眉短嘴旋木雀","english_name":"White-browed Treecreeper","scientific_name":"Climacteris affinis","appearance":"白眉短嘴旋木雀体长14至16厘米，翼展约22厘米，体重21克。雄鸟成鸟上身大部分为深灰色，除棕色的背部和黑色的尾端带。面部特征包括黑色的眼纹、白色且逐渐变细的眉纹，以及黑白相间的耳羽。雌鸟与雄鸟相似，但眉纹上方有一条淡红褐色的边线，上胸部中央有红褐色和暗白色相间的条纹。幼鸟的面部图案较成鸟模糊，喙呈淡灰色。两性均有黑色的喙和腿脚，深褐色的眼睛。","call":"主叫声为清脆的类似昆虫的颤音，有时被描述为‘刺耳的叫声’；此外还有更响亮的口哨声，‘叮叮叮’。叫声的用途尚不完全清楚，因为发出频率不高。","habits":"白眉短嘴旋木雀栖息于干燥和半干旱的林地，尤其是老生长的灌木林，而非河岸的桉树林。它们主要以蚂蚁为主食，同时也会吃蜘蛛、甲虫、蛾、苍蝇、白蚁和各种昆虫幼虫。它们既能攀爬树木，也能在地面活动，经常在倒下的树木、木头堆、枯叶中觅食，特别是在植被茂密的地方。","breeding":"繁殖季节在西澳大利亚始于7月，而在维多利亚则从8月末持续到11月末，但具体时间每年有所不同。通常会尝试第二次繁殖，尤其是在雨量充沛的年份。繁殖群体由一对配偶组成，有时还包括1至3个前一年的雄鸟后代作为帮手。巢由树皮纤维、干草、毛发、羽毛或植物绒毛构成，放置于树洞中，深度从8到42厘米不等，通常位于死树或活树的枯枝上。筑巢期间，只有雌鸟孵化，孵化期约为18天，幼鸟孵化后至少7天内由雌鸟照顾，喂食频率平均为每小时7.3次，直到26天后离巢。","identification":"与较大的、颜色更深的褐短嘴旋木雀相比，白眉短嘴旋木雀的腹部条纹更为明显，耳羽条纹不那么明显，而且在地面上的时间较少。白眉短嘴旋木雀的叫声为独特的‘prrrpt’昆虫般的叫声，而褐短嘴旋木雀的叫声则为短暂的尖锐‘peep’。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚中南部，包括维多利亚州西部和南澳大利亚州东部。两个亚种的分布区域不重叠：C. a. affinis位于斯宾塞湾以东，C. a. superciliosus位于以西。","other":"白眉短嘴旋木雀是澳大利亚特有的7种短嘴旋木雀中的一种，其余6种分布在澳大利亚，1种在新几内亚。"},{"name":"棕短嘴旋木雀","english_name":"Rufous Treecreeper","scientific_name":"Climacteris rufus","overview":"棕短嘴旋木雀（英文名：Rufous Treecreeper，学名：Climacteris rufus），是雀形目短嘴旋木雀科短嘴旋木雀属的独特鸟类。以其庞大的脚著称，活跃于澳大利亚西南部至南澳大利亚艾尔半岛的桉树森林和灌木丛中。上体呈暗棕色，脸部和下体具有红棕色色调，与其它旋木雀种类明显不同。","appearance":"体长16.5至18厘米，体重30至33克。雄鸟拥有丰富的肉桂红棕色眉纹、脸颊、耳羽、喉部和胸部，细长的深灰色眼线，额头、头顶、颈背和颈部侧面为淡褐色，逐渐过渡至较深的橄榄褐色背部和翅膀覆羽。雌鸟类似，但上胸的条纹边缘呈红栗色而非黑色。幼鸟缺乏成年鸟的红棕色眉纹，头部和颈部为暗石板灰色，喉咙和上胸无条纹。","call":"发出缓慢重复的‘peeep…peeep…peeep’叫声。","habits":"栖息于开放的桉树林和马利灌木丛，主要食物为蚂蚁，但也吃其他昆虫如鳞翅目幼虫和成虫、甲虫、蟑螂、蝽象、黄蜂、蜜蜂、白蚁、蜻蜓和蚱蜢，偶尔食用蜥蜴、种子和花蜜。在沿海的桉树林中主要在树上觅食，地面觅食比例不到20%。","breeding":"具体繁殖信息未提供。","identification":"与其它旋木雀相比，具有独特的红棕色脸部和胸部，以及明显的黑白条纹胸斑。雌雄之间主要通过上胸条纹的颜色区别。","protection":"IUCN：LC（无危）。在农业地区因栖息地丧失和碎片化可能有所减少。","distribution":"分布于澳大利亚西南部至南澳大利亚中部，包括西澳大利亚州南部至南澳大利亚州南部。","other":"在破碎的景观中，繁殖成功率低于未破碎的环境，这与较高的种群密度和领土质量下降有关。"},{"name":"褐短嘴旋木雀","english_name":"Brown Treecreeper","scientific_name":"Climacteris picumnus","overview":"褐短嘴旋木雀（英文名：Brown Treecreeper，学名：Climacteris picumnus），是雀形目短嘴旋木雀科短嘴旋木雀属的鸟类。广泛分布于澳大利亚东部，从昆士兰的Cape York至南澳的Port Augusta。偏好由桉树主导的林地环境，常见于海拔1000米以下，避免密集灌木丛。其体型约16.5厘米，重约31.5克。","appearance":"成年个体上体呈灰褐色，脸部和颈部浅灰色，冠部颜色更深，耳羽暗色。眉线明显且淡色，脸颊、喉部和胸部为奶油至灰白色，胸部中央有黑色和白色条纹的小块区域，下腹部和两侧有细致的黑边白纹。飞行时可见宽阔的褐色翼带。雄鸟与雌鸟的主要区别在于雄鸟胸部条纹为黑白相间，而雌鸟为红白相间。幼鸟头部颜色较暗，条纹不明显。","call":"发出类似\"spink spink\"的叫声，可单次或缓慢重复5至10次，有时会加速并以旋律性的哨音或咯咯声结束。也会发出一系列4到100个较弱的单调音符，伴随轻微的音量增强，以及尖锐的嘶嘶声。","habits":"栖息于各种桉树林地，包括干硬叶林、河岸红桉林、河流雪松林、半清理牧场等。偏好粗糙树皮的树木，如stringybarks和ironbarks。通常独居，活动范围不超过10公里。以昆虫为主食，尤其是蚂蚁和蜘蛛，偶尔也吃花蜜和树汁。在树干和地面觅食比例相当，冬季和春季更倾向于地面觅食。","breeding":"繁殖季节为7月中旬至12月初，可能尝试多次筑巢，但通常仅成功抚养一窝。以配对形式繁殖，有时会有合作群体，包括一对繁殖者和最多六个帮助者。巢建在树洞中，通常位于死树或活树的裂缝中，高度从0.3至25米不等。每窝产卵2至4枚，平均3枚，孵化期15至16天。雌鸟独自孵化，雄鸟和帮手提供食物。","identification":"与白喉短嘴旋木雀相比，更偏好开放地带。雄鸟胸部的黑白条纹，雌鸟的红白条纹，是识别关键。不同亚种之间存在差异，如melanotus亚种的深色羽毛和较小体型。","protection":"IUCN：LC（无危）；然而，subsp. victoriae在新南威尔士州被视为Vulnerable（易危），并在国家层面被列为Vulnerable（易危）。","distribution":"分布于澳大利亚东部，包括昆士兰州的Cape York至南澳大利亚的Port Augusta和Flinders Ranges。在南澳大利亚的Adelaide和昆士兰的Cape York有记录的衰退。","other":"社会结构复杂，形成长期的社会单配偶制配对，有时领地会相互重叠。夜间单独栖息，白天在小组或成对中觅食。"},{"name":"黑尾短嘴旋木雀","english_name":"Black-tailed Treecreeper","scientific_name":"Climacteris melanurus","overview":"黑尾短嘴旋木雀（英文名：Black-tailed Treecreeper，学名：Climacteris melanurus），是雀形目短嘴旋木雀科短嘴旋木雀属的鸟类。是澳大利亚北部和西北部特有种。其显著特征为深褐色至黑色的外观，雄鸟拥有黑色的喉部，而雌鸟的喉部为白色。","appearance":"该鸟长16至19厘米，重约32克。雄性黑尾短嘴旋木雀通体黑褐，耳羽盖上有模糊的细白条纹，上翼具宽幅的淡奶油色横带，尾羽黑褐。喉部、胸部覆以粗大的黑边白条纹，腹部呈暗棕色并带有细小的黑色条纹，尾下覆羽黑褐并带有白色侧斑。雌鸟喉部白色，上胸有宽阔的栗色边缘的白条纹。幼鸟喉部颜色各异，雄鸟为黑褐色，雌鸟为淡白色，下体颜色较深，喙和口腔边缘粉白色。wellsi亚种体型略小，色彩更鲜艳，颈部、侧胸和两胁深红棕色，下胸和腹部粉棕至浅肉桂色，尾下覆羽有明显的白色横纹。","call":"鸣叫为缓慢重复的'pip pip pip'声，随后是一串快速的相同音符的颤音。","habits":"生活在干燥森林、灌木草原和湿润低地森林中，主要以蚂蚁、甲虫、蛾子、蝗虫和不明昆虫幼虫为食，偶尔也会访问花朵可能摄取花蜜。在树干、大枝、死枝、树叶上觅食，偏好在8至14米的高度活动，也常在地面觅食，采用啄食和探查的方式。","breeding":"参与合作繁殖，即多个个体协助抚养后代，而非仅限于亲生父母。大约在2岁时达到性成熟。","identification":"与同属物种相比，黑尾短嘴旋木雀是澳大利亚北部和西北部唯一的树栖旋木雀种类，其独特的黑尾和体色有助于识别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚中北部和中西部。"},{"name":"华氏鹩莺","english_name":"Wallace's Fairywren","scientific_name":"Sipodotus wallacii","overview":"华氏鹩莺（英文名：Wallace's Fairywren，学名：Sipodotus wallacii），是雀形目细尾鹩莺科华氏鹩莺属的鸟类。是其属内的唯一物种。主要分布在新几内亚和阿鲁群岛，栖息于亚热带或热带湿润低地森林。","appearance":"体长11-12.5厘米，体重7-8克。雄鸟具有黑色冠羽和颈背，蓝白色耳羽，锈褐色肩背，白色下体，黑喙长而直，尖端白色。雌鸟相似，但喉部呈淡黄色，冠羽较暗。幼鸟比成鸟更暗淡，冠羽具斑点，耳羽和喙较短。","call":"发出一系列高音节的叫声，开始时较长，如“siiiii！sisisisisisisi！”。","habits":"栖息于海拔100-800米的雨林，偶尔可达1250米。主要在树上活动，以昆虫为食，常在林缘藤蔓丛中觅食，常加入混群。","breeding":"全年繁殖，高峰在9月至12月。巢为穹顶状，侧入口，由细草、蜘蛛网和棕榈叶条构成，置于5-10米高的藤蔓中。每窝产2枚卵，双亲共同育雏。","identification":"与雌鸟帝王细尾鹩莺类似，但华氏鹩莺下颌至颏部为白色，有翼斑。雄鸟喉部白色，雌鸟喉部淡黄色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚和阿鲁群岛，包括Misool（四王群岛，新几内亚西北部）、Yapen（鸟头湾，新几内亚西北部）、印尼阿鲁群岛（新几内亚西南部）。","other":"在大型森林砍伐的背景下，华氏鹩莺面临潜在威胁。"},{"name":"阔嘴细尾鹩莺","english_name":"Broad-billed Fairywren","scientific_name":"Chenorhamphus grayi","overview":"阔嘴细尾鹩莺（英文名：Broad-billed Fairywren，学名：Chenorhamphus grayi），是雀形目细尾鹩莺科阔嘴细尾鹩莺属的鸟类。小型且鲜为人知的鸟类，分布于新几内亚的北部和西北部，主要栖息在低地和山麓的原始森林中的树倒空隙地带。其自然生境为亚热带或热带湿润的低地森林。","appearance":"该鸟拥有淡蓝色的下体，背部颜色更深，呈深蓝色，翅膀呈褐色。头部具有显著的黑色眼纹、髭纹和不太明显的冠纹。雌鸟具有白色腹部。雄鸟在繁殖季节颜色更为鲜艳，而雌鸟较为朴素。","call":"鸣叫声被描述为一系列快速高音调的音符，有助于辨识该物种。","habits":"阔嘴细尾鹩莺主要在森林底层的灌木丛中觅食，偏好昆虫为食。它们在地面和密集的植被中寻找食物，特别是在裸露的树根周围。活动范围限于低层森林，最高可达5米。","breeding":"关于繁殖行为的记录有限，已知雄鸟的睾丸在7月时会增大，幼鸟在2月时被发现。唯一已知的巢穴位于主林区的一个20米宽山脊上，距离地面约50厘米的高度，巢穴是在覆盖着苔藓的小树干上的一个洞穴，深度为8厘米，宽度为5厘米，内部铺有干燥的针叶和树皮条，里面养育了两只雏鸟。","identification":"与其他同类相比，如坎氏细尾鹩莺，阔嘴细尾鹩莺的下体颜色更浅，背部颜色更深。蓝细尾鹩莺雄鸟颜色更深蓝，且更常见于次生林。","protection":"IUCN状态未知，需进一步研究确定。","distribution":"分布于澳新界：印尼萨拉瓦蒂岛（四王群岛，新几内亚西北部），鸟头半岛和Neck（新几内亚西北部）至新几内亚中北部。","other":"曾被归类于过时的Todopsis属和Malurus属，直到2011年的DNA分析证实其与坎氏细尾鹩莺存在高度遗传分化，随后被重新分类到独立的Chenorhamphus属中。"},{"name":"坎氏细尾鹩莺","english_name":"Campbell's Fairywren","scientific_name":"Chenorhamphus campbelli","overview":"坎氏细尾鹩莺（英文名：Campbell's Fairywren，学名：Chenorhamphus campbelli），是雀形目细尾鹩莺科阔嘴细尾鹩莺属的鸟类。分布于新几内亚南部低地。以前被归入阔嘴细尾鹩莺中，直到2011年基于线粒体和核DNA分析显示两者之间存在高度遗传差异，才将其重新分类为独立物种，并归入Chenorhamphus属。以苏格兰邓弗姆林的Rob Campbell命名，他在1980年代在巴布亚新几内亚首次识别了这种鸟。","appearance":"坎氏细尾鹩莺体型小巧，腹部和长长的眉毛呈淡蓝色，背部、翅膀和尾巴为棕色。其最显著的特征是黑色的眼纹、髭纹和冠纹。它与相似的阔嘴细尾鹩莺在地理分布上并不重叠。","call":"其鸣叫声为高音调的旋转式歌唱，由一系列尖锐的音符组成。","habits":"这种鸟通常成对或小群活动，栖息于密集的灌木丛中，如竹藤和西谷榈树丛中，偏好低地和山脚下的树倒隙地再生林。","breeding":"关于坎氏细尾鹩莺的繁殖信息目前尚未详细记载。","identification":"与阔嘴细尾鹩莺相比，坎氏细尾鹩莺的下体颜色更淡，眼纹、髭纹和冠纹更为突出，且二者在地理分布上互不重叠。","protection":"IUCN状态未知，需进一步关注。","distribution":"分布于新几内亚的中南部和东南部低地，具体位于其自然生境的亚热带或热带湿润低地森林。","other":"坎氏细尾鹩莺的分类历史反映了鸟类学研究中基于分子数据的物种界定进展。"},{"name":"蓝细尾鹩莺","english_name":"Emperor Fairywren","scientific_name":"Malurus cyanocephalus","overview":"蓝细尾鹩莺（英文名：Emperor Fairywren，学名：Malurus cyanocephalus），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。新几内亚特有种，生活在低地和山脚森林边缘及灌木丛中。雄鸟具有深蓝色的羽毛，头戴淡金属蓝冠，雌鸟则呈现锈褐色上部和白色胸部，两者均拥有翘起的尾巴。最大的细尾鹩莺种类，体长约13至16厘米，体重12至17克。","appearance":"雄鸟头部的冠羽呈淡金属皇家蓝，额头、眼周和头部侧面至狭窄领圈为黑色；背部、肩羽和上尾覆羽为深宝石蓝，下背为蓝黑色；翅膀和尾羽黑中带蓝；喉咙和下体为深海军蓝。雌鸟头部类似雄鸟，但上身是栗色，尾羽黑色且带有宽阔的白色尖端，喉部深蓝，下体白色；眼睛和喙与雄鸟相同，腿为中棕色。幼鸟基本像雌鸟，但头部暗黑色，上身为红褐色，整个下体白色；年轻雄鸟在达到成年羽毛前会经历类似雌鸟的羽毛阶段。三个亚种在色彩深度上有所不同。","call":"鸣唱是一系列混乱的颤音，前后伴随三音符的组合，通常在觅食时由群体发出。接触叫声为干燥的“tst-tst-tst-tst”；报警声为“tschik”。","habits":"生活在浓密的次生林缘，包括森林开阔地带、河边、路边和杂草丛生的花园。全年留居，有一只雄鸟在8年内被捕捉12次，每次都在相距不到100米的地方，且连续与三位不同的雌鸟相伴。以昆虫为食，包括甲虫、蝽象、蛾类、蚱蜢和蜘蛛。在离地面1米内的树叶、棕榈叶和树枝上觅食。以家庭群的方式嘈杂地觅食，不会加入混合物种的群落。","breeding":"繁殖习性知之甚少。幼鸟记录显示从3月到12月均有出现，可能全年繁殖。社会上一夫一妻制，但可能性上多配偶制，全年保持伴侣关系。合作繁殖，常有帮助者，通常是前一年的后代。已知巢穴为葫芦状，侧入口，由蕨类叶片和叶子编织而成，其间穿插苔藓碎片，置于离地1米高的灌木丛中，巢内有4只幼鸟。","identification":"与华莱士细尾鹩莺相比，蓝细尾鹩莺缺乏白色的翼条和面部条纹。雄鸟与雌鸟的颜色差异显著，而不同亚种间主要是色彩深浅的差异。","protection":"IUCN：LC（无危）","distribution":"分布在新几内亚及其周边地区，包括北和西北新几内亚、比亚克岛、南新几内亚和阿鲁群岛。","other":"尽管喜欢受扰动的环境条件，如花园和公园，但并非受到栖息地破坏的影响。"},{"name":"娇美细尾鹩莺","english_name":"Lovely Fairywren","scientific_name":"Malurus amabilis","overview":"娇美细尾鹩莺（英文名：Lovely Fairywren，学名：Malurus amabilis），是雀形目细尾鹩莺科细尾鹩莺属的小鸟。又名: 秀丽细尾鹩莺。以蓝色和白色的长尾为显著特征，尾巴经常呈扇形展开。分布于澳大利亚东北部，包括约克角半岛北部至昆士兰州东北部，是该地区的特有种。","appearance":"繁殖期的雄鸟具有浅蓝色的头盔状冠羽、棕色翅膀和白色腹部，雌鸟和非繁殖期的雄鸟外观相似，全身下方为纯白色，直至下巴，背部、头部和脸颊为蓝色。两性均有白色眼环，眼睛前方有白色斑点，赋予其眼镜般的外观。雄鸟在繁殖季节展现出鲜明的蓝色耳羽和上背，黑色喉咙和颈后，肩部呈栗色，尾巴蓝色并带有宽白尖，翅膀黑色，腹部白色。雌鸟的上部为烟熏蓝色，翅膀深灰色，尾巴烟熏蓝带宽白尖，下方奶油白色。","call":"鸣唱为一连串较弱的卷曲声，典型于该属，接触叫声为拉长的“treeee”，重复发出；警报声为短暂的“zit”。","habits":"主要栖息于雨林边缘、红树林和沿海北昆士兰的密集植被中，偏好在树和灌木丛中觅食而非地面，善于飞行。以昆虫为食，包括各种昆虫如毛虫。","breeding":"被灌丛杜鹃寄生，具体繁殖行为细节未详述。","identification":"与杂色细尾鹩莺相比，尾部明显更短。与其他胸肩蓝色细尾鹩莺物种的区别在于其独特的地理分布和特定的蓝色调。","protection":"IUCN状态未提及。","distribution":"分布于澳大利亚东北部，具体为约克角半岛北部至昆士兰州东北部，包括澳大利亚东北部地区。","other":"属于胸肩蓝色细尾鹩莺组，该组共有五个非常相似的物种。"},{"name":"紫背细尾鹩莺","english_name":"Purple-backed Fairywren","scientific_name":"Malurus assimilis","overview":"紫背细尾鹩莺（英文名：Purple-backed Fairywren，学名：Malurus assimilis），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。澳大利亚特有种。由四个已确认的亚种组成，展现明显的雌雄异型，繁殖季节的雄鸟拥有鲜艳的蓝胸和紫背，而非繁殖季节的雄鸟、雌鸟及幼鸟则以灰褐色为主。广泛分布在澳大利亚大陆的大部分地区，尤其偏好植被茂密的灌木丛。","appearance":"雄鸟在繁殖季节呈现出明亮的蓝色头盔，黑色胸部，紫色背部，以及带有浅色尖端的长蓝尾。雌鸟和非繁殖期的雄鸟通常呈灰褐色，但在特定亚种中，雌鸟可能具有蓝色的冠和背部。成年雄鸟身长约为14.5厘米，体重6.5至10克，具有天空蓝的冠羽，耳羽较淡，与皇蓝的背部通过黑色颈环相隔开。肩部呈栗色，下背黑色，翅膀深灰棕色，尾巴蓝绿色带窄白尖。雌鸟和幼鸟外观相似，但雌鸟的喙和眼圈呈红棕色，而幼鸟在6个月大时会发展出黑色的喙。","call":"其鸣唱如同卷轴般，但相对较弱，类似于‘胸肩组’中的其他种类。联系叫声为拉长的‘treeee’，重复发出；警报声为短暂的‘zit’。","habits":"紫背细尾鹩莺居住在密集的灌木丛生环境中，从沿海灌木到岩石地带的灌木丛，沿着溪流，遍布干旱内陆。它们通常是定居性的，以昆虫为主要食物来源，包括蚱蜢、蝽象、甲虫、苍蝇、蚂蚁、黄蜂和蜘蛛。它们也吃种子。它们成对或小群体生活，穿梭于灌木丛中或开阔地面上觅食。","breeding":"繁殖季节为7月至12月，但也会因夏季末的旋风降雨而繁殖。如果季节适宜，可能抚育两到三窝幼鸟。社会上是一夫一妻制，但可能在性行为上不专一。全年保持配对状态，是合作性繁殖者，经常有来自前一年的后代作为帮手。雌鸟建造巢穴，通常位于灌木或树木低处，有时在蕨类植物丛中。每窝产卵2至4枚，孵化期14至16天，幼鸟在10至12天后离巢，但继续隐蔽7至10天，由群组成员喂养约一个月。","identification":"紫背细尾鹩莺与其他细尾鹩莺的区别在于其独特的色彩模式，尤其是繁殖期雄鸟的蓝胸和紫背。雌鸟在不同亚种间颜色差异明显，特别是在两个亚种中具有蓝色灰色的羽毛。","protection":"IUCN：LC（无危）；在澳大利亚广泛分布，占国土面积的约90%，但在某些地区评估中被列为“Vulnerable”（易危）。","distribution":"紫背细尾鹩莺广泛分布于澳大利亚大陆的大部分地区，除了西南部、东北部、东南部和塔斯马尼亚。在内陆和北部澳大利亚，它们偏好岩石露头和阿卡西亚、埃雷莫菲拉或林木的斑块。","other":"该物种曾被认为是变色细尾鹩莺的一个亚种，直到遗传学证据证明其独特性，于2018年恢复独立物种地位。"},{"name":"杂色细尾鹩莺","english_name":"Variegated Fairywren","scientific_name":"Malurus lamberti","overview":"杂色细尾鹩莺（英文名：Variegated Fairywren，学名：Malurus lamberti），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。是澳大利亚东部特有的小型鸟类，雄鸟繁殖期展现明亮的蓝色头盔、黑色胸膛、皇家蓝背部和栗色肩部，尾羽极长且常翘起。雌鸟和非繁殖期雄鸟主要呈灰褐色，具有长而带淡白色尖端的蓝色尾巴。分布于澳大利亚东南部，从昆士兰东南部至新南威尔士州东南部，偏好湿润密集植被。","appearance":"杂色细尾鹩莺体长约14-15厘米，体重6-11克。繁殖期雄鸟具有醒目的亮蓝色耳罩，稍暗的蓝色头冠，黑色喉咙和颈背，皇蓝色上背，栗色肩部，蓝灰色尾羽。翅膀深灰棕色，腹部乳白色。雌鸟和非繁殖期雄鸟主要为灰褐色，具红棕色眼环和裸皮。雄鸟6个月大时开始发展黑色喙，随后进入繁殖期会换上繁殖羽毛。","call":"基本鸣声为高音的连续短音（每秒10-20个音节），持续1-4秒，为所有细尾鹩莺中最柔和的鸣声。通过tsst或seeee声保持联系，tsit声作为警报。","habits":"栖息于提供浓密覆盖的灌木丛生地，包括海岸灌木到岩石地带的灌木丛，沿溪流，乃至干旱内陆。全年保持领域性，以昆虫为主食，包括蚱蜢、蝽象、甲虫、苍蝇、蚂蚁、黄蜂和蜘蛛，也摄取种子。生活在配对或小群体中，活跃于地面附近寻找食物，跳跃平衡由大尾辅助。","breeding":"繁殖期从春季到夏季晚期，可能因适宜季节而产两至三窝。社会上一夫一妻制但可能性杂交。巢由雌鸟建造，是带有侧面入口的椭圆形穹顶结构，由草、枝条和树皮构成，内部铺有细草、毛发和羽毛，通常位于低矮灌木或树木中。每窝产2-4枚蛋，孵化期14-16天，孵化及喂养由所有群体成员共同承担。","identification":"与紫背细尾鹩莺在Great Dividing Range附近区分，可通过色彩、行为和分布区辨别。雄鸟繁殖期羽毛色彩鲜明，雌鸟羽毛颜色较为灰暗，但某些亚种雌鸟主要呈蓝灰色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东南部，从昆士兰东南部至新南威尔士州东南部，偏好湿润密集植被。在城市环境中，如悉尼郊区，偏好植被覆盖丰富的区域。","other":"曾被认为是在干旱条件下会利用哺乳动物洞穴避热的少数鸟类之一。"},{"name":"蓝胸细尾鹩莺","english_name":"Blue-breasted Fairywren","scientific_name":"Malurus pulcherrimus","overview":"蓝胸细尾鹩莺（英文名：Blue-breasted Fairywren，学名：Malurus pulcherrimus），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。属于细尾鹩莺科，仅分布于澳大利亚西南部至南澳的埃尔半岛。繁殖季节，雄鸟展现亮丽的蓝色头部、蓝黑色胸部和蓝背，肩部呈栗色。雌鸟灰褐色，长尾蓝灰色，喙红色。非繁殖期雄鸟类似雌鸟，但具有黑喙和淡色眼圈。","appearance":"雄鸟在繁殖期时，头顶、上背和耳羽呈蓝紫色，眼上方、颈背、领圈和下背为黑色，有窄蓝色眼圈；肩羽栗色，上翼深褐，尾蓝而尖端白；喉和胸深蓝，腹灰白。雌鸟上体灰褐，脸侧和眼周栗色，下体乳白色；裸部同雄鸟，但喙暗褐。非繁殖期雄鸟似雌鸟，保留黑喙和脸侧黑色，面部和眼周有蓝斑痕迹。幼鸟似雌鸟，雄鸟幼鸟在3个月大时开始显现出脸侧的黑色。","call":"鸣唱柔和，类似其他胸肩栗色细尾鹩莺组的轻柔旋转音。接触叫声为短促高音的“see”；警戒声为弱“tsit”，也有连续的颤音。","habits":"以昆虫为食，包括甲虫、象鼻虫、蝇类、蚂蚁、黄蜂和毛虫。通常2-4个成年鸟组成群体，可能伴有年轻个体；群体领地约2.5公顷。冬季在地面觅食，春夏季节在低矮灌木中觅食，不太愿意飞行。","breeding":"繁殖期为8月至次年1月，雌鸟每年产1-4窝，失败后会再筑巢，可能养育两窝幼鸟。社会上单配偶制但可能性杂交。合作繁殖，通常有前一年的后代帮助。巢由雌鸟建造，为卵圆形穹顶结构，侧入口，由草、叶和小枝制成，内衬细草、植物绒毛、羽毛和兽毛，一般位于灌木、树、密丛或积聚的枯叶下，平均离地约59厘米；后期巢位高于初期。每窝产2-3枚蛋，雌鸟孵卵，孵化期14-15天；所有群成员喂养巢雏，10-12天后离巢；幼鸟藏匿一周，随后随觅食群体移动，由父母和助手喂养约1个月；独立后仍与家庭群同住，可能参与父母后续的筑巢。","identification":"雄鸟在繁殖期的鲜艳色彩明显区别于雌鸟和非繁殖期雄鸟。与其他胸肩栗色细尾鹩莺组成员相比，蓝胸细尾鹩莺具有独特的蓝胸和栗肩。幼鸟与雌鸟相似，但雄鸟幼鸟早期会显示出脸侧的黑色。","protection":"IUCN：LC（无危）。局部地区较为常见，若残存足够适宜植被，即使广泛清除生境用于小麦种植也能生存。全球森林覆盖率变化显示，其生境在三个世代（21年）内丧失了三分之一，提示应视为全球易危。澳大利亚国家层面不认为其有保育担忧。","distribution":"分布于澳大利亚西南部至南澳大利亚的埃尔半岛，形成一条从西澳大利亚东南至南澳大利亚西南的斜向地带。在大澳大利亚湾头东至埃尔半岛间存在300公里的分布空缺。","other":"蓝胸细尾鹩莺的巢被霍斯菲尔德青铜杜鹃寄生。"},{"name":"红翅细尾鹩莺","english_name":"Red-winged Fairywren","scientific_name":"Malurus elegans","overview":"红翅细尾鹩莺（英文名：Red-winged Fairywren，学名：Malurus elegans），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。非迁徙性的澳大利亚特有种，仅见于澳大利亚西南部。雄鸟繁殖期展现出显著的蓝色和红色羽毛，与黑色喉部和灰色尾羽形成鲜明对比；雌鸟和幼鸟则主要为灰褐色。该物种在当地常见，但数量有下降趋势。","appearance":"雄性红翅细尾鹩莺在繁殖期具有银蓝色的冠、耳覆羽和背部，黑色的喉部和颈背，鲜亮的红棕色肩部，深灰棕色的上翼和蓝灰色的长尾，腹部灰白色。雌鸟全身灰褐色，肩部带红褐色，眼环淡灰色，尾羽同雄鸟。非繁殖期雄鸟与雌鸟相似，但保留黑色眼区，偶尔可见蓝色羽毛痕迹。幼鸟外观似雌鸟，雄鸟幼鸟自六周大开始展现黑色眼区。","call":"红翅细尾鹩莺的叫声包括一至四秒的高音卷曲声，由10-20个短音节组成，用于领地宣告和维护。软而重复的下降音调保持群内联系，尖锐的‘tsit’声为警报信号。","habits":"红翅细尾鹩莺栖息于温带湿润森林的灌木层，偏好湿润山谷和河流边的剑形莎草丛。它们以昆虫为主食，尤其是蚂蚁和甲虫，偶尔捕食蜘蛛。群体通常由2-9只鸟组成，维持小领土，进行合作繁殖。它们是弱飞者，主要在地面或低矮植被中觅食。","breeding":"繁殖季节从十月持续到十二月，雌鸟单独筑巢，巢位于浓密植被中，离地约20厘米。每窝产2-3枚奶油色蛋，带有红棕色斑点。雌鸟独自孵化，孵化期约为14-15天，幼鸟在11-12天后离巢，但需一个月的喂养。","identification":"红翅细尾鹩莺与变色细尾鹩莺和蓝胸细尾鹩莺在外形上相似，但通过其独特的繁殖期雄鸟羽毛颜色和分布区域可以区分。","protection":"IUCN：LC（无危）","distribution":"红翅细尾鹩莺主要分布在澳大利亚西南部，从珀斯北部的摩尔河向南至玛格丽特河区域，向东至阿尔巴尼。","other":"红翅细尾鹩莺的生存率在同类中最高，成年鸟的年度存活率可达78%，部分个体能活到16岁。"},{"name":"华丽细尾鹩莺","english_name":"Superb Fairywren","scientific_name":"Malurus cyaneus","overview":"华丽细尾鹩莺（英文名：Superb Fairywren，学名：Malurus cyaneus），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。是澳大利亚东南部常见的留鸟，以其醒目的雌雄异型和鲜艳的繁殖期雄鸟羽毛而著称。繁殖期雄鸟拥有亮蓝色的头部、背部和尾部，与黑色的面罩和喉部形成鲜明对比。非繁殖期雄鸟和雌鸟呈现灰褐色，仅尾部保留蓝色。该物种广泛分布于公园、花园和澳大利亚东南部的开阔林地。","appearance":"华丽细尾鹩莺长约14厘米，体重介于9至14克之间，雄鸟略大于雌鸟。尾巴平均长5.9厘米，是属内最短的。喙宽而窄，底部较宽，形状类似于其他以昆虫为食的鸟类。繁殖期雄鸟具有鲜艳的虹蓝色羽毛，耳羽和冠羽在求偶时尤为突出。雄鸟的前额、耳羽、上背和尾巴呈鲜蓝色，双翼呈褐色，喉咙、眼带和喙均为黑色。雌鸟、幼鸟和非繁殖期雄鸟则为黄褐色，下体颜色较浅，尾巴呈黄褐色或灰蓝色。喙在雌鸟和幼鸟中为褐色，在雄鸟中冬季后变为黑色。","call":"华丽细尾鹩莺的叫声包括了典型的malurid reel，由两性全天候发出，似乎用于宣示领地。还有一种变体reel，通常在潜在捕食者出现时被触发，它在开始时插入一系列不同的音节类型。接触叫声为短暂的'chet'声，警报声为短暂的'chit'声，孵卵中的雌鸟会发出'purrs'声。","habits":"华丽细尾鹩莺主要栖息在开放的桉树森林，现适应于如Lantana、Rosa和Rubus等外来灌木杂草环境，以及大型郊区公园和花园。主要分布在年降水量超过400毫米的区域。该鸟群居，每群由2至5个成年个体组成，以昆虫为主食，包括蚱蜢、盾虫、蚂蚁、苍蝇、象鼻虫及其幼虫，偶尔也会食用小型种子和果实。","breeding":"繁殖期从7月至2月，一季可能产卵多达四窝，有时能抚育超过一窝的幼鸟。社会上保持一夫一妻制，但性行为上多配偶，雌鸟会寻求群外交配，返回巢穴后在群内繁殖（研究显示，76%的后代由群外雄鸟所生）。合作繁殖，通常有来自前一年的后代担任助手。巢由雌鸟建造，是一个草和根须构成的卵圆形穹顶结构，内衬毛发和羽毛，位于低矮密集的覆盖物中。每窝产2至4枚卵，通常3枚，间隔一天产一枚；孵化期14天；雏鸟由群内所有成员喂养，离巢期10至14天；雏鸟由所有群成员喂养，独立于约40天大；幼鸟留在父母身边，可能帮助喂养后续的幼鸟，雄鸟幼鸟通常至少一年作为助手留在出生群内，雌鸟幼鸟更倾向于分散。","identification":"与其他同属物种相比，华丽细尾鹩莺雌鸟的羽毛更加凉爽和灰色，与红背细尾鹩莺温暖的色调形成对比。雄鸟在繁殖期的羽毛亮度和蓝色强度在不同亚种间有所变化，岛上的亚种体型更大，蓝色更深。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东南部和塔斯马尼亚州，主要在公园、花园和开阔林地中，包括城市郊区的悉尼、堪培拉、墨尔本和布里斯班。适应了城市环境，广泛存在于有足够覆盖物的郊区公园和花园。","other":"华丽细尾鹩莺能够应对外来捕食者，如家猫，以及竞争者，如麻雀，并能在郊区公园和花园中繁衍生息，只要存在足够的覆盖物。"},{"name":"辉蓝细尾鹩莺","english_name":"Splendid Fairywren","scientific_name":"Malurus splendens","overview":"辉蓝细尾鹩莺（英文名：Splendid Fairywren，学名：Malurus splendens），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。俗称蓝细尾莺，体型小巧的细尾鹩莺，主要活跃于灌木丛或森林底层。分布于澳大利亚西部至中部，常见于内陆干旱区和西澳大利亚西南部。","appearance":"雄鸟在繁殖期几乎全身呈现明亮的蓝色，头顶至背部、肩羽、喉部及大部分腹部为丰富的紫蓝色，耳簇羽天蓝色，眼线和头后黑色，胸部有一条黑色带，臀部黑色，尾部钴蓝色，翼上的主飞羽边缘为青绿色。雌鸟上体灰褐色，尾部深蓝绿带青色，喉部和下体白色，眼圈和喙基部赤褐色。非繁殖期雄鸟似雌鸟，但尾部钴蓝色，翼上的主飞羽边缘青绿色，喙和腿黑色。幼鸟似雌鸟，冬季首年雄鸟开始展现青绿色主飞羽和黑色喙，眼圈颜色加深。","call":"鸣声为一系列响亮的颤音组成的卷曲鸣唱，前有柔和简单元素引入，比其他细尾莺更响亮刺耳。存在变体，在潜在捕食者面前发出一串不同类型的音符附加在鸣唱末尾。群内联络叫声为轻柔的‘trrt’声，警报声为尖锐的‘tsit’声，对入侵者的威胁声为连续的‘churring’。","habits":"栖息于各种密集植被中，从桉树林到干旱区的灌木丛。主要以昆虫为食，包括蚂蚁、小甲虫、蚱蜢、蟋蟀和蝽象，偶尔也会吃蜘蛛和蜈蚣。偶尔在开花的桉树冠层觅食昆虫。以2至8只成鸟的群体形式生活。","breeding":"繁殖期为8月至1月，可能在一个季节内产下四窝蛋，抚育不止一窝幼鸟。社会上单配偶制，全年保持配对，但性行为上多配偶制。雌鸟会在群外寻求交配，回群中筑巢。巢由雌鸟建造，呈卵形穹顶状，入口位于侧面靠近顶部，由草制成，内衬毛发和羽毛。每窝产2至4枚蛋，通常3枚，间隔一天产下。孵化期14至15天，由雌鸟负责。幼鸟由整个群落成员喂养，离巢期10至13天。雏鸟由所有群成员喂养，保持隐蔽一周，约40天独立。幼鸟留在父母身边，可能帮助喂养后续的幼鸟，雄鸟通常至少一年留在出生群落作为帮手，雌鸟更可能分散。","identification":"与同属其他物种的区别在于雄鸟的蓝色亮度和胸带深度，以及雌鸟的特征颜色。与紫背细尾鹩莺区别在于眼圈与喙的颜色差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西部和中部，包括内陆干旱地区和西澳大利亚西南部。","other":"雄鸟在繁殖季节会摘取粉色或紫色花瓣展示给雌鸟作为求偶行为的一部分。"},{"name":"紫冠细尾鹩莺","english_name":"Purple-crowned Fairywren","scientific_name":"Malurus coronatus","overview":"紫冠细尾鹩莺（英文名：Purple-crowned Fairywren，学名：Malurus coronatus），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。以独特的紫色冠羽而得名，雄鸟繁殖季节时展现出鲜艳的紫色冠羽，搭配黑色眼线和颈圈，雌鸟则具有明显的暗锈色颊斑。该物种主要分布在澳大利亚中北部，偏好河流边的Pandanus（螺旋棕榈）和长草植被。物种历史系统学显示其与华丽细尾鹩莺和辉蓝细尾鹩莺亲缘关系最近。","appearance":"紫冠细尾鹩莺体型小巧，长约14厘米，翼展约16厘米，重9至13克。其整体呈棕色，翅膀灰褐色，腹部奶黄色。最显著特征为其深蓝色的竖直尾巴，尾羽除中央一对外，其余均带白色尖端。繁殖季节，雄鸟头部的紫色冠羽尤为醒目，周围环绕黑色面罩，头顶有一椭圆形黑斑。非繁殖季节，雄鸟的色彩被灰棕色羽毛替代，面罩变成黑色颊斑。雌鸟具蓝灰色冠羽，栗色耳羽，绿色蓝色尾巴。幼鸟类似雌鸟，但色彩更暗淡，有棕色冠羽和较长的尾巴。","call":"紫冠细尾鹩莺的鸣叫声与其它细尾鹩莺明显不同，音调较低，且响亮。它们的叫声包括响亮的'cheepa-cheepa-cheepa'卷曲声，较轻柔的'chet'声用于群内联系，以及刺耳的'zit'声作为警报。","habits":"紫冠细尾鹩莺栖息于澳大利亚北部湿润干燥热带地区的河流边缘，偏好密集的河岸植被。它们主要以昆虫为食，如甲虫、蚂蚁、蜘蛛等，也会少量摄取种子。这种鸟在河流边的密集灌木或高草丛中觅食，通常独自行动，通过快速跳跃在茂密的植被中移动，同时保持彼此间的联系。","breeding":"繁殖行为上，紫冠细尾鹩莺倾向于社会性单配偶制，但实际繁殖率低。雌雄鸟会在适宜条件下全年繁殖，高峰期出现在旱季早期和晚期。巢由雌鸟建造，呈小穹顶状，主要由细根、草、树叶和树皮条构成。每窝产2至3枚卵，仅由雌鸟孵化，孵化期约为14天。雏鸟在出生十天后离巢，之后至少三周内由家庭成员喂养。","identification":"紫冠细尾鹩莺与其他北澳细尾鹩莺的区别在于脸颊斑点的存在（雄鸟黑色，雌鸟红棕色）和深蓝色尾巴。此外，与同类相比，它们的尾巴更为竖直，颜色更深。","protection":"IUCN：LC（无危）；然而，西部亚种被列为Endangered（濒危）。","distribution":"分布于澳大利亚北部，具体包括西澳大利亚州的金伯利地区、北领地的维多利亚河区域，以及昆士兰州卡奔塔利亚湾西南部沿海区域。两个亚种间存在约300公里的地理隔离。","other":"紫冠细尾鹩莺面临的主要威胁包括生境退化、火灾频发、洪水以及采矿活动。"},{"name":"白肩细尾鹩莺","english_name":"White-shouldered Fairywren","scientific_name":"Malurus alboscapulatus","overview":"白肩细尾鹩莺（英文名：White-shouldered Fairywren，学名：Malurus alboscapulatus），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。以其独特的白肩黑色外观著称，主要分布在新几内亚的低地清理区域，包括草场、村庄花园和甘蔗草地。","appearance":"成年雄性白肩细尾鹩莺全身呈现光泽的黑色，仅肩部有一块醒目的白色斑点，其尾部较其他细尾鹩莺种类短。雌鸟的羽毛颜色则因亚种而异，M. a. alboscapulatus和M. a. naimii亚种的雌鸟具有黑白相间的羽毛，上身黑色与白色肩部和下身形成鲜明对比。","call":"其鸣唱为持续重复的高音乱语，叫声则为干燥的咔哒声。","habits":"白肩细尾鹩莺偏好生活在低地的开阔地带，如草场、村庄花园以及甘蔗草地，它们在这些环境中活动并觅食。","breeding":"关于白肩细尾鹩莺的繁殖习性的具体信息未详述。","identification":"与皮埃德灌丛莺相比，白肩细尾鹩莺拥有更长且翘起的尾巴，这是重要的辨识特征。","protection":"IUCN状态未提供。","distribution":"白肩细尾鹩莺主要分布在新几内亚的繁殖区域。","other":"白肩细尾鹩莺共有六个地理隔离的亚种，它们通过雌鸟羽毛的差异得以区分。"},{"name":"红背细尾鹩莺","english_name":"Red-backed Fairywren","scientific_name":"Malurus melanocephalus","overview":"红背细尾鹩莺（英文名：Red-backed Fairywren，学名：Malurus melanocephalus），是雀形目细尾鹩莺科细尾鹩莺属的小型鸟类。繁殖期雄鸟身着醒目的黑头、上体和尾巴，背部与臀部呈现鲜艳的红色；雌鸟及非繁殖期雄鸟则为淡褐色调，腹部偏白，侧翼和下体带黄色或淡黄色。分布于澳大利亚北部至东部沿海区域，从西北部的金伯利地区至新南威尔士州的亨特地区。","appearance":"红背细尾鹩莺体型小，尾部长，站立时尾部通常呈翘起状态。成年雄鸟在繁殖季节呈现出丝滑的黑色头部、上体和尾巴，背部与臀部则为亮丽的橙红色；非繁殖期雄鸟和雌鸟外观相似，均为淡棕色，带有暖色调。雌鸟具淡黄眼斑，冠部及上体为温暖的中褐色，翅膀和尾巴暗灰褐色，下体白色，侧面和下体变为赭色或淡黄色。喙呈粉棕色，腿为浅棕色。幼鸟与雌鸟外观类似。","call":"其典型的叫声为柔和的连续音符，以弱音开头，随后高亢尖锐，结尾部分音节较多。接触叫声为轻微的“ssst”，警戒声为尖锐的“zit”。","habits":"栖息于热带和亚热带夏季降雨区的各种植被环境中，偏好有高草覆盖和稀疏树荫的地带。主要以昆虫为食，如蚂蚁、蟑螂、甲虫、蚱蜢和毛虫，偶尔也吃蜘蛛和种子。觅食方式包括地面的‘跳跃搜寻’和快速的‘飞舞追逐’，通过搅动底物使猎物暴露，然后进行追捕。有时会形成多达30只的觅食群体。","breeding":"繁殖期主要在雨季，除六月外全年均可产卵。社会上保持一夫一妻制，但性行为上多配偶。巢由雌鸟建造，为草和树皮条构成的椭圆形穹顶结构，入口位于侧面，内部铺设精细的草、根须、植物绒毛、毛发和羽毛，一般建于离地面不足一米的草丛或小灌木中。每窝产卵2-5枚，孵化期12-13天，由雌鸟负责，雏鸟由群体成员共同喂养，出巢期11-12天；雏鸟被父母领走并隐藏一周，由群体成员喂养约一个月，之后继续与家庭群同住，可能参与第二次繁殖尝试的辅助工作。","identification":"与华丽细尾鹩莺雌鸟相比，红背细尾鹩莺雌鸟的羽毛色彩更暖、更棕。两个亚种的区别在于，指名亚种尾较长，背部橙色；而cruentatus亚种体型较小，尾较短，背部颜色更偏向猩红色。","protection":"IUCN：LC（无危）","distribution":"红背细尾鹩莺广泛分布于澳大利亚北部至东部，包括西北部的金伯利地区至新南威尔士州的亨特地区，以及附近岛屿如格罗特岛、埃德蒙佩尔岛、弗雷泽岛、梅尔维尔岛和巴瑟斯特岛。在内陆干旱地区较为罕见，被白翼细尾鹩莺取代。","other":"历史上，红背细尾鹩莺曾因人类大规模定居导致适宜的高草环境减少而从某些地区撤退，例如悉尼附近的Port Jackson地区，但总体上在当前分布范围内数量普遍。"},{"name":"蓝白细尾鹩莺","english_name":"White-winged Fairywren","scientific_name":"Malurus leucopterus","overview":"蓝白细尾鹩莺（英文名：White-winged Fairywren，学名：Malurus leucopterus），是雀形目细尾鹩莺科细尾鹩莺属的鸟类。主要栖息于澳大利亚中央干旱区，从昆士兰至西澳皆可见其踪迹。该鸟种展现显著的雌雄异型，繁殖季节时，雄鸟会展现出鲜艳的蓝白相间羽毛，而雌鸟则呈现沙褐色，尾羽略带蓝色。雄鸟体型大于雌鸟，其明亮的蓝色羽毛与白色的翅膀形成鲜明对比。幼年雄鸟外观近似雌鸟，但随年龄增长逐渐显现蓝色特征。","appearance":"体长约11至13.5厘米，体重6至11克，喙长8.4至8.5毫米，尖细且略宽于底部。繁殖期雄鸟羽毛鲜亮，具钴蓝色身躯与白色翅膀，雌鸟呈沙褐色，尾部淡蓝。非繁殖期雄鸟与雌鸟相似，但喙色较暗。幼鸟羽毛呈褐色，喙为粉色，尾羽较短。","call":"叫声为快速的颤音，主要鸣叫为连续升降的长鸣，伴有初始的几声短促音节。另有尖锐的联系和警报声，以及巢边的轻柔鸣叫。","habits":"偏好低矮灌木丛和盐碱地，栖息于干燥和半干旱区域。以昆虫为主食，偶尔摄取种子。群体生活，保持固定领地，有时季节性迁移。跳跃为主要行动方式，善短距离飞行。","breeding":"繁殖期主要在春夏季，但干旱地区可能全年繁殖。雌鸟筑巢，雄鸟和助手参与育雏。一窝产卵2至4枚，孵化期约14天，雏鸟依赖群体成员喂养，约10至11天离巢。","identification":"与紫背细尾鹩莺相比，眼和喙之间的区域（眼上纹）颜色较淡。亚种间羽毛颜色差异明显，岛屿亚种雄鸟繁殖羽为黑色。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚中心至西部，避开北部、南部、东部及塔斯马尼亚。具体包括从昆士兰中部至南澳大利亚，再到西澳大利亚。","other":"受人类活动影响，尤其是岛屿亚种因栖息地破坏面临威胁。"},{"name":"棕鹩莺","english_name":"Orange-crowned Fairywren","scientific_name":"Clytomyias insignis","overview":"棕鹩莺（英文名：Orange-crowned Fairywren，学名：Clytomyias insignis），是雀形目细尾鹩莺科棕鹩莺属的鸟类。在新几内亚山区特有的小型雀形目鸟类，头部呈现锈橙色，背橄榄棕色，两翼和尾部为赤褐色，下体颜色在不同亚种间有所差异，从奶油白色至赭色不等。","appearance":"这种小鸟无性别二态性，雄雌羽毛相同。头部呈锈橙色，大腿和尾巴赤褐色，背部橄榄棕色，翅膀为棕色。喙较宽，比其他同类更显突出，黑色；眼睛深棕色，腿为粉棕色。两个亚种主要通过下体颜色区分：C. i. insignis的下体为奶油白色，而C. i. oorti的下体颜色更偏赭色。","call":"发出一系列高音调的吱吱声和“seeep！”音符。","habits":"栖息于海拔2,000至3,000米的山地雨林厚密下层植被中。通常成对或以六到八只的小群体活动，关于其求偶行为和繁殖细节知之甚少。","breeding":"在新几内亚南部高地省，4月末发现一巢含2枚卵，巢由交织的Parsonsia sanguinea叶构成，装饰有活苔藓，位于地面约0.8米高的灌木藤上。卵为长椭圆形，表面哑光白，带有少量粉红棕色斑点，主要集中在钝端。","identification":"与扇尾鸟有相似之处，但橙冠和淡色下体的组合使其独特。两个亚种通过下体颜色区分。","protection":"IUCN状态未知。","distribution":"分布于新几内亚山区的山地雨林。","other":"首次描述于1879年，分子研究表明它与Malurus属的仙鹟形成一枝系。"},{"name":"帚尾鹩莺","english_name":"Southern Emu-wren","scientific_name":"Stipiturus malachurus","overview":"帚尾鹩莺（英文名：Southern Emu-wren，学名：Stipiturus malachurus），是雀形目细尾鹩莺科帚尾鹩莺属的鸟类。这体型极小、呈锈褐色的鸟，拥有异常长而纤细的尾巴，其尾羽的松散结构类似鸸鹋的羽毛，故得名。分布于澳大利亚东部及南部，尤其偏好沿海地区的灌木丛生地带。","appearance":"帚尾鹩莺体长15.5至19厘米，体重仅5.5至9克。雄鸟成鸟上身锈褐色，带有黑色条纹，冠部颜色更红，前额无条纹，眉线天蓝色；耳覆羽淡棕色，有时带有浅色条纹；翅膀灰棕色，边缘泛红；喉咙和上胸天蓝色，其余下身锈红色，腹部更白。雌鸟外观相似，但上身条纹更明显，前额无红色，眼上无蓝色，全身偏红棕色。未成年个体似雌鸟，但颜色更暗淡，条纹更模糊，喙呈棕色，雄鸟自出生5天起喉部和胸部开始呈现蓝灰色。","habits":"帚尾鹩莺主要以昆虫为食，通过跳跃搜索地面的方式觅食，尾巴保持竖立状态；会拍打蛾类（鳞翅目）去除翅膀；还会劈开灯心草（Juncus）的茎干以捕获藏匿其中的幼虫。它们很少飞行，常在密集的植被中活动，尤其是在刮风天气。通常在非繁殖季节以小型群体活动，可能由家庭成员组成。","identification":"与仙鹟属鸟类相比，帚尾鹩莺的尾巴更长且更为纤细。雄鸟成鸟的天蓝色喉部和眉线是显著的识别特征。","distribution":"帚尾鹩莺分布于澳大利亚东部和南部，包括低矮的灌木丛和沙丘区域，至少有一个亚种出现在南澳大利亚州林肯港附近的Whalers Way轨道发射综合体附近。"},{"name":"马里帚尾鹩莺","english_name":"Mallee Emu-wren","scientific_name":"Stipiturus mallee","overview":"马里帚尾鹩莺（英文名：Mallee Emu-wren，学名：Stipiturus mallee），是雀形目细尾鹩莺科帚尾鹩莺属的鸟类。仅见于澳大利亚东南部，分布于维多利亚州西北部与相邻的南澳大利亚州南部。其最显著的特征为超长而纤细的尾巴，雄鸟拥有天蓝色的喉部。栖息于未受干扰的、拥有大丛狼尾草的桉树灌木林中。","appearance":"雄性马里帚尾鹩莺体长13.5至15厘米，体重6至7克。头部无条纹，呈淡赤褐色，耳羽蓝黑相间，颈背及上体橄榄褐，黑色条纹点缀其间；翅膀及尾巴灰褐色，尾巴由六根松散的羽毛组成，中央两根长度为外侧羽毛的1.5倍；脸侧、眉毛、喉部及胸部呈天空蓝色；腹部中心白色，其余部分赤色；眼睛深棕色，喙黑色，腿粉色。雌鸟外观相似，但缺乏蓝色，赤色限于前额，眼周白色，耳羽灰色，喉部及胸部为浅褐色。幼鸟颜色较成鸟平淡，橄榄褐色，上方仅有微弱条纹，头顶无赤色，下方灰白；年轻雌鸟下方更偏浅褐色。","call":"鸣叫特征为非常微弱、细薄的声音，具体描述不详。","habits":"栖息于未被清理的低矮桉树林，与狼尾草共生，偏好至少15年未经火烧的植被。以昆虫为主食，可能也食用种子，常在距地面0.5米内的灌木丛和狼尾草丛中快速觅食。全年大部分时间生活在家庭群体中，非繁殖季节可能会形成觅食群。","breeding":"繁殖信息了解不多，已知繁殖期为9月至11月。巢穴为草制的穹顶形状，深藏于狼尾草丛中，每次产卵2至3枚，卵长13.5至16毫米，宽10至12毫米，白色底色带有红褐色斑点。","identification":"与仙女鹟属鸟类相比，尾巴明显更长且更为纤细。识别时需注意其天蓝色的喉部及独特的尾羽结构。","protection":"IUCN：EN（濒危）","distribution":"分布于澳大利亚东南部，具体为南澳大利亚州南部墨累河以南的马里地区，以及维多利亚州西北部。核心种群位于维多利亚州的Murray-Sunset国家公园和Hattah-Kulkyne国家公园及其周边地带。","other":"曾因生境破坏面临极大威胁，近期频繁大火导致孤立亚种群消失，火灾后的栖息地恢复目前不可能。全球数量估计在2008年约为16,821只，其中92%集中在Murray-Sunset区域。"},{"name":"棕帚尾鹩莺","english_name":"Rufous-crowned Emu-wren","scientific_name":"Stipiturus ruficeps","overview":"棕帚尾鹩莺（英文名：Rufous-crowned Emu-wren，学名：Stipiturus ruficeps），是雀形目细尾鹩莺科帚尾鹩莺属的鸟类。以其鲜艳的色彩和细长的尾巴著称。分布于澳大利亚的内陆干旱地区，从西澳大利亚中西部到昆士兰西南部及南澳大利亚中北部。雄鸟头顶红褐色，上身淡棕色带轻微暗色条纹，下体淡棕色，喉部及上胸部为鲜亮的天蓝色。","appearance":"体型极小，全长约10.5至15厘米，体重仅6克。雄鸟具有明亮的红褐色冠羽和颈部，上身呈肉桂棕色，背部有微弱的暗色条纹。翅膀灰棕色，边缘泛红，尾部长而纤细，约为身体长度的1.3倍。雌鸟外观与雄鸟相似，但缺乏蓝色羽毛，喉部呈黄色或奶油色。","call":"鸣唱为典型的Maluridae家族的卷曲音，高音而微弱。联络叫声为连续的高音‘tsee, tsee’，难以与昆虫声音区分；警报声为更响亮的‘trrrt’。","habits":"栖息于温暖至亚热带的干旱地带，偏好高大密集、未经火烧的Triodia草丛，位于沙丘、洼地、沙平原或岩石山丘，周围稀疏覆盖着Mallee桉树或低矮灌木。活动范围通常在地面以上0.5米以内，以昆虫为食。","breeding":"繁殖季节为8月至10月，受季节条件影响。巢由雌鸟建造，由草茎和蜘蛛网编织而成，内衬植物绒毛和羽毛，通常位于Triodia草丛顶部或中心，离地20至25厘米。一窝产2至3枚蛋，具体孵化和抚育细节未知。","identification":"与仙女鹪鹩相比，尾部更长且更为纤细。雄鸟的明亮红褐色冠羽和蓝色喉部是辨识要点。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚内陆干旱地区，从西澳大利亚中西部至昆士兰西南部及南澳大利亚中北部。","other":"依赖成熟的Triodia草丛生存，可能因过度频繁的火烧而受到威胁。"},{"name":"灰草鹩莺","english_name":"Grey Grasswren","scientific_name":"Amytornis barbatus","appearance":"灰草鹩莺体长18至20厘米，翼展约21厘米，体重介于15至23克之间。其上体呈淡肉桂棕色，掺杂灰色和米色条纹。脸部有独特的黑白斑纹，包括宽阔的白色眉纹和穿过眼睛的黑色眼线，连接到喉咙两侧的细黑线。雄鸟指名亚种有白色条纹的黑色顶冠，白色面部区域，黑色眼线，白色耳羽带有黑色V形标记，穿过下喉部；背部呈淡肉桂色，边缘有黑色和白色条纹；尾部黑色；腹部白色，胸部有淡淡的灰黑色条纹，两胁淡黄色；虹膜深棕色；喙黑色或暗黑色；腿呈深灰棕色至灰黑色。雌鸟外观与雄鸟相似，但体型较小，色彩较暗淡。幼鸟颜色较成鸟暗淡，面部图案不明显。Diamantina亚种比指名亚种更大，背部更红。","call":"灰草鹩莺的鸣叫为柔和的双音节声调，持续发出。声音特征为一系列三至四个高音金属音，类似‘pit-choo’。","habits":"灰草鹩莺栖息于澳大利亚干旱内陆泛滥平原，偏好由Lignum灌木主导的厚密环境。在干旱年份，它们几乎完全留在这种环境中；而在湿润年份，则会探索周围的生境。食物主要为种子和昆虫，觅食活动接近地面，通过灌木丛或下方的枯叶层进行。在旱季，个体倾向于聚集在偏爱的Lignum丛中。","breeding":"繁殖期记录显示，灰草鹩莺通常在7月至8月间繁殖，可能在洪水或大雨后。巢为松散且体积较大的结构，有轻微的穹顶，侧面入口平台，由草构成，内衬精细的草、根须和植物绒毛，位于地面以上30至60厘米处的Lignum或芦苇丛中央。每窝产卵2至3枚，平均重量约为2.4克，蛋壳呈哑光白色，布满肉桂棕色、肉桂至红棕色或肉桂棕色的斑点。雌鸟独自孵化，估计孵化期为13至15天，双亲共同喂养雏鸟。","identification":"灰草鹩莺以其灰褐色的体色和极长的尾巴区别于其他草鹩莺。脸部的黑白斑纹，尤其是V形标记和贯穿喉咙的线条，是其显著的识别特征。","protection":"IUCN：LC（无危）","distribution":"灰草鹩莺分布于澳大利亚中东部的特定泛滥平原区域，包括新南威尔士州与昆士兰州边境的Bulloo泛滥区、库珀溪下游、Diamantina河的Kallakoopah支流及南澳大利亚的Eyre溪附近的湖泊Machattie、Koolivoo和Mipea溢流区域。","other":"灰草鹩莺的种群数量高度波动，受气候条件影响，表现为‘繁荣与萧条’周期。"},{"name":"黑草鹩莺","english_name":"Black Grasswren","scientific_name":"Amytornis housei","overview":"黑草鹩莺（英文名：Black Grasswren，学名：Amytornis housei），是雀形目细尾鹩莺科草鹩莺属的鸟类。被Wunambal人称为dalal，仅分布于澳大利亚西澳州东北部的Kimberley地区，特别是Mitchell高原至Admiralty海湾一带，与大型砂岩巨石和密集的Triodia草丛为伴。","appearance":"体型小巧，体长19-21厘米，体重29-35克，拥有粗壮的身躯和长长的尾巴。雄鸟上身黑色，布满白色条纹，背部下部呈栗色，尾羽黑色；腹部黑色，喉部有白色条纹，腹部无条纹；眼睛棕色，喙黑色或深色，下颌基部较浅；腿脚暗灰褐色至黑色。雌鸟与雄鸟相似但体型较小，下胸和腹部为红褐色。幼鸟外观与成年鸟相近。","call":"其鸣唱特征尚未充分了解。歌曲短而音调相对低沉，开头是引子音符，随后包含嗡嗡颤音、短暂颤音和偶尔的上滑音或下滑音哨声，比Malurus的歌声更加多样化。联系叫声包括尖锐的'chip'声、呼噜声和'seep'声；警报声为响亮的'tik'声或咔哒声。","habits":"栖息于Kimberley高原的翻滚砂岩悬崖、峡谷和岩石露头，以Triodia草丘为主要地面覆盖。偏好地中海型灌木植被和开阔林地，间杂着巨大的砂岩巨石。活动范围有限，受火灾和降雨模式影响。","breeding":"1998年首次发现其巢穴和蛋。巢为椭圆形，由干草茎和叶片构成，位于柔软的Triodia pungens草丛中，入口处有一个小喷口，前方有平台。雌鸟孵卵，通常产两枚蛋，蛋壳白色，稀疏带有深色标记，尺寸约为21-22.2毫米×15.6-16.7毫米。","identification":"与其他草鹩莺相比，黑草鹩莺具有较大的体型、较长的尾巴和独特的黑白配色。","protection":"IUCN：LC（无危）","distribution":"分布于西澳大利亚东北部的Kimberley地区，包括Mitchell河国家公园在内的特定地带。","other":"自1901年被Frederick Maurice House首次发现以来，直至1968年才再次被观察到。"},{"name":"白喉草鹩莺","english_name":"White-throated Grasswren","scientific_name":"Amytornis woodwardi","overview":"白喉草鹩莺（英文名：White-throated Grasswren，学名：Amytornis woodwardi），是雀形目细尾鹩莺科草鹩莺属的鸟类。澳大利亚北领地西部阿纳姆高原特有的中型雀形目鸟类，体长20–22厘米，体重29–35克，是草鹩莺属中体型最大的一种。其最显著的特征为黑色头部与栗色背羽形成鲜明对比，喉部纯白，尾长而宽。该种仅分布于北领地阿纳姆兰中西部的高原台地与阶地，栖息于裸露砂岩巨石间丛生的三齿稃（Triodia）草丛中。由于频繁人为焚烧，其栖息地日益破碎，种群极难在可达区域被观察到。","appearance":"雄鸟头顶至后颈黑色，具白色羽干纹，背部及腰转为栗色；翼黑褐色，羽缘栗色；尾黑色，长而宽；黑色髭纹显著；喉与胸纯白，与栗色腹部之间隔以一列黑缘羽形成的带状斑；虹膜褐色；喙深灰色，尖端及脊线黑色；脚灰色。雌鸟似雄鸟，但腹部栗色更深。幼鸟羽色较成鸟暗淡，整体偏褐，缺乏成鸟鲜明的黑白对比。","call":"鸣唱为甜美而悠长的多变旋律，由上扬与下滑音符、颤音及嗡嗡声串联而成，含极高频成分，传播距离远。联络声为尖细“peep”；受惊时发出短促“tsit”。","habits":"留鸟，不迁徙。栖息于海拔300–500米的裸露高原台地及阶状山坡，地表多裸岩，三齿稃草丛呈斑块状分布。小群在裸岩与草丛间跳跃奔跑，受惊即钻入石缝。以草茎、莎草茎、种子及昆虫为食，觅食方式以地面拾取及小跳搜寻为主。","breeding":"繁殖期12月至翌年6月，湿季及其后，一年可育两窝。具合作繁殖习性，曾记录3–4只个体共同喂养雏鸟及刚离巢幼鸟。巢为大型圆顶结构，厚壁侧口，以三齿稃细茎、细叶及千层树皮交织而成，内衬细草，置于草丛基部离地不足0.5米处。每窝2枚卵；孵化期及育雏期尚无数据；幼鸟离巢后约1个月可独立，并继续留在出生群内。","identification":"与同属其他种相比，体型最大，尾最长；黑白喉胸对比及栗色背羽组合独一无二。与曾被视为同种的多氏草鹩莺比较，后者喉部非纯白，背羽栗色范围较小，分布区亦不同。与纹草鹩莺相比，本种缺乏明显的眉纹及胸腹纵纹。","protection":"IUCN: EN（濒危）。","distribution":"繁殖区与非繁殖区一致，均限于澳大利亚北领地阿纳姆兰中西部高原，即西北澳大利亚特有鸟区（North-west Australia EBA）内，呈高度片段化分布。","other":"种级地位经近年研究确认，与多氏草鹩莺及纹草鹩莺共同置于亚属 Magnamytis。栖息地因干季末高温火烧频率增加，三齿稃被一年生高粱属植物替代，导致种群持续下降。"},{"name":"多氏草鹩莺","english_name":"Carpentarian Grasswren","scientific_name":"Amytornis dorotheae","overview":"多氏草鹩莺（英文名：Carpentarian Grasswren，学名：Amytornis dorotheae），是雀形目细尾鹩莺科草鹩莺属的鸟类。分布于澳大利亚中北部的NT QLD远东北部和远西北部，偏好岩石地带的Triodia草丛或低矮灌木林。受频繁火燎影响，种群数量急剧下降。","appearance":"体长16-17.5厘米，体重21-25克。雄鸟头部黑色渐变为背部的锈色，全身覆有黑色边缘的白色条纹，上背至尾上覆羽为无条纹的深锈色；上翼和尾部暗褐色带锈色边缘；有强烈的黑色颊纹；胸部和上腹部白色，下腹和两胁转为淡褐色；虹膜深褐至红褐色；喙灰黑，基部蓝灰色；腿灰色。雌鸟相似，但两胁和下腹为深栗色。幼鸟似成鸟。","call":"鸣唱响亮悦耳，由颤音、嗡嗡声和旋律组成，部分频率极高。接触叫声为高音的蟋蟀似的啾啾声；警报声为响亮的‘tzzzt’。","habits":"居住在澳大利亚北部的沙岩山脉地带，偏好长时间未受火燎的Triodia草丛或低矮开阔的林地。可能为定居型，大范围内觅食。以昆虫和种子为食，在地面觅食，搜寻岩石裂缝和灌木下的落叶。","breeding":"可能全年皆可繁殖，条件适宜时。可能是合作性繁殖者，有3-4只成鸟群体的记录。巢由Triodia和其他草类茎叶交织而成，内衬细草，筑于地面20-60厘米处的草丛顶部。每窝产卵2-3枚；幼鸟在独立后似乎仍与家庭群同住。巢穴常被灌丛杜鹃寄生。","identification":"与灰胸草鹩莺的区别在于具有白色喉部，整体更偏锈色，体型较小，体态更纤细，下方白色面积更大，无胸部条纹带。","protection":"IUCN：VU（易危）","distribution":"分布于澳大利亚北部，具体为NT QLD远东北部和远西北部。主要栖息地为Mount Isa、Wollogorang和Boodjamulla，其中Borroloola子种群自1986年后无记录。","other":"多氏草鹩莺的栖息地几乎仅限于Mount Isa北侧的岩石山脉，该物种受到频繁火燎的威胁，导致种群数量和分布范围持续减少。"},{"name":"短尾草鹩莺","english_name":"Short-tailed Grasswren","scientific_name":"Amytornis merrotsyi","appearance":"成年雄鸟体长约15-16厘米，体重约23克，尾部较短。羽毛颜色为暗赤褐色，背部有黑白相间的条纹，前额略显暗色，喉咙白色，腹部浅黄色，胸部有灰色条纹。虹膜深棕色，喙色从暗灰色至黑色，下颚基部常呈淡色或蓝灰色，腿色灰至黑。雌鸟与雄鸟相似，但下胸两侧有深赤色斑块，胸部条纹更为明显。幼鸟特征未详述。","call":"已知的叫声包括高音的‘see’声，有时会重复，以及在受惊时发出的吱吱声报警叫声，与纹草鹩莺的叫声有所区别。","habits":"生活在石质山坡上的Triodia草丛中，常见于山脊、岩石沟壑和峡谷，通常伴有树木或灌木的遮蔽层。在火灾后约5年返回烧毁的栖息地，密度在7年左右达到峰值。单独或小群体出现。","breeding":"繁殖习性信息缺失。","identification":"与纹草鹩莺相比，短尾草鹩莺具有更短的尾巴，喙部更粗壮，腿较长，脸颊条纹不那么明显，色彩较为鲜亮的赤褐色。","protection":"IUCN状态未知。","distribution":"分布于澳大利亚南部，具体包括弗林德斯山脉和高尔山脉。","other":"系统学历史信息缺失。"},{"name":"纹草鹩莺","english_name":"Striated Grasswren","scientific_name":"Amytornis striatus","overview":"纹草鹩莺（英文名：Striated Grasswren，学名：Amytornis striatus），是雀形目细尾鹩莺科草鹩莺属的鸟类。仅见于澳大利亚南部的墨累-马利地区，是当地特有的草鹩莺。体长约14.5至19厘米，重约15至23克，具有黑色髭纹和红褐色上体，常出没于多刺的三蕊草丛中，善于在地面和低枝间穿梭。上体呈锈褐色，喉部白色，下体淡黄色，具灰色条纹。","appearance":"纹草鹩莺体型中等，尾长而尾羽尖锐，喙相对细长。雄鸟指名亚种具有白色眼周、红褐色前眉纹；冠部和背部灰褐色，边缘镶以黑色和白色条纹（颜色变异，西北部地区底色更偏肉桂红）；翅膀和尾巴棕色（西北部地区的尾巴更红）；宽大的黑色颊纹位于暗灰色耳羽下方；喉部白色至灰奶油色，腹部淡黄色，胸部上方有灰色条纹；眼睛深棕色；喙深灰色，尖端和鼻孔处更暗；腿色为深灰色至灰棕色。雌鸟与雄鸟相似，但侧胸有明显的红褐色斑块。幼鸟与成鸟相似。","call":"鸣唱为断续的‘tew，tew，tew’声后接一串旋律般的颤音和嗡嗡声。联系叫声为单一高音‘seep’；警报声为尖锐的‘tchirr’。","habits":"纹草鹩莺生活在三蕊草丛生的环境，无论是否有灌木或马利桉树的覆盖层，栖息于干旱和半干旱地带的沙平原、沙丘或石质山坡。它们以昆虫和种子为食，主要捕食甲虫和蚂蚁，同时也会食用三蕊草种子。它们通常成对或小群活动，偶尔单独出现。","breeding":"纹草鹩莺的繁殖期一般在7月至11月，但降雨充足时可能提前或延后。巢为圆顶状，由三蕊草刺构成，内衬树皮条、草、植物绒毛和羽毛，靠近地面并隐藏得很好，通常建在三蕊草丛中。蛋为卵圆形，白色到粉白色，表面细腻，稀疏分布着紫色或红色斑点，主要集中在大端。一窝通常产2枚蛋，有时3枚，由雌鸟孵化13至14天。雏鸟在12至14天后离巢，但仍在靠近巢穴的浓密遮蔽处隐藏3至4天，完全独立需再过3至4周。","identification":"纹草鹩莺与短尾草鹩莺的区别在于前者尾长、喙较细长、颊纹更明显，且颜色不如后者红。雌鸟有突出的红褐色侧胸斑。rowleyi亚种体型比其他亚种小，背部红褐色，胸腹淡奶油色。","protection":"IUCN：LC（无危）","distribution":"纹草鹩莺分布于澳大利亚中部和东部地区，包括南澳大利亚、新南威尔士州西部、维多利亚州西北部以及南澳大利亚和新南威尔士州南部。","other":"棕草鹩莺与锈色草鹩莺已被国际鸟盟（IOC）10.2版列为独立物种。"},{"name":"埃坎草鹩莺","english_name":"Eyrean Grasswren","scientific_name":"Amytornis goyderi","overview":"埃坎草鹩莺（英文名：Eyrean Grasswren，学名：Amytornis goyderi），是雀形目细尾鹩莺科草鹩莺属的小型鸟类。其特征为淡色条纹羽衣，头部较暗，尾部长而翘起。分布于澳大利亚中部的辛普森沙漠和斯特泽莱基沙漠沙丘上的甘蔗草丛中。于1874年由F.W. Andrews在艾尔湖附近的麦克姆巴河发现。","appearance":"埃坎草鹩莺长约15至16.7厘米，体重15至19克。雄鸟上部呈肉桂棕色，有棕色边缘的白色条纹；翅膀和尾巴棕色，边缘红褐色；脸部有黑色髭纹，但被条纹遮掩，融入耳羽；喉咙白色，下体淡白色，两胁淡红褐色。雌鸟与雄鸟相似，但两胁更亮的红褐色。雏鸟比成鸟毛茸茸，颜色更暗，条纹不明显，尾巴羽毛边缘更红褐。","call":"其鸣唱为悦耳的颤音，由多种短音节组成，部分音调极高。接触叫声为“seeep”，警报声为“zeeet”。","habits":"主要栖息在辛普森沙漠和斯特泽莱基沙漠的沙丘地带，以甘蔗草为主要栖息地。饮食上以种子为主，尤其是甘蔗草和刺状草的种子，同时也会食用昆虫和蜘蛛。觅食时在地面或靠近地面处活动，跳跃或奔跑，偶尔飞行，通常在甘蔗草丛或其它植被边缘寻找食物。","breeding":"关于繁殖习性的信息有限。筑巢主要由雌鸟负责，用时约一周，巢位于甘蔗草丛中，离地面不足一米。巢由草类编织而成，内衬细草或蛛丝。繁殖季节可能全年都有，已知的繁殖记录集中在7月至9月间。","identification":"与其它草鹩莺相比，埃坎草鹩莺具有更像雀类的喙，上体颜色差异以及面部特征。在野外，其独特的叫声和活动方式也是识别的重要依据。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚中部的辛普森沙漠和斯特泽莱基沙漠，具体包括南澳大利亚州东北部、昆士兰州西南部以及北领地东南部。","other":"埃坎草鹩莺的系统发育研究显示它与灰胸草鹩莺和乌草鹩莺关系密切，这三者可能源自共同祖先。"},{"name":"西草鹩莺","english_name":"Western Grasswren","scientific_name":"Amytornis textilis","overview":"西草鹩莺（英文名：Western Grasswren，学名：Amytornis textilis），是雀形目细尾鹩莺科草鹩莺属的鸟类。原生于澳大利亚，曾被归入厚喙草鹩莺的指名亚种。小型、害羞、主要栖息于地面的鸟类，具有褐色的羽毛，黑白细纹相间，尾部长而细。雄鸟略大于雌鸟，成年体重分别为22-27克和20-25克。雌鸟在1-2个月大时会在翼下发育出独特的栗色斑块。通常以两到三只为一群出现。","appearance":"西草鹩莺体型小，体长15-20厘米，重量在21.6-27.6克（雄鸟）和19.6-25.6克（雌鸟）之间。外观较为暗淡，喙粗钝。指名亚种种雄鸟呈较深的灰棕色，背部有黑色边缘的白色条纹，尾部深灰棕色，腹部浅黄褐色，下巴和胸部有白色条纹；眼睛棕色，喙黑或暗色，下颚基部淡蓝灰色；腿灰色至暗色。雌鸟与雄鸟相似，但胸部侧边有栗色斑块。幼鸟与成鸟相似。亚种myall颜色比指名亚种种稍深。","call":"其鸣唱包含一系列短促的“pip”音符，下滑的哨声和短暂的颤音。接触叫声为柔和的颤音和更响亮的“chet”声；警报声为短而尖锐的“tik”。","habits":"栖息于干旱和半干旱地区的灌木丛，主要植物有盐碱地植物、蓝莓灌木、金合欢、Ptilotus和Thryptomene。全年固守领地，最大记录的幼鸟分散距离为400米。杂食性，以种子、果实和昆虫等无脊椎动物为食。主要在地面觅食，从灌木下的落叶层中寻找食物。","breeding":"繁殖期为7月至10月在西澳大利亚（指名亚种），在适宜降雨后其他范围内繁殖。巢由雌鸟建造，部分呈穹顶状，壁厚，由草、枝条和树皮条构成，内衬细草和植物绒毛，放置于距地面30厘米的灌木中心。每次产卵2枚，卵色为偏白至粉红，有中等程度的深红色至红棕色斑点，间隔超过一天产一枚；仅由雌鸟孵化，孵化期15-17天；雏鸟由双亲喂养，巢期10-14天；幼鸟在离开巢穴后仍隐蔽1-2周。部分巢穴受到霍氏金鹃的寄生。","identification":"与其他细尾鹩莺科鸟类相比，西草鹩莺更加健壮，喙粗钝，头胸有精细的白色条纹。与其他亚种的区别在于颜色的深浅，尤其是雌鸟的胸部侧边栗色斑块。","protection":"IUCN：LC（无危）。在当地分布从常见到罕见。指名亚种曾在西南澳大利亚广泛分布，但范围已大幅收缩，现仅限于鲨鱼湾地区；在当前限制区域内，尤其在Peron半岛，由于实施了广泛的捕食者控制措施，此亚种相对常见。亚种myall可能从未广泛分布，现已减少；被列入易危状态，分布于不到十个地点，估计约有8400个个体，可能正在下降的人口受到干旱的影响，栖息地质量下降，过度放牧，以及军事活动的威胁。","distribution":"分布于澳大利亚西部和南部，具体包括西澳大利亚州的鲨鱼湾地区（包括Dirk Hartog岛）至南澳大利亚东部的Nullabor平原东部。在Gawler山脉的分布已减少。","other":"历史上，西草鹩莺的分布范围更广，但由于过度放牧导致栖息地质量下降，其分布范围自1910年以来向西收缩。"},{"name":"厚嘴鹩莺","english_name":"Thick-billed Grasswren","scientific_name":"Amytornis modestus","overview":"厚嘴鹩莺（英文名：Thick-billed Grasswren，学名：Amytornis modestus），是雀形目细尾鹩莺科草鹩莺属的鸟类。分布于澳大利亚中部、中南部和中东部的特定生境中，如低矮的盐碱灌木丛和排水沟旁。其显著特征为褐色体羽，白色条纹，以及厚实而略短的喙。","appearance":"厚嘴鹩莺体型小巧，长度约15至20厘米，体重介于17至20克之间。上体呈淡棕色，下体颜色更浅。头部和胸部有精细的白色条纹，喙厚实且较短，比仙女鸟更为健壮。雄鸟尾巴较长，雌鸟胸侧呈栗色。不同亚种间存在细微差异，如尾长、喙长和羽色深浅。","call":"其叫声为一系列高音的‘see, see, see-see-stuzeep’，雄鸟有时会发出更复杂的短音和下滑的哨声，但由于音调较高，人类耳朵可能不易察觉。","habits":"厚嘴鹩莺几乎完全生活在低矮的盐碱灌木丛中，偏好在石质平原的洼地和排水线上。它们是杂食性鸟类，以种子、果实、昆虫和其他无脊椎动物为食，主要在地上觅食，偶尔在灌木基部的落叶层中搜寻食物。","breeding":"关于繁殖的了解甚少，但已知在8月时会在新南威尔士州和北领地发现筑巢迹象。巢通常建在溪流边的甘蔗草根部，每窝产两枚淡白色或极淡粉色的蛋，带有不同程度的红棕色斑点。","identification":"与其他细尾鹩莺科鸟类相比，厚嘴鹩莺拥有更厚实的喙和较短的尾巴，且羽色较为暗淡，条纹不那么明显。不同亚种间的识别主要依据尾长、喙长和羽色差异。","protection":"IUCN：LC（无危）。尽管全球范围内不被视为受威胁物种，但在局部地区数量较少，某些亚种如raglessi被评估为Vulnerable（易危），curnamona为Near Threatened（近危），obscurior为Critically Endangered（极度濒危）。最近描述的cowarie亚种尚未正式评估，但据估计可能属于Vulnerable（易危）。过度放牧和外来物种入侵导致了栖息地丧失，干旱和野火也是当前威胁。","distribution":"厚嘴鹩莺主要分布在澳大利亚的中西部新南威尔士、北部南澳大利亚以及南部北领地的干旱区域。曾经的分布范围更广，但目前主要局限于莱茵湖区域（L Eyre）附近。","other":"厚嘴鹩莺曾被认为与西部草鹩莺同种，直到2010年才被划分为独立物种。其飞行能力较差，因此对栖息地的碎片化极为敏感。"},{"name":"乌草鹩莺","english_name":"Dusky Grasswren","scientific_name":"Amytornis purnelli","overview":"乌草鹩莺（英文名：Dusky Grasswren，学名：Amytornis purnelli），是雀形目细尾鹩莺科草鹩莺属的鸟类。特有种于澳大利亚内陆，分布于北领地、西澳大利亚和南澳大利亚的特定地区。以岩石地带和灌木丛生的环境为家，具有独特的深褐色羽毛和细白条纹。","appearance":"乌草鹩莺是一种中等体型的长尾鸟，长度约15.5至18厘米，体重18至25克。雄鸟面部呈暗锈色，带有白色条纹，没有明显的面部标记；上体颜色较暗，有窄细的白色羽轴条纹，边缘模糊；翅膀和尾巴棕色，边缘锈色；喉咙和胸部颜色较淡，带有白色条纹，腹部颜色加深。眼睛深棕色，喙灰黑色，基部偏蓝灰色；腿深灰色。雌鸟与雄鸟相似，但侧腹有一块暗锈色斑点。幼鸟外观与成鸟相似。","call":"其鸣唱为一系列变化的短颤音，持续2至3秒。接触叫声为“seeet”，还有柔和的叽叽喳喳声；警报声为“tchk, tchk”。","habits":"栖息于岩石峭壁和脊岭的稀疏开阔林地，地面层覆盖有三叶草（Triodia）灌木。活动范围主要限于岩石地带和灌木丛，食物包括种子、果实和昆虫等无脊椎动物。它们通常在地面上觅食。","breeding":"繁殖季节可能在7月至10月间，但会因降雨而提前或延后。筑巢于三叶草丛中，巢由干草构成，内衬碎草和纤维，呈半圆顶状。雌鸟负责孵卵，每窝产2至3枚蛋。","identification":"与西草鹩莺的区别在于喙更细，喉部和下体颜色更深。雌鸟的侧腹有一块亮锈色斑点。与灰胸草鹩莺、厚嘴鹩莺和纹草鹩莺有区别，主要在于栖息地、鸣叫和外表差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚中部山区，从北领地的阿什伯顿山脉向南至西澳大利亚的罗林森山脉和汤普金森山脉，以及南澳大利亚的比克斯盖特山脉和埃弗拉德山脉。","other":"乌草鹩莺在历史上曾与混淆，导致其分布范围的改变可能被掩盖。"},{"name":"灰胸草鹩莺","english_name":"Kalkadoon Grasswren","scientific_name":"Amytornis ballarae","overview":"灰胸草鹩莺（英文名：Kalkadoon Grasswren，学名：Amytornis ballarae），是雀形目细尾鹩莺科草鹩莺属的鸟类。体型小而结实的褐色草鹩莺，仅在澳大利亚昆士兰西北部伊萨山（Mount Isa）东南方的塞尔温山脉（Selwyn Range）岩石山地的三齿稃（Triodia）灌丛中发现。其上体为暗灰褐色，下体呈丰富灰色，雌鸟体侧具鲜明的红褐色斑块，雄鸟体侧为灰色；头胸部有细白纵纹，尾长且常上翘。","appearance":"体长14.7–15.9厘米，体重20–25克，尾长而常上翘。雄鸟面部暗赤褐并具白纵纹，无显著面纹；上体亮赤褐，头颈部白羽干纹具清晰黑缘；翼及尾灰褐色；喉胸草黄色，具暗缘白羽干纹，羽毛硬而尖；腹灰色；虹膜深褐；上嘴深灰至近黑，下嘴基部暗蓝灰；腿深灰色。雌鸟似雄鸟，但体侧具大片暗赤褐色斑块。幼鸟尚未描述。与同属其他种相比，体型较小，羽色更亮，喉部羽毛尖端坚硬。","call":"鸣声为一系列高亢多变、短促的颤音；联络叫为单声尖细“吱”；告警时发出响亮“嘎”声。","habits":"栖息于干旱地区岩石山坡、山脊及沟壑地表的三齿稃（Triodia）灌丛下层；全年成对或3–10只小群活动，基本定居。约半数食物为昆虫，半数种子；在岩石缝隙及三齿稃丛下觅食。","breeding":"繁殖期7–10月，可能为合作繁殖；曾记录3只成鸟共同喂养巢中已长羽的雏鸟。巢由草茎及细枝构成，隐蔽地筑于距地面约50厘米高的三齿稃丛顶端；每窝1–3枚卵；双亲共同育雏，孵化及雏鸟期尚无数据。","identification":"本种体型小于乌草鹩莺，羽色更亮，喉部羽毛尖端硬挺；雌鸟体侧具大面积暗赤褐色斑块，可资区分。","protection":"IUCN: VU（易危）。","distribution":"繁殖及非繁殖区域相同，仅见于澳大利亚昆士兰州西北部伊萨山（Mount Isa）东南方的塞尔温山脉（Selwyn Range）。","other":"曾被视为乌草鹩莺的亚种，现为单型种。"},{"name":"棕草鹩莺","english_name":"Rufous Grasswren","scientific_name":"Amytornis whitei","overview":"棕草鹩莺（英文名：Pilbara Grasswren，学名：Amytornis whitei），是雀形目细尾鹩莺科草鹩莺属的鸟类。澳大利亚西澳州皮尔布拉地区特有的小型长尾鹩莺。雄雌通体红棕褐色，具醒目的黑色“髭纹”及黑白相间的头纹；行动隐秘，栖息于铁石山丘与三齿稃丛之间，鸣声高细，须刻意搜寻方能得见。过去长期被视为纹草鹩莺的亚种或同种，分子研究支持其独立地位。","appearance":"体长14.5–19厘米，长尾上翘，喙厚直而略钩；雄鸟略大于雌鸟。成鸟上体深红棕，密布窄白纵纹；头侧具粗黑髭纹，喉白，胸腹肉桂色。雄鸟前胁无斑，雌鸟前胁具明显的红棕块；飞羽基部外侧红棕，合翼时形成明显翼斑。幼鸟羽色似成鸟但较松软，头纹模糊，髭纹灰褐，初级飞羽外缘淡红棕。","call":"鸣唱为甜美多变的啭鸣，常以断续的“tew tew tew”起音，接连串颤音与嗡嗡声，末段重复短促音符；平时发出高而尖细的“see”声，传播约20米，但部分人听觉难及；警戒时发出短促的“tchirrr”。鸣声与纹草鹩莺、沙丘草鹩莺、锈色草鹩莺极相似，但缺少厚嘴鹩莺及黑草鹩莺的模仿与金属般断音。","habits":"留鸟，性隐蔽，多单独或成对活动，受扰即钻入三齿稃（Triodia）丛。栖息于皮尔布拉铁石山脊、陡坡及沟壑，亦见于零星灌木、桉树或澳洲松之间；西北岬角亚种则生活于石灰岩高原的沙丘与稀疏灌丛。觅食方式缺乏研究，推测与纹草鹩莺相似，以昆虫及草籽为主。","breeding":"繁殖资料匮乏，仅知卵的形态。推测繁殖生态与纹草鹩莺类似，成鸟五月可见换羽。","identification":"在其分布区内无重叠近缘种。与纹草鹩莺、沙丘草鹩莺、锈色草鹩莺极似，可靠区分需借助形态测量：棕草鹩莺尾显著短于纹草鹩莺（♂85.4对90.8毫米），翅长于沙丘草鹩莺（♂61.5对56.4毫米），嘴长且深；锈色草鹩莺体型更小，尾翅均短。与乌草鹩莺同域但后者色更深且偏好岩地。","protection":"IUCN: NE（未予单独评估）。指名亚种因分布广、人迹罕至，暂无威胁，已列入卡里吉尼国家公园与米尔斯特里姆–奇切斯特国家公园；西北岬角亚种（parvus）范围仅160–1600平方千米，曾被推断为濒危，急需调查。","distribution":"繁殖区：西澳州皮尔布拉地区，自奇切斯特、哈默斯利、奥夫thalmia、帕里山脉至巴利山脉，西北岬角的石灰岩高原为孤立亚种分布。非繁殖区：全年留居，无迁徙。","other":"属名 Amyto 表示“无剪尾”，ornis 为“鸟”；种加词 whitei 纪念澳大利亚收藏家亨利·卢克·怀特。曾长期并入“纹草鹩莺复合体”，分子研究支持其独立，但线粒体DNA差异微弱，需更多数据厘清关系。"},{"name":"锈色草鹩莺","english_name":"Opalton Grasswren","scientific_name":"Amytornis rowleyi","overview":"锈色草鹩莺（英文名：Opalton Grasswren，学名：Amytornis rowleyi），是雀形目细尾鹩莺科草鹩莺属的小型鸟类，体长约14.5至19厘米，体重约15至23克。其特征为长尾和黑色髭纹，上体呈锈褐色，仅在澳大利亚昆士兰州西部的Winton-Opalton区域被发现，是该区域内特有的草鹩莺。此前曾被视为纹草鹩莺的一个亚种，2020年7月被国际鸟类分类委员会（IOC）确认为独立物种。","appearance":"锈色草鹩莺具有中等体型，喙相对纤细，尾部较长。雄鸟成鸟的头部两侧白色，眉线锈红色，头顶和背部为灰褐色，带有黑色边缘的白色羽轴条纹（颜色在西北部地区更偏红棕色）；翅膀和尾巴呈褐色（尾巴在西北部更显锈色）；脸部下方有一条宽大的黑色髭纹，耳羽暗淡有白色条纹；下巴和喉咙白色至灰奶油色，下体浅黄色，上胸部有灰色条纹；眼睛深棕色，喙暗灰色，尖端和上喙基部颜色更深；腿为暗灰色至灰棕色。与短尾草鹩莺相比，尾部长而明显，喙较细长，髭纹更加突出，色彩不那么偏红。雌鸟类似雄鸟，但侧胸有明显的锈色斑块。幼鸟外观与成鸟相似。白氏亚种（whitei）比指名亚种更鲜艳，背部底色深锈色，下体更深的黄褐色；rowleyi亚种体型最小，尾部较短，背羽如前者，但胸腹部呈淡奶油色。","call":"其鸣唱为断续的‘tew, tew, tew’声，随后是一串旋律流畅的颤音和嗡嗡声。接触叫声为单个高音的‘seep’声，警报声为尖锐的‘tchirr’声。","habits":"锈色草鹩莺栖息于三蕊木属（Triodia）植被群落，无论是否有灌木或桉树（Eucalyptus）的上层植被，常见于干旱和半干旱地区的沙地平原、沙丘或岩石山坡。它们以昆虫和种子为食，主要食物为甲虫（Coleoptera）、蚂蚁（Formicidae）和三蕊木属植物的种子。觅食活动主要在地面进行，尤其是在灌木下的落叶层和三蕊木丛基部周围。通常成对或小群体活动，偶尔单独行动。","breeding":"关于锈色草鹩莺的繁殖行为信息尚不充分。","identification":"与其他草鹩莺属物种相比，锈色草鹩莺的尾部更长，喙更细，髭纹更加显著，颜色不那么偏红。雌雄个体在胸部侧边的锈色斑块上有差异。","protection":"IUCN：LC（无危）。在当地分布区内数量从常见到罕见不等。指名亚种在其东南部范围内数量有所下降，主要是由于适宜生境的大规模减少，这种破坏仍在继续。rowleyi和whitei亚种似乎没有面临风险。保护措施需停止土地清理，并结合放牧和火控管理，以减少成熟三蕊木的损失，特别是在桉树林中。","distribution":"锈色草鹩莺主要分布在澳大利亚中东部的昆士兰中部，具体为Opalton和Lark Quarry南部的Winton西部区域。","other":"锈色草鹩莺是从纹草鹩莺中分离出来的独立物种，这一分类变更由IOC于2020年7月确认。"},{"name":"黑吸蜜鸟","english_name":"Black Honeyeater","scientific_name":"Sugomel nigrum","overview":"黑吸蜜鸟（英文名：Black Honeyeater，学名：Sugomel nigrum），是雀形目吸蜜鸟科黑吸蜜鸟属的鸟类。这雌雄异型明显的鸟类，雄鸟通体黑色，带白色腹部；雌鸟上部灰褐色，下部具斑驳暗色痕迹。广泛分布于澳大利亚干旱内陆地区，尤其在开花的Eremophila灌木丛附近常见。其鸣叫为悠长高音哨声，缓慢重复。","appearance":"体型小巧，长度约10至13厘米，翼展约19厘米，体重约9.5克。具有细长向下弯曲的喙，头部圆润，颈部纤细，躯体丰满，尾巴短小，略呈叉状。雄鸟上体和头部全黑，腹部中央有一条黑色纵纹延伸至腹部，腹面白色；雌鸟上体灰褐色，下体斑点灰褐，腹部淡白色。幼鸟类似雌鸟，但上胸部和喉部更均匀灰褐色，喙基部较浅。","call":"繁殖季节前和期间较为活跃，发出金属质感的软调\"chwit, chwit\"声，有时发出响亮的\"tieee\"音，间隔数秒，音调单调均匀。还发出弱\"peeee\"声，通常由繁殖雄鸟发出。幼鸟孵化后，两性都会发出轻微的斥责声。","habits":"栖息于澳大利亚干旱和半干旱地区的开阔林地和灌木丛，依赖Eremophila灌木。主要以花蜜为食，偶尔捕食空中昆虫，会聚集在开花的植物群中。迁徙模式与食物源相关，春季和夏季向南移动，秋季和冬季北移。干旱时期可能出现在异常地带。","breeding":"繁殖季为7月至12月，雨后可能增加。筑巢于小树或灌木的低枝或树叉，巢由细枝、草和其他植物材料构成，内衬蜘蛛网。每窝产2到3枚蛋，孵化期约16天，雏鸟约18天离巢。雌鸟独自孵化，雄鸟守卫巢穴。","identification":"与同科其他物种相比，黑吸蜜鸟通过其独特的黑色（雄鸟）或灰褐色（雌鸟）外观辨识。雄鸟的黑色头部和胸腹部纵纹是明显特征。雌鸟的灰褐色上体和斑点下体也有助于区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚内陆干旱地区，自西海岸向东，主要在南纬19°以南，至大分水岭西坡；在较大沙漠区域（如辛普森沙漠）、纳拉伯平原、西南、南及东南沿海湿润地带罕见。","other":"已知黑吸蜜鸟会在营巢前和孵化期间食用露营地火堆中的灰烬，可能是为了获取钙质。"},{"name":"鳞顶岩吸蜜鸟","english_name":"Scaly-crowned Honeyeater","scientific_name":"Sugomel lombokium","overview":"鳞顶岩吸蜜鸟（英文名：Scaly-crowned Honeyeater，学名：Sugomel lombokium），是雀形目吸蜜鸟科黑吸蜜鸟属的鸟类。主要分布在印尼的小巽他群岛，包括龙目岛、松巴哇岛和弗洛勒斯岛的山区。其特征为橄榄色的上体和灰黄色的下体，具有细长而下弯的喙，如同太阳鸟一般。此鸟种之前被归类于Lichmera属下，但在2022年基于系统发育证据，国际鸟类学大会（IOC）将其重新分类至Sugomel属。","appearance":"鳞顶岩吸蜜鸟长约13.5至14.5厘米，上体呈现均匀的橄榄绿色，脸部和喉部为灰色，下体带有淡黄橄榄色的洗染，尤其是在上胸部更为明显。头部前额和眼先呈暗灰色，与头顶的暗斑形成渐变。眼睛周围有一圈较淡的灰色眼环，而耳羽、颊部、下巴和喉咙也是浅灰色。翅膀和尾巴的上部与身体颜色相似，初级飞羽边缘细致地勾勒着橄榄色。下体非常浅灰，覆以淡黄橄榄色。虹膜深棕色至深红棕色，喙黑色，腿为灰色到蓝灰色。雄鸟和雌鸟在外表上似乎相同，但雄鸟可能比雌鸟稍大。幼鸟的描述未详。","call":"其叫声包括持续的啾啾声，鼻音的“jeez”，以及低沉的“grrt”。","habits":"鳞顶岩吸蜜鸟栖息于原生森林和退化森林，包括高海拔半常绿森林和低海拔山地森林，森林边缘，灌木丛，轻度林化的农田，甚至花园。在龙目岛，它们通常出现在海拔800-1600米之间，主要是在1000米以上；在松巴哇岛，仅在800米以上；而在弗洛勒斯岛，高度范围在700-2140米之间，主要在1000米以上。它们似乎不会迁徙，更常见于较高海拔处。","breeding":"关于繁殖的信息尚未记录。","identification":"与印尼岩吸蜜鸟相比，鳞顶岩吸蜜鸟外观更朴素，没有后者明显的苍白面部皮肤、黄色翼斑和深色面罩。苏门答腊吸蜜鸟在其下体颜色上也更加黄色。通过观察其独特的橄榄色上体、灰黄色下体和下弯的喙可以识别。","protection":"IUCN：LC（无危）。鳞顶岩吸蜜鸟在弗洛勒斯岛和松巴哇岛的所有高海拔站点都很常见，由于其海拔范围内的广阔森林，这些岛屿上的种群并不受到威胁。建议创建保护区，以保护高海拔物种，包括该物种。","distribution":"鳞顶岩吸蜜鸟分布在小巽他群岛西部和中部的龙目岛至弗洛勒斯岛，包括松巴哇岛。","other":"无"},{"name":"布氏摄蜜鸟","english_name":"Drab Myzomela","scientific_name":"Myzomela blasii","overview":"布氏摄蜜鸟（英文名：Drab Myzomela，学名：Myzomela blasii），是雀形目吸蜜鸟科摄蜜鸟属的小型鸟类，主要分布于印度尼西亚的Seram、Boano和Ambon岛屿。森林居民，常见于低地和山区森林的树冠层。","appearance":"体长约11.5厘米，体重12至17克。头部、颈部和上体呈灰橄榄色，臀部颜色略深，有淡淡的暗色眼纹和狭窄的眼圈，眼后有条纹延伸一小段距离。翅膀和尾巴比上体更暗一些，羽翼和尾羽边缘细长。喉部和下巴呈灰色，带有较暗的羽毛中心形成鳞状外观。腹部淡黄灰色，部分个体额头和喉部有红褐色痕迹。虹膜棕色，喙全黑，腿灰蓝色。两性相似，雄鸟可能体型稍大，但缺乏具体数据。幼鸟特征未详述。","call":"发出高音的“sis, sis, sis...”叫声和叽叽喳喳的音符，具体叫声特征未详细描述。","habits":"在树冠层活动，常在开花树木中觅食花蜜，尤其是Eugenia属植物的花蜜，推测也吃小昆虫。主要在树冠层活动，曾在Seram岛上看到它们在高大的开花树木的树冠中觅食。通常隐秘，容易被忽视，常以10到20只的小群出现在开花的树木中。","breeding":"关于繁殖行为的信息尚未记录。","identification":"与Wakolo摄蜜鸟的区别在于面部无红色，喉部斑点不明显。与Seram吸蜜鸟的区别在于体型较小，喙全黑，胸羽无重叠条纹，脸颊无淡色标记。","protection":"IUCN：LC（无危）；限制分布物种，在Seram EBA存在。在Seram岛上分布稀少或常见，在Manusela国家公园稀缺或常见，最近才在Boano被记录。","distribution":"分布在印度尼西亚的Seram、Boano（位于Seram西北部）和Ambon（位于中东部摩鹿加群岛）。","other":"布氏摄蜜鸟是Seram、Boano和Ambon岛屿特有的物种。"},{"name":"白颏摄蜜鸟","english_name":"White-chinned Myzomela","scientific_name":"Myzomela albigula","overview":"白颏摄蜜鸟（英文名：White-chinned Myzomela，学名：Myzomela albigula），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。小型的摄蜜鸟，活跃于新几内亚东南部的森林环境中。其显著特征为暗褐色的羽毛，胸部带有条纹，喉咙呈淡色，雄鸟的下巴有一条细长的红色条纹，有时喉部缺乏白色。雌雄体型差异明显，雌鸟较小，喉部灰白而对比鲜明。","appearance":"体长约13至14厘米，雄鸟体重约16.3克，雌鸟稍轻，约为13克。雄鸟的上身颜色均匀，呈深褐灰色，下身较浅，头部中央隐约可见红色痕迹，下巴和喉咙中央有鲜红条纹，胸部有模糊的暗色条纹。雌鸟的下巴和喉咙明显灰白，红色喉纹不明显。幼鸟特征未详述。","call":"发出混杂的口哨式歌曲，叫声简单高亢，类似‘chip’声。","habits":"生活习性尚不明确，推测栖息于森林地带。迁徙、飞行特性、活动范围和觅食方式均未知。","breeding":"繁殖信息不明。","identification":"与同属的巴布亚黑摄蜜鸟相比，白颏摄蜜鸟胸部有条纹。雄鸟的红色喉纹是重要辨识点。","protection":"IUCN：DD（数据缺乏）。分布范围受限，仅见于路易西亚德群岛，总面积仅350平方公里。物种了解程度极低，无法准确评估灭绝风险。","distribution":"仅分布于新几内亚东南部的路易西亚德群岛，具体包括该群岛的东部区域。","other":"尽管有报道指出在Misima和Tagula存在，但实际上可能并不在此地或已不再存在。"},{"name":"灰摄蜜鸟","english_name":"Ashy Myzomela","scientific_name":"Myzomela cineracea","overview":"灰摄蜜鸟（英文名：Ashy Myzomela，学名：Myzomela cineracea），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。分布于新不列颠岛和乌姆博伊岛的低地和山麓次生林中。其全身呈暗灰色，头部颜色更深，飞行时可见白色翼下。灰摄蜜鸟与红喉摄蜜鸟曾被视为同一物种的亚种。","appearance":"雄性灰摄蜜鸟上体为深棕色至暗灰褐色，尾羽更暗，呈黑褐色，部分上翼覆羽边缘较淡。头部有时有较深的烟灰色额、眼圈和面颊，胸部有玫瑰色斑块。下体较淡，呈浅灰褐色，腹部和尾下覆羽颜色更浅。翼下白色，边缘有银灰色。雌鸟较小，仅喉部中央有小块玫瑰粉色。鸟喙黑色，腿脚灰至蓝灰色。","call":"灰摄蜜鸟发出的声音稀少而低调，通常在黎明时发出一系列单音或双音，如“chip-chip-chip”或“chip-chop, chip-chop”。也会发出快速尖锐的颤音“chee-chee-chee…”，音调忽高忽低，以及细长的哨声“hoet, hoet”。","habits":"栖息于提供遮蔽的各种低地环境，包括原始雨林、森林边缘、次生林和再生林，以及花园和椰子种植园等人类改造的环境。活动范围从海平面到海拔1200米以上。以花蜜和昆虫为食，从树冠层至林下层觅食，常见于开花树木、椰子棕榈和低矮灌木丛中。","breeding":"繁殖季节似乎在旱季的后半段和雨季中期；产卵时间为7月底、10月初和1月至2月晚期。巢穴为薄壁碗状或杯状，由细茎、根和叶鞘纤维制成，内部直径约4厘米，深度3.7厘米，悬挂在灌木或小树的枝叉上。每窝产卵通常为2枚。","identification":"与斯莱特尔氏摄蜜鸟、红摄蜜鸟和红黑摄蜜鸟共存，但灰摄蜜鸟体型更大且无红色。与俾岛摄蜜鸟和黑花蜜鸟相似，但灰摄蜜鸟体型更大且为灰色而非黑色。","protection":"IUCN：LC（无危）。灰摄蜜鸟在低地和山麓广泛分布，数量被认为是中等到丰富。","distribution":"分布于新不列颠岛（俾斯麦群岛东南部）和乌姆博伊岛（新不列颠岛西部）。","other":"灰摄蜜鸟曾被视作红喉摄蜜鸟的一个亚种。"},{"name":"红喉摄蜜鸟","english_name":"Ruby-throated Myzomela","scientific_name":"Myzomela eques","overview":"红喉摄蜜鸟（英文名：Ruby-throated Myzomela，学名：Myzomela eques），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。分布于新几内亚和四王群岛的西北部。其显著特征为均匀的暗褐色体羽，雄鸟拥有红色的喉纹，体型略大。","appearance":"雄性红喉摄蜜鸟全身呈黑褐色，下方稍淡，具有光泽的红色至鲜红的颏部和喉部条纹，额部有微弱的红色斑点。雌鸟体色较淡，为暗褐至灰褐色，喉部红色斑点可能缺失。幼鸟描述不明，但幼鸟整体呈现灰褐色，下部稍淡，额头和脸颊上的红色较淡或不存在，喉纹不明显。","call":"发出高音的‘chip’声，典型于该属，偶尔会发出一系列悦耳的鸣叫声，当两只鸟追逐展示时，声音发展为嘶哑的啾啾声。","habits":"栖息于低地雨林、森林边缘及高大的次生林。活动于海平面至海拔500-600米，局部可达1200米。以花蜜为主食，来自多种开花植物，包括桃金娘科和无花果，同时也捕食昆虫，有记录显示也会食用树干上生长的无花果。通常在高大的开花树木的外冠层觅食，偶尔在较低的冠层、亚冠层、中间层和次级层活动。","breeding":"繁殖期记录到晚三月有雏鸟的巢穴；东部地区的繁殖被认为持续到七月底至八月初，而西部地区则几个月后。巢由强韧的黑色树苔条制成，悬挂于叶枝叉上，高度约3米，靠近树干，被茂密的树叶遮蔽。","identification":"与红头和巴布亚黑摄蜜鸟的雌鸟相似，但红喉摄蜜鸟体型更大，额部无红色。与暗摄蜜鸟非常相似，但红喉摄蜜鸟有红色喉纹。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚和四王群岛的西北部。在Sepik区的低地森林中一般较为罕见，在Crater山（Chimbu省）也较少见；在其他地区被认为是常见的物种。"},{"name":"暗摄蜜鸟","english_name":"Dusky Myzomela","scientific_name":"Myzomela obscura","overview":"暗摄蜜鸟（英文名：Dusky Myzomela，学名：Myzomela obscura），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。这小型、棕色的鸟类，常见于阿鲁群岛、新几内亚南部以及澳大利亚北部和东部。其在澳大利亚有两个独立的群体，一个位于北端，另一个从约克角半岛沿东海岸分布至新南威尔士州边界，但在洛克汉普顿以南较为罕见。","appearance":"暗摄蜜鸟体长约12至15厘米（5至6英寸），整体呈暗淡的棕色，行动迅速且敏捷，常悬停于高处取食昆虫或花蜜。它们活跃于多种生境，包括季风雨林、灌木丛、林地、沼泽以及任何邻近水源的区域。","habits":"暗摄蜜鸟倾向于在适宜的环境中定居，而在较不理想的区域则表现出游荡或迁徙的行为，尤其是在其分布范围的南部。它们广泛适应各种环境，包括森林、湿地和接近水体的地带。","breeding":"繁殖季节通常发生在旱季，大约从三月至九月。暗摄蜜鸟会建造小巧而精致的杯状巢，由细小的树皮、蜘蛛网和树叶构成，置于隐蔽的树枝上，离水面较高。其蛋壳为白色，表面点缀着细微的红褐色斑点。","distribution":"分布于澳新界，具体包括新几内亚南部和澳大利亚北部、东北部。","other":"该物种曾与乌摄蜜鸟、淡红摄蜜鸟和比岛摄蜜鸟被视为同一物种，但自2021年起被国际鸟类联盟（IOC）认定为独立物种。"},{"name":"红摄蜜鸟","english_name":"Red Myzomela","scientific_name":"Myzomela cruentata","overview":"红摄蜜鸟（英文名：Red Myzomela，学名：Myzomela cruentata），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。主要分布在新几内亚和新不列颠岛（位于俾斯麦群岛东南部）。其显著的外部特征是鲜艳的红色，是当地森林中的独特居民。","appearance":"红摄蜜鸟拥有鲜明的红色羽毛，这一特征使其在同类中独树一帜。然而，具体的体型、羽毛细节及性别差异等信息需进一步描述以提供更详尽的外观特征。","habits":"红摄蜜鸟栖息于新几内亚和新不列颠岛的亚热带或热带湿润低地森林以及亚热带或热带湿润山地森林。它们的生活习性与栖息环境紧密相关，具体包括迁徙模式、飞行特性、活动范围及觅食行为等细节待补充。","identification":"红摄蜜鸟与新爱尔兰的红摄蜜鸟在外观上有相似之处，但基于遗传学证据，两者被确认为独立物种。具体辨识特征包括颜色、大小及行为上的细微差别。","protection":"IUCN：LC（无危）","distribution":"红摄蜜鸟主要分布于新几内亚和新不列颠岛（位于俾斯麦群岛东南部）。在这些地区，它们占据了亚热带或热带湿润的低地和山地森林生境。"},{"name":"黑摄蜜鸟","english_name":"Papuan Black Myzomela","scientific_name":"Myzomela nigrita","overview":"黑摄蜜鸟（英文名：Papuan Black Myzomela，学名：Myzomela nigrita），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。在新几内亚及其附近岛屿上常见的鸟类。雄鸟通体呈现光泽的黑色，雌鸟则为暗褐色，头部前部和喉部带有红褐色调。广泛分布于新几内亚的山麓森林及边缘。","appearance":"黑摄蜜鸟体长约12至13厘米，雄鸟体型大于雌鸟。雄鸟全身漆黑发亮，翼下覆羽为白色，雌鸟呈暗橄榄褐色，额部、颊部及喉部有红褐色斑块。幼鸟的描述尚不详尽，但可能表现为较深色或灰褐色，与雌鸟相似。","call":"其鸣叫为高音单调的“tsip！”声，类似于其他Myzomela属鸟类。","habits":"栖息于山麓和低山的原始森林、森林边缘及高大次生林中，偶尔在桉树草原林地和季风林中发现。活动范围通常在海拔500至1000米之间，但在某些地区如Trans-Fly地区和Aru岛，也会出现在低地。它们会从山脚迁移到低地，以利用开花树木。","breeding":"关于繁殖的详细信息有限，但已观察到在7月晚期，雄鸟追逐可能携带筑巢材料的雌鸟，以及在3月至4月间收集的‘繁殖’样本。具体繁殖行为需进一步研究。","identification":"雄性黑摄蜜鸟与黑花蜜鸟相似，但后者具有虹彩光泽和白色翼下覆羽。雌鸟与红摄蜜鸟和山摄蜜鸟雌鸟相似，但红摄蜜鸟雌鸟有红色尾巴，而山摄蜜鸟雌鸟无红色额部。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚及其附近的岛屿，包括Goodenough岛。在Goodenough岛上，黑摄蜜鸟占据低地，未记录高于620米的地区。","other":"黑摄蜜鸟在开花的树木如合欢树（Albizia）、桉树（Eucalyptus）中常见，也访问开花的西谷椰子（Metroxylon）和多种开花植物，如Albizia、Astronia、Syzygium和Poikilospermum。"},{"name":"秀丽摄蜜鸟","english_name":"New Ireland Myzomela","scientific_name":"Myzomela pulchella","overview":"秀丽摄蜜鸟（英文名：New Ireland Myzomela，学名：Myzomela pulchella），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。以红脸、橄榄绿上体和奶油色下体为显著特征。主要栖息于新爱尔兰山区，海拔通常在200米以上，更常见于500米以上。","appearance":"体长约11厘米，重约10克。头部、冠羽、耳羽前部、颊区和下巴至胸上部呈现红色，形成醒目的红色面具，包围着一条狭窄的黑色眼纹，环绕着眼睛。上体颜色从暗灰褐色到深橄榄褐色不等，较大的上翼覆羽和次级飞羽边缘带有精细的橄榄绿色。下体红色渐变为略带暗红色的上胸，其余下体部分为淡黄色至脏黄白色，下胸部有模糊的暗色条纹。虹膜呈深灰色至深棕色，喙为黑色，腿脚蓝灰色，足底黄色。雄雌成鸟外观相似，可能在体型上有所差异。幼鸟头部、颈部和上体为橄榄褐色，面部散布红色羽毛，下颏和喉咙有小片红色，胸部橄榄灰色，其余下体颜色与成鸟相似或更偏橄榄黄色。","call":"发出嗡嗡的下滑音“bzzr”或重复的“zzr”。","habits":"居住于新爱尔兰岛的蒙特森林，主要位于海拔500米以上地区，最高记录达到1840米。单个或小群体在树冠层觅食，聚集在开花树木中；曾观察到它们在寄生植物中搜索食物。关于饮食的具体信息尚缺。","breeding":"繁殖信息未知。","identification":"雄鸟独特，不易混淆。雌鸟通过主要是棕色的羽毛和红色头部诊断，与较暗的黑色的俾岛摄蜜鸟形成对比。","protection":"IUCN：LC（无危）。物种分布有限，常见于500米以上高度。","distribution":"分布于新爱尔兰岛的山区（俾斯麦群岛东北部），特别是在海拔500米以上的地区。"},{"name":"红巾摄蜜鸟","english_name":"Wetar Myzomela","scientific_name":"Myzomela kuehni","overview":"红巾摄蜜鸟（英文名：Wetar Myzomela，学名：Myzomela kuehni），是雀形目吸蜜鸟科摄蜜鸟属的小型鸟类。以独特的红头、红臀和灰身搭配白色腹部著称，分布于小巽他群岛东部的Wetar岛，是该地特有种。","appearance":"成年雄性红巾摄蜜鸟头部至耳羽后方呈现深红色，形成鲜明的头罩，与灰色的颈背、肩部和背部形成鲜明对比，黑色的眼纹延伸至额头和眼周，红色的臀部和上尾覆羽与头部颜色一致。上翼橄榄褐色，翼羽有淡色边缘，下体白色或淡黄色，胸部红色。雌鸟和幼鸟的描述尚未记录。","call":"鸣叫包括中高音的下滑哨声“tsiew”，以约1-1.5秒的频率重复，以及短而尖细、类似昆虫的“tsii-tsii”声，每约6.5秒重复一次。","habits":"栖息于低地季风林和花园中，最近观察到其在沿海灌木丛、茂盛的农田和高大的次生林中活动，尤其在开花的桉树附近。通常单独或成对出现，有时会加入混群觅食队伍。","breeding":"关于繁殖的信息尚无记录。","identification":"在Wetar岛，红巾摄蜜鸟的雄鸟具有明显的红色头罩和臀部，易于识别。Alor岛上的种群可能代表另一种未描述的物种，二者可通过红头覆盖范围和分布区进行区分。","protection":"IUCN：LC（无危）。红巾摄蜜鸟仅分布于Wetar小岛，全球范围极小，但种群数量被描述为‘相当可观’，估计全球有20,000至50,000对。尽管森林覆盖率仍高，但存在一定的伐木和人口迁移压力。","distribution":"红巾摄蜜鸟仅分布于澳新界Wetar岛，属于小巽他群岛东部。","other":"红巾摄蜜鸟在Alor岛的记录可能涉及本种或未知的分类单元。"},{"name":"红头摄蜜鸟","english_name":"Red-headed Myzomela","scientific_name":"Myzomela erythrocephala","overview":"红头摄蜜鸟（英文名：Red-headed Myzomela，学名：Myzomela erythrocephala），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。分布于澳大利亚北部和新几内亚南部沿海。这体型较小的鸟类，以其独特的红头和活跃的觅食行为著称。","appearance":"成年雄鸟拥有醒目的亮红色头部和臀部，背部黑色，腹部灰褐色；雌鸟头部和颈部灰褐色，前额、耳羽、脸颊、下喉及上喉呈现淡红色，上体其余部分灰褐色。幼鸟类似雌鸟，但脸部红色较淡，下颌基部黄色，虹膜和腿可能颜色较浅。","call":"发出重复的金属般清脆鸣声，接触叫声被描述为快速而略带粗糙的‘chiew-chiew-chiew’，还有尖锐响亮的‘cheep’声。","habits":"主要栖息于红树林地带，以花蜜为主食，同时也捕食小型节肢动物。活跃于树冠层，快速穿梭于花朵间，也捕捉飞虫。通常单独或成对出现，偶尔形成小群体。","breeding":"筑巢于红树林中，使用树皮碎片、叶子、植物纤维等材料，巢呈杯状，悬挂于枝条的水平叉上。繁殖期在澳大利亚记录为3月至10月，一窝产卵2枚，有时3枚。","identification":"与同类物种相比，红头摄蜜鸟具有独特的红色头部和臀部，雌雄异色明显。与绯红摄蜜鸟有小范围重叠，但后者栖息环境不同。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚南部沿海至澳大利亚北部沿海区域，包括澳大利亚的西部、北部领地和昆士兰州的热带海岸线。","other":"尽管分布广泛，但在其范围内并不普遍，最大记录密度为每公顷5.5只。"},{"name":"松巴摄蜜鸟","english_name":"Sumba Myzomela","scientific_name":"Myzomela dammermani","overview":"松巴摄蜜鸟（英文名：Sumba Myzomela，学名：Myzomela dammermani），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。仅分布于印尼松巴岛（小巽他群岛中西部）。以森林中显著比例的落叶树为主要栖息环境。","appearance":"雄鸟具有鲜明特征：黑色身躯搭配鲜红的头部和臀部，形成独特的红黑相间的外观，腹部颜色较淡。雌鸟主要为灰褐色，头部、喉部有轻微的红色痕迹。雄鸟与雌鸟的差异类似，雌鸟上身灰褐色，尾羽和翅膀较暗，头部、下巴和喉部可见红色。幼鸟和亚成鸟特征未知。","call":"叫声尚未详细描述，被认为较为安静。","habits":"主要栖息于原始森林，尤其偏好落叶林及其边缘地带，偶尔也在常绿森林中被观察到。活动高度通常在森林中层至树冠层，以单个或成对（可能是配偶）形式出现，有时会组成最多七只的小群体。食性细节未知。","breeding":"繁殖信息未知。","identification":"在分布范围内是唯一的Myzomela种类，通过其独特的红黑配色即可轻松辨认。","protection":"IUCN：LC（无危）","distribution":"分布局限于印尼的松巴岛，最近在罗蒂岛也有记录，但具体状况不明。","other":"在松巴岛上的总估计数量约为129,600只，基于森林密度每平方公里120只的估算。"},{"name":"山摄蜜鸟","english_name":"Mountain Myzomela","scientific_name":"Myzomela adolphinae","overview":"山摄蜜鸟（英文名：Mountain Myzomela，学名：Myzomela adolphinae），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。以纪念 Adolphine Susanna Wilhelmina Bruijn。主要分布在新几内亚的山地森林中，包括鸟头半岛、中北部、中东部、东北部（休恩半岛）和东南部。","appearance":"山摄蜜鸟体型极小，长度约9-10厘米，体重平均7.4克。雄鸟大多呈暗灰色至灰黑色，腹部为偏白色，头部和臀部鲜红，翼黑，背暗。雌鸟多为橄榄灰色，腹部较浅，面颊带淡红色，眼周淡色，翼端和尾羽边缘橄榄黄色。幼鸟和亚成鸟特征未详述。","call":"鸣声包括高音上滑的“sweeit”、下降的喘息声“tzzew”、尖锐的“tsit”、粗糙的颤音以及连续快速的短音符。其歌曲由两个高音符组成，第一个音符更高且常上扬，第二个音符通常带有颤音。","habits":"栖息于新几内亚的山地和中海拔森林，包括次生林和其他改造过的生境，如村落、城镇、花园、开阔地带和农田，常见于卡斯泰诺皮斯橡木林地。活动范围在海拔约1150米至2000米间，最低可达500米，最高至2225米。以花蜜和小型节肢动物为食，包括甲虫和小同翅目昆虫。通常单独或小群活动，有时追逐同类。","breeding":"已知的繁殖记录发生在7月中旬和10月底。巢穴精致，编织成杯状，嵌入枯死的蕨类植物叶片中，形成一个小平台，外部有苔藓覆盖的屋顶和侧面，是摄蜜鸟属中罕见的巢型。父母双方共同喂养雏鸟。","identification":"雄性山摄蜜鸟容易识别，而雌鸟与其它物种相似，但体型更小，仅在下巴处有红色。与花蜜鸟属其他种类如黑摄蜜鸟、红喉摄蜜鸟和红摄蜜鸟在开花树中共同活动。","protection":"IUCN：LC（无危）。一般而言，山摄蜜鸟数量较为普遍，但在某些地区可能稀少或缺失。","distribution":"分布于新几内亚的西部、北部和东部山区，包括鸟头半岛、中北沿海山脉、中部高地东至科皮亚戈湖、阿德尔伯特山脉、休恩半岛和东南部。","other":"在受干扰的环境和城镇花园中较为常见。"},{"name":"斑达摄蜜鸟","english_name":"Banda Myzomela","scientific_name":"Myzomela boiei","overview":"斑达摄蜜鸟（英文名：Banda Myzomela，学名：Myzomela boiei），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。其显著特征为雄鸟头部、颈部、上胸部至背部的艳丽红色与黑色翅膀、尾巴形成鲜明对比，腹部白色。分布于印尼的Banda、Babar和Tanimbar岛屿，仅限于低地森林和红树林区域。","appearance":"雄性斑达摄蜜鸟具有引人注目的外观，头部、颈部、上胸部至背部呈鲜艳的苹果红，与黑色的翅膀、尾巴和胸部条带形成强烈对比，腹部白色。雌鸟全身灰棕色，脸部和喉咙带有淡化的红色调。成年雄鸟和雌鸟大小可能有所不同，幼鸟和未成熟个体的特征未详细描述。","call":"斑达摄蜜鸟的鸣唱由几个起始音符后接快速颤音组成：“chi-chi-churrrrrrrr”。","habits":"单独或成对出现在低地森林、森林边缘、红树林和开阔的林木地带，有时会加入混杂物种的鸟群。在Banda群岛的分布范围有限，可能在局部区域游荡。","breeding":"在Banda群岛，记录到的筑巢、孵卵和育雏活动发生在9月，最近一次观察到的离巢幼鸟出现在4月末。具体繁殖细节未知。","identification":"斑达摄蜜鸟在其分布范围内是独一无二的，雄鸟的红黑对比色彩以及雌鸟的灰棕色和脸部的淡红色痕迹使其易于识别。","protection":"IUCN：LC（无危）。斑达摄蜜鸟属于限制分布物种，在Banda海岛屿生态区存在。目前评估为数量适中，但对其了解甚少。","distribution":"分布于澳大利亚新几内亚地区，具体包括Babar（小巽他群岛远东部分）和印尼摩鹿加群岛南部。","other":"斑达摄蜜鸟是华莱士区特有的物种，自然栖息地为亚热带或热带湿润低地森林、亚热带或热带红树林森林以及亚热带或热带湿润山地森林。"},{"name":"苏拉摄蜜鸟","english_name":"Sulawesi Myzomela","scientific_name":"Myzobela chloroptera","appearance":"雄性苏拉威西摄蜜鸟身长9至12厘米，头部、颈部、胸部、肩部至臀部为醒目的红色，翅膀和尾巴为深色，腹部为灰白色，眼睛周围有黑色环带。雌鸟和幼鸟全身为灰棕色，面部和喉咙带有红色调。幼鸟与雌鸟相似，但有更广泛的黄色边缘和散在的红色羽毛。亚种juga略大，雄鸟的翅膀和尾巴为棕黑色，雌鸟额头的红色更广泛。","call":"雄鸟的鸣唱为短暂而高音的颤音，类似于“chew-chew-wit-wit”。叫声包括清晰响亮的“peeeew”声，快速三音节的“tuwéédu”，以及快速、薄而高音的颤音。","habits":"栖息于山地原始森林和高大的次生林，包括苔藓森林，可能也会出现在红树林。在北苏拉威西的有选择性砍伐的森林中也有记录。在塔里阿布岛上观察到它们在次生林中活动，高度可达950米，也可能在低地活动。以花蜜为食，频繁访问开花的树木和寄生灌木。","breeding":"繁殖信息未知。","identification":"雄性苏拉威西摄蜜鸟与类似体型的黄腰太阳鸟相比，体型更小，喙更短，尾巴更短，腹部为白色。雌鸟和幼鸟与雄鸟的色彩形成鲜明对比。","protection":"IUCN：LC（无危）。在苏拉威西较为罕见至常见，但在洛雷林杜国家公园和其他保护区较为普遍。在塔纳贾姆佩亚岛中等常见，佩伦岛上数量合理，塔里阿布岛上非常常见。奥比岛上的种群于2010年首次被确认，其状态不明。","distribution":"主要分布在印尼的苏拉威西岛、塔里阿布岛、塞拉亚群岛和坦哈詹佩亚岛。在苏拉威西岛的山区和低地均有分布，高度从200米至2400米不等；在塔里阿布岛主要分布在800至1100米的高度，但也下降至约100米；在坦哈詹佩亚岛仅限于低地；在佩伦岛的记录位于700至900米左右。","other":"关于其生态习性和具体繁殖行为的信息有限。"},{"name":"摩鹿加摄蜜鸟","english_name":"Wakolo Myzomela","scientific_name":"Myzomela wakoloensis","overview":"摩鹿加摄蜜鸟（英文名：Wakolo Myzomela，学名：Myzomela wakoloensis），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。特有于印尼的摩鹿加群岛，具体分布于布鲁岛和塞拉姆岛的山林地带。其最显著的特征是雄鸟的鲜红色羽毛，除了翅膀、尾巴和腹部呈黑色。","appearance":"雄性摩鹿加摄蜜鸟以全身鲜亮的红色为主色调，仅翅膀、尾巴和腹部部分为黑色，形成鲜明对比。雌鸟则呈现较为暗淡的灰棕色，头部带有独特的红晕。体型小，约9至11.5厘米长，体重在7到9克之间。喙部弯曲向下，适应了其摄蜜的生活习性。","call":"在布鲁岛，摩鹿加摄蜜鸟的叫声包括了双音节的滑音“tsiwit”以及带有颤抖质感结尾的“tsisewoo”歌曲。而塞拉姆岛上的个体声音有所不同，可能指示着它们可能是不同的物种。","habits":"偏好丘陵和山区的森林及其边缘地带，通常单独或成对出现，有时也会加入多种鸟类的觅食群。它们在花丛中觅食，以花蜜为食，同时也会捕食小型无脊椎动物。","breeding":"关于摩鹿加摄蜜鸟的繁殖习性尚无确切信息。","identification":"雄鸟与雌鸟的颜色差异明显，雄鸟几乎通体鲜红，雌鸟则为灰棕色，头部带红晕。不同岛屿的个体叫声不同，可能暗示着物种的分化。","protection":"IUCN：LC（无危）；该物种在布鲁岛和塞拉姆岛上被描述为中等到常见。","distribution":"分布于澳新界，具体为印尼的布鲁岛山区和塞拉姆岛（摩鹿加群岛中部）。在印尼摩鹿加群岛的繁殖区域内，海拔高度从低地到1500米，主要出现在800米以上的地区。","other":"摩鹿加摄蜜鸟是吸蜜鸟科摄蜜鸟属的成员，属于雀形目。"},{"name":"绯红摄蜜鸟","english_name":"Scarlet Myzomela","scientific_name":"Myzomela sanguinolenta","overview":"绯红摄蜜鸟（英文名：Scarlet Myzomela，学名：Myzomela sanguinolenta），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。澳大利亚特有的小型吸蜜鸟。雄鸟拥有醒目的红色头部、颈部和上胸，雌鸟则呈现统一的淡棕色外观。分布于澳大利亚东部，从昆士兰东北部至维多利亚州南部，包括山地森林和红树林地带。","appearance":"雄鸟头部、颈部至胸部呈鲜艳的红色，背部有一条中央红色条纹，翅膀和尾巴黑色，腹部以灰色为主，带有红色晕染。雌鸟头部、颈部和上体淡棕色，喉咙和下巴灰棕色，有时带粉红色调，上体有时可见红色斑点。年轻鸟类似雌鸟，但上体颜色更暖，尾羽上方较浅。","call":"拥有独特而响亮的旋律般的铃声，由六音符组成，音调起伏不定，有时表现为短暂的金属般颤音。","habits":"栖息于干燥的硬叶林和木地，以桉树为主的环境，常见于湿地周边和开花灌木丛。迁徙模式部分定居，部分迁徙，北方种群在冬季向南迁移。春季和夏季主要在南部繁殖区出现。","breeding":"繁殖期从7月持续到1月，可能提前开始。巢由细长的树皮条和草构成，悬挂于树枝上，通常隐藏于茂密的树叶中。每窝产卵2枚，偶尔3枚，孵化期11-12天，雏鸟孵化后在巢中停留11-12天。","identification":"雄鸟与红头摄蜜鸟在东部卡奔塔利亚半岛北部有重叠分布，但后者仅头部红色，且偏好红树林而非林地。雌鸟与暗色摄蜜鸟相似，但体型较小，喙和尾巴较短，且面部和喉咙带有粉色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，北起昆士兰州东北部，南至维多利亚州南部，内陆延伸至查特斯塔沃斯、卡纳文峡谷和英吉利伍德。","other":"其迁徙和游荡模式与喜食的植物开花周期相关，种群数量随特定树木和灌木的开花而波动。"},{"name":"新喀摄蜜鸟","english_name":"New Caledonian Myzomela","scientific_name":"Myzomela caledonica","overview":"新喀摄蜜鸟（英文名：New Caledonian Myzomela，学名：Myzomela caledonica），是雀形目吸蜜鸟科摄蜜鸟属的鸟类，分布于新喀里多尼亚的Grande Terre和Ile des Pins。以其醒目的红、黑、白三色羽毛著称，雄鸟头部和胸部鲜红，背部、翅膀和尾巴黑色，腰部白色。雌鸟较朴素，主要呈棕色，面部略带红褐色调。","appearance":"体长约10-12厘米，雄鸟体重约7.5至8.2克，雌鸟稍轻，约6.6至6.9克。雄鸟头部、颈部及上身中央深红色，具黑色眼环，肩部和背部散有黑色斑点，上翼黑色，边缘灰白至橄榄灰色。雌鸟较小，头部和颈部呈棕灰色，下巴和喉部淡灰色，额头、耳羽、脸颊和下巴红褐色，上体棕灰色，下体浅棕色，腹部逐渐变白。幼鸟类似雌鸟，但上体颜色偏暖，次级飞羽和三级飞羽边缘更宽、更黄。","call":"雄鸟鸣唱为一系列短促急促的短语，通常由2至10个音符组成，如干涩的双音‘tchu-tchu—tchu-tchu—tchu-tchu…’或‘tch-tchwy-tchwy’。联系叫声为极短、尖锐、高音的单音‘tsip’。","habits":"栖息于湿润森林，包括高山矮林和niaouli（Melaleuca leucadendron）草原森林，也出现在森林边缘、种植园和花园等改造生境。主要以花蜜为食，同时捕食小型节肢动物（昆虫）。在各种开花树木间活跃觅食，包括niaouli树。","breeding":"繁殖期为11月至1月。巢为小巧的杯状，由细枝、根须和其他植物纤维构成，直径约4.5至5厘米，常利用蜘蛛网固定在树枝上。每窝产2枚蛋，父母共同承担孵卵和喂养雏鸟的任务，但孵卵和育雏期的持续时间未知。","identification":"新喀摄蜜鸟相较于新喀里多尼亚其他吸蜜鸟体型更小，雄鸟的红黑白色彩对比鲜明，雌鸟色彩较朴素，易于识别。","protection":"IUCN：LC（无危）。新喀摄蜜鸟虽分布范围有限，但在其范围内广泛存在，全球数量估计未知，但被描述为普遍常见或稀少。","distribution":"分布于澳新界的新喀里多尼亚，具体包括Grande Terre和Ile des Pins两个岛屿。"},{"name":"深红摄蜜鸟","english_name":"Cardinal Myzomela","scientific_name":"Myzomela cardinalis","overview":"深红摄蜜鸟（英文名：Cardinal Myzomela，学名：Myzomela cardinalis），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。体型纤小的吸蜜鸟，雄鸟以鲜亮的深红色头、背、腰和黑色翼、腹、胸、尾形成强烈对比，雌鸟暗褐带暗红色，两性皆具明显色彩。分布于太平洋西南所罗门群岛、瓦努阿图、圣克鲁斯群岛及洛亚蒂群岛等。偏好森林，但在任何有开花植物的生境均可出现，包括人工椰林、花园及城镇。","appearance":"体长9–12.5厘米，雄鸟体重14–23克，雌鸟11.5–14克。雄鸟指名亚种（M. c. cardinalis）头、颈背、上背及腰深红或猩红，呈斑驳黑斑；背部红色在停栖时部分被翼覆，飞行时醒目；其余上体、翼及尾黑色略具光泽；喉至上胸深红，下体黑褐。雌鸟体形较小，头至上背暗橄榄褐，腰及尾上覆羽淡红褐，红色仅限于头顶少量；翼覆羽具淡褐缘，下体污黄白，胸侧灰褐具暗斑。幼鸟似雌鸟但更淡，红色仅见于前额、颏及上喉，翼羽缘淡黄；亚成雄鸟呈杂合羽色，红黑与雌鸟型羽并存。各亚种在红色分布范围、体型及羽色浓淡上差异显著。","call":"不甚喧闹，常见叫声为细而尖的“tseet”或昆虫般高音“tzwee / tzeer”，觅食时几乎不断重复；另有上扬的“cheet”或干涩“tk”。受威胁时发出“tzeer”作警报。雄鸟在繁殖期于高枝发出重复而清脆的“tzeewyt-tzeewyt-tweet-weet”旋律，黎明歌曲更为响亮，由清晰的哨音短语组成，有时被形容为似白眼鸟般悦耳。","habits":"主要栖息原始林、次生林、林缘、红树林及椰林、花园、村落等人工环境；海拔自海平面至1250米。留鸟，局部随花源有短距离迁移；可在近岛间飞行，偶见于极小岩礁。食物以花蜜、花粉为主，兼食昆虫及蜘蛛。活跃于林冠至中上层，不断穿梭于花丛间，可在细枝上悬停或倒挂取食；也追捕飞行昆虫。常成对或家族小群活动，花源丰富时集大群；与其他吸蜜鸟混群，但对同种及小型吸蜜鸟具攻击性，常在食源处追逐争斗。","breeding":"繁殖期：瓦努阿图9月至翌年1月，部分个体6月亦繁殖；所罗门群岛12月见刚离巢雏鸟，9月已有独立幼鸟。巢由雌鸟主导编织，为细小开放的草杯，外缠蜘蛛丝，有时附生苔藓，悬于细枝叉或藤蔓上，高多在3米以上，隐蔽于浓叶中。每窝通常2卵，偶3卵；孵化期12–14天，主要由雌鸟承担，雄鸟协助；双亲育雏，巢期亦为12–14天。","identification":"与萨摩亚摄蜜鸟相比，后者体型更小，喙更短，雄鸟羽色相似，雌鸟头顶至上背黑褐并具猩红斑。各亚种间差异：lifuensis体型较小，雄鸟红色不及上胸，雌鸟几无红色；sanfordi雄鸟红色更扩展到背侧及胸腹，雌鸟头顶及胸具明显红羽；pulcherrima体型最小，雌鸟头、颈、背及腰红色明显；sanctaecrucis体型较大，雄鸟红色似指名亚种，雌鸟头顶至背具猩红鳞纹；tucopiae喙最短，雄鸟红色仅及喉部；tenuis整体更小，羽色更偏橄榄。","protection":"IUCN: LC（无危）。虽为局限分布种，但在各大群岛普遍常见或数量丰富，并适应人工环境，种群稳定。过去曾被圣克鲁斯群岛土著取羽制“羽毛货币”，此习俗现已消失。","distribution":"繁殖区：所罗门群岛（包括马基拉岛、乌吉岛、三姐妹群岛、雷内尔岛）、瓦努阿吐（班克斯群岛至阿纳托姆岛）、圣克鲁斯群岛（包括图科皮亚岛、瓦尼科罗岛、乌图普阿岛等）及洛亚蒂群岛（乌韦阿岛、利富岛、马雷岛）。非繁殖区：无迁徙，仅局部移动。","other":"系统分类上，本种曾被视为与罗岛摄蜜鸟或密岛摄蜜鸟同种，但形态与鸣声差异显著。亚种变异大，部分种群（如lifuensis）或应提升为独立种。亚种pulcherrima在20世纪初由邻近岛屿新近扩散至圣克里斯托瓦尔岛，可能与烟色摄蜜鸟曾有杂交。"},{"name":"罗岛摄蜜鸟","english_name":"Rotuma Myzomela","scientific_name":"Myzomela chermesina","overview":"罗岛摄蜜鸟（英文名：Rotuma Myzomela，学名：Myzomela chermesina），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。分布于太平洋中的Rotuma岛，位于斐济远西北部和波利尼西亚西南部。以其鲜明的红黑对比羽毛著称，雄鸟头部、翅膀、腹部和尾巴为丝滑的黑色，背部和臀部为亮丽的红色，而雌鸟色彩较暗淡。","appearance":"成年雄鸟身长约13厘米，上体中央（肩背、背部、臀部和尾羽覆羽）有明亮的红色至猩红色条带，下体自喉至前腹侧为鲜艳的红色至猩红色，黑色斑点不规则点缀，尤其是上体和胸部。雌鸟类似，但色彩较暗，头部和上体呈灰黑色，红色部分更暗淡且范围缩小，下体较暗淡，黑色至棕色的下巴到上胸带有微弱的红色，下腹至下体为棕色或棕黑色，下胸和上腹带有强烈的红色。幼鸟描述不详，但据说上体无红色，翼羽覆羽边缘为橄榄褐色。","call":"关于其鸣叫特征，目前尚无具体描述。","habits":"罗岛摄蜜鸟广泛分布于Rotuma岛上所有生境，包括原始森林、次生林、边缘地带、农业园和种植园。它们是居民鸟，以花蜜为主食，同时也大量捕食昆虫。在森林的外围枝条上觅食，也会在开阔地带的杂草种子头下悬挂。会飞扑捕捉空中昆虫，表现出高度活跃、好斗且显眼的行为。","breeding":"最近观察到的幼鸟是在五月中期离巢，其巢和蛋与橙胸摄蜜鸟相似，但无更多信息。","identification":"雄鸟与雌鸟在色彩上有明显区别，雄鸟色彩更加鲜艳，雌鸟则较为暗淡。在同属其他物种中，可通过色彩对比和分布区域进行区分。","protection":"IUCN：VU（易危）","distribution":"主要分布于Rotuma岛及其周边小岛，包括Uea，在斐济的远西北部。","other":"尽管大部分原生森林因农业开发而被清除，包括种植园，但存在广泛的次生植被，这似乎提供了适宜的栖息地。物种的丰度和对栖息地的容忍度应能保护其免受飓风损害。太平洋鼠（Rattus exulans）已在岛上存在，但引入其他外来掠食者可能构成潜在威胁。"},{"name":"密岛摄蜜鸟","english_name":"Micronesian Myzomela","scientific_name":"Myzomela rubratra","overview":"密岛摄蜜鸟（英文名：Micronesian Myzomela，学名：Myzomela rubratra），是雀形目吸蜜鸟科摄蜜鸟属的小型亮红色鸟类，以头部和颈部至胸部、腹部和上体中央的深红至鲜红色羽毛，以及黑色的翼和尾为显著特征。在密克罗尼西亚广泛分布，主要见于森林边缘和灌木丛。本种仅限于密克罗尼西亚，是该地区唯一的摄蜜鸟。其鸣声包含喘息的上升哨音和复杂的叽喳声。","appearance":"雄鸟成鸟的头颈至胸腹部和上体中央（肩背和背部、臀部及尾羽覆羽）呈鲜艳的深红色到鲜红色，眼前方有一条窄黑纹环绕眼周并延伸至眼后。上体其余部分、翅膀和尾部为黑色，次级飞羽有细淡橄榄灰色边缘；下腹和尾羽覆羽暗色至烟灰黑色，下体暗灰至橄榄灰色。雌鸟较雄鸟小，颜色较为暗淡，头部和上体中央为暗红色，其余上体、翅膀和尾部为暗棕灰色至橄榄棕色。幼鸟描述不详，但可见于雄鸟亚成鸟，上体红色斑块较少，下体更偏黄灰色，仍保留一些幼鸟时期的棕灰色羽毛。","call":"鸣声为尖锐的喘息式上升哨音，通常伴随啾啾声，重复有规律。歌曲是一系列复杂多变的啾啾、吱吱和哨音，通常在黎明前短暂鸣唱。","habits":"栖息于森林、森林边缘、红树林、本土棕榈林、海岸灌木丛、次生植被、灌木或杂草草原，以及受干扰的环境，包括椰子种植园和农田。在不同的岛屿上，偏好森林边缘、开阔地带和其他受干扰的栖息地。觅食时会飞至花丛中，主要以花蜜为食，也会捕食昆虫和小型无脊椎动物。飞行敏捷，常单独或成对出现。","breeding":"全年繁殖，无明显季节性波动。筑巢于小树或灌木的浓密枝叶间，高度通常低于5米。巢由细草、蕨类叶片、桉树叶、根须和蜘蛛网构成，呈杯状，内衬苔藓或细草。每窝产卵2枚，偶尔1枚，双亲共同孵卵和育雏。孵化期约为12天，雏鸟期超过13天。","identification":"与其他摄蜜鸟的区别在于其独特的亮红色羽毛和黑色翼尾。不同亚种在羽色深浅和模式上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于马里亚纳群岛和加罗林群岛（密克罗尼西亚），包括罗塔岛、提尼安岛、塞班岛、雅普岛、楚克岛、波纳佩岛和科斯雷岛。曾存在于关岛，但该地种群现已几乎灭绝。","other":"在某些岛屿上，因人类活动和外来物种入侵（如棕色树蛇）而面临威胁。"},{"name":"红襟摄蜜鸟","english_name":"Sclater's Myzomela","scientific_name":"Myzomela sclateri","overview":"红襟摄蜜鸟（英文名：Sclater's Myzomela，学名：Myzomela sclateri），是雀形目吸蜜鸟科摄蜜鸟属的小型鸟类。拥有深棕色的背部和浅黄色的腹部，胸部有条纹，翅膀下方呈白色。雄鸟头部黑色，喉部鲜红色，而雌鸟的红色仅限于下巴斑点。该物种分布于新几内亚和新不列颠附近的小岛屿森林中。","appearance":"红襟摄蜜鸟体型小，长度介于10.5至12厘米，重量雄鸟约为10.5至12克，雌鸟10至11克（以卡卡岛为例）。雄鸟头部、颈部顶部和上背黑色至暗橄榄棕色，逐渐过渡到较淡的橄榄棕色臀部和上尾羽盖；翅膀中央和较大的上翼覆羽有细微且模糊的橄榄色边缘，飞羽有细橄榄色边缘；尾羽边缘略显淡棕色；喉部和下巴亮红色；上胸暗橄榄棕色，向下变为污浊的橄榄黄至脏白色腹部，腹部和前侧腹模糊条纹或斑点；下尾羽灰色；下翼白色，边缘和尖端银灰色；虹膜黑色；喙黑色；腿蓝灰色。雌鸟较小，上体棕色至橄榄棕色，臀部和上尾羽盖赤褐色，上翼覆羽有淡色黄褐色边缘，飞羽边缘淡黄色橄榄色，尾羽边缘橄榄色；下体淡橄榄色，下巴和喉侧有小而不明显的红色斑块，喉部和上胸有模糊的暗橄榄灰斑，下尾覆羽棕色，下尾淡灰棕色，下翼和裸露部位如雄鸟。幼鸟描述未知，但‘未成鸟’被描述为不起眼，缺乏所有红色部分，可能是幼鸟；幼鸟了解不多，似乎类似于成年雌鸟。","call":"发出刺耳的滑音‘siieeuw’；上升的滑音‘sweei’后跟重复的上升‘tsiib, tsiib’；叫声（或歌曲）由一对短促、粗糙的嗡嗡声组成，第二个音更低且颤音；以及持续的‘chip, chip, chip’。叫声被比作白眼鸟（Zosteropidae）的声音。","habits":"栖息于原始森林（包括海滨森林）、次生植被和改良的栖息地，包括椰子种植园；在卡卡岛，还包括矮化的山地灌木丛和岛上峰顶潮湿的苔藓覆盖的森林。海拔从海平面到1830米；大多数岛屿非常小，低珊瑚岛，除了最近失去野生动物的火山岛Long和邻近的Tolokiwa和Crown（海拔从海平面到600至1350米）；在卡卡岛，主要栖息在1000至1200米之间，但有时会访问低地。","breeding":"在卡卡岛，繁殖季节似乎延长，可能从五月到六月开始；在Witu岛上，八月中旬发现带有幼鸟的巢。巢为薄壁杯状，偶尔有蜘蛛网附着于外部，悬挂在隐蔽处，通常位于低矮植被中（例如地面以上2米的甘蔗草丛中），但在椰子树中高达10米。关于窝卵数、孵化期和雏鸟期的信息未知；双亲喂养雏鸟。","identification":"雄性红襟摄蜜鸟很容易识别。雌鸟与雌性黑花蜜鸟或黄腹花蜜鸟相似，但喉咙和胸部有轻微的条纹。与雌性红摄蜜鸟相似，但雌性红襟摄蜜鸟缺乏红色尾巴和额头。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚北部的卡卡岛（Karkar）和新不列颠岛周围的岛群，包括Crown、Long、Tolokiwa、Tamuniai、Umboi、Unea（Bali）、Witu群、Kimbe湾内的小岛和新不列颠岛北海岸的岛屿、Talele、Watom和Credner岛（靠近约克公爵岛，包括Nanuk和Palakuru）。","other":"红襟摄蜜鸟在乌姆博伊岛上的状态不确定；至少偶尔出现，早期报告在1955年前，近期记录在1994年。在新几内亚西北部的Schouten岛（Biem/Bam岛）上的可能分布似乎不太可能。"},{"name":"俾岛摄蜜鸟","english_name":"Bismarck Black Myzomela","scientific_name":"Myzomela pammelaena","overview":"俾岛摄蜜鸟（英文名：Bismarck Black Myzomela，学名：Myzomela pammelaena），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。亦被称为黑摄蜜鸟或ebony myzomela，以全身漆黑的羽毛而著名，分布于澳新界的俾斯麦群岛，包括阿德默勒尔蒂群岛和附近岛屿。此鸟种体型小，雄鸟平均重17克，雌鸟平均14.6克。","appearance":"雄性俾岛摄蜜鸟通体呈光泽的黑色，仅翼下覆羽略显黑灰色；眼睛颜色为棕色至黑色，喙和腿均为深灰色到黑色。雌鸟相似但略小，色泽稍显灰暗。幼鸟全身呈暗褐色，下方颜色略偏棕色，喙基部带有肉黄色。不同亚种在大小和翼下色彩上存在差异。","call":"俾岛摄蜜鸟的叫声主要由响亮、粗哑的责骂声组成，尤其是nigerrima亚种的声音相对较大。","habits":"这种摄蜜鸟栖息于几乎所有植被覆盖的环境，从原始森林到次生林、灌木丛、椰子种植园乃至人类居住区周边。在Long岛上，它们更倾向于开放的沿海栖息地，包括果树林和椰子树冠。海拔分布从海平面到山峰，最高可达1300米。它们可能主要是留鸟，但会进行局部移动。","breeding":"有关繁殖的细节有限，已知的单个巢穴位于离地面约2.4米的小树水平叉枝上，巢由精细的植物纤维构成，悬挂于外层枝叶中，被上方的树叶遮掩。巢中发现有雏鸟。","identification":"雄性俾岛摄蜜鸟与雄性灰摄蜜鸟的区别在于后者更偏向灰色，有红色下巴和橄榄色翼斑。与雄性黑花蜜鸟相比，后者喉部和头部有绿色斑块，而雌性黑花蜜鸟头部呈淡灰色。","protection":"IUCN：LC（无危）","distribution":"分布于俾斯麦群岛，包括新几内亚东北部的阿德默勒尔蒂群岛和邻近岛屿，西至某些特定岛屿。","other":"在Manus岛上，近期有小群个体的记录，当地居民反映该物种在岛上并不常见，但退化植被面积的增加可能促进了这一‘超级流浪者’物种在当地建立繁殖种群。"},{"name":"红枕摄蜜鸟","english_name":"Red-capped Myzomela","scientific_name":"Myzomela lafargei","overview":"红枕摄蜜鸟（英文名：Red-capped Myzomela，学名：Myzomela lafargei），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。主要特征为头部、颈部和整个上部呈黑色，雄鸟的头部具有独特的红色斑块，雌鸟则呈现较为暗淡的黄色。广泛分布在所罗门群岛的多个岛屿，包括布卡岛、布干维尔岛、肖特兰群岛、乔斯尔岛、圣伊莎贝尔岛及其周边小岛。","appearance":"雄性红枕摄蜜鸟长约12-13厘米，重约12-14克，头部和上体黑色，头顶有红色斑块，有时延伸到额头和眼睛下方，甚至到下巴。翼羽边缘泛黄，下体橄榄黄至芥末黄，胸部和上腹部颜色最鲜艳。雌鸟体型较小，头颈绿灰至橄榄灰，下体喉咙以下黄灰色至黄橄榄色。幼鸟类似雌鸟，但喙较暗，前额和前冠可能带有红色。","call":"鸣声多样，包括甜美的高音“tsip-tsip”、尖锐的哨音“chip”或“chitt”、响亮的干燥“chtt”声以及芦苇般的啾啾声。快速的叽叽喳喳叫声。","habits":"栖息于低地、中海拔和高山原始森林，包括云雾林、森林边缘、高大的次生森林、低地沼泽森林、红树林和其他沿海栖息地，以及经过改造的环境，如森林中的农场空地、椰子种植园、花园和村庄。海拔从海平面至2000米以上。不与菲律宾花蜜鸟共同出现，但两者有时会在同一区域被发现。","breeding":"一月中观察到雌鸟携带食物，七月至八月大部分鸟处于繁殖状态，而此时低地的个体并未进入繁殖期。具体繁殖细节尚无更多信息。","identification":"与菲律宾花蜜鸟相比，雌性红枕摄蜜鸟颜色更暗淡，雄鸟有黑色头部和背部。雄鸟头顶的红色斑块是其显著特征。","protection":"IUCN：LC（无危）；在布干维尔岛上相对常见，但在乔斯尔岛较为罕见，圣伊莎贝尔岛上稀少。在阿纳沃恩岛、马拉科比和梅加波德的现状未知，缺乏近期信息。","distribution":"分布于所罗门群岛的布卡岛至圣伊莎贝尔岛及其卫星岛屿，包括北至所罗门群岛中东部的部分地区。"},{"name":"黄臀摄蜜鸟","english_name":"Crimson-rumped Myzomela","scientific_name":"Myzomela eichhorni","overview":"黄臀摄蜜鸟（英文名：Crimson-rumped Myzomela，学名：Myzomela eichhorni），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。其最显著的特征是鲜红的臀部和喉咙斑块，主要分布于所罗门群岛的西方省，尤其是新乔治亚岛一带。","appearance":"这种小型鸟类，全身大致呈黑色，拥有弯曲的喙，红色喉部斑点，以及醒目的红色臀部。雄鸟成鸟上身深橄榄灰，头部和颈背略暗，翼和尾更黑，带有鲜艳的红色臀部和上尾覆羽，翼覆羽和飞羽边缘呈淡黄色橄榄色。雌鸟相似，但下体颜色较暗淡的褐色。幼鸟则呈现非常暗淡的棕灰色，没有橄榄绿的色调，下巴和喉咙中央有暗红灰斑。","call":"其声音为响亮高音的“tseep-tseep”，在追逐时会发出尖锐的“zeeeet-zeeeet”，以及快速高音的颤鸣声，类似但比Rufous Fantail的叫声更快。","habits":"栖息于原始森林、高大的次生林，偶尔在村庄花园、椰子种植园和树丛中出现。在Kolombangara岛上，常见于各种树或灌木丛环境，尤其在高苔藓森林中最为丰富。海拔高度从海平面至1500米以上，较高海拔处更为密集。","breeding":"关于繁殖的详细信息较少，仅知自由飞翔的幼鸟出现在8月底。","identification":"雄鸟与雌鸟的主要区别在于色彩饱和度，雌鸟下体颜色较为暗淡。在同属物种中，黄臀摄蜜鸟以其独特的红色臀部和喉咙斑块易于辨认。","protection":"IUCN：LC（无危）","distribution":"黄臀摄蜜鸟主要分布在所罗门群岛的西方省，具体而言，它们的栖息地集中在新乔治亚岛（New Georgia group，位于所罗门群岛的西中部）。"},{"name":"红腹摄蜜鸟","english_name":"Red-vested Myzomela","scientific_name":"Myzomela malaitae","overview":"红腹摄蜜鸟（英文名：Red-vested Myzomela，学名：Myzomela malaitae），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。这体型较大、外观醒目的鸟类，全身大部分为深黑色，拥有鲜艳的红色臀部和胸部，形成独特的‘马甲’外观。雌鸟上身呈巧克力棕色，腹部为锈棕色。该鸟种特有于所罗门群岛东南部的马莱塔岛。","appearance":"红腹摄蜜鸟体态丰满，主要颜色为深黑，其最显著的特征是明亮的红色臀部和胸前的‘马甲’，包括胸部、喉咙和两侧。腹部、背部和头部均为深黑色。雌鸟颜色较为柔和，上半身为巧克力棕色，下半部为锈棕色。雄鸟与雌鸟在色彩上有明显差异。","call":"鸣声清脆，高音调，表现为连续的‘tsip-tsip’声。","habits":"偏好原始森林环境，但也偶尔会出现在次生林和灌木丛中。它们的活动范围通常在山地森林地带。","breeding":"关于其繁殖行为的具体细节尚未详细记录。","identification":"在其分布范围内没有相似物种，通过其独特的红黑相间的羽毛很容易辨认。","protection":"IUCN：NT（近危）。其生存受到栖息地丧失的威胁。","distribution":"仅分布于所罗门群岛东南部的马莱塔岛山区。","other":"红腹摄蜜鸟的生存状况引起了关注，主要威胁来自于其栖息地的破坏。"},{"name":"黑头摄蜜鸟","english_name":"Black-headed Myzomela","scientific_name":"Myzomela melanocephala","overview":"黑头摄蜜鸟（英文名：Black-headed Myzomela，学名：Myzomela melanocephala），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。分布于所罗门群岛的中心地带。拥有独特的黑色面部与喉咙，形成面具状外观，而身体呈黄绿色，翅膀较暗橄榄绿。该物种在各种生境中普遍可见。","appearance":"成年雄鸟主要为富丽的橄榄色，上部及颈侧、胸部带有光泽的黑色面罩，覆盖前额至头顶，耳羽、颊区、下巴及喉咙黑色。背部、翅膀深橄榄棕色，翼羽边缘有细淡橄榄色条纹。胸部橄榄色，下腹部略暗灰橄榄色，腹部和两胁常带有暗色斑点。雌鸟体型较小，颜色略淡，面罩可能更小，下腹颜色更浅。幼鸟的面罩更暗淡，上部颜色更淡，腹部灰黄色，喙基部暗黄色，口角鲜黄色。","call":"发出甜美的高音‘chip-chip’声，有时会发出响亮、类似笛音的‘teep…teep…’声，伴随有变体叫声，如‘tleep’或‘ti-eep’。","habits":"常见于原始森林、森林边缘、高大的次生林和包括花园在内的改造生境，从海平面至至少1550米的高度。主要以昆虫为食，偶尔尝试啄食果实。活跃于树冠层，也出现在森林边缘和受扰动地区的较低层次。善于在花朵间觅食，如椰子花，动作敏捷，常倒挂取食，跳跃于枝条间，偶尔悬停捕食飞虫。","breeding":"关于繁殖信息有限，观察到11月中旬有刚离巢仍带绒毛的幼鸟。","identification":"与黄腹花蜜鸟相似，但黑头摄蜜鸟具有暗色面部和苍白喉部，下方颜色更加暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于瓜达尔卡纳尔岛（Guadalcanal）、萨沃（Savo）和恩盖拉（Nggela），位于东所罗门群岛。"},{"name":"烟色摄蜜鸟","english_name":"Sooty Myzomela","scientific_name":"Myzomela tristrami","overview":"烟色摄蜜鸟（英文名：Sooty Myzomela，学名：Myzomela tristrami），是雀形目吸蜜鸟科摄蜜鸟属的鸟类，主要分布于澳新界的马基拉岛（所罗门群岛），Ugi岛（位于马基拉岛西北部外海）以及Santa Catalina和Santa Ana岛（位于马基拉岛东南部外海，所罗门群岛东南部）。其显著特征为全身呈丝滑黑色，翼羽和尾羽在阳光直射下显现出微弱的蓝绿色光泽。","appearance":"成年雄性烟色摄蜜鸟体长约11至12厘米，体重介于12.5至16.5克之间；全身黑色，带轻微的紫蓝色光泽，翼羽和腋下羽毛较暗淡，呈灰黑色至暗黑色，翼下覆羽间或带有斑点状的灰白色。雌鸟体型略小，可能稍显暗淡。幼鸟颜色较暗，上部为烟黑色，下部为灰橄榄色，喙部为暗黄色至橙黄色，端部黑色，腿色较浅。","call":"通常较为安静，最常见的是轻柔的低语式鸣叫和‘tz, witcher-witcher-witcher’、‘churr, churr, churr-chirr, chi chi chi, churr, churr’的细语声。黎明时的鸣唱为短暂的鼻音哨声后跟快速再转慢的颤音。","habits":"栖息于各种生境，包括原始森林、次生林、椰子种植园和花园等，占据所有植被覆盖的环境，从海平面到约900米的高度。常见于海岸线和中海拔地区，而非山脚或700至900米的高度。以花蜜为主食，也捕食小型昆虫，偶尔观察到携带小果实在空中接住。通常成群活动，由约6只个体组成，其中亚成鸟比成鸟多，有时会在开花的树上聚集多达十只或更多。","breeding":"已知的繁殖行为包括巢穴建造，巢穴类似太阳鸟的巢，但更宽且深度较小，悬挂在离地面10米高的次生林树枝上。除此之外，关于繁殖的其他信息尚不清楚。","identification":"与深红摄蜜鸟相似，但烟色摄蜜鸟的羽毛缺乏红褐色调，通过羽毛色泽和声音可以区分。","protection":"IUCN：LC（无危）。在所罗门群岛的特定区域内普遍且数量众多，但在Ugi岛上的状态不确定，可能是迷鸟或偶尔访客，但也可能存在常驻种群，需进一步研究。","distribution":"主要分布于所罗门群岛的马基拉岛、Ugi岛以及Santa Catalina和Santa Ana岛。","other":"烟色摄蜜鸟在所罗门群岛的特定岛屿上被认为是常见的至丰富的物种，特别是在马基拉岛的沿海地区。"},{"name":"橙胸摄蜜鸟","english_name":"Sulphur-breasted Myzomela","scientific_name":"Myzomela jugularis","overview":"橙胸摄蜜鸟（英文名：Sulphur-breasted Myzomela，学名：Myzomela jugularis），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。该鸟以鲜明的红帽（雌鸟缺乏）、黑色面颊、额头和背部、黄色胸部、带有白色斑点和橄榄色大块的黑色翅膀，以及灰白下体为特征。臀部鲜红，尾巴下方黑色带白色尖端。在各种生境中常见，包括森林、椰林、花园等。","appearance":"体长9-11厘米，体重雄鸟8-10克，雌鸟8-9克。具有短尾和弯曲的长喙。雄鸟头部和颈部主要为黑色，带有红色后冠至颈背，喉咙上方红色，胸前黄至橙黄色。上身黑色，下背、臀部和尾羽覆羽红色，尾羽黑褐色，翼上具白色尖端和橄榄绿色边缘。雌鸟较雄鸟小、暗淡，头部、颈部和上身呈烟灰色，红色部分较暗淡。幼鸟无红色羽毛，与雌鸟相似但更暗淡，胸部脏橄榄灰色。","call":"频繁发出尖锐的‘chit-chit’或‘sweet-sweet’声，尤其是在群体中，可产生几乎连续的高音颤音。雄鸟的歌曲由2-4个音节的短语组成，如‘tee-ter’，在树顶持续一小时以上单调重复。","habits":"栖息于各种环境，包括原始和次生森林、沿海森林和红树林；在受干扰的环境中常见，如道路旁、林间空地、种植园和农田、城镇、村庄和花园，以及开阔地带的散落树木。在维提岛的干燥地区，会进行局部移动，有时形成小群，可能几个月不见踪影。","breeding":"繁殖记录全年除3-4月外均有发生，可能双窝。巢由草和细根制成的脆弱松散杯状，悬挂在密集树叶中的灌木、藤蔓或小树之间，通常低于4米。每次产2枚卵，孵化和育雏期未知，由双亲喂养。","identification":"雄鸟具有独特的红帽和鲜红臀部，雌鸟和幼鸟缺乏这些特征，颜色更为暗淡。与其他Myzomela物种相比，可通过其鲜艳的红色标记和叫声辨识。","protection":"IUCN：LC（无危）","distribution":"分布于太平洋的斐济群岛（波利尼西亚西南部），包括所有岛屿，除了Rotuma。在马科盖和高乌岛上常见。","other":"在斐济，是最小的本地鸟类物种，常见于花园、农村森林和红树林栖息地，以及受干扰地区的椰子树中。"},{"name":"红黑摄蜜鸟","english_name":"Black-bellied Myzomela","scientific_name":"Myzomela erythromelas","overview":"红黑摄蜜鸟（英文名：Black-bellied Myzomela，学名：Myzomela erythromelas），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。体型小巧，长约9至10厘米，雄鸟体重7至9克，雌鸟略轻，约6.5至7.5克。雄鸟全身黑色，头戴鲜艳的红色帽饰；雌鸟橄榄色，脸部略显红色。广泛分布于新不列颠岛的森林环境中。","appearance":"雄性红黑摄蜜鸟全身漆黑，仅头部呈鲜亮的红色，下颌处有细窄的黑色条纹，翼下有银灰色斑块。雌鸟体型略小，主色调为橄榄绿，脸部红色较淡，覆于前额、前顶、耳羽前方、颊部及喉部，眼周暗色。喙、腿均为黑色，脚底黄色。幼鸟特征未详。","call":"常见叫声为快速的‘tsi-tsi-tsi’，音调尖锐，类似黑太阳鸟的叫声。","habits":"栖息于新不列颠岛的原始森林、林缘及次生林中，偶尔出现在花园和开阔地带。常见于低地和山麓，海拔高度可达约900米。主要以花蜜为食，也会捕食小型节肢动物。通常成小群在树冠外层觅食，但在林缘和次生林中会降低觅食高度。","breeding":"已知繁殖季节在7月初，幼鸟已能独立。巢为开放式的杯状，悬挂在茂密的藤蔓中。具体繁殖细节待进一步研究。","identification":"与Sclater's摄蜜鸟相似，但Sclater's摄蜜鸟头部为黑色，身体呈灰白色，容易区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在新不列颠岛（Bismarck Archipelago），在Whiteman山脉的低地和热带雨林中常见。"},{"name":"红腰摄蜜鸟","english_name":"Black-breasted Myzomela","scientific_name":"Myzomela vulnerata","overview":"红腰摄蜜鸟（英文名：Black-breasted Myzomela，学名：Myzomela vulnerata），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。小型而独特的吸蜜鸟科摄蜜鸟属鸟类，以黑色、白色和红色的鲜明组合为特征。该鸟种仅分布于帝汶岛（小巽他群岛东部），在低地和山麓森林、林缘及灌木丛中可见。","appearance":"红腰摄蜜鸟体长约10.5厘米，拥有宽阔的黑色面罩，覆盖眼下方区域、颊部、颈侧以及连接黑色胸带和背部，与鲜红色的顶冠、喉部斑块隔离。臀部和上尾覆羽呈鲜红色，上翼主要为黑色，狭窄的灰色边缘形成折翼时模糊的浅色面板。下体在黑色胸带下方为白色至灰白色。雄鸟和雌鸟的羽毛相似，但雄鸟体型略大，雌鸟黑色部分缺乏光泽，呈烟熏状棕色；幼鸟的黑色部分呈现灰色调。","call":"发出微弱而高音的昆虫般的单音节声，以约1秒的间隔单调重复，\"sit-sit-sit-…\"；快速重复一系列双音节音调相近的音符，\"tipa-tipa-tia-tipa-…\"，第二个音节比第一个低。","habits":"红腰摄蜜鸟主要栖息于次生季风林和灌木丛，偶尔在原始森林中被发现，活动海拔从海平面到1300米。它们可能保持定居，但存在局部移动的可能性。主要以花蜜为食，也捕食昆虫。通常在树冠层至中层寻找食物，活跃但较为隐蔽，单独或成对出现。","breeding":"已观察到雌鸟在12月初携带食物，以及5月期间的亚成鸟或幼鸟。推测繁殖季节为3月至4月和11月，具体繁殖信息有限。","identification":"红腰摄蜜鸟的独特之处在于其鲜明的黑白红三色搭配，尤其是黑色面罩和红色顶冠、喉部斑块以及臀部，使其在有限的分布范围内易于识别。","protection":"IUCN：LC（无危）。红腰摄蜜鸟是限制分布物种，在帝汶和Wetar EBA存在。总体上数量适中，局部地区非常常见。","distribution":"红腰摄蜜鸟的分布限于帝汶岛（东小巽他群岛）。"},{"name":"红领摄蜜鸟","english_name":"Red-collared Myzomela","scientific_name":"Myzomela rosenbergii","overview":"红领摄蜜鸟（英文名：Red-collared Myzomela，学名：Myzomela rosenbergii），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。具黑色喉部，胸部和臀部有减淡的红色。此鸟种在高海拔区独一无二，但在中海拔与其它物种共存。","appearance":"雄性红领摄蜜鸟长约10至12.5厘米，重9.3至12.7克，全身漆黑，仅颈环、胸侧、背部、臀部及上尾覆羽为亮丽的猩红色，翼下为烟灰色。雌鸟体型较小，上半身黑褐色，面部、喉部及上胸部黑色，额头及头顶有模糊的赤褐色斑点，下半身赤褐色，翼下白色带银灰边缘。幼鸟上半身暗棕至栗褐色，下半身稍浅，胸部有红色痕迹，成年特征逐渐显现。","call":"其鸣声充满活力且多变，包括上下起伏的“tweepy-tweepy-tweepy”音节，带有轻微电子感的音符。","habits":"栖息于新几内亚的高山原始森林，包括云雾林、苔藓林、橡树林和密集的河岸林，偶尔在花园的开花灌木丛中出现。主要以花蜜为食，也会捕食小昆虫和偶尔吃些小果实。在树冠层活动，但矮林中会下降至低层，也在高山灌木地觅食。","breeding":"繁殖记录显示，巢雏出现在7月底和9月底，幼鸟在7月中旬，幼鸟在9月初出现。巢穴为由根须构成的杯状结构，离地面约3米高。已知雌鸟独自喂养幼鸟，具体繁殖行为细节尚需进一步研究。","identification":"雄鸟的鲜明红黑对比和雌鸟的特有红色胸部和臀部使其在同类中易于识别。与同属其他物种相比，其特有的高海拔栖息地和鸣声也是辨识关键。","protection":"IUCN：LC（无危）。在阿尔伯特山脉海拔1400至1600米处极为常见。雄鸟比雌鸟更常被观察到，可能由于性别比例偏斜或生态行为差异。尽管皮肤被当地居民用于装饰，但目前全球范围内不被视为受威胁。","distribution":"分布于新几内亚的高山地区，从沃格尔科普山脉向东延伸，覆盖了福克福克山、库马瓦山、福贾山、环形山、贝瓦尼山、阿德尔伯特山和休恩半岛的山脉，直至欧文斯坦利山脉。在德安特卡斯特罗群岛中的古登诺夫岛也有分布。","other":"在2021年，国际鸟类联盟将古登诺夫岛的长嘴摄蜜鸟认定为独立物种，之前曾被认为与红领摄蜜鸟同种。"},{"name":"罗地岛摄蜜鸟","english_name":"Rote Myzomela","scientific_name":"Myzomela irianawidodoae","overview":"罗地岛摄蜜鸟（英文名：Rote Myzomela，学名：Myzomela irianawidodoae），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。吸蜜鸟科摄蜜鸟属的小型鸟类，仅分布于印度尼西亚小巽他群岛中东部的罗地岛。该鸟以鲜明的红黑羽毛著称，雄鸟拥有黑色身体搭配鲜艳的红色头部和臀部，腹部颜色较淡；雌鸟则呈现棕色，腹部更浅，喉部、前额和脸颊有明显的红色痕迹。该物种被命名为纪念印尼当时的首位夫人Iriana Joko Widodo。","appearance":"雄性罗地岛摄蜜鸟体型较小，全长约11厘米，重32.2克。其头部、颈背至臀部覆盖着鲜艳的红色羽毛，背部上半部分为深灰色，腹部和两翼下侧为橄榄色，翅膀上覆羽为黑色，边缘带有白色。雌鸟个体整体呈棕褐色，腹部颜色较浅，头部、喉部、前额和脸颊有红色斑块。喙、虹膜、脚和足均为黑色，足垫黄白色。","call":"鸣叫特征独特，表现为快速连续的金属质感音节，如'zip-zip-zip-zip-zip-zip...'。","habits":"栖息于低地森林、林缘和花园，偏好树冠层，广泛分布于整个罗地岛。它们常单独或成对出现，以花蜜为主要食物来源。","breeding":"可能在森林、林缘和干燥的木本地带繁殖。","identification":"与其他Myzomela物种相比，如松巴摄蜜鸟，罗地岛摄蜜鸟的雄鸟具有更窄的黑色胸带，体型更大，表现在尾长和跗跖长度上。雌鸟与松巴摄蜜鸟相似，但通过结构、喙形和尾长可以区分。","protection":"IUCN：未评估（由于栖息地丧失的威胁，建议关注其脆弱性）","distribution":"该物种仅分布于印度尼西亚的小巽他群岛中的罗地岛（Rote），属于澳新界。","other":"由于近几十年来的森林砍伐，该物种的大部分分布范围受到威胁，岛上缺乏指定的保护区。"},{"name":"阿洛摄蜜鸟","english_name":"Alor Myzomela","scientific_name":"Myzomela prawiradilagae","overview":"阿洛摄蜜鸟（英文名：Alor Myzomela，学名：Myzomela prawiradilagae），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。仅在印尼小巽他群岛东端的阿洛岛高地被发现。此鸟以鲜艳的红色头部和王冠为显著特征，雄鸟的色彩更鲜艳且覆盖范围更广。在有限的范围内极为显眼，主要栖息于桉树为主的森林中。","appearance":"雄性阿洛摄蜜鸟拥有明亮的红色面部和王冠，背部呈灰色，腹部淡色，臀部红色，喙略弯曲且深色。雌鸟的红色头饰较小，喉咙和颈背部分为灰色。雄鸟上翼呈暗褐色，边缘有橄榄灰的痕迹，尾羽上覆羽和臀部也是相对淡红。胸部烟灰色，逐渐过渡到奶油色的腹部至尾下覆羽。雌鸟的描述较少，但据报其红色头饰不如雄鸟广泛，下喉和颈背为灰色。","call":"阿洛摄蜜鸟的鸣唱是一系列高音的快速颤音，叫声为上升后下降的高音‘tseeep’。","habits":"此鸟常在开花的树木附近被发现，偏好在海拔900米以上的桉树森林中活动，尤其偏爱山顶的林地。它们通常单独、成对或小群活动，主要在亚冠层觅食，取食花蜜、果实和昆虫。","breeding":"关于阿洛摄蜜鸟的繁殖信息目前未知。","identification":"在阿洛岛上，阿洛摄蜜鸟的辨识非常直接，因为没有其他相似物种。与邻近Wetar岛的红巾摄蜜鸟相比，阿洛摄蜜鸟的头部红色更为鲜明，且延伸至颈背的部分较少，翅膀和胸部的灰色更明显，上翼的橄榄灰边缘也更为突出。","protection":"IUCN：VU（易危）","distribution":"阿洛摄蜜鸟仅分布在印尼小巽他群岛中的阿洛岛中部和东部的山区。","other":"阿洛摄蜜鸟的分布范围极其有限，仅在三个局部地区被记录，且似乎局限于海拔900米以上的桉树林。"},{"name":"塔里摄蜜鸟","english_name":"Taliabu Myzomela","scientific_name":"Myzomela wahe","overview":"塔里摄蜜鸟（英文名：Taliabu Myzomela，学名：Myzomela wahe），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。2020年新描述的物种。以印尼塔利亚布岛的Wahe村命名，此村为通往岛上最高海拔处的门户，而塔里摄蜜鸟主要在此区域被发现。目前仅在塔利亚布岛发现，分布于森林冠层和边缘生境。","appearance":"雄鸟体色鲜亮，整体呈鲜艳的红色，黑色的翅膀、腹部和尾巴形成鲜明对比。雌鸟的外观尚未正式描述，但预计与苏拉威西摄蜜鸟相似，主要为暗褐色，翅膀和尾巴较深，腹部淡色，带有红棕色臀部，耳羽至下耳覆羽为淡红色。雄鸟头部、背部至上尾覆羽和下体均为明亮的红色，黑色眼圈狭窄，上翼、背部侧面、肩羽和尾羽均为哑光黑色，飞羽略带橄榄色边缘，腹中部有黑色灰色楔形斑。","call":"发出一系列高音的sip声，音量逐渐增大，每秒约7个音符，最终以混乱的低音和金属质感的元素结束，如'twee-twit twee-too-wee'，整个序列持续2-4秒。还有一种尖锐、金属质感的高音tit叫声。","habits":"塔里摄蜜鸟居住于森林冠层和边缘，从海平面到1,300米高度均有记录，可能延伸至塔利亚布岛最高点约1,415米。它们通常单独或成对出现，以花蜜和果实为食，已观察到其在花朵上觅食。","breeding":"关于繁殖的信息目前未知。","identification":"与苏拉威西摄蜜鸟和瓦科洛摄蜜鸟（Myzomela wakoloensis elisabethae）最相似，但塔里摄蜜鸟有更广泛的红色体色，翅膀、肩羽和尾巴更黑，红色羽毛基部大多为黑色和灰色，与黑色部分形成鲜明对比，缺乏黄色条纹，使身体颜色更接近橙色。雄鸟瓦科洛摄蜜鸟的腹部和下腹部为灰色而非黑色。","protection":"IUCN：尚未评估","distribution":"仅限于印尼的塔利亚布岛，位于苏拉群岛，紧邻苏拉威西岛东部。","other":"塔里摄蜜鸟的发现增加了该地区鸟类多样性的认识，强调了对其栖息地保护的重要性。"},{"name":"乌摄蜜鸟","english_name":"Moluccan Myzomela","scientific_name":"Myzomela simplex","overview":"乌摄蜜鸟（英文名：Moluccan Myzomela，学名：Myzomela simplex），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。原被认为是暗摄蜜鸟的亚种，但基于遗传学证据，现已确认其为独立物种，被IUCN红名单、BirdLife International和国际鸟类学家联盟认可为独立种类。分布于印尼摩鹿加群岛的摩罗泰岛至Bacan。","appearance":"具体外形特征的详细描述在此处，包括雌雄幼鸟的羽毛颜色、大小、特殊标记等。","call":"描述乌摄蜜鸟的鸣唱、叫声特点。","habits":"栖息于印尼摩鹿加群岛的亚热带或热带湿润低地森林，活动范围、迁徙习性、飞行特点、食物来源及捕食者等生活习性细节。","breeding":"繁殖期、求偶、营巢、交配、产卵、孵化、育雏等生长繁殖相关行为。","identification":"与暗摄蜜鸟及其他相似物种的辨识要点，包括外形、行为、分布差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的印尼摩罗泰岛至Bacan（印尼摩鹿加群岛北部），主要繁殖区域为上述岛屿。","other":"关于乌摄蜜鸟的其他重要信息，如历史上的分类变迁、生态角色等。"},{"name":"淡红摄蜜鸟","english_name":"Red-tinged Myzomela","scientific_name":"Myzomela rubrotincta","overview":"淡红摄蜜鸟（英文名：Red-tinged Myzomela，学名：Myzomela rubrotincta），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。原被认为是暗摄蜜鸟的一个亚种，但在2021年被国际鸟类联盟（IOC）认定为独立物种。该物种主要分布于印尼摩鹿加群岛中北部的Obi和Bisa两岛，栖息于原始森林和高大的次生森林中，海拔高度可达1210米。","appearance":"淡红摄蜜鸟具有独特的粉红色肩部、翼缘和上尾羽，以及带有玫瑰色的灰色下体。与乌摄蜜鸟相比，其尾部较短（雄性平均长度为48毫米）。头冠和颈背呈中灰色，上体部分呈现出更强烈、更鲜亮的红色，下体羽色为玫瑰色灰，区别于比岛摄蜜鸟的红灰色鳞状下体羽色。","call":"鸣唱由三个上升的、细而尖锐的高音组成，如\"wit-see-si'\"，持续时间约为0.4秒，偶尔最后一个音节会更低。典型叫声为连续的细高音\"sut-sit, sut-sit, sut-sit\"。","habits":"栖息环境主要为原始森林和高大的次生森林，包括边缘地带。分布范围从海平面至至少1210米的高度。","identification":"与暗摄蜜鸟的区别在于粉红色的肩部、翼缘和上尾，以及带有玫瑰色的灰色下体。与比岛摄蜜鸟的区别在于中灰色的头冠和颈背，以及更为鲜明的上体红色。","protection":"IUCN：LC（无危）。该物种为限制分布种，仅限于北方摩鹿加EBA内的两个岛屿。据信数量适中，但在低海拔地区（低于200米）较为稀少，总体种群被认为稳定。","distribution":"分布于澳新界：Obi和Bisa（印尼摩鹿加群岛中北部）。","other":"淡红摄蜜鸟曾被视为暗摄蜜鸟的一个亚种，后被IOC认定为独立种。"},{"name":"比岛摄蜜鸟","english_name":"Biak Myzomela","scientific_name":"Myzomela rubrobrunnea","overview":"比岛摄蜜鸟（英文名：Biak Myzomela，学名：Myzomela rubrobrunnea），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。曾被视为暗摄蜜鸟的一个亚种，但在2021年被国际鸟类联盟（IOC）认定为独立物种。其自然栖息地位于新几内亚西北部的比岛（Biak），生活在亚热带或热带湿润的低地森林中。","appearance":"成年比岛摄蜜鸟总体上较暗，羽毛呈红棕色，喉咙处有一条红色条纹，头部冠羽深色，翅膀和尾巴相对短小，平均体长介于13至15厘米之间。幼鸟的羽毛细节未知。","call":"鸣唱由三个上升的、尖锐的高音组成，例如\"wit-see-si'\"，持续时间约0.4秒，有时最后一个音符会更低。典型叫声为连续的\"sut-sit, sut-sit, sut-sit\"。","habits":"生活于亚热带或热带湿润的低地森林中。","identification":"与暗摄蜜鸟相比，比岛摄蜜鸟的头部更暗，身体羽毛红棕色，翅膀和尾巴明显更短。","protection":"IUCN：LC（无危）。该物种为限制分布种，仅限于新几内亚西北部的比岛。据信种群数量稳定。","distribution":"分布于澳新界的新几内亚西北部比岛（Biak）。"},{"name":"暗红摄蜜鸟","english_name":"Reddish Myzomela","scientific_name":"Myzomela erythrina","overview":"暗红摄蜜鸟（英文名：Reddish Myzomela，学名：Myzomela erythrina），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。为巴布亚新几内亚特有种，广泛分布于新爱尔兰岛及其周边岛屿（位于俾斯麦群岛东北部）。该鸟曾被视为红摄蜜鸟的一个亚种，但基于系统发育证据，现已确认其为独立物种。","appearance":"雄鸟具有独特的外观，其头部顶部、侧面及喉部呈现闪烁的红色，而非一般的锈灰色；雌鸟体羽呈暗淡的灰红色，带有粉边的初级飞羽，不同于褐色带白色边缘的羽色。此外，暗红摄蜜鸟的喉咙和头部侧面颜色更为鲜艳，而前额冠部则不如红摄蜜鸟那般鲜亮。","habits":"暗红摄蜜鸟偏好栖息于低地森林和山地森林中，常在亚热带或热带湿润的森林地带活动。","identification":"与红摄蜜鸟相比，暗红摄蜜鸟的雄鸟在头部色彩上更偏向于红色，雌鸟的体羽更加暗淡，带有粉色边缘。同时，它们的生境偏好于低地森林，而红摄蜜鸟则倾向于山地森林。","protection":"IUCN：LC（无危）","distribution":"暗红摄蜜鸟的分布局限于澳新界的巴布亚新几内亚，具体而言，新爱尔兰岛及其周边岛屿（位于俾斯麦群岛东北部）。","other":"暗红摄蜜鸟已成为新种，从红摄蜜鸟中分离出来，这一分类变更得到了IUCN、BirdLife International以及国际鸟类学家联盟的认可。"},{"name":"长嘴摄蜜鸟","english_name":"Long-billed Myzomela","scientific_name":"Myzomela longirostris","overview":"长嘴摄蜜鸟（英文名：Long-billed Myzomela，学名：Myzomela longirostris），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。仅限于巴布亚新几内亚东南部的Goodenough岛上的山区森林中，具有独特的黑帽、腹部、翅膀和尾巴，以及醒目的红胸、背部、臀部和颈圈，雄鸟特征鲜明，雌鸟以棕色为主，胸部和臀部带有红色。该物种在2021年被国际鸟类联盟（IOC）认定为独立物种。","appearance":"雄性长嘴摄蜜鸟具有黑色的头部、腹部、翅膀和尾巴，以及鲜艳的红色胸部、背部、臀部和颈圈，这一特征使其在同类中独一无二。雌鸟则主要呈棕色，胸部和臀部带有红色斑块。其最显著的特征是比红顶啄花鸟更长的喙。","call":"鸣叫声尚不为人所熟知，但可能类似于红领摄蜜鸟，发出充满活力的啾啾声和哨音。","habits":"长嘴摄蜜鸟生活在Goodenough岛的亚热带或热带湿润山地森林中，偏好较高的海拔环境。它们的活动模式、觅食习惯和食物种类目前了解较少。","identification":"与红顶啄花鸟相比，长嘴摄蜜鸟拥有明显更长的喙，这成为它们之间的重要辨识特征。同时，与所有太阳鸟相比，其羽毛中的红色部分也是显著的区别点。","protection":"IUCN：LC（无危）","distribution":"长嘴摄蜜鸟的分布仅限于Goodenough岛的山区（巴布亚新几内亚当特尔卡斯托群岛，东部，新几内亚东南部）。","other":"曾被视为红领摄蜜鸟的亚种，但在2021年被IOC确认为独立物种。"},{"name":"巴占摄蜜鸟","english_name":"Bacan Myzomela","scientific_name":"Myzomela batjanensis","overview":"巴占摄蜜鸟（英文名：Bacan Myzomela，学名：Myzomela batjanensis），是雀形目吸蜜鸟科摄蜜鸟属的鸟类。分布于印尼摩鹿加群岛北部的巴占山区。其显著的特征是雄鸟拥有鲜艳的红色头部、背部和臀部，与深色的尾巴和翅膀形成鲜明对比，腹部呈白色。","appearance":"雄性巴占摄蜜鸟具有引人注目的红色头部、背部和臀部，深色的尾巴和翅膀，以及白色的腹部。雌鸟和幼鸟全身灰褐色，有时脸部和喉咙带有锈红色。雄鸟的胸部在Obi岛上可能呈现红色，这可能代表了一个独立的分类单元。","call":"巴占摄蜜鸟的鸣唱是一系列短促、高音、嗡嗡上升的声音，表现为‘bzze-bzee-bzee!-bzeee!-bzeet！’，还发出吱吱声‘bijee！’。","habits":"巴占摄蜜鸟通常单独或成对出现在山地和丘陵森林的上层，偏好于热带湿润森林环境。","identification":"雌鸟和幼鸟可能与暗摄蜜鸟混淆，但后者体型更大、颜色更深，且不具备红色部分。","protection":"IUCN状态未提及。","distribution":"巴占摄蜜鸟仅分布于印尼摩鹿加群岛北部的巴占山区，包括山地和丘陵森林。","other":"曾被认为是苏拉威西摄蜜鸟的亚种。"},{"name":"茶冠澳蜜鸟","english_name":"Tawny-crowned Honeyeater","scientific_name":"Gliciphila melanops","overview":"茶冠澳蜜鸟（英文名：Tawny-crowned Honeyeater，学名：Gliciphila melanops），是雀形目吸蜜鸟科茶冠澳蜜鸟属的鸟类。澳大利亚南部特有。最显著的特征是茶色的冠羽，上体灰褐色，下体白色，带有黑色颊纹延伸至胸部，形成独特的黑色斑点。分布于澳大利亚南部及塔斯马尼亚州。","appearance":"成年鸟长约14至18厘米，体重介于14至22克。上体颜色为灰褐色，具淡橄榄褐色的条纹和斑点，头部有明显的图案，包括乳白色前额渐变为锈棕色至浅橙色或赭色的冠羽，大胆的白色眉纹，黑色面颊纹延伸至颈侧和上胸侧面，包围着耳羽后方的小白新月形区域，以及白色颏和喉部。初级飞羽和次级飞羽下方显现出黄色和鲑鱼色。幼鸟上体呈棕色，下体较浅，翼间有黄色。","call":"发出哀伤的笛声哨音，包括延长的单音符后跟快速重复的双音符，重复6至8次，或高亢上升的‘a-peer-peer-pee-pee-pee’声。春季常在黎明前鸣唱，叫声为晨歌的主要组成部分。还有一种哀伤的长音，经常听到。","habits":"栖息于沿海的低矮灌木丛和荒野地带。它们有时在地上跳跃觅食，这是其近亲中罕见的行为。主要以昆虫和花蜜为食。","breeding":"繁殖季节从6月至12月。巢为大型杯状，由树皮、草和海藻制成，内部衬有柔软材料如毛发或羊毛。通常产2至3枚，偶尔4枚蛋，卵呈椭圆形，大小约21x14毫米，底色为米黄色，带有点缀的淡黄色或粉色斑点。","identification":"与东部和西部脊嘴吸蜜鸟及新月吸蜜鸟相似，但可通过茶色冠羽上方的白色线条以及脸部黑色标记区分。两个亚种：指名亚种 melanops和G. melanops chelidonia，后者为塔斯马尼亚特有，羽毛带有红褐色色调。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部，包括新南威尔士州北岸至南澳大利亚州的艾尔半岛，维多利亚州和塔斯马尼亚州，以及西澳大利亚州西南部，从以色列湾向西。自1971年以来，悉尼市区已局部灭绝。","other":"DNA分析显示，吸蜜鸟与鹦鹉科、澳大利亚莺科和澳洲仙鹟科在大型超科Meliphagoidea中有关联。"},{"name":"白眼吸蜜鸟","english_name":"Green-backed Honeyeater","scientific_name":"Glycichaera fallax","overview":"白眼吸蜜鸟（英文名：Green-backed Honeyeater，学名：Glycichaera fallax），是雀形目吸蜜鸟科白眼吸蜜鸟属的鸟类。是其属下的唯一物种。体型微小，广泛分布于新几内亚和澳大利亚东北部的约克角半岛中东部。以橄榄绿的背部和黄色腹部为主要特征，拥有淡色的眼睛和眼环，以及蓝灰色的腿脚。","appearance":"白眼吸蜜鸟长约11至12.5厘米，体重介于7.5至18克之间，雌雄羽毛相似，雄鸟略大。头部和颈部为灰橄榄棕色，上体暗橄榄色，尾羽上覆羽带黄色调，下体淡黄色，翼下黄褐色。眼环和下颌淡黄色，眼睛淡蓝灰色，喙灰黑色，腿蓝灰色。幼鸟颜色较暗，眼环不明显。","call":"鸣叫包括连续的“pee pee pee pee pee”声，以及在新几内亚被描述为高音重复的“chick”声，或重复的“whit whit”，间隔约一秒。","habits":"栖息于热带雨林、次生林及边缘地带，常在树冠层活动，偶尔在地面附近觅食。主要以昆虫为食，也会摄取小果实和花蜜。在澳大利亚，常见于树冠，尤其在20米以上的高度；在新几内亚，活动高度不明确，但在树冠和下层均有记录。","breeding":"繁殖信息知之甚少，已知在新几内亚的8月和12月观察到筑巢，7月和10月见到幼鸟。可能在澳大利亚的干季繁殖，依赖性幼鸟记录在8月和6月。巢穴可能受到青铜鸠的寄生。","identification":"与黑头噪刺莺区别在于后者有黑眼、较短的黑喙。幼鸟与成鸟的区别在于更暗淡的色彩和不明显的淡色眼环。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚低地至山地（最高海拔1200米），以及澳大利亚东北部的约克角半岛中东部。在澳大利亚，常见于Iron Range，也有来自McIlwraith Range的记录。","other":"在新几内亚，尽管局部常见，但总体被认为稀有。"},{"name":"铅色嗜蜜鸟","english_name":"Leaden Honeyeater","scientific_name":"Ptiloprora plumbea","overview":"铅色嗜蜜鸟（英文名：Leaden Honeyeater，学名：Ptiloprora plumbea），是雀形目吸蜜鸟科嗜蜜鸟属的罕见物种。分布于新几内亚高地的中西部、中部及东南部山区，栖息于亚热带或热带湿润山地森林。","appearance":"体长约14至15厘米，体重介于12.5克至16.5克之间。头部、颈部和上身呈铅灰色，头顶、颈后及两侧有细小的黑褐色条纹，逐渐变为头部侧面和下巴的稀疏灰白色斑点，背部、肩部有更宽泛的黑褐色条纹。翅膀和尾巴上部为灰棕色，翼羽和飞羽边缘橄榄绿至橄榄灰，腹部几乎均匀铅灰色，腹底有橄榄棕色晕染。尾下覆羽棕色，下翼为淡灰蓝色，边缘和尖端深棕灰色。虹膜通常为浅灰至银灰色，部分个体（可能为幼鸟）为棕色；喙黑色至灰黑色；腿色为淡蓝灰色。雄鸟和雌鸟羽毛相似，雄鸟体型较大。幼鸟描述不详。","call":"鸣声包括吹哨般的、略带喘息的‘wshee wshee wshee…’和微弱的‘teu teu’或‘tswee’音符，约每3秒重复一次。","habits":"栖息于中海拔原始森林、森林边缘和次生林，偶尔在花园中被记录到。活动范围在海拔1000米至2100米之间，可能高达2400米。以昆虫和花蜜为食，觅食高度从树冠层至地面，常见于低层和中层（3至15米高）。昆虫从树叶、枝条和叶柄上获取，花蜜来自花朵，包括下层的姜科（Zingiberaceae）等植物。不畏人但隐蔽，活跃，觅食时持续跳跃，常单独出现，尾巴常翘起。","breeding":"繁殖信息未知。","identification":"与黄纹嗜蜜鸟相似，但铅色嗜蜜鸟底色为灰色而非黄褐色。与其他近缘种区别在于体型较小，侧翼无红褐色。鸣声独特，可作为辨识依据。","protection":"IUCN：LC（无危）。属于受限范围物种，见于中央巴布亚山脉EBA。总体稀少，但在某些地区如Suria森林内部（新几内亚东南部，中央省）可能较为常见。","distribution":"分布于新几内亚的中西部、中部和东南部山区。"},{"name":"绿纹嗜蜜鸟","english_name":"Yellowish-streaked Honeyeater","scientific_name":"Ptiloprora meekiana","overview":"绿纹嗜蜜鸟（英文名：Yellowish-streaked Honeyeater，学名：Ptiloprora meekiana），是雀形目吸蜜鸟科嗜蜜鸟属的鸟类。这中等体型、较为罕见的鸟类，分布于新几内亚山区中西部至东南部，自然栖息于亚热带或热带湿润山地森林。","appearance":"绿纹嗜蜜鸟全身呈淡黄色，头部、颈部及上体带有黄橄榄色，有明显的黑色条纹，条纹在头顶部较细，在背部变宽，使上体呈现明显的条纹外观。两眼后方有两条显著线条，下方为深色，上方为浅色，侧翼有明显的黄色簇毛。下体为淡黄色，喉咙处颜色更浅，腹部为黄色，全身有深橄榄色条纹，尤其在喉咙处最为明显。喙黑色，下颚及切割边缘灰色，腿蓝灰色。雌雄羽色相似，雄鸟体型略大。","call":"叫声为柔和的双音下滑哨声‘piuu piuu’。","habits":"绿纹嗜蜜鸟主要栖息于中高海拔的森林中，高度介于1300米至2800米之间。它们通常独居或成对活动，有时加入混合物种觅食群。食物以中等大小的节肢动物为主，包括昆虫，也会摄取开花树木的花蜜。在新几内亚雪山区，它们通常在次生树冠中觅食。","breeding":"关于繁殖的信息有限，仅知在12月观察到繁殖中的雌鸟。","identification":"绿纹嗜蜜鸟与灰条纹嗜蜜鸟和赤背嗜蜜鸟相似，但体型略小，底色为黄色而非灰色，侧翼无赤褐色。与铅色嗜蜜鸟相比，体型略大，色彩有所不同。","protection":"IUCN：LC（无危）；绿纹嗜蜜鸟虽不全球受威胁，但在Adelbert和Huon山脉以及中央巴布亚山脉中分布有限，总体被认为是稀少至罕见，但在某些地区如新几内亚雪山西坡局部常见。","distribution":"分布于新几内亚山区中西部至东南部，主要栖息地在亚热带或热带湿润山地森林，高度范围从约1300米至2800米。"},{"name":"红胁嗜蜜鸟","english_name":"Rufous-sided Honeyeater","scientific_name":"Ptiloprora erythropleura","overview":"红胁嗜蜜鸟（英文名：Rufous-sided Honeyeater，学名：Ptiloprora erythropleura），是雀形目吸蜜鸟科嗜蜜鸟属的鸟类，分布于印尼西巴布亚的鸟头半岛山区和新几内亚中西部。其自然栖息地为亚热带或热带湿润山地森林。","appearance":"体型中等，长约17厘米。头部和颈部铅灰色，额头、眼先和眼下方有细密的灰白色斑点或鳞片状花纹。背部至翅膀暗灰棕色，带有模糊的橄榄灰纹。臀部和上尾覆羽呈橄榄褐色。上翼覆羽边缘变色，从橄榄红到极淡的橄榄色。下体呈浅铅灰色，胸部和腹部中央有淡白色到灰色的羽毛边缘，两胁为栗棕色。虹膜红色，喙黑色，腿脚蓝灰色至灰蓝色或板岩灰色。雄鸟和雌鸟羽毛相似，雄鸟略大于雌鸟。幼鸟和亚成鸟的羽毛一般为橄榄色或奶油黄色至黄绿色，尤其在下体部分。","call":"鸣唱由哀怨的哨音“chwee”组成，每秒约2个音符。在库马瓦山脉和法克法克山脉，其鸣声由高音哀婉的滑音组成，间隔3-6秒重复（类似红背嗜蜜鸟、麦氏嗜蜜鸟和黑背嗜蜜鸟的鸣唱）。在库马瓦山脉，重复的部分通常包含2-3个不同音高的独立音符，第一个音符通常短促。","habits":"栖息于中高海拔山地森林及次生林，高度范围在1300-2800米之间。主要在植被的中上层觅食，偶尔进入下层；以采集和探查为主。活跃、大胆、快速移动且通常显眼；常见成双（可能为配偶）或小群（可能是家庭群体）出现。","breeding":"繁殖信息未知。","identification":"与黑背嗜蜜鸟相似，但红胁嗜蜜鸟体型较小，条纹不明显，眼睛颜色为红色而非灰色。","protection":"IUCN：LC（无危）。红胁嗜蜜鸟是限定分布物种，存在于西巴布亚高地和中巴布亚山脉的特定生态区。总体数量稀少，但在阿尔法克山脉的高海拔处较为常见；在库马瓦山脉则较罕见。","distribution":"分布于澳新界，具体包括鸟头半岛山区和Neck（新几内亚西北部）以及新几内亚中西部。","other":"系统学历史和分类细节未在本次描述中详述。"},{"name":"红背嗜蜜鸟","english_name":"Rufous-backed Honeyeater","scientific_name":"Ptiloprora guisei","overview":"红背嗜蜜鸟（英文名：Rufous-backed Honeyeater，学名：Ptiloprora guisei），是雀形目吸蜜鸟科嗜蜜鸟属的鸟类。广泛分布于新几内亚东部山区的热带湿润森林中。其显著特征为灰头和下体，背部及两胁呈模糊的赤褐色，全身饰以深色条纹，长而弯曲的喙，淡灰色的眼和一条从眼上方延伸的特征性浅灰条纹。","appearance":"红背嗜蜜鸟体长16至18厘米，雄鸟体重21至27克，雌鸟19至22克。头部顶端和颈后黑色，带有不规则的橄榄至橄榄灰色条纹，逐渐变为赤褐色斑驳。头部侧面黑褐色，伴有灰色条纹和洗染，尤其在眉线和眼周明显。上体黑至黑褐色，饰以赤褐色斑点，背部和肩羽尤其密集，其余部位则较稀疏。翼上覆羽边缘为淡橄榄至黄橄榄色，主羽外缘为淡橄榄至橄榄赤色。下体大部分为淡灰至灰白色，饰以粗犷而不规则的黑褐色条纹，胸部和腹部两侧及两胁呈赤褐黑色，饰以赤褐色条纹。腹下和尾下覆羽为赤褐色或黄色，仅有微弱条纹。下翼为灰白色，覆羽上饰以淡灰褐色条纹和褐色边缘。","call":"红背嗜蜜鸟的常见鸣声是一种先降后升的‘piuuwiiii！’声，高亢而悠扬。","habits":"红背嗜蜜鸟栖息于新几内亚东部的山地和上山地原始森林，偏好苔藓森林环境，海拔分布从约1340米至2900米，有时高达树线处约3500米。它们主要在林下层至树冠层活动，偏好灌木层和中间层，偶尔访问开花树木和灌木。以昆虫为主的节肢动物为食，也会食用果实、种子和花蜜。它们通过摘取、探查（如寄生植物和花朵）觅食，常倒挂觅食，表现活跃、显眼且好奇。","breeding":"有关繁殖的资料较少，已知雏鸟记录出现在2月初，幼鸟出现在5月初。巢位距地面1.25至2米高的小树上，一窝通常产一枚蛋，但关于孵化和育雏期的信息缺失。","identification":"与灰条纹嗜蜜鸟相似，但红背嗜蜜鸟通常在较低海拔出现，背部为赤褐色而非灰色。叫声也有所不同。","protection":"IUCN：LC（无危）","distribution":"红背嗜蜜鸟主要分布于新几内亚东部的山区，包括Adelbert山脉和休恩半岛，以及新几内亚东南部。","other":"红背嗜蜜鸟在适合的生境中普遍到丰富，特别是在Simbai谷和Mt Albert Edward等地，是东方高地苔藓森林中最丰富和具代表性的物种。"},{"name":"麦氏嗜蜜鸟","english_name":"Mayr's Honeyeater","scientific_name":"Ptiloprora mayri","appearance":"麦氏嗜蜜鸟体长约19.5厘米，雄鸟体重在30至37.5克之间，雌鸟稍轻，约24至29克。头部和颈部上方及上体为黑褐色至暗黑色，头顶部有不规则的灰白色条纹，颈后下方和侧面有淡红褐色斑点，上体其余部分有更弱的红褐色斑点。下体主要为灰白色，胸腹部有灰黑色条纹，侧腹和胁部带有红褐色。幼鸟下体有橄榄色或黄绿色的底色。acrophila亚种与指名亚种的区别在于额头和头顶的羽毛略深，颈部和颈后为暗橄榄色，上体边缘的红褐色更深，翼羽边缘为淡红橄榄色，下体的条纹更淡，更灰色，对比度较低。","call":"发出一种上升和下降的滑音‘piiwiiiuu！’，音调时高时低，间隔规律。同样的音符也可以是先降后升或单纯上升。","habits":"栖息于山地森林、苔藓森林和次生林，通常在1200至2150米的海拔范围内活动。生活方式被认为是定居的。食谱包括节肢动物（如昆虫）、花蜜和果实。觅食范围从林下层到树冠，包括开花树木的树冠；以啄食为主，也会探入花朵中。","breeding":"已知的繁殖信息有限，雌鸟准备在9月初产卵。具体繁殖细节尚不清楚。","identification":"麦氏嗜蜜鸟的辨识特征在于其独特的灰黑色体羽、长曲喙、红褐色斑点以及特定的鸣叫声。没有其他类似物种与其共享栖息地。","protection":"IUCN：LC（无危）；该物种在北巴布亚山脉生态区存在，虽然了解不多，但在其海拔限制范围内普遍被认为是丰富的。","distribution":"主要分布在新几内亚中北部沿海山区，具体在1200至2150米的山地森林中，acrophila亚种似乎局限于门瓦纳山（北海岸山脉最高峰）1280至1885米的范围内。","other":"在2008年至2023年期间，没有确认的目击记录，直到2023年的一次科学考察在新几内亚的Cyclops山脉拍摄到了一对麦氏嗜蜜鸟的影像。"},{"name":"黑背嗜蜜鸟","english_name":"Grey-streaked Honeyeater","scientific_name":"Ptiloprora perstriata","overview":"黑背嗜蜜鸟（英文名：Grey-streaked Honeyeater，学名：Ptiloprora perstriata），是雀形目吸蜜鸟科嗜蜜鸟属的鸟类。主要分布于新几内亚的山区，特别是在新几内亚高地的蒙特森林和亚高山灌木丛中，以灰黑色为主色调，带有明显的条纹，两胁呈赤褐色，喙长而弯曲，眼色为灰色。","appearance":"中等体型，身长19.5-20厘米，体重雄鸟23.5-30克，雌鸟21-25.5克。头部和颈部为黑褐色，头顶、颈后和颈侧有不规则的淡灰色条纹，上体几乎全黑，背部和肩羽有橄榄灰色到淡橄榄棕色的条纹。翼上覆羽和外缘具红褐色尖端，下体黑褐色至暗红褐色，布满浅灰色至近白色的条纹，两胁覆盖着强烈的红褐色洗染。幼鸟暗橄榄褐色，下体重重的棕条纹，缺乏明显的两胁赤色，喙软且苍白。","call":"发出一系列下降的、哀怨的哨音，单个下降的哨声“piiiiiiuuuuu”，有时会连续发出。还发出鼻音的“wek！”。","habits":"栖息于海拔约1300米至3750米的中高山原始森林，从开阔到密集的森林，包括苔藓森林，森林边缘，延伸至高山草甸的矮树和灌木丛，以及高山和亚高山的灌木丛。觅食从下层灌木，接近地面，直到冠层水平，常在边缘生境的灌木丛中活动。以昆虫、果实和花蜜为食，通过从树叶、树枝、根部采集昆虫和果实，偶尔捕捉飞虫。","breeding":"繁殖期记录在10月初、1月晚期，巢材包括苔藓、粗草、叶子和树枝，内衬植物纤维、羽毛和细毛，通常筑深而大的杯状巢，悬挂于树枝或树蕨叶片上，高度从2.5米至5.5米不等。每巢含一枚卵，孵化和育雏期未知。","identification":"与Rufous-backed和Rufous-sided Honeyeaters相似，但灰条纹吸蜜鸟体型更大，有灰色眼睛，上体无赤色。叫声包括一系列短暂的高音哨声。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的西至东南部山区，主要栖息在中高海拔的森林地带。","other":"在某些地区，与红背嗜蜜鸟存在几百米的海拔重叠，但通常生活在更高的海拔范围内。"},{"name":"东尖嘴吸蜜鸟","english_name":"Eastern Spinebill","scientific_name":"Acanthorhynchus tenuirostris","overview":"东尖嘴吸蜜鸟（英文名：Eastern Spinebill，学名：Acanthorhynchus tenuirostris），是雀形目吸蜜鸟科尖嘴吸蜜鸟属的鸟类。这种小型吸蜜鸟以独特的黑色、白色和栗色羽毛著称，拥有红眼和细长弯曲的喙。广泛分布于澳大利亚东部、东南部和塔斯马尼亚州的森林、林地及城市花园中。","appearance":"成年东尖嘴吸蜜鸟长约13至16厘米，雄鸟头部呈黑色，喉咙白色，胸部带有栗色斑块，背部灰褐色，腹部淡肉桂色，尾巴深色且侧缘有白色尖端。雌鸟体型较小，头冠橄榄灰色，色彩较雄鸟暗淡。幼鸟全身浅暖肉桂色，上半身灰至橄榄褐色，眼睛棕红色，下喙基部橙色。","call":"其叫声为清晰高亢的断续笛声“chip-chip-chip”，有时会连续重复长达数分钟。","habits":"东尖嘴吸蜜鸟活跃于干燥的硬叶林、灌木丛和山地，也能适应城市环境中的公园和花园。它们主要在低矮灌木和树冠层觅食，以花蜜和昆虫为食，偏好探入花朵或悬停取食。","breeding":"繁殖季节为8月至次年1月，通常筑深杯状巢于小灌木或树木分叉处，高度1至15米。每窝产卵1至4枚，平均2枚，孵化期13至16天，由雌鸟单独孵化，双亲共同喂养雏鸟。","identification":"与西部尖嘴吸蜜鸟相似，但可通过更长的喙和不同的分布区加以区分。雌鸟与雌性绯红摄蜜鸟可能混淆，但前者喙更长。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部、东南部，包括昆士兰州库克镇南部至南澳大利亚弗林德斯山脉东部，以及整个塔斯马尼亚岛。","other":"东尖嘴吸蜜鸟能够适应多种生境，包括受干扰的森林再生区，但过度伐木对其有一定负面影响。"},{"name":"西尖嘴吸蜜鸟","english_name":"Western Spinebill","scientific_name":"Acanthorhynchus superciliosus","overview":"西尖嘴吸蜜鸟（英文名：Western Spinebill，学名：Acanthorhynchus superciliosus），是雀形目吸蜜鸟科尖嘴吸蜜鸟属的鸟类。分布于澳大利亚西南部的湿森林、公园和花园中。具有独特的头部和喉部图案，以及细长弯曲的喙。体重约10克，长度介于12至16厘米之间。","appearance":"雄性西尖嘴吸蜜鸟上半身橄榄灰，下半身奶油色，面部有鲜明的黑色面罩，边缘有短而窄的白色眉纹和细白颊纹，以及白色下巴；胸部有宽阔的赤褐色颈环和喉部斑块，下方是狭窄的白色带和更宽的黑色带。雌鸟较小，颜色较暗淡，缺乏雄鸟的黑色面罩，全身以灰色调为主。幼鸟外观单调，呈淡褐色，上身略显棕色。","call":"鸣叫声音高亢、尖锐，通常被描述为重复的“kleat”声。","habits":"栖息于以班克斯亚属植物为主的环境，包括低矮开放的灌木丛、沙平原灌木丛、海岸灌木丛和山地灌木丛。也可见于班克斯亚或桉树主导的开阔林地，通常有灌木或灌木丛下层。有时在成熟的桉树林或以桉树或纸皮树（Melaleuca）为主的河流边森林或林地中。偶尔在城市花园中出现。主要以花蜜为食，同时也捕食小昆虫。","breeding":"繁殖季节主要在春季到夏季，筑巢由雌鸟负责，雄鸟偶尔参与，巢为小型圆形杯状，由草、树皮和其他植物材料制成，内部铺有羽毛和植物绒毛。每窝产卵1至2枚，孵化主要由雌鸟承担，孵化期未知。雏鸟由双亲共同喂养，离巢期大约15天以上。","identification":"雄鸟与雌鸟在羽毛颜色上有明显区别，雄鸟具有鲜明的黑色面罩和白色眉纹，而雌鸟颜色较为暗淡。与其他吸蜜鸟种类相比，西尖嘴吸蜜鸟拥有最长且最弯曲的喙。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西南部沿海和近沿海地区，从Eneabba南部至Pingelly和Fitzgerald河，向东延伸至Israelite Bay和Cape Arid国家公园。","other":"在干旱时期，西尖嘴吸蜜鸟可能会向北移动，有季节性数量变化的迹象。"},{"name":"白肩黑吸蜜鸟","english_name":"Pied Honeyeater","scientific_name":"Certhionyx variegatus","overview":"白肩黑吸蜜鸟（英文名：Pied Honeyeater，学名：Certhionyx variegatus），是雀形目吸蜜鸟科白肩黑吸蜜鸟属的鸟类。中等体型、具长而下弯喙的吸蜜鸟，分布于澳大利亚干旱与半干旱内陆地区，随蜜源植物开花而游荡，种群数量年际波动极大。雄鸟通体黑色，腹、翼斑及尾基白色，眼下具蓝色裸皮；雌鸟与幼鸟为褐色，翼部隐现白斑，胸具细斑。其体型明显大于黑吸蜜鸟。","appearance":"体长15–20厘米；雄鸟体重22–34克，雌鸟22–29克。雄鸟头、颈、上体及胸侧黑色，眼下方具淡蓝色弯月形裸皮；下背至尾上覆羽白色；折叠翼具由白色覆羽及次级飞羽缘构成的长锥形白纹；尾黑，除中央一对尾羽外基部皆白；胸中部至腹、尾下覆羽白色；飞时白色腰斑显眼，上翼呈黑底白肩斑；虹膜暗红褐，喙及跗跖蓝灰至灰黑。雌鸟头颈褐色，喉灰白，眼下方蓝斑较小；上体淡褐，具黑褐鳞斑；翼覆羽中央白斑与次级飞羽窄白条连成断续肩斑；胸污白，上胸具深褐泪滴斑，下腹白；裸部色泽似雄但较淡。幼鸟似雌鸟而更黯淡，头顶及上体淡褐，翼覆羽缘带黄褐或浅黄色，眼下皮肤黄色，喙褐，下颚基部及口裂黄色。","call":"鸣声为重复、凄婉而拖长的哨音，常见4–7个音节的“te-titee-tee-tee”或“titi-te-te”，求偶飞行或栖枝时发出，飞行时更尖锐，栖枝时更哀婉；抵达繁殖地后鸣唱频繁，繁殖开始后则多静默；雌鸟亦会于灌丛中对雄鸟的空鸣作出回应；另有单声弱哨音报道。","habits":"栖息于干旱及半干旱灌丛，尤以爱神木属（Eremophila）及银桦属（Grevillea）灌丛为主，偶见稀疏桉树上层；亦见于无脉相思（Acacia aneura）灌丛、三齿稃（Triodia）草丛或滨藜灌丛。活动于内陆平原、沙丘、山岭及岩地，西澳偶至海岸。游荡性极强，无明显迁徙规律，出现常与寄主植物开花或雨后相关；西南新南威尔士及西北维多利亚曾出现数十只大群。南澳弗罗姆湖地区为留居地。","breeding":"繁殖期多在澳洲冬末至春季（7–11月产卵），条件适宜时亦可在其他月份；雌雄共同取材筑巢，巢为浅杯状，外径7.6–14厘米，内径4.4–6厘米，以细枝、草、根茎、蛛丝构成，内衬细软植物、绒毛、花、羽毛，常悬于灌丛或小树0.6–4.6米处。每窝通常3卵，偶2或1卵，孵化由双亲承担，孵化期不超过14天；雏鸟由双亲饲喂，巢期约12–13天；遇威胁成鸟会进行迷惑表演。","identification":"体型远大于同域黑吸蜜鸟，后者上体全黑而无白肩斑；与同属其他种相比，本种雄鸟具独特的白色腹面及蓝裸皮，雌鸟及幼鸟亦可通过体型及翼上白斑区分。","protection":"IUCN: LC（无危）。全球未受威胁，局地为常见种；新南威尔士列为“易危”，视为生态专性种且种群规模小。目前无全球数量估计，记录密度0.19–0.72只/公顷；分布虽广，但对其时空利用及内部移动仍缺乏研究。","distribution":"繁殖区包括西澳大利亚（金伯利分区以南）、南澳、西南昆士兰、西新南威尔士，南至南澳大利亚海岸及西维多利亚；非繁殖期游荡至正常分布区边缘以外地区。","other":"本种为单型种，无亚种分化。"},{"name":"簇胸吸蜜鸟","english_name":"Tui","scientific_name":"Prosthemadera novaeseelandiae","overview":"簇胸吸蜜鸟（英文名：Tui，学名：Prosthemadera novaeseelandiae），是雀形目吸蜜鸟科簇胸吸蜜鸟属的鸟类。又名: 秃儿吸蜜鸟，是新西兰特有的吸蜜鸟科物种，以其独特的胸口白色羽球闻名，仿佛佩戴着领结的绅士。广泛分布于新西兰的北岛、南岛、斯图尔特岛、Kermadec群岛、查塔姆群岛及奥克兰群岛。偏好原生森林、灌木丛，亦常见于城市公园、农田与乡村花园。","appearance":"大型吸蜜鸟，体长27-32厘米，体重62-240克，雄鸟较大。全身呈光泽黑至黑褐色，头部、颈部、上身和胸部有强烈的金属光泽，颜色随光线变化，可见蓝、绿或金黄。喉侧具一对白色球状羽团，通常看似单一羽球。翼下有白色斑块，下腹部、大腿和肛区为黑褐色，两胁暗灰，尾下覆羽金属绿色至蓝色，尾部黑色，翼下黑色带轻微金属光泽。雄雌羽色相似，但雄鸟体型更大。幼鸟较暗淡，喉部灰色，可能有淡色斑点，头部至背部有细浅条纹。","call":"发出复杂多变的鸣声，包含清澈的颤音、钟鸣般的'bong'声、清脆的铃声、啼叫、咕噜声、口哨、咳嗽和喘息声。也会发出轻柔的耳语声，夹杂正常鸣叫。叫声包括尖锐的哀鸣、高音的'ke-e-e-e'、刺耳的尖叫以及粗犷的嘎嘎声。雄鸟在求偶展示时会发出高音调的叫声。","habits":"栖息于混合型森林，包括豆杉-阔叶、豆杉-山毛榉森林，以及海岸灌木丛和茶树灌木丛。常出现在城市公园与花园，特别是在北岛北部，偶尔见于果园。觅食以花蜜为主，辅以昆虫和季节性水果，偶尔吃种子和花粉。在花期丰富的地区聚集，如多达200只的小群在卡皮蒂岛上。","breeding":"繁殖期春季至夏季，受开花植物影响。巢由树枝、树叶、植物茎、草根等材料构成，内衬细枝、草、根须、蕨类、苔藓，有时掺杂羽毛。巢置于树叉、小树顶端或大树冠层。每窝产2-4枚蛋，孵化期12-15天，雌鸟负责孵化。雏鸟孵化后由双亲喂养，平均14-15天离巢，之后数周仍受双亲照料。","identification":"与欧乌鸫容易区分，因后者无白喉羽球和金属光泽。其鸣声虽与铃鸟相似，但簇胸吸蜜鸟的歌中包含明显的咳嗽、呻吟和喘息声。种族chathamensis与指名种的区别在于体型稍大、重量更重，且具有略蓝的金属光泽。","protection":"IUCN：LC（无危）。簇胸吸蜜鸟在新西兰广泛分布，但在19世纪经历数量下降，主要因低地森林砍伐和农业发展导致。已适应在异域花蜜植物中觅食，面临猫、鼬等外来掠食者的威胁。","distribution":"分布于新西兰的北岛、南岛、斯图尔特岛北部与南部、Kermadec群岛、查塔姆群岛及奥克兰群岛。在查塔姆群岛较为常见。","other":"曾因狩猎和非法出口羽毛而受到威胁，现已采取措施在查塔姆岛重新建立种群，2009-2010年转移了54只幼鸟，存活率较高。"},{"name":"新西兰吸蜜鸟","english_name":"New Zealand Bellbird","scientific_name":"Anthornis melanura","overview":"新西兰吸蜜鸟（英文名：New Zealand Bellbird，学名：Anthornis melanura），是雀形目吸蜜鸟科新西兰吸蜜鸟属的鸟类。新西兰特有的中型吸蜜鸟类。其主要特征为黄绿色的羽毛，黑色翅膀和尾巴，红眼，雄鸟头部带有紫色光泽，雌鸟头部光泽较弱，呈蓝绿色。广泛分布于新西兰北岛和南岛，包括许多离岸岛屿，如小屏障岛和蒂里蒂里马塔基岛。在斯图尔特岛北部、南部和奥克兰群岛的卫星岛上也有发现。","appearance":"新西兰吸蜜鸟体长17至20厘米，雄鸟体重约31克，雌鸟约24克。雄鸟的指名亚种全身橄榄绿，头颈有紫色金属光泽，黑色眼周区，上尾羽黑色带窄边蓝黑色光泽，翼上覆羽深橄榄绿，飞羽黑色带蓝色光泽。雌鸟较小，上体暗橄榄褐色，下体稍淡，头部和颈部有微弱的蓝绿色光泽。幼鸟颜色更灰暗，上部暗灰，下部灰色，头颈腹部有橄榄色，眼圈黑色，嘴角黄色持续至少14天。","call":"其叫声为一系列清脆悦耳的音符组成，如同远处的钟声，尤其在黎明时分，能听到2至6个纯净的铃铛般的音符，偶尔穿插安静的音符，反复单调地持续10至40分钟。雄鸟歌声更丰满响亮，包含‘chonk’、‘clonk’和刺耳的‘jarr’声。","habits":"偏好密集的本土森林，包括低地混合豆杉-硬木林和沿海阔叶林，也出现在混合山毛榉林、沼松、黄银松和山毛榉林中。在南岛，主要栖息在以罗汉松为主的沿海森林，封闭的树冠层，丰富的附生植物和茂密的灌木层。在城市区域如公园、花园、高尔夫球场、农田和果园中也很常见。","breeding":"繁殖期主要在9月至1月，有时会产第二窝或失败后重产。雌鸟负责筑巢，巢由枝条、树叶、根须、草和苔藓构成，内部用细草、苔藓和树蕨鳞片铺垫，直径约15厘米，通常建在地面附近或高达16米的树上。每窝通常产3枚蛋，孵化期13至15.5天，由雌鸟负责，雄鸟提供食物。雏鸟孵化后由双亲共同喂养，离巢期约为14至19天。离巢后至少7天，有时数周，双亲继续喂养。","identification":"与欧金翅雀的区别在于后者具有淡色锥形喙和体型较小，同时新西兰吸蜜鸟的歌声缺乏嘟哝、喘息和咔哒声，这有助于与簇胸吸蜜鸟区分开来。","protection":"IUCN：LC（无危）。在新西兰广泛分布，包括多个离岸岛屿，但在北岛最北端和南岛内陆凯库拉山脉以西地区较少见。在一些岛屿上的密度很高，例如三王岛和贫骑士岛。19世纪后期在北岛北部和一些邻近大岛数量急剧下降，可能因疾病或鼠类扩散导致。主要威胁是本土森林的砍伐和农场残留植被的清除，以及普通刷尾负鼠对本土森林的破坏。","distribution":"广泛分布于新西兰的北岛和南岛，包括许多离岸岛屿，如小屏障岛、蒂里蒂里马塔基岛、亨和鸡群岛、斯图尔特岛附近的鲁阿普库岛、羊肉鸟岛、鳕鱼岛、索兰德岛和小索兰德岛。在斯图尔特岛北部、南部和奥克兰群岛的卫星岛上也有分布。","other":"曾被毛利人猎杀。在19世纪后期北岛北部和一些邻近大岛数量下降，可能因疾病或鼠类扩散导致。"},{"name":"查塔姆吸蜜鸟","english_name":"Chatham Bellbird","scientific_name":"Anthornis melanocephala","overview":"查塔姆吸蜜鸟（英文名：Chatham Islands Bellbird，学名：Anthornis melanocephala），是雀形目吸蜜鸟科新西兰吸蜜鸟属的已灭绝鸟类。曾是查塔姆群岛特有种。","appearance":"外观上，查塔姆吸蜜鸟与新西兰吸蜜鸟极为相似，但体型更为庞大。其头部和颈部覆盖着亮丽的紫蓝色光泽羽毛。","call":"它的鸣声被誉为所有南极洲鸟类中最悦耳的歌声。","habits":"查塔姆吸蜜鸟的栖息地局限于查塔姆群岛，包括查塔姆岛、皮特岛、曼格雷岛及小曼格雷岛。","breeding":"繁殖期从8月至10月，通常在比大陆吸蜜鸟更大的巢中产三枚卵。","identification":"与新西兰吸蜜鸟相比，查塔姆吸蜜鸟在体型和头部颜色上有明显差异。","protection":"IUCN：EX（已灭绝）","distribution":"查塔姆吸蜜鸟的分布仅限于查塔姆群岛（新西兰东部）。","other":"猫被认为是导致查塔姆吸蜜鸟灭绝的主要原因，尤其是在1831年猫到达朗加蒂拉岛之后，随后在曼格雷岛上。最后一次观察到该鸟是在1906年的小曼格雷岛上。"},{"name":"绿褐吸蜜鸟","english_name":"Plain Honeyeater","scientific_name":"Pycnopygius ixoides","overview":"绿褐吸蜜鸟（英文名：Plain Honeyeater，学名：Pycnopygius ixoides），是雀形目吸蜜鸟科鹎吸蜜鸟属的鸟类。广泛分布于新几内亚的森林及其边缘地带，从低地至中高山脉均有其踪迹。以几乎缺乏显著的野外识别特征而闻名，最佳的识别特征是其小头小喙的外观，整体呈现灰褐色，仅在新几内亚东南部的个体更偏赤褐色。","appearance":"绿褐吸蜜鸟体长约18厘米，雄鸟体重28-33克，雌鸟22-31克。其头部相对较小，喙为中等大小且略微向下弯曲。头部顶部和颈部为暗橄榄灰色，额头和前冠部有细小的黑色斑点，后颈处的斑点更加明显。上体为橄榄棕色，翅膀和尾巴的上部为深橄榄棕色，翼羽边缘呈明亮的橄榄色。下体为灰色，胸部上方有淡淡的暗色条纹。虹膜颜色从浅棕色到红棕色不等，喙为黑色或灰黑色，腿为淡灰色。雄鸟和雌鸟的羽毛相似，但雄鸟体型更大。幼鸟的描述尚未详细记载，但似乎与成鸟相似，难以在野外区分。","call":"绿褐吸蜜鸟的叫声为柔和的‘wi-wi-wi’，间隔重复出现。","habits":"绿褐吸蜜鸟主要栖息于森林环境，包括山地森林、森林边缘和高大的次生林。在Crater Mountain野生动物管理区，主要见于老的次生林，以及在Brown R地区常出现在路边植被中。海拔高度从海平面至约1200米，局部地区可达1400米。它们的饮食包括小型果实（如Pipturus）、花蜜，可能还有小型节肢动物。它们主要在植被的下层至中层活动，偶尔会下降至林下层，但也会上升至树冠层觅食。通常单独或成对出现，偶尔会形成小群，例如在开花的Sago树上，最多可达十二只，有时会在同一朵花上发现四只鸟。它们有时也会与其他物种混群。","breeding":"关于绿褐吸蜜鸟的繁殖信息尚无具体记录。","identification":"绿褐吸蜜鸟与棕鵙鹟相比，具有较薄的喙；与茶胸吸蜜鸟的区别在于面部图案；而与灰喉直嘴吸蜜鸟相比，后者有粉红色的腿和直而尖的喙。此外，不同亚种之间在颜色上有细微差别，例如proximus亚种的上体颜色更深，unicus亚种的头部和颈部的灰色具有更明显的橄榄色调。","protection":"IUCN：LC（无危）","distribution":"绿褐吸蜜鸟主要分布在新几内亚（除Trans-Fly地区）的森林地带，包括低地至中高山脉的森林及其边缘。","other":"尽管绿褐吸蜜鸟一般较为稀少，但在某些地区，如Baiyer River Sanctuary和Maprik地区，以及东Sepik地区的低地森林中，它们的数量被认为是丰富的。"},{"name":"苍额吸蜜鸟","english_name":"Marbled Honeyeater","scientific_name":"Pycnopygius cinereus","overview":"苍额吸蜜鸟（英文名：Marbled Honeyeater，学名：Pycnopygius cinereus），是雀形目吸蜜鸟科鹎吸蜜鸟属的中等体型的吸蜜鸟，主要分布在新几内亚的山区，常见于中海拔的山林地带。","appearance":"该鸟上体橄榄色，下体灰色，头部顶部黑褐色，前额和前冠部有细腻的灰纹，颈背处的纹路更宽更明显。侧面头颈为暗褐至黑褐色，眼周有淡蓝灰色的眼圈，脸颊下方有灰白的半月形斑。翼和尾上覆羽呈深棕色，初级飞羽边缘略带橄榄色，次级飞羽形成明显的淡色翼斑。下体颜色较暗，胸腹部为灰褐色，腹区有更深的斑点。喙黑色，腿脚浅蓝灰色，虹膜棕色。性别间羽毛相似，但雄鸟比雌鸟稍大。","call":"发出重复的下滑音“tyert”，间隔约2秒，偶尔会发出类似‘chirrup’的口哨声或更悦耳的‘chii-pi-dup’声。","habits":"主要栖息于中低山林，包括森林边缘和次生植被，也见于花园。海拔高度主要在1000-2000米之间，有时低至500米。通常独居，沉默且行动缓慢。以花蜜、小果子、昆虫和花的部分为食。","breeding":"繁殖信息知之甚少，已知的繁殖记录发生在3月和11月，具体繁殖行为尚不清楚。","identification":"独特的白色半月形斑位于眼下方和脸颊上，这是与其他吸蜜鸟区分的关键特征。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚的山区，包括新几内亚高地的亚热带或热带湿润低地森林和亚热带或热带湿润山地森林。","other":"全球数量未知，但在部分地区被认为是局部常见的物种。"},{"name":"纹头吸蜜鸟","english_name":"Streak-headed Honeyeater","scientific_name":"Pycnopygius stictocephalus","overview":"纹头吸蜜鸟（英文名：Streak-headed Honeyeater，学名：Pycnopygius stictocephalus），是雀形目吸蜜鸟科鹎吸蜜鸟属的鸟类。头部呈暗褐色，头顶有细白条纹，脸部有一条显著的白色条纹，与新几内亚吮蜜鸟相似但体型更小。常见于低地和山麓森林边缘及花园，分布于印尼萨拉瓦蒂岛、阿鲁群岛以及新几内亚。","appearance":"纹头吸蜜鸟是一种中等体型、略显暗淡的吸蜜鸟，上身深棕色，下身灰棕色。头部顶部黑色带细微的灰白色斑点，侧面和颈部深棕色，具明显的浅色颊纹。两性羽毛相似，雄鸟比雌鸟大。幼鸟腹部颜色较淡，呈淡黄色，胸部有灰色调，尾羽边缘和尖端呈淡棕色至淡赤褐色。","call":"其叫声多样，包括一系列重复音符或强烈、哨声式的短语。","habits":"纹头吸蜜鸟偏好森林边缘和受干扰的开放环境，如次生林、部分砍伐的森林、画廊植被、桉树林、沼泽森林、季风林或灌木丛，以及花园。常见于海拔0-500米，局部可达750米。","breeding":"繁殖信息有限，已知在9月初和3月9日有活跃的筑巢记录，巢为精细编织的杯状或篮状，由细枝构成，悬挂在树叶中的细叉上，深度和位置各异。","identification":"与新几内亚吮蜜鸟和幼年褐鹂相似，但体型较小，喉部和胸部无条纹。叫声模仿褐鹂的歌曲短语。","protection":"IUCN：LC（无危）","distribution":"分布于印尼的萨拉瓦蒂岛（四王群岛西北部，新几内亚）、阿鲁群岛（新几内亚西南部）和新几内亚全境。"},{"name":"带胸黑吸蜜鸟","english_name":"Banded Honeyeater","scientific_name":"Cissomela pectoralis","overview":"带胸黑吸蜜鸟（英文名：Banded Honeyeater，学名：Cissomela pectoralis），是雀形目吸蜜鸟科带胸黑吸蜜鸟属的鸟类。以其独特的黑色胸带而著称。这种小型黑白相间的吸蜜鸟分布于澳大利亚热带北部的干燥林地，其黑色上身与白色下身形成鲜明对比。","appearance":"成年带胸黑吸蜜鸟的背部、尾巴和头部呈黑色，下体白色，最显著的特征是其胸部的黑色条带。非繁殖季节的成鸟背部转为棕色。幼鸟具有黄色脸颊和棕色上体，而雏鸟则更为淡棕色，胸带模糊不清。体长约11.5至13.5厘米，体重在8至13克之间。","habits":"带胸黑吸蜜鸟栖息于热带草原林地、开阔森林、红树林及Melaleuca沼泽地带。它们以桉树和其他开放花朵如Grevilleas、Paperbarks和Bauhinias的花蜜为食，同时也会捕食昆虫。通常成对或小群活动，但在花期丰盛时会聚集大群。","identification":"其独特的黑色胸带是与其他吸蜜鸟区别的关键特征。在行为上，它们的迁徙模式随季节变化，特别是在花期丰富的地区。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东北部，从西澳大利亚北部直至约克角半岛，向东北延伸至昆士兰州中部北部。"},{"name":"绿岩吸蜜鸟","english_name":"Olive Honeyeater","scientific_name":"Lichmera argentauris","overview":"绿岩吸蜜鸟（英文名：Olive Honeyeater，学名：Lichmera argentauris），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。广泛分布在印尼的摩鹿加群岛和西新几内亚沿海地带。这体型类似麻雀的小型鸣禽，以其独特的橄榄绿色外观和淡灰色腹部著称。","appearance":"绿岩吸蜜鸟拥有橄榄绿色的背部和淡灰黄色的腹部，两者的过渡清晰，尤其是在后腹侧部更为明显。头部特征包括脸颊上的显著白色斑点和眼下方的裸露皮肤，颜色从黄褐色到粉红褐色。虹膜呈灰棕色，喙黑色，下颌基部黄褐色，腿部呈现蓝灰色调。性别在羽毛上无明显差异，雄鸟可能体型稍大。幼鸟特征尚未详细描述。","call":"发出尖锐刺耳的‘zhip’声，以及嘈杂的鸣唱，由一系列每秒多达10个硬质‘chep’音符组成，通常以一个类似的响亮音符开始，之后是一段短暂的停顿，然后是连续的叽喳声。","habits":"绿岩吸蜜鸟栖息于海岸线的树木、棕榈树和灌木丛中，包括海滨的木麻黄和椰子树丛。它们主要为留鸟，但在卢萨奥莱特岛只有零星记录，可能不是常驻种类。食物包括花蜜和果实，它们在木麻黄树、椰子树的花朵和番木瓜树上觅食，也曾在小群体中被观察到。","breeding":"关于繁殖行为的信息目前缺失。","identification":"通过头部的白色颊斑和眼下的裸露皮肤可以轻易辨认出绿岩吸蜜鸟，这些特征使其在同类中脱颖而出。","protection":"IUCN：LC（无全球性威胁）。在塞拉姆EBA、北马鲁古EBA和西巴布亚低地EBA中为限制分布物种。在华莱士区一般被视为稀有且局部分布的物种。","distribution":"绿岩吸蜜鸟主要分布在摩鹿加群岛的哈马黑拉岛、达马尔岛、西巴布亚群岛（包括瓦伊盖奥、斯奇尔帕德和米索尔岛）以及塞拉姆北部的卢萨奥莱特岛。","other":"绿岩吸蜜鸟被认为是一种‘超级流浪者’物种，仅限于物种贫乏、小而偏远的岛屿。"},{"name":"印尼岩吸蜜鸟","english_name":"Indonesian Honeyeater","scientific_name":"Lichmera limbata","appearance":"体长约14厘米。雄鸟上体暗灰至橄榄灰色，头顶稍深，眼周有暗灰色裸皮环，眼后有小而常不明显的淡黄色至棕黄色三角状簇毛；飞羽和尾羽有明显的淡黄橄榄色边缘；喉部和上胸部灰褐色，向下渐变为近白色或棕白色；尾下覆羽灰棕色或橄榄棕色，翼下覆羽灰白色带灰褐色边缘；虹膜深棕色；喙和口腔黑色；腿灰色。雌鸟似雄鸟但体型较小，喉部和脸颊呈黄橄榄色至污黄色，其余下体略带黄色调，头部颜色与上体一致；裸露部位可能有所不同，如淡黄色的口腔和下颌基部。幼鸟描述不详，但似雌鸟，上体和下体颜色略显棕色，脸部有黄色斑纹，眼后簇毛不明显或缺失，裸露部位可能有差异，如淡色的喙基部和肿胀的黄色口腔。","call":"发出一系列中等响亮的断续音符、哨声和尖锐的喋喋不休声；报警叫声被描述为尖锐刺耳。鸣唱甜美有力，有时连续数秒，最长一次约75秒。","habits":"栖息于季风林、红树林、次生植被、开阔林地、灌木丛、河流旁的藤本灌木丛，以及半栽培区、椰子园、种植园、城镇和村庄中的公园和花园。在Lembata岛上，记录到在沼泽森林、高至25米的多样植物封闭森林和沿海复合植被中活动，海拔从海平面至约100米。在龙目岛和松巴哇岛，主要出现在较高海拔(海平面至2600米，主要在800-1200米)，但在松巴岛上主要为海岸地带(至950米，主要低于400米)。季节性游荡于本地范围内，追踪开花的食物植物。活跃、嘈杂且好斗，常单独、成双或小群活动。","breeding":"在Roti岛中旬发现巢中幼鸟，其余繁殖信息未知。","identification":"与和银耳岩吸蜜鸟形成超物种，通常被认为与前者同种。雌雄两性外观相似，但雌鸟体型较小，喉部和脸颊颜色不同，眼后簇毛不明显或缺失。幼鸟与雌鸟相似，但颜色略显棕色，眼后簇毛不明显或缺失。","protection":"IUCN：LC（无危）；在龙目岛、松巴哇岛、桑加安岛、松巴岛和帝汶岛局部常见至中等常见；在Atauro岛上数量丰富；在巴厘岛不常见至非常常见或局部丰富。在其他地区一般少见。","distribution":"分布于巴厘岛，以及印尼小巽他群岛的龙目岛、松巴哇岛、桑加安岛、科莫多岛、弗洛雷斯岛、Lembata岛、阿洛尔岛、松巴岛、萨武岛、罗蒂岛、Ndao岛、Ndoo岛、Semau岛和帝汶岛(包括Atauro岛)。","other":"印尼岩吸蜜鸟与和银耳岩吸蜜鸟形成超物种，过去曾被认为是独立物种，但现在主要分类权威将其视为褐岩吸蜜鸟的亚种。"},{"name":"褐岩吸蜜鸟","english_name":"Brown Honeyeater","scientific_name":"Lichmera indistincta","overview":"褐岩吸蜜鸟（英文名：Brown Honeyeater，学名：Lichmera indistincta），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。广泛分布于澳大利亚西部、北部、中部和东部，新几内亚中南部，印尼阿鲁群岛，小巽他群岛，以及巴厘岛，是唯一跨过华莱士线进入亚洲地区的吸蜜鸟。中等体型的灰褐色吸蜜鸟，具有黄色橄榄色的翼和尾部斑块，眼后有一黄色小绒毛，分布广泛，适应性强。","appearance":"褐岩吸蜜鸟体长12至16厘米，体重9至11克，雌雄差异不大。头部、背部、臀部及上尾覆羽呈棕色，翅膀较暗。特征包括眼后的小黄色斑块，翼和尾折叠时显现出淡黄橄榄色。雄鸟额头和冠部为暗褐色，雌鸟和雄鸟相似，但额头和顶冠与上体颜色一致。幼鸟似雌鸟，黄色眼后斑可能缺失。喙黑色，适于探花，雄鸟繁殖季时口裂黑色，其余时间淡黄色，幼鸟口裂肿胀且亮黄色。","call":"拥有响亮、清脆、音乐般的鸣声，被赞誉为澳大利亚吸蜜鸟中最佳歌手，鸣唱‘sweet-sweet-quarty-quarty’，音量对于其体型而言非常响亮。清晨时分鸣叫频繁，报警时发出急促的‘ke-ke’声。","habits":"生活在各种林地环境，包括红树林、桉树森林、公园花园等，随开花植物季节性迁徙。主要以花蜜为食，辅以昆虫，活跃于树冠层，有时至地面觅食。早晨活动最为频繁，此时花蜜最丰。身体质量日间波动，早晨摄食能量最高，冬季需精挑食物平衡能量。","breeding":"繁殖期变化大，一年中几乎每个月都有记录，筑杯状巢于密林或枝叉，由雌鸟为主建造，雄鸟协助。巢材包括草、软树皮、蜘蛛网等，内衬植物绒毛。每窝产卵2至3枚，雌鸟独自孵卵，双亲共同喂养幼鸟，孵化期13至14天，幼鸟离巢期约13至17天。","identification":"与Dusky Honeyeater（灰岩吸蜜鸟）幼鸟易混淆，但后者更暗，无翼部黄色斑块。各亚种间差异细微，主要体现在色彩深浅和嘴尾长度上。","protection":"IUCN：LC（无危）","distribution":"分布于巴厘岛、小巽他群岛、印尼阿鲁群岛、新几内亚中南部，以及澳大利亚西部、北部、中部和东部地区。在澳大利亚，常见于公园、花园和农场周边，城市化导致的死亡因素增加。","other":"尽管部分地区数量下降，如西澳大利亚小麦带，但总体上褐岩吸蜜鸟种群稳定，分布广泛。"},{"name":"银耳岩吸蜜鸟","english_name":"Grey-eared Honeyeater","scientific_name":"Lichmera incana","overview":"银耳岩吸蜜鸟（英文名：Grey-eared Honeyeater，学名：Lichmera incana），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类，分布于西南太平洋的瓦努阿图和新喀里多尼亚。有时被误称为白耳岩吸蜜鸟，但这一名称亦用于新几内亚的白耳岩吸蜜鸟。","appearance":"体长13至17厘米，雄鸟较雌鸟大。上身呈暗绿棕色，下身灰而带橄榄色。脸颊为银灰色，头顶深灰色。黑色喙细长且略向下弯曲，腿脚蓝灰色。幼鸟比成鸟颜色更淡，缺乏银色颊部。","call":"它们是喧闹的鸟类，黎明前便开始鸣叫。发出尖锐的‘tchoo-tchoo-tchoo’叫声和婉转的鸣唱。","habits":"在低地和低山丘的多种生境中常见，包括森林、灌木丛、红树林和花园。它们在花间穿梭，从树冠层到灌木层寻找花蜜和花粉。它们还捕食昆虫和蜘蛛，有时悬停在花朵前或蛛网旁寻找食物。","breeding":"繁殖季通常从十月持续至二月。巢主要由草和植物纤维构成，以蛛丝加固，筑于树或灌木的枝叉处。每窝产两枚蛋，白色带少许红斑，孵化期约14天。幼鸟以昆虫和蜘蛛喂养，12天后离巢。","identification":"与其他吸蜜鸟种类明显不同，尤其以其银灰色耳羽区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，具体为瓦努阿图中部、南部和新喀里多尼亚，包括新喀里多尼亚忠诚群岛。","other":"存在五个亚种，其中指名亚种 L. i. incana 在新喀里多尼亚主岛Grande Terre发现；L. i. poliotis和L. i. mareensis在新喀里多尼亚东北部的忠诚群岛；L. i. flavotincta和L. i. griseoviridis在瓦努阿图。"},{"name":"白耳岩吸蜜鸟","english_name":"Silver-eared Honeyeater","scientific_name":"Lichmera alboauricularis","overview":"白耳岩吸蜜鸟（英文名：Silver-eared Honeyeater，学名：Lichmera alboauricularis），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。拥有一个向下弯曲的喙，显眼的白色耳斑，上体呈单调的棕色，下体淡色并带有明显的暗色斑点。该鸟种广泛分布于新几内亚中北部和东南部的沿海地带。","appearance":"成年白耳岩吸蜜鸟长约15厘米，雄鸟体重在13.5至19克之间，雌鸟略轻，介于12.5至14.5克。上体颜色为暗褐色，翼和尾部更显橄榄棕，翅上的羽缘带有微弱的黄褐色尖端，翼折处有淡淡的绿色晕染。头部下方至耳后有一道由稀疏白色羽毛构成的暗色弯月形纹，后方接壤一块大的浅色斑。耳覆羽上方银白色，下方灰白，喉部灰褐间杂白色，胸部和腹部偏白色，带黄色调，胸腹部分布有棕色条纹或斑点。两性羽色相似，雄鸟体型较雌鸟大。幼鸟特征未详述。","call":"白耳岩吸蜜鸟的叫声包括刺耳的喋喋不休声和鼻音的‘weet-weet-weet’声，以及尖锐的‘jit’音节。","habits":"白耳岩吸蜜鸟通常栖息在靠近水源的开阔沿海区域，偏好高大的甘蔗草（Saccharum）和其他草类，常见于湿地边缘或其中，亦见于椰子林、红树林和椰子种植园。它们在低地活动，接近海岸线，可能大部分时间是居民鸟。以花蜜和昆虫为食，活跃于茂密植被中，单个或成对或小群体觅食，善于在密集的植被中快速移动，有时难以观察。","breeding":"繁殖记录显示，繁殖活动可能在旱季晚期（9月至10月）达到高峰，而雨季早期繁殖较少。筑巢由双方共同完成，平均耗时7至10天，巢为杯状，主要由枯叶、植物纤维（如椰子树）、细小的树皮碎片和干草组成，加固以蜘蛛网，内部铺垫植物绒毛。巢通常悬挂在树枝末端，高度平均1.7米，位于灌木丛或树木中，包括椰子树。每窝产2枚蛋，孵化期约14天，雏鸟由双亲喂养，离巢期约为12天。","identification":"其独特的白色耳斑、棕色上体和平淡的下体，尤其是胸部的条纹，使其与新几内亚其他吸蜜鸟种类区分开来。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的中北部和东南部，包括沿海地带和内陆湿地附近的生境。","other":"在一些城镇或家庭花园的树木和灌木丛中局部常见。"},{"name":"白簇岩吸蜜鸟","english_name":"Scaly-breasted Honeyeater","scientific_name":"Lichmera squamata","overview":"白簇岩吸蜜鸟（英文名：Scaly-breasted Honeyeater，学名：Lichmera squamata），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。体型与麻雀相近，橄榄灰褐色的外表，胸前带有暗色斑点，脸颊上有一小块白色斑纹。分布于印尼的小巽他群岛东部和南部摩鹿加群岛，包括Wetar、Leti、Babar、Tayandu、Kai和塔宁巴尔群岛。在Yamdena和Damar岛上相当常见。","appearance":"成鸟的上半身呈橄榄灰色，臀部和尾羽覆羽颜色较淡，偏向黄橄榄色。脸部图案显著，黑色裸露皮肤覆盖眼周，细小而坚硬的白色羽毛点缀其间，形成独特的三角或新月形白色斑块。下巴和喉咙为偏白或微黄色，腹部颜色变异较大，从接近白色到淡黄橄榄色，胸部带有黑橄榄色的‘花边’，逐渐变淡至腹部的亮黄色。虹膜颜色从浅灰黄至深棕色不等，喙和腿为黑色。雌雄羽毛相似，雄鸟体型略大。","call":"鸣叫声包括下滑的哨音‘chirrup’、‘chisip’或上升的‘chirrup’，以及响亮下降的颤音‘teu, tututututututututututu-tu-tu’，还有快速重复的尖锐哨声‘tsi-tsi-tsi-tsi...’或‘tchi-tchi-tchi-tchi...’。","habits":"栖息于沿海和低地的次生季风林、开阔灌木丛、轻度森林边缘、椰子种植园和村庄地带。以花蜜和昆虫为食，常在花间觅食，包括椰子树和其他不显眼的树冠层花卉。单个、成双（可能是配偶）或小群体活动，有时加入混种群。","breeding":"巢穴装饰精致，外部挂有蜘蛛网、羊毛或棉絮，入口侧向，有时顶部部分封闭，尾巴从下方垂下。每窝产卵2枚，更多繁殖信息未知。","identification":"与印尼岩吸蜜鸟相比，白簇岩吸蜜鸟胸前有斑点，脸部有白色标记。幼鸟下体橄榄灰色，仅隐约可见斑点。","protection":"IUCN：LC（无危）。在Yamdena和Damar岛常见，但在Terbang Utara和Terbang Selatan两个小岛上罕见。","distribution":"主要分布于印尼的小巽他群岛东部和南部摩鹿加群岛，具体包括Wetar、Leti、Babar、Tayandu、Kai和塔宁巴尔群岛。","other":"白簇岩吸蜜鸟是当地较为常见的鸟类之一，但在某些岛屿上的分布状况较为特殊。"},{"name":"布鲁岩吸蜜鸟","english_name":"Buru Honeyeater","scientific_name":"Lichmera deningeri","overview":"布鲁岩吸蜜鸟（英文名：Buru Honeyeater，学名：Lichmera deningeri），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。主要分布在印尼摩鹿加群岛中西部的布鲁岛山区。这种鸟具有橄榄褐色的羽毛，以黄色的喙基部和眼周的黄色细线为显著特征。","appearance":"布鲁岩吸蜜鸟体型中等，长约15至16厘米，雄鸟体重约18至19克，雌鸟略小，重14至16克。其上身呈淡黄橄榄色，尾羽上方和飞羽边缘颜色稍亮；上眼睑、下眼睑、颊部和喉部为淡灰色；胸部至腹部的颜色由灰黄橄榄色渐变为淡黄橄榄色；下尾覆羽为棕色灰色；虹膜深色；喙黑色，基部和嘴角处呈黄色；腿为铅灰色。雌雄羽毛相似，雌鸟体型较小，色泽似乎略淡。","call":"其鸣唱单调而富有节奏感，发出连续的‘chew-chew-chew…’声，音符间有音高变化。","habits":"栖息于原生雨林、被选择性砍伐和受干扰的森林、高大的次生林及灌木丛，海拔高度从低地到2060米，主要在1500米以上。它们可能保持定居状态，但会进行局部移动。观察到它们单独或成对活动，偶尔与摩鹿加摄蜜鸟（未翻译）一同在同棵树上觅食，已知它们会在杜鹃花和其他植物的花朵上觅食。","breeding":"有关繁殖的信息有限，有记录显示在11月至次年早期12月期间，有一只最近离巢的幼鸟。除此之外，没有更多信息。","identification":"比摩鹿加摄蜜鸟雌鸟体型更大，喙更粗壮，可通过明显的浅色喙基部和黄色面部细线加以区分。","protection":"IUCN：LC（无危）；该物种虽不面临全球性威胁，但在Buru EBA区域有分布，数量一般较为罕见。","distribution":"分布于印尼摩鹿加群岛中西部的布鲁岛山区，主要在海拔1500米以上的地区。"},{"name":"塞兰岩吸蜜鸟","english_name":"Seram Honeyeater","scientific_name":"Lichmera monticola","overview":"塞兰岩吸蜜鸟（英文名：Seram Honeyeater，学名：Lichmera monticola），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。麻雀般大小，以橄榄灰色的上部羽毛和头部暗淡的橄榄色条纹为显著特征，常在印尼摩鹿加群岛中的塞兰岛高山森林及高海拔的山地灌木丛中活动。","appearance":"塞兰岩吸蜜鸟的长度约14.5至16.5厘米。雄鸟鸟上身呈橄榄灰色，臀部和尾羽覆盖物颜色较浅，呈绿橄榄色，头部、颈背、肩部和背部有深色的橄榄灰条纹，部分中翼和大翼覆羽尖端带有黄白色。面部特征独特，额头和眼区为均匀的暗橄榄灰色，眼眶周围有窄的灰蓝至灰色环，下方有一圈部分银白色硬羽毛组成的半圆形眼环，黄色裸皮线从喙基部延伸至眼环后方，耳羽为灰色至黄白色，耳后上方有小片黄色。下颌灰白，喉部灰黑斑点，腹部为淡灰黄色至橄榄黄色，胸部有深橄榄至灰黑色的条纹。雌鸟相似，但体型较小，眼环部位无白色羽毛，为裸皮。幼鸟特征未描述。","call":"发出响亮而重复的“tschök tschök tschök”叫声，类似于欧乌鸫的警报声。","habits":"生活在高山森林和高海拔的山地灌木丛中，特别是在主食植物生长的地方。在Kobipoto山，于2500米以上的苔藓森林中发现。记录的高度范围从900米到至少2500米，主要分布在1200米以上，偶尔下降至600米。通常以小型群体活动，主要食物为花蜜和昆虫，尤其是来自杜鹃花科的树木和灌木。","breeding":"关于繁殖的信息尚不明确。","identification":"与Seram Myzomela相比，塞兰岩吸蜜鸟更大，具有喙基部的淡色部分、脸部的淡色线条、裸露的面部皮肤和下面明显的条纹。","protection":"IUCN：LC（无危）","distribution":"分布于印尼摩鹿加群岛中东部的塞兰岛山区西部和中部，主要在1200米以上的高度，偶尔下降至600米。","other":"塞兰岩吸蜜鸟是印尼特有种，目前在全球范围内并不受到威胁，但在岛上东部地区因海拔过低而未见其踪迹。"},{"name":"黄耳岩吸蜜鸟","english_name":"Flame-eared Honeyeater","scientific_name":"Lichmera flavicans","overview":"黄耳岩吸蜜鸟（英文名：Flame-eared Honeyeater，学名：Lichmera flavicans），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。以独特的黄色耳斑和绿色橄榄色的羽衣著称，广泛分布于帝汶岛的森林及边缘地带。","appearance":"这种小型吸蜜鸟体长约12.5至14厘米，拥有弯曲而结实的喙。上部呈浓郁的绿橄榄色，脸部黑色面罩覆盖眼区，下缘为淡灰色至淡蓝灰色的须纹和前耳羽，后耳羽则有醒目的金色斑块。下体大部分为橄榄黄色，颏部和喉部为灰暗色，向下逐渐变为密集的灰橄榄色斑点或条纹。尾下覆羽为灰橄榄色。两性在羽毛上相似，但雄鸟可能比雌鸟略大。幼鸟尚未充分描述，但已知缺乏黄色耳斑，下体的斑点或条纹也不够明显。","call":"其鸣唱包括一系列悦耳、轻快的音符，带有类似莺的特质。叫声为短暂的嗡嗡声‘zirt’，频繁重复。","habits":"黄耳岩吸蜜鸟栖息于季雨林、林缘、河流旁的林木、次生植被和尤加利树林（Eucalyptus urophylla）。它们主要分布在海拔500至1000米的山脚区域，但在低地至少可达230米，最高可达2000米。它们通常为留鸟，可能进行局部迁移。","breeding":"有关繁殖的单一报告指出，繁殖活动发生在四月。除此之外，没有更多关于繁殖的信息。","identification":"与纹胸吸蜜鸟的区别在于其下体的黄色底色、细长的须纹和缺乏白色喉咙。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，具体为帝汶岛（小巽他群岛东部）。"},{"name":"黑胸岩吸蜜鸟","english_name":"Black-necklaced Honeyeater","scientific_name":"Lichmera notabilis","overview":"黑胸岩吸蜜鸟（英文名：Black-necklaced Honeyeater，学名：Lichmera notabilis），是雀形目吸蜜鸟科岩吸蜜鸟属的鸟类。仅见于东小巽他群岛的Wetar岛。以橄榄色上体、鲜明的黑白黄三色搭配和弯曲的喙而引人注目。","appearance":"体型中等偏小，长约13至15厘米，拥有略长且细的向下弯曲的喙。上体呈橄榄色，额部黑色，颈部后方有显著的黑色条纹形成项圈状图案。下体柠檬黄色，胸前有明显的白色喉部，其下方被黑色条纹所框定。雌雄羽毛相似，但雄鸟体型可能较大。雏鸟尚未具体描述。","call":"叫声为短促的嗡嗡两声“tzer-tzer”。","habits":"栖息于低地季雨林和花园中，也被观察到出现在沿海灌木丛、过度生长的农田和高大的次生林中。通常成小群活动。关于迁徙和移动模式的信息缺乏。","breeding":"繁殖信息缺失。","identification":"在Wetar岛上没有相似物种，其独特的黑黄白三色组合和项圈状的黑色条纹是辨识的关键。","protection":"IUCN：LC（无危）。全球范围内并不受威胁，但在Wetar岛上是广泛分布和数量众多的物种。","distribution":"仅分布于东小巽他群岛的Wetar岛。","other":"尽管一度被认为罕见，现在已被确认是在Wetar岛上分布最广、数量最多的鸟类之一。"},{"name":"月斑澳蜜鸟","english_name":"Crescent Honeyeater","scientific_name":"Phylidonyris pyrrhopterus","overview":"月斑澳蜜鸟（英文名：Crescent Honeyeater，学名：Phylidonyris pyrrhopterus），是雀形目吸蜜鸟科澳蜜鸟属的鸟类。主要分布在澳大利亚中南部、东南部以及塔斯马尼亚州。这小型吸蜜鸟，以其独特的黄色翼斑和黑色新月形胸部标记而著称。月斑澳蜜鸟的分布广泛，尤其在塔斯马尼亚较为常见。","appearance":"成年月斑澳蜜鸟体长约14至17厘米，体重在12至23克之间，雌雄异形。雄鸟以深灰色为主，头部、颈部和上体呈暗灰，翼上有明显的黄色斑块，胸部两侧有清晰的黑色新月形标记，边缘白色。雌鸟主要为褐色，新月形标记较淡，翼上的黄色斑块也较为暗淡。幼鸟类似雌鸟，但雄鸟幼鸟的黄色翼斑更亮。","call":"月斑澳蜜鸟具有复杂多变的鸣叫声，包括响亮的‘eejik’声和尖锐的‘jik’声，以及复杂的旋律歌曲。","habits":"栖息于湿性森林、桉树林和高海拔地区，冬季会向低海拔迁移。以花蜜、果实和昆虫为食，常在树冠层和灌木丛中觅食。在非繁殖季节，它们可能形成小群或大群觅食。","breeding":"繁殖期主要在晚冬和春季，巢由雌鸟建造，通常位于低矮灌木中，每窝产2至3枚蛋，孵化期约13天，幼鸟在13天左右离巢。","identification":"月斑澳蜜鸟通过其独特的黄色翼斑和新月形胸部标记与其它吸蜜鸟相区别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚中南部、东南部和塔斯马尼亚，包括沿海和内陆森林地带，以及山地森林。","other":"月斑澳蜜鸟的两个亚种中，P. p. halmaturinus仅限于袋鼠岛和Mount Lofty山脉。"},{"name":"黄翅澳蜜鸟","english_name":"New Holland Honeyeater","scientific_name":"Phylidonyris novaehollandiae","overview":"黄翅澳蜜鸟（英文名：New Holland Honeyeater，学名：Phylidonyris novaehollandiae），是雀形目吸蜜鸟科澳蜜鸟属的独特鸟类。广泛分布于澳大利亚西南部、东南部以及塔斯马尼亚岛的沿海地带。以鲜明的黑白配色和黄色翼尾斑块著称，易于识别。","appearance":"体型中等，长度约18厘米，重量介于10至29克之间，因亚种而异。羽毛底色为黑色，腹部白色，伴有黑色条纹。头部主要为黑色，额头两侧有小块白色条纹，两颊有明显白色斑点，颈部有白色羽饰。翅膀和尾部有醒目的黄色边缘。虹膜白色，喙和腿呈黑色或黑褐色。","call":"鸣叫声丰富，以单音节的高音调“cheet”、“seet”、“ssee”或“sit”为主，还发出一系列尖锐的哨声作为警报。","habits":"栖息于灌木丛、林地和花园中，偏好含多种灌木如Banksia、Leptospermum的环境。主要以花蜜为食，也会摄取昆虫和其它节肢动物。季节性和时间上的饮食变化影响其觅食行为。","breeding":"繁殖期全年可见，但主要集中在冬季至春季，筑杯状巢于树上，通常由草、树皮、苔藓等材料构成。每窝产卵2-3枚，由雌鸟孵化，孵化期13-15天，幼鸟由双亲共同喂养，离巢期12-16.5天。","identification":"与白颊澳蜜鸟区别在于面部两侧有两个较小的白色斑点而非一大片。亚种间在体型和羽毛细节上有细微差异。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚西南部、东南部及塔斯马尼亚岛。在南澳大利亚阿德莱德平原的分布自1970年代中期以来有所扩展。"},{"name":"白颊澳蜜鸟","english_name":"White-cheeked Honeyeater","scientific_name":"Phylidonyris niger","overview":"白颊澳蜜鸟（英文名：White-cheeked Honeyeater，学名：Phylidonyris niger），是雀形目吸蜜鸟科澳蜜鸟属的鸟类。具有显著黑白配色的中型吸蜜鸟。其特征为脸颊上的大白色斑块，黑色头部和黄色翼尾装饰。广泛分布于澳大利亚东海岸和西南部，常见于湿润的灌木丛生环境。","appearance":"成年白颊澳蜜鸟体长约16至20厘米，雄鸟体重介于15.5至25克，雌鸟略轻。头颈部以黑色为主，两颊有醒目的三角形白色斑块，覆盖耳羽、颈部侧面和喉部。背部、翅膀和头部呈黑色，带黄色翼尾边缘，下体白色，胸腹部有黑色条纹，腹中部条纹稀疏。雄雌羽色相似，但雄鸟体型稍大。幼鸟颜色较暗淡，头部和颈部为深灰褐色，黄色调较淡，白色颊斑较小。","call":"白颊澳蜜鸟的叫声多样，包括特有的‘chwikup, chwikup’吠声、悦耳的‘chippy-choo, chippy-choo’和在繁殖季节展示时发出的高音‘twee-ee-twee-ee’旋律。","habits":"主要栖息于湿润的灌木丛、纸皮沼泽、湿地、森林和林地中的灌木层。它们以花蜜为主食，尤其是Banksia和桉树的花蜜，同时也捕食昆虫。白颊澳蜜鸟通常独居或成对活动，有时会形成小群，活跃于低矮的灌木丛中。","breeding":"繁殖期因花蜜供应而异，主要集中在8月至11月和3月至5月。雄鸟保卫领地，雌鸟单独筑巢，巢由细枝、树皮条、蜘蛛网等材料构成，内部铺垫草、花和植物绒毛。每窝产卵2至3枚，孵化期约15天，双亲共同喂养幼鸟直至离巢。","identification":"与黄翅澳蜜鸟相似，但可通过白色颊斑与黑色胸部的差异以及不同的叫声来区分。此外，它们选择的栖息地和繁殖季节也有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从昆士兰的大分水岭东侧，沿新南威尔士州沿海延伸至杰维斯湾；在西澳大利亚州的西南部，范围从伊斯雷尔特湾向东至埃斯佩兰斯，向北至卡巴里国家公园附近的默奇森河。","other":"尽管适应性强，容易接近人类居住区，但有时会成为猫的猎物。"},{"name":"白纹岩吸蜜鸟","english_name":"White-streaked Honeyeater","scientific_name":"Trichodere cockerelli","overview":"白纹岩吸蜜鸟（英文名：White-streaked Honeyeater，学名：Trichodere cockerelli），是雀形目吸蜜鸟科白纹岩吸蜜鸟属的鸟类。是吸蜜鸟科白纹岩吸蜜鸟属下的唯一物种。此鸟种以独特的白色条纹羽毛和黄色耳羽而闻名，主要分布在澳大利亚东北部的约克角半岛。其命名来源于希腊语，意为‘毛发般的喉咙’，反映了其独特的喉部羽毛质地。","appearance":"体型小巧，体长14至17厘米，体重雄鸟14至20克，雌鸟12至13.5克。头部顶部和侧面呈灰色，脸颊斑块为灰蓝色，眼后有亮黄色簇状羽毛，下巴至胸上部的羽毛白色带细灰褐色条纹，背部暗棕色带黑色条纹，翼上具有明显的绿色边缘和白色尖端。腹部白色，侧胸有黄色条纹，两腿蓝灰色。幼鸟与成鸟相似，但颜色较淡，喉部羽毛不呈枪状，眼睛深棕色。","call":"叫声响亮，主叫为一连串快速的断音或似机枪声的颤音，亦发出金属质责备声‘churrr’。鸣唱为清晰尖锐的哨音，四音节，带有金属质感。","habits":"栖息于热带干燥森林和灌木林，如桉树、纸皮树、洛普斯托蒙或班克斯亚等。偶尔在雨林边缘或红树林中出现。以花蜜为主食，也捕食昆虫。在低矮的开花树木或灌木丛中觅食，有时与多种吸蜜鸟和其他鸟类共同觅食。","breeding":"繁殖季节未知，记录显示在湿季有繁殖行为，巢由细草、根须或植物纤维编织而成，通常位于低矮的灌木或树木中，离地面0.45至2米高。每次产卵2枚，孵化和育雏期未详。","identification":"与同属其他物种区别明显，主要通过其独特的白色喉部条纹和亮黄色耳后簇毛来识别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东北部的约克角半岛，南至Aurukun西部和Cooktown东部的Shiptons Flat。","other":"遗传研究表明，白纹岩吸蜜鸟与Phylidonyris属关系密切，其祖先约在700万年前分化。"},{"name":"彩蚊蜜鸟","english_name":"Painted Honeyeater","scientific_name":"Grantiella picta","overview":"彩蚊蜜鸟（英文名：Painted Honeyeater，学名：Grantiella picta），是雀形目吸蜜鸟科彩蚊蜜鸟属的鸟类。属于吸蜜鸟科下的单型属Grantiella。中等体型、极具特色的吸蜜鸟，主要栖息于澳大利亚东部内陆的开放林地和灌木丛，与槲寄生紧密相关。其显著的外部特征包括黑色上身、白色下身，以及红色喙和翼尾上的鲜艳黄色斑块。分布于澳大利亚东北部和中北部至昆士兰东南部及维多利亚州中南部。","appearance":"成年雄性彩蚊蜜鸟具有强烈的黑白相间外观，上身为黑色（臀部略显暗淡），下身为白色，头部黑色与白色喉部界限分明，两胁有稀疏的黑色条纹。雌鸟体型稍小，上体和下巴颜色较暗，呈橄榄褐色。幼鸟颜色更淡，上体呈棕色至灰棕色，翼覆羽边缘呈淡黄至近白色。成年雄鸟体重约20.5-25克，雌鸟约18克，体长约14-15厘米。","call":"彩蚊蜜鸟发出响亮且重复的双音节鸣叫，类似“sue-see sue-see sue-see”。","habits":"彩蚊蜜鸟栖息在多种环境，但强烈依赖槲寄生的存在。它们偏好红铁桉、木栓桉、黄箱树等主导的桉树森林，以及金合欢与槲寄生混生的林地。在春季和夏季，它们分布于维多利亚州内陆至新南威尔士州大部分地区，冬季迁往北昆士兰和北领地东部。它们以槲寄生果实、花蜜和其他水果为食，也吃昆虫和蜘蛛。","breeding":"繁殖季节可能依据槲寄生果实的可用性，通常在8月至次年2月之间，但在北领地3月也有记录。雌雄共同收集筑巢材料，巢通常是一个由草或细根编织的薄杯状结构，直径6.4-7.6厘米，深3.8-5.1厘米。每窝通常产2枚卵，偶尔1或3枚，孵化期至少13天。幼鸟由双方父母喂养，出巢期约为20天。","identification":"彩蚊蜜鸟通过其独特的黑白相间和黄色翼尾斑块与其它吸蜜鸟区分。此外，它们对槲寄生的依赖也是辨识要点。","protection":"IUCN：LC（无危）","distribution":"彩蚊蜜鸟分布于澳大利亚东北部，从中北部北领地至昆士兰东南部，向南延伸至维多利亚州中南部。在春季和夏季，它们出现在维多利亚州内陆至新南威尔士州大部分地区，冬季则迁往北昆士兰和北领地东部。","other":"彩蚊蜜鸟的生存受到栖息地丧失的威胁，尤其是农业导致的树木清除和缺乏再生。"},{"name":"纵纹吸蜜鸟","english_name":"Striped Honeyeater","scientific_name":"Plectorhyncha lanceolata","overview":"纵纹吸蜜鸟（英文名：Striped Honeyeater，学名：Plectorhyncha lanceolata），是雀形目吸蜜鸟科纵纹吸蜜鸟属的鸟类。体长约23厘米。其特征为灰褐色上体，带暗褐色条纹，白色下体，头部和颈背具有独特的黑色条纹。广泛分布于澳大利亚东部内陆地区，常见于各种干燥的硬叶林环境中。","appearance":"纵纹吸蜜鸟体型中大，喙短且几乎直，尾部长而末端微凹。头部与颈部羽毛常形成蓬松的冠状，头部和颈部呈白色，有显著的黑褐色条纹，侧翼有一细长的黑色须纹，延伸至颈侧，与黑色条纹在喉部和上胸部融合。下喉与上胸部的羽毛长而矛尖状；其余下体白色，有细小的棕色条纹；上体为棕灰色，背部和肩部有粗大的黑褐色条纹，臀部和上尾覆羽有淡色黑褐色条纹；次级飞羽和三级飞羽的中央覆羽有灰色边缘，其他飞羽有窄白边；新鲜时尾巴有细白边；下尾深灰色；下翼深灰色，覆羽有宽白斑；虹膜棕色至黑棕色；喙蓝灰色，尖端灰黑色；腿深蓝灰色或灰黑色。雌雄羽毛相似，雄鸟略大于雌鸟。幼鸟与成鸟类似，但头部和颈部的条纹更短、更细、颜色较暗，头部顶部有淡黄色晕染，条纹更细、颜色更暗淡，上体和背部的条纹也更细、颜色更暗淡。","call":"鸣声独特，是一连串响亮的旋律音符，通常音调逐渐升高，被描述为'chirp, chirp, cherry, cherry'，富有节奏感。","habits":"纵纹吸蜜鸟栖息于澳大利亚东部的多种高大开阔的干燥硬叶林地带，包括桉树林、河岸林、灌木丛和针叶林为主的环境。它偶尔出现在半干旱和干旱的金合欢灌木丛中，有时也会在软木树丛和森林中发现。沿海和近海地区，它们常出现在纸皮树和卡苏里纳树的硬叶沼泽森林和树林中，或是在卡苏里纳树、纸皮树或班克斯树的灌木丛和密林中。偶尔在红树林中出现。常见于城市公园、保护区和花园、果园、葡萄园和住宅花园以及有孤立树木的清理农业土地。活动范围广泛，从海岸到内陆干旱和半干旱地区，最高可达约1000米。","breeding":"繁殖期在8月至1月，主要集中在10月至11月。通常单独筑巢，偶尔观察到合作繁殖现象。巢由双方共同建造，深杯状或袋状，常呈较小的开口，边缘向上延伸至固定点，通常由细草制成，有时加入植物绒毛、毛发、根须或其它植被，用蜘蛛网和蛋壳粘合，外部覆盖植物绒毛、刺果种子、羽毛或羊毛，内部铺垫干草茎，有时有细根须和羊毛，外部直径6至10.4厘米，深度6.5至12.3厘米，内部直径约7.6厘米，深度6.5至9.6厘米。巢通常悬挂在细枝、树叶或树枝上，位于高大、通常是活的灌木、幼树或低矮树木的水平枝顶端附近的树叶中，距地面1至12米（平均4.5米）。每窝产卵1至5枚，通常3枚，平均孵化期可能为15至17天；雏鸟由双亲共同哺育，孵化和喂养，部分雌鸟比雄鸟承担更多的孵化任务，若有帮手在场，也会帮助喂养雏鸟，雏鸟期约15天至17天以上；双亲喂养离巢幼鸟。巢穴有时会被淡色杜鹃寄生。从35个巢中的98枚卵统计，平均每巢成功孵化出0.7只幼鸟。","identification":"与其他吸蜜鸟相比，纵纹吸蜜鸟头部和颈背的黑色条纹是其最明显的识别特征。在同属中，它是唯一的物种。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部和东南部，从昆士兰州中部向南延伸至南澳大利亚东南部和新南威尔士州中南部。具体分布包括昆士兰州中北部至东南部，向南贯穿内陆和新南威尔士州东北部，延伸至悉尼海岸以南地区，西北维多利亚州和南澳大利亚州东南部（约克半岛东侧）。偶尔在主要分布区北侧的昆士兰州（至汤斯维尔西）、新南威尔士州的大分水岭和悉尼以南（主要缺失南岸和高地）、维多利亚州中部和西南部以及南澳大利亚州东南部（洛夫蒂山脉和阿德莱德平原）有零星记录，主要在小规模爆发期间。在澳大利亚东部，从昆士兰州中部和东南部延伸至南澳大利亚东南部和新南威尔士州中南部。","other":"虽然属于吸蜜鸟科，但纵纹吸蜜鸟的食物主要来源于昆虫，其喙已经适应了昆虫饮食。它曾在果园中被视为害虫。"},{"name":"斑吸蜜鸟","english_name":"Spotted Honeyeater","scientific_name":"Xanthotis polygrammus","overview":"斑吸蜜鸟（英文名：Spotted Honeyeater，学名：Xanthotis polygrammus），是雀形目吸蜜鸟科黄脸吸蜜鸟属的中等体型鸟类。其独特外观和分布于新几内亚的山脚及低地森林树冠，亦见于南新几内亚的草原。背呈褐色带小白点，腹部白色，饰以大块暗色斑点和胸间深色条纹。","appearance":"斑吸蜜鸟长约15至17厘米，雄鸟体重介于19.7到23.5克之间，雌鸟约18至19.5克。拥有适度长而略弯的喙。头部与颈部暗色，颈背点缀白点，眼周环绕着粉红色裸露皮肤，耳部有一黄色斑块。背部暗色伴以小白色斑点，腹部白底微泛黄绿，布满深色图案与斑点。尾羽混杂棕灰色，翼下羽毛白色，喉部白色，嘴黑色，腿灰色。雌雄外观相似，雄鸟略大。","call":"发出悦耳的重复上升音调的‘wudee’叫声。","habits":"栖息于印尼与新几内亚的亚热带或热带湿润低地森林。食谱以昆虫、蠕虫和其他无脊椎动物为主，常在植被底层觅食，但也食用花蜜与果实，如无花果，取自树冠层和开花植物。观察显示，该鸟多单独觅食，偶尔成对或小群出现。","identification":"其腹下部的图案和粉红色眼环有助于与其他物种区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的新几内亚，包括繁殖区域。"},{"name":"黄纹吸蜜鸟","english_name":"Macleay's Honeyeater","scientific_name":"Xanthotis macleayanus","overview":"黄纹吸蜜鸟（英文名：Macleay's Honeyeater，学名：Xanthotis macleayanus），是雀形目吸蜜鸟科黄脸吸蜜鸟属的鸟类。分布区域极为有限，仅见于澳大利亚东北部，从库克镇至帕卢马山脉南端一带的昆士兰州北部。具有独特的外观特征，上体橄榄色带白色条纹，下体褐色，背部点缀小至大的白色斑点。头部黑色帽状，喉部灰色，眼周有一片淡粉色裸皮，周围环绕橙色羽毛，后方有黄色羽毛。体长约17至21.5厘米，雄鸟体重30至39克，雌鸟25.5至31克。","appearance":"中等体型，尾部较短，喙长而粗壮，略向下弯曲。头顶及颈背呈暗黑色，颈部中央和后颈有白色斑点；面颊、眼圈和下颚区橙棕色，形成围绕眼睛的淡色斑块，其中嵌有窄白边和粉白色眼下斑，被金黄色至赭色羽毛覆盖。下颏、喉部和颈侧灰白，喉部下方橄榄色；背部黑褐，肩羽至腰羽有黄色条纹，余部上体橄榄色斑驳；上翼和上尾深棕色，飞羽边缘绿黄色，覆羽尖端白色；胸腹部灰白至灰褐色，混杂黑色和白色条纹，下腹近似单一灰褐色；下翼基部粉黄，边缘暗灰。","call":"鸣声为快速且略具音乐性的两到三个双音节叫声，描述为“t-wit, t-weee, t-whit”或“chewit-che-wew”，也有清脆的“chip”单音和颤音叫声。","habits":"主要栖息于低海拔雨林，包括中叶藤本森林和复杂的小叶藤本森林，偶尔出现在红树林、桉树森林、公园、花园、果园和城镇内的次生林及伐木林。以昆虫为主食，亦食花蜜和果实，如小无花果。在森林各层觅食，偏好树冠层，活跃于树叶丛中或树皮上，有时倒挂取食。在食物源处可聚集多达30只个体。","breeding":"繁殖习性知之甚少。已知繁殖期在9月至12月和2月至3月，筑杯状巢，由棕榈纤维、小叶、树皮和其他植物材料构成，内部衬以棕榈纤维和羽毛，巢深而小，通常位于树冠或灌木丛中。每窝产卵2枚，由雌鸟孵化，父母双方喂养雏鸟，孵化和育雏期未知。","identification":"与同属物种相比，黄纹吸蜜鸟具有独特的色彩组合和斑点图案，尤其是头部的黑色和胸部的橄榄色与黄色条纹。叫声和行为模式也是识别的关键。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东北部，从约克角半岛东南部至昆士兰东北部，包括赫钦布鲁克岛等地。","other":"黄纹吸蜜鸟在澳大利亚的分布非常局限，是当地特有的物种，常在雨林及其边缘环境活动。"},{"name":"茶胸吸蜜鸟","english_name":"Tawny-breasted Honeyeater","scientific_name":"Xanthotis flaviventer","overview":"茶胸吸蜜鸟（英文名：Tawny-breasted Honeyeater，学名：Xanthotis flaviventer），是雀形目吸蜜鸟科黄脸吸蜜鸟属的鸟类。中等体型的鸟类，广泛分布在新几内亚和澳大利亚东北部，尤其偏爱潮湿的森林环境，包括红树林。","appearance":"茶胸吸蜜鸟体长18至21厘米，体重介于26.5至55克之间，雄鸟通常比雌鸟稍大。其上半身呈暗棕色，带有橄榄绿调，下半身颜色较浅，为淡黄褐色，颈部和脸部为灰色。喙长而略向下弯曲，黑色。眼周有一条明显的白色皮肤线，延伸至脸颊。翼上覆羽边缘为细薄的黄褐色，尾羽尖端亦为黄褐色，腹部下方颜色更深，为赤褐色，翅膀下表面为富丽的黄褐色。虹膜颜色为黑褐色到红褐色，眼环为蓝灰色，喙为黑色，腿色为浅蓝灰色至灰色。幼鸟与成鸟相似，但黄色耳羽较小，不那么明显，尾羽尖端为黄褐色，腹部颜色较为暗淡。","call":"不常发出噪音，但白天时常能听到其叫声。主要叫声为一系列响亮的单音哨声，音调和音量升降不定。在东新几内亚，叫声通常由3个音符组成，‘whit-wut-wu’或‘whip-to-whee’，长度约为1至1.6秒，重复3至10次以上，每10秒约6.5至7.5个短语。还有一种兴奋的‘tip-tip-tip-tip-tip’接触叫声，在飞行中或混合物种群中觅食时发出，当受到惊扰时会发出高音的‘tjiewiet-tiet…tjiewiet-tiet’叫声。","habits":"主要栖息于低地雨林，包括藤蔓森林、河岸林和其他湿地，偶尔出现在城镇中。在澳大利亚，也可见于开放的桉树和纸皮树森林。以昆虫为主食，如甲虫、蚱蜢、蟑螂、蝉和毛虫，同时也会食用花蜜和果实，例如无花果。觅食范围广泛，从地面到树冠都有其踪迹，常倒挂觅食。","breeding":"在新几内亚，繁殖期似乎在旱季末至雨季初，以及雨季末，记录显示繁殖活动发生在8月至次年2月和4月至5月。巢由雌鸟建造，杯状，由树皮条、纤维和叶子编织而成，内部铺有细腻的纤维、细根和树皮条。巢悬挂在密集树叶中的细枝叉上，高度在3至20米间，通常隐藏得很好。一窝产两枚卵，孵化期约为15天，雏鸟期约为14天，雌雄共同照料。","identification":"与其他吸蜜鸟相比，茶胸吸蜜鸟的头部和背部具有明显的橄榄绿色调，腹部下方为独特的赤褐色。叫声也是辨识的重要特征。","protection":"IUCN：LC（无危）。在新几内亚的低海拔地区普遍且数量众多，但在较高海拔处较为罕见。在澳大利亚东北部，可能较为少见。","distribution":"主要分布在新几内亚和澳大利亚东北部，包括一些卫星岛屿。在澳大利亚，主要见于东北部地区。"},{"name":"黄脸肉垂吸蜜鸟","english_name":"Kadavu Honeyeater","scientific_name":"Meliphacator provocator","overview":"黄脸肉垂吸蜜鸟（英文名：Kadavu Honeyeater，学名：Meliphacator provocator），是雀形目吸蜜鸟科Meliphacator的鸟类。体型较为大型，具有独特的黄色裸露面部皮肤和黑色胡须纹。分布于斐济的Kadavu岛，偏好森林、花园等多样生境。","appearance":"体长16至21厘米，上体橄榄灰，有白色细纹，头部和颈后橄榄灰，顶部有淡灰色斑点，耳羽绿色，眼周有大的黄到金黄色区域。喉部橄榄灰，胸前有白色条纹的白色倒三角羽毛。背部橄榄灰，有白色细纹，翅膀和尾巴棕色，有黄色边缘。下体略淡橄榄灰，重白条纹，腹部几乎全白，尾下覆羽淡棕色。虹膜灰褐至褐色，喙黑，腿灰绿。雄鸟比雌鸟大，幼鸟上体更黄橄榄色。","call":"声音混合了柔和的哨音和响亮的铃声，常以强烈的‘kee-kow’开始，类似的叫声。","habits":"广泛适应各种环境，包括成熟山地和低地森林、次生林、沿海灌木丛和沼泽、红树林、农田、城镇、乡村和城市花园。从海岸到内陆都有分布，被认为是定居物种。","breeding":"繁殖信息有限，记录到在五月和九月繁殖，巢为脆弱杯状，由细草和根制成，内部铺软材料，通常仅产一枚蛋，具体孵化和育雏时间未知。","identification":"与生态相似，但有明显的黄色眼圈和绿色耳羽，以及特有的叫声。","protection":"IUCN：LC（无危）。全球范围内非常常见，仅限于单个岛屿，全球种群估计不明。","distribution":"太平洋区域，特指斐济西南部的Kadavu岛。","other":"曾被归入Xanthotis属，2019年基于分子系统发育研究转至Meliphacator属。"},{"name":"麦氏吮蜜鸟","english_name":"Meyer's Friarbird","scientific_name":"Philemon meyeri","overview":"麦氏吮蜜鸟（英文名：Meyer's Friarbird，学名：Philemon meyeri），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。得名于德国人类学家兼鸟类学家阿道夫·伯纳德·迈耶。体型较小，羽毛呈单调的灰褐色，具有长长的弯曲喙，喙尖锐而向下弯。分布于新几内亚的低地森林、沼泽森林及次生林等地，常见于雨林冠层。","appearance":"麦氏吮蜜鸟体长约22厘米，体重介于46至58克之间。全身羽毛统一的暗灰褐色，上部略带淡褐色条纹，下部颜色较浅。头部皮肤部分露出，呈蓝黑色至黑色，眼睛深棕色，喙黑色，腿灰色。幼鸟背部至尾羽覆盖白色细斑点，翅膀和尾巴边缘黄绿色，喉部泛金黄色，胸部有暗褐色和金黄色的条纹。随年龄增长，羽毛逐渐变棕。","call":"发出尖锐的‘tchew’叫声，其歌声由一系列‘witch-oo’音符或‘chew-hoo’短语组成。","habits":"栖息于新几内亚的低地至海拔约1200米的山地，偏好雨林、森林边缘、沼泽森林和次生林。以水果、花蜜和昆虫为食，主要在树冠层觅食，偶尔会降至较低层的植被中。通常单独或成对出现，有时会在开花树木中与其他鸟类混群。","breeding":"关于繁殖信息有限，已知一窝产两枚卵。具体繁殖行为和生态细节尚待研究。","identification":"与纹头吸蜜鸟的区别在于更大的喙、单一的棕色羽毛、无白色冠条和无浅色髭纹。与巨嘴盗蜜鸟相比，喙较短且眼睛深色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚，包括鸟头半岛以外的地区，如Lower Fly西北部和新几内亚中南部。","other":"麦氏吮蜜鸟在当地被认为是常见的到丰富的物种，例如在Lakekamu盆地，密度可达每公顷0.2只鸟。"},{"name":"布氏吮蜜鸟","english_name":"Brass's Friarbird","scientific_name":"Philemon brassi","overview":"布氏吮蜜鸟（英文名：Brass's Friarbird，学名：Philemon brassi），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。体型较大的棕色鸣禽，以其长而沉重的喙著称。上体和头顶呈灰褐色，脸部两侧和胸部明显带有白色斑点。眼周有一大块灰色裸露皮肤。幼鸟上体部分的羽毛尖端呈白色，喉部和胸部呈黄色。仅分布于印度尼西亚的西巴布亚，常见于甘蔗草丛和密集的次生植被中。比盔吮蜜鸟小，头部和胸部的淡色标记以及喙顶无隆起是其区别特征。鸣声为鼻音的“tchew”。","appearance":"成年布氏吮蜜鸟长约21至22厘米，喙长且略向下弯曲，无基部突起。上体主要为深橄榄棕色，翼羽和尾羽更暗，近黑色。前额、眉纹、眼先及眼周有大面积裸露的蓝灰色至黑灰色皮肤，点缀着稀疏的灰白羽毛。头顶、颈背、耳羽和颊区呈暗灰色，带有白色斑点；下颌和上喉显著白色，上胸的羽毛为暗灰色，细密地点缀着白色。下体淡灰色，胸部略深，大腿处带褐色。翅膀下表面为暗淡的污白色，边缘和尖端较暗。随着羽毛磨损，体色会变得更浅，呈灰褐色。虹膜深棕色，喙黑色，腿深灰至蓝灰色。雌雄羽毛相似，但雄鸟略大于雌鸟。幼鸟头部顶部、肩部、背部和覆羽有红褐色色调，翼羽外缘和尾羽有橄榄绿色边缘，上胸有时泛黄。","call":"发出上滑的鸣叫声，这是该属鸟类的典型叫声。","habits":"在伊登堡河，布氏吮蜜鸟常见于水淹甘蔗草丛和沿湖沼泽边的茂密次生植被。在提拉维瓦河和洛加里河，它们在当地植被沿河边缘和受扰动区域较为常见，但不会进入甘蔗草丛。记录的高度在海拔50米左右和80至275米之间。似乎为留鸟。以花蜜、果实和昆虫为食，曾在开花的Elaeocarpus树上低处觅食。相较于盔吮蜜鸟，它们的叫声和好斗程度较低。通常以约十二只的小群体活动，会在开花树木中与其他吸蜜鸟聚集。","breeding":"三月时，雄鸟个体的性腺增大，但关于繁殖的其他信息未知。","identification":"与盔吮蜜鸟相比，布氏吮蜜鸟较小，头部和胸部有淡色标记，喙顶无隆起。","protection":"IUCN：LC（无危）。目前数量稳定，但在Mamberamo河和Idenburg河的低地森林位于Foja自然保护区，该地区难以到达且未被干扰。然而，木材采伐、农业项目以及提议在Mamberamo峡谷建坝可能构成潜在威胁。","distribution":"仅限于西巴布亚的Mamberamo盆地（新几内亚西北部），包括Idenburg河、Mamberamo河下游、Rouffaer河、Wapoga盆地、Tirawiwa河和Logari河。","other":"种名和通用名纪念了澳大利亚植物学家Leonard J. Brass（1900-1971），他曾任职于昆士兰植物标本馆。"},{"name":"小吮蜜鸟","english_name":"Little Friarbird","scientific_name":"Philemon citreogularis","overview":"小吮蜜鸟（英文名：Little Friarbird，学名：Philemon citreogularis），是雀形目吸蜜鸟科吮蜜鸟属的鸟类，也是该属中体型最小的种类。以蓝灰色裸露的面部皮肤和缺失的喙上突起而容易识别。广泛分布于新几内亚中南部和澳大利亚北部及东部地区，常见于河流附近和郊区花园。","appearance":"体长约25至29厘米，平均体重介于50至84克。成鸟具褐色羽冠，上体灰褐色，下体奶油色。脸部有独特的蓝灰色裸露皮肤，边缘由暗褐色和细小的淡色鳞片状羽毛包围。翼羽有薄白边，尾羽尖端白色。下颏和喉部银白色，胸腹部呈淡灰棕色。幼鸟喉部和肩部有黄色调。雌雄羽毛相似，但雄鸟略大。","call":"发出重复的液态柔和‘gee-wit’或‘chewip’声，繁殖季节时的鸣唱扩展，包含嘈杂的斥责声。","habits":"栖息于多种开放森林和林地环境，偏好有水源附近的地带，如桉树林、河岸植被和城市公园。主要以花蜜和昆虫为食，偶尔食用花朵、果实和种子。在空中、树上和灌木丛中觅食，偶尔在地面活动。常与其它吸蜜鸟混群。","breeding":"繁殖期从8月至翌年4月，通常筑巢于水体附近的树枝间，巢为深杯形，由多种材料构成，包括树皮纤维、草、蜘蛛网等。每窝产2至3枚卵，有时可达4枚，孵化期约13至16天，由雌鸟单独孵卵，双亲共同喂养雏鸟，雏鸟期13至15天。","identification":"与同属其他种类相比，小吮蜜鸟因体型较小、无喙上突起和蓝灰色裸露面部皮肤而易于辨识。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚中南部和澳大利亚北部、东部，夏季向东南澳大利亚扩散，包括新南威尔士州、维多利亚州、南澳大利亚州和澳大利亚首都特区。"},{"name":"灰吮蜜鸟","english_name":"Grey Friarbird","scientific_name":"Philemon kisserensis","overview":"灰吮蜜鸟（英文名：Grey Friarbird，学名：Philemon kisserensis），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。南部摩鹿加群岛（Kisar、Leti和Moa岛屿）特有的大型灰色吸蜜鸟。其独特的蓝色裸露眼下方皮肤和长而重的喙使其在分布区内独树一帜。","appearance":"体长约25厘米，是一种体型略小的吸蜜鸟，具有中等长度且稍向下弯曲的喙，喙上无盔状突起。全身覆盖着单调的棕灰色羽毛，上尾羽尖端有狭窄的白色边缘，初级飞羽有细薄的淡色边缘；面部有一块较窄且呈三角形的蓝灰色裸露皮肤，上方被细密的暗棕色鳞片状浅色眉纹和眼上纹包围，后方则是黑棕色的耳羽；颈部后侧有淡灰色至银灰色的绒毛半颈环；下巴和上喉部白色至银白色，逐渐过渡到淡棕色的下喉和胸部，带有少许白色条纹；胸部的棕灰色与更淡的灰色或灰白色下腹部相融合，下腹部中央最浅；下尾羽浅灰色，尖端和边缘有狭窄的偏白色；翅膀下方浅灰棕色，末端和边缘深灰棕色；虹膜棕色至深棕色；喙黑色或灰黑色；腿色为石板灰至黑色。雄鸟可能比雌鸟大，但羽毛颜色相同；幼鸟和未成熟个体特征未详述。","call":"发出连续的‘kwit-kwit-woo-woo’声，有时更快的‘kwit-woo’声，以及各种粗糙的嘶哑音。","habits":"生活在森林、森林边缘及开阔的林地，以单个、成对或小群体出现。","identification":"在分布范围内独特，因无其他相似的吸蜜鸟种类。注意其蓝色裸露的面部皮肤是辨识关键。","protection":"IUCN：LC（无危）。状态不确定，通常被视为小吮蜜鸟的一个亚种；可能不是全球受威胁物种。限制性分布物种，存在于Banda群岛EBA。极不为人所知，目前没有关于其生态或状态的最新信息。过去被认为是常见的，现在可能仍然如此。","distribution":"分布于澳新界，具体包括Kisar、Leti和Moa岛屿（东帝汶岛东部，小巽他群岛东部）。","other":"目前无其他重要信息提及。"},{"name":"帝汶吮蜜鸟","english_name":"Timor Friarbird","scientific_name":"Philemon inornatus","overview":"帝汶吮蜜鸟（英文名：Timor Friarbird，学名：Philemon inornatus），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。大型棕色的吸蜜鸟，拥有长而有力的喙，腹部显白色细纹，眼下方有波浪状白条纹。幼鸟的翼板呈黄绿色，喉部和胸部带有黄色。在低地至山脚地带的森林、边缘、稀树区、耕作地和红树林中可见单个或小群活动。","appearance":"帝汶吮蜜鸟体长约24厘米，具中等长度且略向下弯的喙，喙基无突出部分。上身呈单调的棕灰色，颈部后方和侧面有明显的灰白色半环状羽毛；面部较暗，由深色耳羽覆盖，面部皮肤有小块暗色裸露区域；飞羽有橄榄色边缘（折叠翅膀时形成淡色斑块），尾羽有细小橄榄色边缘；下巴和喉咙银白色，向下渐变为灰白色点状斑纹；胸腹部非常淡的灰褐色，胸部有模糊的条纹或鳞片状斑纹（由稍长且尖端偏白的羽毛形成），下体逐渐变为偏白色或极淡灰色；虹膜深棕色，喙黑色，腿深灰色至黑色。雄雌羽毛相同，雄鸟平均比雌鸟稍大。幼鸟上体颜色比成鸟更棕色，翼板有更明显但模糊的黄绿色斑块，下巴、喉咙和胸部有黄色痕迹。","call":"帝汶吮蜜鸟发出刺耳的翠鸟般的“kichup-chow”叫声，也有波动的“kichup-weee-chow-chow...”叫声。","habits":"帝汶吮蜜鸟栖息于季风林、次生林、开阔林地、灌木丛，偶尔出现在轻度树木覆盖的农田，海拔高度从海平面到2400米。它们主要在树冠层觅食，通常单独或成对出现，性格嘈杂、好斗且显眼。","identification":"与盔头吮蜜鸟相比，帝汶吮蜜鸟体型较小，喙更纤细且无盔状突起，面部有白色线条，面部皮肤上没有大片裸露区域。","protection":"IUCN：LC（无危）。帝汶吮蜜鸟在小范围内广泛且常见，但具体种群数量未知。全球范围内未受到威胁，但在帝汶和韦塔尔EBA内分布有限。","distribution":"帝汶吮蜜鸟主要分布在帝汶岛（小巽他群岛东部），在澳大利亚-新西兰生物地理区。它们倾向于在接近道路的地区活动，尤其是靠近河流和红树林的平坦低交通量道路附近。","other":"帝汶吮蜜鸟在岛上扮演着重要的文化角色，主要以花蜜为食，同时也吃昆虫和果实。近十年来，由于人类活动导致的栖息地丧失和盗猎，其种群数量显著下降。"},{"name":"暗吮蜜鸟","english_name":"Morotai Friarbird","scientific_name":"Philemon fuscicapillus","overview":"暗吮蜜鸟（英文名：Morotai Friarbird，学名：Philemon fuscicapillus），是雀形目吸蜜鸟科吮蜜鸟属的的鸟类。这体型较大的灰褐色吸蜜鸟，具有长长的、强有力的匕首状喙和眼周粉色裸露皮肤。腹部颜色较浅，常单独或成对出现在低地森林、森林边缘及种植园的树冠层。与Halmahera Oriole相似，但通过喙形和眼部裸皮区加以区分。","appearance":"体长约30厘米，上身呈灰褐色，头顶和颈部颜色更深。翅膀略带橄榄色，眼周和面颊有大片粉红色裸皮，覆盖着细小的毛发。脸部有一条浓密的黑色颊纹，延伸至耳羽处，下巴和喉咙呈现淡灰色，喉部下方隐约泛黄。下体颜色比上体更淡，胸部有微弱的黄色调。翅膀下侧灰褐色，虹膜红色，喙和腿黑色。雄鸟可能比雌鸟稍大，幼鸟和未成年个体特征未详述。","call":"发出类似黑鹂的笛声般的鸣唱，重复的“chewit-woow”音节。还会发出尖锐的‘ker’声作为警报。","habits":"栖息于热带湿润的低地森林和湿润灌木丛，偶尔在椰子种植园和次生林中观察到。可能为留鸟，有局部迁移现象。通常独行，偶尔成双出现，过去曾见到小群体。以树冠层觅食为主，较为隐蔽，观察难度较大。","breeding":"雄鸟在四月时生殖腺增大，五月观察到幼鸟。关于繁殖行为的其他信息尚缺乏。","identification":"与Halmahera Oriole在外观上极为相似，主要通过喙的形状和眼周裸皮区加以区分。喙尖更锐利，裸皮区更明显。","protection":"IUCN：NT（近危）","distribution":"分布于印尼北摩鹿加群岛的摩罗泰岛，有未经证实的记录显示也在Bacan岛上出现过。在Halmahera岛上的记录低于120米，可能高达510米。","other":"由于栖息地的持续丧失和退化，暗吮蜜鸟面临威胁，尽管其能容忍一定程度的栖息地恶化。"},{"name":"灰颈吮蜜鸟","english_name":"Seram Friarbird","scientific_name":"Philemon subcorniculatus","overview":"灰颈吮蜜鸟（英文名：Seram Friarbird，学名：Philemon subcorniculatus），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。亦被称为灰颈吸蜜鸟或Ceram吸蜜鸟，是印尼摩鹿加群岛中东部的特有种，广泛分布于Seram岛的低地森林、椰林、红树林和稀树地带。其显著特征是长而弯曲的喙和颈部周围的灰色羽毛。","appearance":"成年灰颈吮蜜鸟体型大至非常大，长度约35厘米，体重介于172至223克。上身呈橄榄褐色，头部两侧有大面积裸露皮肤，颜色从黑褐色到黄褐色不等。颈后有一小撮略显蓬松的羽毛，颈部下方有银灰色至深灰色的羽毛。下体偏淡褐色，带有黄色调的喉部和胸部。喙长且略微向下弯曲，尖端较细，雄鸟和雌鸟在外貌上相似，但雄鸟可能比雌鸟稍大。幼鸟上身更偏向棕色，缺乏橄榄色调，背部和肩部有黄色边缘，下体灰褐色，胸侧有黄色痕迹。","call":"清晨时分，灰颈吮蜜鸟会发出响亮的‘k’PROW！’的爆炸声，持续到日出，声音穿透力强，有时被描述为‘gock’或‘geck’，并在2至3秒间隔重复单个响亮、略带鼻音且不太悦耳的音符。","habits":"它们在海岸的红树林和椰子种植园，以及原生和受扰动的低山森林中广泛分布，活动高度从海平面至海拔1100米。通常单独、成对或以小型群体出现，主要在森林的上层活动，觅食行为尚不清楚。","breeding":"灰颈吮蜜鸟的繁殖活动记录有限，已知会在8月筑巢，巢穴建在高大的树木顶端。曾观察到它们攻击一对正在检查潜在巢穴的红鹦鹉，攻击原因不明。","identification":"与Seram Oriole的区别在于眼部周围有裸露皮肤，体型略大，尾巴相对更长，喙尖细且头部顶部常扁平。幼鸟相比成鸟色泽更偏棕，缺乏橄榄色，背部和肩部有黄色边缘。","protection":"IUCN：LC（无危）；灰颈吮蜜鸟在Seram岛上分布广泛且数量众多，常见于Manusela国家公园。","distribution":"该物种仅限于印尼摩鹿加群岛的Seram岛，包括低地森林、椰林、红树林和稀疏植被区，分布海拔从海平面至1100米。","other":"灰颈吮蜜鸟是其家族中体型最大的成员，大约比灰领鹂重78%，后者几乎完美模仿它的外观。"},{"name":"黑脸吮蜜鸟","english_name":"Buru Friarbird","scientific_name":"Philemon moluccensis","overview":"黑脸吮蜜鸟（英文名：Buru Friarbird，学名：Philemon moluccensis），是雀形目吸蜜鸟科吮蜜鸟属的大型灰褐色鸟类，其面部有一片暗色裸露皮肤，喙长而尖，略向下弯曲。分布于印尼摩鹿加群岛中的布鲁岛，栖息于各种林地环境。","appearance":"成年黑脸吮蜜鸟体长31至37厘米，全身灰褐色，刚换羽时略带橄榄色，逐渐变为较淡的棕色。头部侧面呈银白色至银灰色，耳羽处有短小的银色羽毛簇，脸部有大片黑色裸露皮肤覆盖眼窝至头部两侧。喉部至胸上部有细密的暗色条纹，其余下体颜色较浅，翼下呈淡锈色，尾羽端部及边缘深色。虹膜鲜红或红色，喙黑色，基部略带蓝黑色，腿蓝色至灰黑色。雌雄羽毛相似，雌鸟体型略小于雄鸟。幼鸟下喉及胸部侧面有淡黄色斑点或条纹，翅膀边缘有绿色或黄色痕迹。","call":"发出多种声音，包括尖锐的‘skidup’警戒声，重复的‘chuwee-chow’和‘wee-o-wer’叫声，以及类似翠鸟的响亮流利‘yio-wheea’叫声及其变体，短促的‘ka wha’和硬朗的‘kawah’声。可能有二重唱行为。","habits":"单独或成对活动，偏好森林、森林边缘和开阔的林区，包括低地和山地原始森林、季雨林、次生林、林地、红树林、受干扰和选择性砍伐的森林、农田和椰子种植园。海拔分布从海平面到1760米。据观察，似乎偏好有老树残留的开阔地带，常见于被砍伐的森林而非原始或次生林。被认为是留鸟，以中上层林间活动为主，性格嘈杂、好斗且显眼。","breeding":"繁殖信息未知。","identification":"比黑耳鹂大，面部暗色部分由裸露皮肤组成，喙更长且尖锐。与灰颈吮蜜鸟外观更为相似，而非东黑脸吮蜜鸟。","protection":"IUCN：LC（无危）。限制分布物种，仅见于Buru EBA。总数量估计约920,000只，虽然常见，但因其单一岛屿分布，未来可能面临风险。","distribution":"分布于印尼摩鹿加群岛中西部的布鲁岛。","other":"历史上曾与东黑脸吮蜜鸟归为同一物种，统称为‘黑脸吮蜜鸟’，现已确认为独立物种。"},{"name":"东黑脸吮蜜鸟","english_name":"Tanimbar Friarbird","scientific_name":"Philemon plumigenis","overview":"东黑脸吮蜜鸟（英文名：Tanimbar Friarbird，学名：Philemon plumigenis），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。具有长而沉重的微弯喙，尖端锐利且鼻孔明显。脸部皮肤裸露，眼下方有一片裸皮。分布于印尼的Kai和塔宁巴尔群岛，栖息于低地的森林、林地、红树林和种植园。体型比褐耳鹂大，通过裸露的脸部皮肤、平坦的头顶、更尖的喙和突出的鼻孔加以区分。","appearance":"体长31-37厘米，上体呈单一灰褐色，新羽时略带橄榄色，旧羽转淡棕色。翼羽边缘橄榄色，颈后和颈侧有银色短羽。头部两侧有大片黑色裸露区，耳羽后方有小块暗棕色斑点。下巴至胸部为深棕色，喉部羽毛尖端灰色，胸部有淡黄色条纹或洗色。其余下体中部棕色，翅膀下方浅赤褐色，边缘和尖端较暗。虹膜鲜红色或红色；喙黑色，基部略带蓝黑色；腿灰黑色或黑棕色。雄鸟可能比雌鸟稍大，幼鸟描述未详。","call":"非常善于鸣叫。在Kai岛，主要叫声是一对鸟的响亮对鸣，首鸟发出上扬的“seeow”，紧接着第二只鸟发出持续约1秒的气泡状号角声，或一系列音调起伏的音乐性音符。一对鸟曾连续对鸣约25秒。单个“seeow”和类似啄鹃（Dicrurus）的叫声也有报道。","habits":"栖息于低海拔的森林、林地、红树林和种植园。分布于Kai和塔宁巴尔群岛（印尼摩鹿加群岛南部）。","identification":"与黑脸吮蜜鸟相比，东黑脸吮蜜鸟更大，有明显的裸露面部皮肤、平坦的头顶、更尖锐的喙尖和显著的鼻孔。","protection":"IUCN状态未知。","distribution":"分布于澳大利亚新几内亚地区，具体为印尼的Kai和塔宁巴尔群岛（南部摩鹿加群岛）。","other":"1858年，由英国鸟类学家George Robert Gray首次描述为Tropidorhynchus plumigenis。种小名来自拉丁语pluma（意为羽毛）和genis（意为脸颊）。"},{"name":"盔吮蜜鸟","english_name":"Helmeted Friarbird","scientific_name":"Philemon buceroides","overview":"盔吮蜜鸟（英文名：Helmeted Friarbird，学名：Philemon buceroides），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。是澳大利亚大陆体型最大的吸蜜鸟，因喙基具盔状突起而得名。体长32–36厘米，体重90–180克，分布自印尼小巽他群岛、新几内亚至澳大利亚北部沿海与内陆低地，栖息于红树林、季风林、河岸林、次生灌丛乃至城市公园。该种在新几内亚低地被视为代表性鸟声，全年繁殖，营大型悬巢，杂食。IUCN评估为无危（LC）。","appearance":"成鸟具粗厚微下弯的黑喙，上喙基部具向后倾斜、圆钝而突出的盔突；眼先及头侧裸皮呈深青灰至黑色，喉至上胸具银白纵纹，下胸具矛状羽领；全身灰褐，尾上覆羽具细白点。雌雄同色。幼鸟盔突仅为小突起，后颈羽冠短而不显，上体带褐，翼覆羽具窄褐端，喉至上胸纯白无纹，眼色褐红或灰。各亚种差异主要在体型、盔突大小及羽色深浅：指名亚种羽色最浅；jobiensis盔突几乎缺如；yorki盔突大而突出，头顶银白；novaeguineae整体色深。","call":"极为嘈杂，声域宽广且粗糙。在新几内亚与华莱士区，2–4音节响亮鼻音短语如“keeyo-keoway”或“kowee ko keeyo”反复12次左右，清晨与夜间均闻；另有嘶哑“kurr-rk”、哀婉“poor devil”、警戒“watch out”及清脆“chilanc chilanc”等。雌雄可二重唱，常于傍晚与黎明前对答。","habits":"主要为留鸟，局部随蜜源微动。栖息海拔自海平面至1600米（新几内亚局部达2170米）。生境多样：红树林、季风林、河岸千层树林、桉树林、次生灌丛、城市花园等。以花蜜、果实、种子及昆虫、蜘蛛为主食，偶食蜥蜴及鸟卵；在树冠层探花取蜜，也悬停啄食。常单独、成对或小群活动，富攻击性，驱赶小型鸟，却与褐黄鹂（褐鹂）并存。","breeding":"澳大利亚繁殖期9月至翌年2月，新几内亚全年（除旱季初期）。巢为大型松散敞口杯，直径15–23厘米，深15–18厘米，由树皮条、叶、藤蔓构成，常利用旧巢材料，悬于树梢或水平枝末端，高1.5–18米，常近水。每窝2–4卵（澳3–4、新几内亚2–3），孵化17–19天，雏期15–18天，双亲育雏，离巢后继续喂养2–3周。巢常被噪鹃（Eastern Koel）及噪八声杜鹃（淡色杜鹃）寄生。","identification":"以体型最大、盔突显著及头侧大块裸皮区别于同属其他吮蜜鸟。与银冠吮蜜鸟相比，后者头顶银白且无盔突。亚种间差异主要为盔突大小与羽色深浅，需结合分布与体型综合判断。","protection":"IUCN: LC（无危）","distribution":"繁殖区：印尼小巽他群岛（罗地岛、帝汶、龙目岛、松巴哇岛、弗洛勒斯岛等）、新几内亚主岛及近岸岛屿、澳大利亚北部（北领地阿纳姆地、昆士兰约克角半岛沿海）。非繁殖区：局部仅作短距离游荡，如澳大利亚北部旱季向达尔文地区移动，托雷斯海峡小岛偶见。","other":"分类尚未完全厘清，分子研究及羽饰磨损与声纹分析仍需深入；可能包含多个隐存种。"},{"name":"新几内亚吮蜜鸟","english_name":"New Guinea Friarbird","scientific_name":"Philemon novaeguineae","appearance":"见盔吮蜜鸟。整体羽色比盔吮蜜鸟略暗一些。","distribution":"新几内亚吮蜜鸟的地理分布集中在澳新界的新几内亚及附近的卫星岛屿。","other":"现为盔吮蜜鸟亚种。"},{"name":"犀吮蜜鸟","english_name":"Hornbill Friarbird","scientific_name":"Philemon yorki","overview":"犀吮蜜鸟（英文名：Hornbill Friarbird，学名：Philemon yorki），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。在澳大利亚东北部广泛分布，被观鸟爱好者亲切地称为“leatherhead”。","appearance":"犀吮蜜鸟拥有暗灰色的脸庞和红色的眼睛，全身呈现灰褐色，胸部逐渐过渡至白色，腹部接近脚部颜色加深。雄鸟个体体长可达32至36厘米，体重约127-179克，而雌鸟稍小，体长和体重分别为32至36厘米和92-112克。雄鸟平均体长约38厘米，是澳大利亚四种盔头吮蜜鸟中体型最大的亚种。","call":"犀吮蜜鸟发出响亮的‘squawks’声，能远距离传播，其叫声常被描述为keeyo-keoway或kowee ko keeyo，可连续重复多达十二次。它们还会发出kurr-rk的声音，缓慢重复八到十次。它们通常在清晨和暴风雨期间最为活跃，其余时间较为安静。","habits":"犀吮蜜鸟栖息于澳大利亚北部海岸、印尼的亚热带或热带干旱森林、低地森林及红树林中。它们倾向于在靠近水源的高树上筑巢，巢穴由树皮、树叶和茎干构成，辅以枝条加固和草料增加舒适度。","breeding":"繁殖季节主要集中在9月至2月，偶尔会延伸至2月至5月或10月至12月，但不会在5月和7月繁殖。一次产卵2-4枚，最多可达5枚，孵化期大约持续15-18天。犀吮蜜鸟的平均寿命约为5-7年，尽管当前种群数量稳定，但预计未来十年内可能下降10%，这使物种面临脆弱状态。","identification":"与盔头吮蜜鸟的其他亚种相比，犀吮蜜鸟在外观上有细微差别，特别是在颜色模式和大小上。新几内亚吮蜜鸟（P. b. novaeguineae）和澳大利亚东北部的犀吮蜜鸟有时被视为盔头吮蜜鸟的亚种或独立物种。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚东北部，包括澳大利亚的Cape York Peninsula和沿海北东部昆士兰州。","other":"尽管犀吮蜜鸟的种群数量目前被认为稳定，但每一代的减少率约为10%，预示着该物种未来的生存风险。现为盔吮蜜鸟亚种。"},{"name":"白纹吮蜜鸟","english_name":"New Britain Friarbird","scientific_name":"Philemon cockerelli","overview":"白纹吮蜜鸟（英文名：New Britain Friarbird，学名：Philemon cockerelli），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。体型较大的棕色吸蜜鸟，以其独特的长而尖锐的喙、暗色头部、鲜明的淡色颈部及下体以及深色裸露面部皮肤为显著特征。该鸟种仅分布于新不列颠岛（俾斯麦群岛东南部），常见于低地至山脚地带的森林、边缘、开阔地和种植园。","appearance":"体长33-35厘米，体重约139-177克。成鸟具长颈，喙长且重，微弯，上喙基部无突出。背部呈暗淡的深棕色，与颈部和侧面形成强烈对比的银灰色项圈，下巴和喉咙淡棕色。脸部有大块暗灰色至黑色裸露区域，下颌有一条浓密的黑褐色条纹。尾羽顶部边缘呈淡白色，二级飞羽和内侧初级飞羽边缘有淡橄榄色晕染。胸部稍暗，下喉至胸有模糊的暗色斑点，腹部非常浅的灰棕色。翼下大部分为白色，覆羽有棕灰色斑点，边缘和尖端呈银色暗棕色。虹膜深棕色，喙黑色，腿蓝灰色。雌雄羽毛相似，雄鸟体型较大。幼鸟翅膀和尾巴带橄榄色，项圈较暗，灰白色，胸侧带黄褐色条纹或斑点。","call":"发出类似长笛的、 Oriole-like 'chewik-chow' 的叫声，第二音较低，还有尖锐的 'chow' 声和类似乌鸦的 'kra' 声。叫声多样，从沙哑声到号角般的音符，混杂着类似笑声的爆发。黎明前开始鸣叫，重复 'tok tok tok' 直至天亮。歌唱包含重复的泡沫状或嬉戏的短语。","habits":"栖息于各种林木环境，从低地至中高山雨林，森林边缘，高大的次生林，近期清理和干扰区域，椰子种植园和花园。活动于低地至海拔约1600米处，常见于低地和丘陵至约1150米的新不列颠岛和约760米的Umboi岛。以花蜜和节肢动物为食，常在植被的上层觅食，主要在树冠层。被观察到在开花的树木和寄生植物如槲寄生（Loranthaceae）中觅食，可能为了花蜜；偶尔通过捕获昆虫或短暂飞扑捕食。通常单独或成对出现，有时会形成小群，最多七只。","breeding":"繁殖期在新不列颠岛北岸的晚干季至雨季，南岸的中干季。筑巢期记录在9月底至翌年2月初，活跃的巢穴在2月和10月中旬被发现，筑巢期在4月中旬，幼鸟离巢在7月初。巢为大型杯状，由干燥的藤蔓和草茎制成，内部铺有干燥的棕榈叶条，外部有时覆盖绿色厚叶藤蔓，悬挂在强枝之间，可能位于树枝分叉处，隐藏在树叶中，通常高于地面10米以上。","identification":"与Bismarck Honeyeater的区别在于缺乏苍白的眼环，具有淡色的下体和颈部，以及深色的面部皮肤。","protection":"IUCN：LC（无危）","distribution":"分布于新不列颠岛（俾斯麦群岛东南部），常见于低地至山脚地带。"},{"name":"新爱尔兰吮蜜鸟","english_name":"New Ireland Friarbird","scientific_name":"Philemon eichhorni","overview":"新爱尔兰吮蜜鸟（英文名：New Ireland Friarbird，学名：Philemon eichhorni），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。体型较大的暗色吸蜜鸟，具有显著的长而弯曲的喙，常见于新爱尔兰山区（俾斯麦群岛东北部）的高海拔森林中。","appearance":"体长约32厘米，体重82至116克。上体为单调的深棕色至黑褐色，前额有黑色斑点，头顶、眉纹和后颊区呈现细腻的银色与暗色条纹相间。颈部后方有一圈突出的银灰色羽毛，侧颈处带有黑白斑驳。脸部和颈部有斑点，尾巴长且棕色，尖端白色，尤其是在外侧边缘更宽。下体淡棕色，比上体浅得多，腹部除外，下尾覆羽棕色，尖端灰白色。虹膜颜色从浅棕到深棕色，喙黑色，腿色从蓝灰色到灰蓝色或石板灰色。性别相似，雄鸟可能略大于雌鸟。幼鸟似成鸟，但上体部分羽毛边缘较浅，喉咙部分带黄色。","call":"典型鸣声为三音节的哨音“pu-du-leet”，音调逐渐升高。","habits":"栖息于海拔750米至至少2200米的山地森林中，偶尔会下降至900米以下。被认为是留鸟，关于其饮食和觅食行为的信息尚不清楚。","breeding":"繁殖信息未知。","identification":"与其他吸蜜鸟相比，新爱尔兰吮蜜鸟的长而弯曲的喙和全身暗色系的羽毛是明显的辨识特征。","protection":"IUCN：LC（无危）","distribution":"仅分布于新爱尔兰岛，位于俾斯麦群岛的东北部。","other":"全球数量不明，但在其偏好的海拔范围内被认为较为常见。"},{"name":"白枕吮蜜鸟","english_name":"Manus Friarbird","scientific_name":"Philemon albitorques","overview":"白枕吮蜜鸟（英文名：Manus Friarbird，学名：Philemon albitorques），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。在当地语言Lele中称为'souka'，巴布亚新几内亚Manus省特有种。白枕吮蜜鸟体型巨大，具独特外观，头部全黑，上体灰褐色，与颈部和下体的奶油白色形成鲜明对比。常出现在受干扰的生境，如森林边缘、村落周边和人类居住区，且在人类活动区域较为常见。","appearance":"体长34至37厘米，是一种体型大至非常大的、整洁的吸蜜鸟，喙中等长度，粗壮且略向下弯曲，上喙基部仅有小突起。上体呈丰富棕色，翅膀和尾巴稍暗，头顶带细密黑色条纹的深栗色，颈后有显著的白色绒毛领圈，与下巴和喉咙的白色相接。脸部裸露区域黑色，靠近喙基部转为粉黑色。下体白色到近白色，侧翼和上胸有不同程度的淡褐色洗色，喉部羽毛稀疏，有时可见粉色皮肤。下翼呈淡黄色，边缘和尖端深色。虹膜深棕色，喙黑色，下喙基部带粉色调，腿蓝灰色。性别相似，雄鸟可能比雌鸟大。幼鸟描述未详。","call":"鸣声特征明显，频繁发出，由2至5个响亮快速的音符组成的重复欢腾短语，如“chick-ou cou”、“cou, cou”或“tchau-ka-ka”，前2至3个音符音调下降，其余音符音调相似。最常见的是单鸟发出的响亮‘chauka’叫声，或是在领土争执中由鸟儿发出的‘chaukapowe’叫声。此外还有类似鹦鹉的尖叫声、类似家禽的大笑声，以及较轻的单个尖锐鼻音。已观察到二重唱，第一只鸟发出‘chook ook’的短语，另一只则发出尖锐的‘arrrk’声，最后由第一只鸟发出疯狂的‘choong’声结束。","habits":"偏好受干扰的生境，包括森林边缘、城镇花园和村落附近，以及其它人类居住区；在次生林和红树林中较少见，在封闭森林中更为罕见。通常单独或成对出现，或形成小群，性格好斗，对于开花树的保护极具攻击性。取食花树的花蜜，推测亦食昆虫。活动时嘈杂、活跃且显眼。","breeding":"筑巢活动记录于三月中旬、八月初和十一月初，以及七月中旬正在筑巢的情况。巢为植物材料制成的大型杯状结构，通常置于细枝分叉处的中等高度。","identification":"其独特的头部全黑、上体灰褐色与下体奶油白色的对比，以及颈部的白色绒毛领圈是识别白枕吮蜜鸟的关键特征。在所限范围内独一无二。","protection":"IUCN：LC（无危）。白枕吮蜜鸟在其微小的全球范围内普遍至非常普遍。有人认为，随着人类殖民、定居和Manus岛上的开垦活动，其种群数量可能大幅增加，但这对曼岛扇尾鹟造成不利影响，后者现被视为Vulnerable（易危）。","distribution":"分布于Manus岛和卫星岛（新几内亚东北阿德默勒尔蒂群岛，俾斯麦群岛中北部）。主要在低地的受干扰生境，包括森林边缘、村落周边和人类居住区，以及次生林和红树林中较为少见。","other":"白枕吮蜜鸟在当地文化中占有重要地位，被认为是能报时的鸟，与社区生活紧密相关，包括警告蛇类威胁和告知社区近期出生的消息。它在Manus省的旗帜上也有象征性的表现，反映了其对当地的重要意义。"},{"name":"银冠吮蜜鸟","english_name":"Silver-crowned Friarbird","scientific_name":"Philemon argenticeps","overview":"银冠吮蜜鸟（英文名：Silver-crowned Friarbird，学名：Philemon argenticeps），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。主要分布在澳大利亚北部，包括昆士兰州。这大型灰色的吸蜜鸟，具有浅灰色的帽状头部，裸露的黑色面部皮肤，以及长而尖的黑色喙上的小而突出的‘角’。上部呈灰棕色，下部呈淡白色，头部背面的羽毛比背部更浅。","appearance":"成年银冠吮蜜鸟体长25至32厘米，体重介于59至106克之间，雄鸟通常大于雌鸟。其上部为浅棕灰色，头部的前额、顶部和颈背为银白色，颈部后侧和侧面有短束深色基底的银色羽毛。脸部裸露部分为黑色，逐渐尖锐至颈部侧面。下胸至腹面为淡棕色至灰色，尾下覆羽和翼下覆羽为棕灰色。喙和盔甲为黑色，腿为灰黑色至黑色。幼鸟的盔甲仅初具雏形，看起来像是上喙底部的小凸起，颈部后侧的羽毛颜色更深，与上体较暗的棕色一致。","call":"银冠吮蜜鸟非常嘈杂，发出一系列刺耳、不和谐的鸣叫声，包括尖叫声和粗哑的叫声。它们在黎明时分会开始鸣叫，有时在开花树木中的群体叫声几乎震耳欲聋。","habits":"银冠吮蜜鸟主要栖息于热带桉树林和林地，有时也会出现在纸皮树（Melaleuca）和Grevillea树林中，通常有草地层，偶尔有灌木层。它们经常在河流或沿岸林地和森林中被发现，有时与桉树共存，下层植被中有金合欢和Pandanus。它们也出现在城市公园和花园中。它们可能在某些区域内迁移，特别是在昆士兰的Mt Isa附近，9月至1月更为常见，而在北领地的Larrimah地区，旱季期间几乎完全消失。它们的移动往往与食物树的开花有关。","breeding":"繁殖季节为9月至3月，偶尔在7月。雌鸟收集材料并筑巢，有时伴有雄鸟协助，巢由树皮条、树皮纤维、蜘蛛网等构成，悬挂在树的厚横枝上，高度从地面2.8至15米。一窝通常产2至3枚蛋，孵化期为16天，由雌鸟负责，雏鸟由双亲共同喂养。","identification":"与盔吮蜜鸟相比，银冠吮蜜鸟总体上更偏灰色，头部后部的裸露部分呈尖锐形状。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚北部，包括昆士兰州，可能在东北澳大利亚的分布范围正在收缩。","other":"银冠吮蜜鸟以花蜜为主食，同时也会捕食昆虫、蜘蛛，以及食用果实（尤其是无花果）和一些种子。"},{"name":"噪吮蜜鸟","english_name":"Noisy Friarbird","scientific_name":"Philemon corniculatus","overview":"噪吮蜜鸟（英文名：Noisy Friarbird，学名：Philemon corniculatus），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。分布于新几内亚中南部和澳大利亚东部。这种大型的吸蜜鸟以其裸露的黑色头部和独特的‘角’状突起著称，上体暗棕灰色，下体颜色较浅。叫声嘈杂，其中一种叫声被形容为‘四时的钟声’。","appearance":"噪吮蜜鸟体长30-35厘米，是同科中的大型种类。上体为暗棕灰色，下体颜色较浅。头部除颊下和眉毛周围外几乎无毛，黑色的喙上有一个圆形的突出。脚为暗蓝色，眼睛为红色。雌雄羽毛相似，但雄鸟平均略大于雌鸟。幼鸟具有初步的‘角’状突起，上体更棕色，头部和颈部有较多但稀疏的暗色羽毛。","call":"噪吮蜜鸟因嘈杂的叫声而得名，其声音可以非常响亮，几乎令人耳聋。叫声种类繁多，通常为响亮、刺耳且不和谐的鸣声，但歌声有时更为悠扬。叫声包括‘chocka-lock’、‘four o’clock’等多种，以及‘kow-kow-kow’等报警和威胁声。","habits":"栖息于澳大利亚东部的多种生境，包括干燥的硬叶林、公园和花园，尤其在桉树林、箱木和铁皮树森林中常见。在沿海地区，也可见于由班克西亚、卡苏阿里纳和茶树等主导的植被中。在澳大利亚的东南部，部分种群迁徙，飞往北方越冬，春季返回。食性广泛，包括花蜜、昆虫、蜘蛛、果实、勒普和曼纳等，也观察到捕食小鱼和巢中幼鸟。","breeding":"繁殖季节为每年7月至翌年1月，期间可能养育一至两窝雏鸟。巢为大而深的杯状结构，外围向外翻，由树皮和草构成，通常位于离地面1至3米处，位置隐蔽。雌鸟产卵2至4枚，偶尔5枚，卵长33毫米，宽22毫米，颜色为棕粉红色或偏紫色，表面有暗黄色或浅粉红色的斑点。","identification":"与同属其他物种相比，噪吮蜜鸟的显著特征是其完全裸露的黑色头部和喙上的圆形突起。叫声独特，易于通过声音辨识。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚中南部和澳大利亚东部，包括维多利亚州的Lakes Entrance和Murray河谷北至昆士兰州的Cape York半岛。在新几内亚，限于岛屿南部的Trans-Fly地区，局部地区数量众多。","other":"在澳大利亚某些地区，由于食用商业种植的水果，如葡萄和浆果，可能与人类发生冲突，被视为害鸟。"},{"name":"新喀吮蜜鸟","english_name":"New Caledonian Friarbird","scientific_name":"Philemon diemenensis","overview":"新喀吮蜜鸟（英文名：New Caledonian Friarbird，学名：Philemon diemenensis），是雀形目吸蜜鸟科吮蜜鸟属的鸟类。大型、声音响亮的吸蜜鸟，以其长而厚重的喙著称。主要分布在新喀里多尼亚和洛亚尔蒂群岛的大部分岛屿上，拥有典型的僧侣鸟羽毛，大部分呈棕色，翅膀和尾巴颜色较灰，胸部有淡色的羽毛状羽毛。","appearance":"新喀吮蜜鸟体长27-32厘米，雄鸟体重69.5-84克，雌鸟53-62克。喙长且略向下弯曲，无基部突起。头部和颈部主要为棕色，额头、头顶和颈背有深棕色和灰色条纹，下巴和喉咙颜色较浅，后颈有一圈银灰色的羽毛环。背部棕色，肩胛、臀部和上尾覆羽逐渐变为深橄榄棕色。尾羽上部黑色带宽泛的蓝灰色边缘，翼上部黑色带明显的蓝灰色边缘，形成折叠翼上的明显淡色条纹。下体颜色从浅灰棕色到淡褐色，喉咙和上胸中央有一束长而弯曲的白色至银白色细黑条纹的羽毛。下尾和下翼为淡棕色，有稀疏的白色斑点。虹膜红棕色至浅棕色，喙黑色，腿蓝色至深灰棕色。雌雄羽毛相同，雄鸟略大于雌鸟。幼鸟颜色较浅，缺乏成鸟喉咙和胸部的特化银白色羽毛。","call":"新喀吮蜜鸟的声音多样而响亮，是岛上黎明合唱的重要组成部分，包括下降的口哨声、追鸟时的粗糙摩擦声和响亮的‘hee-haw’声。","habits":"新喀吮蜜鸟常见于森林中，但主要栖息在开阔地带，常在人类居住区周围的花园觅食，也会出现在其他受干扰的区域。它们以昆虫、花蜜和果实为食，会探入花朵中吸食花蜜，也被观察到在水面捕捉昆虫。这种鸟大胆、活跃且好斗，经常追逐同类和其他鸟类，包括猛禽、乌鸦（Corvus）和鹦鹉（Psittacidae）。","breeding":"繁殖期为10月至12月，幼鸟在12月被观察到。巢穴是一个厚壁编织的杯状结构，由树枝和树叶制成，直径12-13厘米，内部直径8.5-9厘米，悬挂在树顶的小枝上。每窝产2枚卵，关于孵化期和雏鸟期的信息未知。","identification":"与暗棕色吸蜜鸟相比，新喀吮蜜鸟体型更大，喙明显更长，身体比例更为瘦长。可以通过其独特的叫声和羽毛特征来识别。","protection":"IUCN：LC（无危）。新喀吮蜜鸟在新喀里多尼亚普遍分布，但在洛亚尔蒂群岛的利富岛较为稀少。全球种群数量估计未知。","distribution":"新喀吮蜜鸟主要分布在新喀里多尼亚的格兰德特尔、松树岛和洛亚尔蒂群岛（New Caledonia）。在新喀里多尼亚广泛分布，但在洛亚尔蒂群岛的利富岛较为罕见。","other":"新喀吮蜜鸟在当地被称为‘Koniyou’，源自其一种叫声。"},{"name":"摩鹿加吮蜜鸟","english_name":"White-streaked Friarbird","scientific_name":"Melitograis gilolensis","overview":"摩鹿加吮蜜鸟（英文名：White-streaked Friarbird，学名：Melitograis gilolensis），是雀形目吸蜜鸟科摩鹿加吮蜜鸟属的鸟类。分布于印尼摩鹿加群岛北部的摩罗泰岛、哈马黑拉岛、Kasiruta和Bacan等地。具有显著的白条纹，头部上方呈灰褐色细条纹，眼上具淡色簇毛。","appearance":"这种中大型吸蜜鸟状似修士鸟，长23厘米，雄鸟重约54克。头部顶部为偏白色，上体为褐色至黑色，带有橄榄色色调，翅膀和尾巴呈深栗色。下体暗棕色，有精细的白色条纹覆盖在下巴、喉咙和胸部。眼睛深色，喙和腿呈暗灰色至黑色。性别相似，幼鸟特征未详述。","call":"发出弱音“yip”，粗糙的“chup”声，以及上升、吠叫般的“wit-wit-wit”叫声。","habits":"栖息于低地和山地森林，包括沼泽林、森林边缘、草地和耕作区的残余森林，选择性砍伐的森林和再生森林，以及椰子种植园和红树林。活动高度从海平面到960米（Halmahera）和2130米（Bacan）。以节肢动物、花蜜和小果实为食。通常单独或成对出现，偶尔加入小群。在开花的树木和灌木中觅食，会驱赶其他试图进入其领地的鸟类。","breeding":"9月观察到雄鸟有增大的生殖腺，其余繁殖信息未知。","identification":"与Halmahera Oriole相似，但后者全身呈深棕色，而摩鹿加吮蜜鸟有明显的下体白条纹和白色的头部顶部。在行为上，它更具攻击性。","protection":"IUCN：LC（无危）。在Halmahera较为常见，以前认为分散且很少见到。","distribution":"分布于印尼摩鹿加群岛北部的摩罗泰岛、哈马黑拉岛、Kasiruta和Bacan。自然栖息地为亚热带或热带湿润低地森林、亚热带或热带红树林和亚热带或热带湿润山地森林。"},{"name":"蓝脸吸蜜鸟","english_name":"Blue-faced Honeyeater","scientific_name":"Entomyzon cyanotis","overview":"蓝脸吸蜜鸟（英文名：Blue-faced Honeyeater，学名：Entomyzon cyanotis），是雀形目吸蜜鸟科蓝脸吸蜜鸟属的唯一物种，与Melithreptus属的吸蜜鸟亲缘关系最近。成鸟体长约29.5厘米，头部黑色，喉部有白色条纹，最显著特征是成鸟具蓝色裸露面部皮肤，幼鸟则为黄色或绿色。广泛分布于澳新界的新几内亚中南部、澳大利亚北部和东部。","appearance":"体型较大，长度在26至32.3厘米之间，体重雄鸟约110.5至135克，雌鸟约94.1至118.8克。拥有强壮弯曲的喙，圆形的宽翼，中等长度的尾巴。成年鸟上身橄榄色，下身白色，头部黑色，带有白色颈纹，两侧有显著的蓝色裸露面颊皮肤。幼鸟相似，但裸露皮肤呈黄色或绿色，上身带橄榄棕色，下身白色。雄雌羽毛相似，雄鸟体型大于雌鸟。","call":"早晨的第一批鸣叫者，全天发出重复的、哀怨的‘woik’或‘queet’声，音调上升，黎明时也会发出响亮的‘weet！weet！weet！’声。此外，还发出尖锐的嘶鸣、喵喵声或责骂声，以及‘hwit hwit’叫声和喂食伴侣或雏鸟时的柔和啾啾声。","habits":"常见于开阔的森林和林地，尤其是河流旁的环境。主要栖息于干燥的硬叶林地，包括开阔的灌木林，常与桉树、Callitris或Casuarina混合生长。也出现在城市公园、花园和高尔夫球场。饮食以昆虫为主，辅以花蜜和果实，偶尔在地面觅食。群居、活跃、好斗。","breeding":"繁殖季节从四月至十二月，通常每年两窝。巢由双亲共同建造，使用树皮条、叶子、树枝和茧，内部衬以细树皮、草、植物绒毛和羊毛。巢建于树叉中，有时利用旧巢或侵占其他鸟类的巢穴。每窝产两枚蛋，偶尔三枚，仅雌鸟孵卵，孵化期16至17天。双亲和可能存在的辅助鸟共同喂养雏鸟。","identification":"与Melithreptus属的吸蜜鸟相比，蓝脸吸蜜鸟体型更大，羽色更鲜艳，面部裸露皮肤面积更大。亚成鸟与成鸟的主要区别在于面部裸露皮肤的颜色。在同属内无明显亚种差异。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚中部至南部，澳大利亚北部至东部，包括昆士兰、新南威尔士州、维多利亚州和南澳大利亚州的部分地区，海拔从海平面至850米，偶尔可达1000米。","other":"曾被视为果园害鸟，有记录显示数量在某些地区有所波动，但在其他地区稳定。"},{"name":"黑颏抚蜜鸟","english_name":"Black-chinned Honeyeater","scientific_name":"Melithreptus gularis","overview":"黑颏抚蜜鸟（英文名：Black-chinned Honeyeater，学名：Melithreptus gularis），是雀形目吸蜜鸟科抚蜜鸟属的鸟类。澳大利亚特有种。两个亚种的外观显著不同。分布于澳大利亚北部至东部地区，包括西北部的金伯利、皮尔巴拉、大桑迪沙漠、北部吉布森沙漠，穿过北领地的顶端和卡奔塔利亚湾地区，至昆士兰的约克角半岛，向南延伸至新南威尔士州的中央河流区。","appearance":"体长14至16.5厘米，体重15至20克（雄鸟），16.1至20.2克（雌鸟）。头部呈黑色，颈背及喉部有蓝色裸露皮肤，眼周皮肤颜色从淡绿色至稻黄色。背部橄榄绿至黄绿色，腹部偏白色，胸及两侧灰褐色。翼及尾羽主要为棕色，下尾覆羽灰棕色。初级飞羽、次级飞羽及尾羽边缘有黄橄榄色。幼鸟比成鸟更暗淡，头顶呈棕色，眼周皮肤暗蓝色，上体橄榄棕色，下巴黑色逐渐变为喉咙的棕色，胸部棕色渐变为腹部的白色。","call":"以响亮的昆虫般叫声首先被发现，重复的“chir chir chir chir”声，清脆悦耳。也会发出尖锐的‘chee-chee’、‘creep-creep-creep’及‘chip-chip-chip, chur-chur-chur-chur’声音，有时在飞行中发出。","habits":"栖息于高大的开阔林地，如桉树（Eucalyptus）和血木（Corymbia）树林，或以纸皮树（Melaleuca）、桉树或金合欢为主的河岸植被。偏好有水道附近的干燥硬叶林。以花蜜和昆虫为主食，偶尔食用蜜露和种子。","breeding":"繁殖季节从1月到8月，偶尔至10月初。通常合作繁殖，有时单独繁殖。巢杯状，由纤维状树皮编织，内部铺以毛发或羊毛，悬挂在高树冠中，隐藏于叶丛中。每窝产2-3枚卵，孵化及育雏由双亲和辅助者共同承担。","identification":"与金色背亚种（laetior）的区别在于背部颜色、下巴黑色面积、胸部颜色、翅膀颜色及眼周裸露皮肤的颜色。金色背亚种背部明亮黄色，下巴黑色较小，胸部更偏灰色白色，翅膀颜色较浅，眼周皮肤黄绿色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括澳大利亚北部和东部，从西澳大利亚的西北部至昆士兰的东北部，南至新南威尔士州的中央河流区。","other":"曾被认为与金色背亚种为同一物种，后确认为两个独立亚种。"},{"name":"坚嘴抚蜜鸟","english_name":"Strong-billed Honeyeater","scientific_name":"Melithreptus validirostris","overview":"坚嘴抚蜜鸟（英文名：Strong-billed Honeyeater，学名：Melithreptus validirostris），是雀形目吸蜜鸟科抚蜜鸟属的鸟类，特有于澳大利亚塔斯马尼亚州和巴斯海峡岛屿。拥有中等体型，黑色头冠，眼后有一白色带纹，背部橄榄绿色，下体灰褐色，腿脚鲜黄。成鸟喙部漆黑，而幼鸟则呈亮黄色。栖息于成熟湿润森林，冬季会迁至较干燥环境。","appearance":"体长约15厘米，体重介于23.5到30.5克（雄鸟）和17.5到28.5克（雌鸟）。头部顶侧和颈后具黑色盖帽，眼上方有淡蓝至蓝绿或淡绿色裸皮弧线，宽阔的白色新月形带纹横跨颈背。喙下部至颈背有明显白带渐变为象牙色。上体大部分橄榄灰色，杂以橄榄绿斑点，臀部和尾上覆羽更鲜亮且均匀的橄榄色。尾羽暗橄榄色，上翼大部灰褐，初级飞羽深褐，边缘微泛橄榄色（新鲜羽毛）。下体浅棕灰色，下尾棕灰色，下翼棕色，边缘宽大棕色。虹膜红棕色，喙和口腔黑色，腿脚棕色至脏粉色。两性羽毛相似，雄鸟体型大于雌鸟。幼鸟类似成鸟，但具暗褐色头冠，柠檬黄色颊部和颈背带纹，橄榄绿斑点延伸至肩至颈后，初级飞羽边缘和尖端显着橄榄色，喙棕色，前端渐变为橙色，口腔橙色且肿胀，虹膜深棕色至红棕色，眼上方裸皮最初缺失，后发育小块淡蓝色区域，眼眶环橙色，腿脚橙色至暗粉。","call":"发出连续响亮的短促尖锐‘cheep’声，可单发、双发或连串急促。轻柔的‘cheep’声在筑巢时作为联络呼叫，但在其他时间不会发出。其他叫声包括在警戒或保卫领地时的粗厉‘churr’声，以及在附近发现猛禽时的尖锐哨声。","habits":"主要栖息于成熟的湿硬叶林，包括山桉树或高山桉树林，特别是在有硬叶灌木或温带雨林下层植被的沟壑。常见于干硬叶林，特别是在冬季，也见于南极山毛榉、胡安松、芹菜顶松或黑木等主导的温带雨林。有时出现在公园和花园中。","breeding":"繁殖季节主要在晚冬至仲夏，7月至次年1月中旬，卵记录在8月至12月，雏鸟记录在8月中旬至9月初。偶尔合作繁殖，但细节未知。巢为小型深杯状，通常由树皮条（有时覆盖苔藓）构成，有时也包含草、叶、羊毛和蜘蛛网，内部常铺垫柔软的树皮纤维、植物绒毛、羊毛、毛发、皮毛或纸张，有时无衬垫，外部直径10.2厘米，深度8.9厘米，内部直径6.4厘米，深度3.8厘米；通常悬挂在桉树或树苗枝干上，或在其他树或灌木下层，偶尔在树蕨树冠中，通常位于巢植物的外层枝叶或顶部的外枝和细枝上，距地面2至11米（平均4.6米）。每窝产卵3至4枚，通常为3枚；孵化和喂养巢雏通常由双亲共同承担；无关于孵化期和雏鸟期持续时间的信息。巢可能被苍鹰寄生。","identification":"与同属其他物种相比，坚嘴抚蜜鸟具有更强壮的喙部，头部黑色，颈背有明显的白色带纹，以及腿脚的鲜黄色。在塔斯马尼亚，其分布和觅食模式与黑头抚蜜鸟很少重叠。","protection":"IUCN：VU（易危）","distribution":"分布于澳大利亚塔斯马尼亚州和巴斯海峡岛屿（King Island、Flinders Island、Cape Barren Island）。","other":"历史上，分子标记显示坚嘴抚蜜鸟与棕色头抚蜜鸟和黑颏抚蜜鸟的共同祖先分离于670万至340万年前。"},{"name":"褐头抚蜜鸟","english_name":"Brown-headed Honeyeater","scientific_name":"Melithreptus brevirostris","overview":"褐头抚蜜鸟（英文名：Brown-headed Honeyeater，学名：Melithreptus brevirostris），是雀形目吸蜜鸟科抚蜜鸟属的鸟类。分布于澳大利亚西南部、南部至中东部地区。其特征是头部棕色，眼周有奶油色或橙色裸皮斑块，背部橄榄褐色，腹部淡色，腿脚橙色。以昆虫为主食，同时摄取花蜜。","appearance":"体长11.5-14厘米，体重因亚种而异，介于11-20克之间。头部顶部和侧面覆盖着暗棕色的帽子，眼睛周围有裸露的奶油黄色皮肤，形成明显的半圆形颈带。上身呈暗橄榄绿色，下体为缓冲白色，带有淡红棕色的洗色。喙黑色，腿部浅棕色至棕灰色。","call":"发出尖锐、不悦耳的中高音调‘chip’声，常在觅食或飞行时重复呼叫，亦能发出急促的‘chip-chip-chip...’声。","habits":"栖息于干燥开阔的桉树林和灌木丛，活跃于小群体中，主要在树冠层觅食，偏好在成熟桉树上寻找食物。以昆虫、蜘蛛、花蜜和露水为主要食物来源。","breeding":"繁殖季节主要在晚冬至仲夏，通常双窝繁殖。巢建在树梢的外叶中，呈深杯状，由细长的树皮条和草编织而成，内部衬有毛发、羽毛等软材料。每窝产卵2-3枚，孵化和喂养由双亲及辅助鸟共同承担。","identification":"需与幼年白颈抚蜜鸟区分，后者缺乏颈部的苍白半环。不同亚种在大小、羽色深浅及头冠的灰棕色鳞片上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚的西南部、南部及中东部地区，包括昆士兰州中部至南部、新南威尔士州中央和东部、维多利亚州、南澳大利亚州东部以及埃yre半岛。","other":"已知的寄生巢穴者包括淡色杜鹃、扇尾杜鹃、闪亮青铜杜鹃及可能的霍斯菲尔德青铜杜鹃。"},{"name":"白喉抚蜜鸟","english_name":"White-throated Honeyeater","scientific_name":"Melithreptus albogularis","overview":"白喉抚蜜鸟（英文名：White-throated Honeyeater，学名：Melithreptus albogularis），是雀形目吸蜜鸟科抚蜜鸟属的小型鸟类，原产自新几内亚和澳大利亚东部与北部地区。其显著特征为黑色顶冠，橄榄绿上体和白色下体，眼周有白色皮肤环带，颈背具白色条纹。","appearance":"成鸟体长11.5至14.5厘米，重10至15克。头部顶部、侧面及颈背覆以整洁的黑色帽状羽毛，眼上方有白色至淡蓝白色的裸露皮肤弧线，形成明显的白色新月形颈带。下颈黑色延伸至胸部侧面，似小黑刺。背部大多呈橄榄绿色，臀部较亮。尾羽上覆羽和尾羽大多呈橄榄黄色，闭合时中央较暗，展开时侧边橄榄色更显。翅膀橄榄棕色，飞羽边缘橄榄绿色，折叠翼时形成醒目面板。下巴、喉咙及下体（除上胸侧面）均为白色。下尾灰褐色，下翅略带白色，有宽大的棕色边缘和尖端。虹膜红棕色，喙和口裂黑色，腿粉红色带深棕色调。雌雄羽毛相似，雄鸟体型大于雌鸟。幼鸟头颈部淡棕色，头部侧面对比鲜明的深棕色，仅有初步形成的偏白色颈带，眼上弧线淡蓝色，上体淡棕色，外侧大覆羽有较淡的棕色边缘和尖端，喙黑棕色，下颌基部有大型淡橙色部分，口裂肿胀且淡橙色，虹膜暗棕色。","call":"记录了多种叫声。","habits":"栖息于各种森林类型，偏好靠近溪流或河流的地带。常见于开阔的桉树森林和林地，伴有草本或灌木层，也出现在低地河流边的桉树林，或密集的河流和沿海纸皮树森林。在半干旱地区常与河流相关联，偶尔出现在干燥的林地或草原。有时在公园和花园中可见。在北领地，相比非河流植被，更频繁出现在河流植被中，与高降雨区的河流区域相关联，拥有丰富的纸皮树和竹子，但也占据覆盖较多草地而少Pandanus、纸皮树或雨林植被的河流区域，距离河流相对较远。在新几内亚，栖息于草原林地，主要为桉树主导的群落，较少见于纸皮树主导的群落，偶尔进入雨林边缘；分布于低地和山麓，海拔从海平面至450米，但在索格里高原可达800米。以昆虫为主食，也摄取蜘蛛和花蜜，如桉树、纸皮树、Grevillea的花蜜。在所有层次觅食，主要在外围树叶和树木上部花冠的花朵中；偶尔在树枝或树干上，下层灌木丛中，或寄生植物中觅食。通过探花取蜜，通常从叶子或花朵中捡食节肢动物；有时倒挂觅食或悬停捕食外围树叶的食物，很少在空中掠食。非常活跃和嘈杂。","breeding":"在新几内亚，巢中有雏鸟记录于10月中旬，幼鸟于10月和4月被观察到，表明繁殖可能发生在旱季中期至后期，以及雨季末期（可能为双峰模式）。在澳大利亚，繁殖记录从4月至10月在北部，全年除2月外（主要在冬季至仲夏）在东部，新南威尔士州从7月至1月产卵。通常是单独繁殖，但有证据表明偶尔会合作繁殖。巢呈杯状，通常由纸皮树皮制成，用蛛丝绑定，有时使用草，较少情况下使用叶子、羽毛、蛛卵囊、绒毛或合成纤维，外部直径5.7至6.4厘米，深度5.1至5.7厘米，内部直径4.4至6.4厘米，深度3.8厘米；通常悬挂在细枝，有时水平叉枝或悬挂叶中，有时在外围枝条，位于高树（常为桉树或纸皮树）中，离地面1.4至20米（平均7.5米）。一窝通常有2枚卵；孵化期至少13天；雏鸟由两性喂养，育雏期至少14天；幼鸟由双亲喂养。巢穴可能被淡色杜鹃和灌丛杜鹃寄生。","identification":"与西白颈抚蜜鸟和白颈抚蜜鸟相似，但后者分别具有不同的地理分布和眼部特征，如白色眼斑和红色眼斑，帮助区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚中南部、东南部和澳大利亚北部、东北部。"},{"name":"白颈抚蜜鸟","english_name":"White-naped Honeyeater","scientific_name":"Melithreptus lunatus","overview":"白颈抚蜜鸟（英文名：White-naped Honeyeater，学名：Melithreptus lunatus），是雀形目吸蜜鸟科抚蜜鸟属的鸟类。中等体型的吸蜜鸟科鸟类，分布于澳大利亚东部和东南部，从昆士兰中东部到南澳大利亚东南部。该鸟以头部黑色、颈部白色带状标记及眼周红色皮肤为显著特征。","appearance":"成鸟具有黑色顶冠，覆盖头顶、侧面及颈后，眼上方有一弧形明亮橙红色裸皮，短而呈白色新月形状的颈带；上体和尾羽橄榄绿色，尾部具褐色边缘；翼上多为橄榄棕色，翼盖和飞羽边缘橄榄绿；下体白色，胸侧及胁部暗灰棕色，尾下覆羽淡棕色，翼下白色带棕色边缘；虹膜棕色；喙及口裂黑色；腿脚棕至黑色，常带有橙色。雄鸟比雌鸟大，但羽毛相似。幼鸟头部顶部和颈后部呈棕色，面部黑色加深，眼上方裸皮淡棕色至浅橙色，颈带较窄且颜色偏黄，上体多为棕色，下体灰白色，喙呈暗橙色，上喙前端灰黑色。","call":"常见叫声为半哨音半嘶声的连续‘sherp-sherp-sherp’或‘tserp-tserp-tserp’，全天频繁发出。还有上扬音调的单音节叫声，高音略带哀伤的昆虫般‘chip’、‘tsip’、‘tsit’或‘twit’，以及领土宣告的‘joe-joe-joe’。","habits":"栖息于开阔的桉树森林和灌木丛，偏好干燥硬叶林或桉树林，偶尔出现在城市花园和街道。部分迁徙，部分定居，随季节变化有规律的迁徙和分散。以昆虫和花蜜为主食，偶尔食用露水和蜜露，觅食高度通常在9.6米左右，主要在树冠层搜索食物。","breeding":"繁殖期从8月至1月，可能两次繁殖。巢由雌鸟单独建造，杯状或袋状，悬挂于树冠外层枝叶间，高离地面0.2至40米。每窝产2至3枚蛋，平均2.67枚，孵化期约10至14天，幼鸟由双亲共同喂养，辅以辅助鸟，巢期约14至16.5天。巢可能被寄生。","identification":"与白喉抚蜜鸟和黑颏抚蜜鸟外观相似，但可通过眼周红皮和颈带区分。幼鸟与成鸟在颜色上有明显差异。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚东部和东南部，从昆士兰中东部至南澳大利亚东南部，包括维多利亚和南澳大利亚东南部的袋鼠岛。","other":"在一些地区，由于其他物种的移除，白颈抚蜜鸟会进入空缺的生态位觅食。"},{"name":"西白颈抚蜜鸟","english_name":"Gilbert's Honeyeater","scientific_name":"Melithreptus chloropsis","overview":"西白颈抚蜜鸟（英文名：Gilbert's Honeyeater，学名：Melithreptus chloropsis），是雀形目吸蜜鸟科抚蜜鸟属的鸟类。原生于澳大利亚西南部的桉树林区。其特征为橄榄绿上身，白色下身，头部黑色，眼后有白色斑块，颈部有白色新月形标记。","appearance":"西白颈抚蜜鸟体型中等，橄榄绿色覆盖上身，腹部至尾巴底部为白色。头部、颈背及喉部呈黑色，眼后具有一白色斑块，颈背有白色新月形标记。喙为褐色至黑色，眼睛呈暗红色。雌雄羽毛相似，幼鸟则呈棕色，喙黄色。成年鸟与白颈抚蜜鸟极为相似，仅在眼周裸露部位颜色、喙及跗跖长度上有细微差别。","call":"西白颈抚蜜鸟发出刺耳的摩擦声叫声，还有连续的单音节tsip声。","habits":"栖息于开放的桉树森林和灌木林，主要活动于冠层，偶尔会到地面觅食。食物以昆虫为主，也摄取花蜜、甘露、蜜露和树胶。觅食高度平均为7.7米，多在高处的树叶和花朵中搜寻食物。","breeding":"繁殖季节为9月至翌年2月，筑巢于树冠中，巢由草、树皮或蜘蛛网编织而成，通常悬挂于高处的树叶间。每窝产卵2-3枚，孵化期约14天，雏鸟孵化后由双亲共同喂养，离巢期亦约为14天。","identification":"与白颈抚蜜鸟区别在于眼周裸露部分的颜色、较长的喙和跗跖，以及整体略大的体型。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西南部，从Moora向北，穿过jarrah森林带至Broomehill，Stirling山脉及沿海至Stokes Inlet。","other":"曾被视为白颈抚蜜鸟的亚种，现确认为独立物种。"},{"name":"黑头抚蜜鸟","english_name":"Black-headed Honeyeater","scientific_name":"Melithreptus affinis","overview":"黑头抚蜜鸟（英文名：Black-headed Honeyeater，学名：Melithreptus affinis），是雀形目吸蜜鸟科抚蜜鸟属的鸟类。中型吸蜜鸟科鸟类，其最显著特征是全黑头部与眼周蓝白色的裸露皮肤。分布于澳大利亚塔斯马尼亚州、Bass海峡岛屿及周边地区，偏好干湿混合的硬叶林生境。","appearance":"黑头抚蜜鸟体型小，约14厘米长，雄鸟体重14-17.5克，雌鸟略轻。头部全黑，与白色下体形成鲜明对比，仅眼部有一圈蓝白色裸露皮肤。上身橄榄绿色，尾羽较短。幼鸟头部为橄榄棕色，无黑色头部，仅眼周有黑色。两性羽毛相似，雄鸟体型较大。","call":"叫声喧闹，主要发声为连续尖锐的‘pee’声，通常由两个或更多音符组成，全年均可听到，尤其在筑巢期间。此外，还有粗糙的‘shirp-shirp-shirp...’声和柔和的‘chip’声。","habits":"栖息于干湿混合的硬叶林，偶尔出现在开放的桉树林、亚高山森林、海岸灌木丛等地。以昆虫、蜘蛛为主食，辅以花蜜和果实。觅食活动主要在树冠层进行，有时倒挂于枝条上。","breeding":"繁殖季节为9月至次年2月，主要集中在11月至1月。巢为深杯状，由两性共同建造，通常悬挂在树冠中，高度2.1至30米。每窝产卵3枚，由双亲共同孵化，孵化期少于21天。雏鸟由双亲共同喂养。","identification":"与同属其他物种相比，黑头抚蜜鸟的全黑头部和眼周的蓝白色裸露皮肤是主要辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚塔斯马尼亚州及Bass海峡岛屿，包括King岛和Furneaux群岛组。在塔斯马尼亚州广泛分布，但在西南部较为罕见。","other":"与坚嘴抚蜜鸟有时共栖，但因觅食习性的差异，两者很少发生竞争。"},{"name":"肉垂吸蜜鸟","english_name":"Polynesian Wattled Honeyeater","scientific_name":"Foulehaio carunculatus","overview":"肉垂吸蜜鸟（英文名：Polynesian Wattled Honeyeater，学名：Foulehaio carunculatus），是雀形目吸蜜鸟科肉垂吸蜜鸟属的鸟类。属于吸蜜鸟科。其特征为中等体型，灰橄榄色，喉部、背部和翅膀带有橄榄色调，最显著的特征是从喙基到颈部的大块鲜黄色肉垂。分布于太平洋中央岛屿，包括美国萨摩亚、斐济、萨摩亚群岛、汤加和瓦利斯及富图纳群岛。自然栖息地包括热带低地湿润森林、红树林和热带山地湿润森林。","appearance":"成年肉垂吸蜜鸟体长约19至21厘米，雄鸟重约34克，雌鸟约28克。全身暗橄榄色，头部和颈部有黑色斑点，背部和肩羽模糊或微有条纹，黄皮肤从嘴角延伸至下颚处的肉垂。眼下方有一黄色羽毛带，绕过耳羽后方，上耳羽部分有暗橄榄灰色小斑。臀部和尾上覆羽呈棕色至橄榄灰色，翼和尾深橄榄褐色至深褐色，翼羽和初级飞羽边缘呈橄榄黄色，尾羽边缘亦为橄榄黄色。下体比上体稍淡，橄榄灰色带黄色调，胸部和两胁有淡色斑点。大腿和下尾覆羽淡灰褐色，下翼白色至浅米色，边缘和尖端为淡灰褐色。虹膜深褐色至蓝灰色，眼周橙黄色；喙黑色，嘴角橙黄色；腿蓝灰至蓝灰色，足底黄色。雌雄羽毛相似，雄鸟略大。幼鸟较暗淡，肉垂较小，上体橄榄色较弱，头部和颈部强烈条纹状，下体更淡，胸部强烈斑点状，腹部、臀部和两胁更黄橄榄色。","call":"发出多种响亮、充满活力的鸣叫声，通常是一系列变化的清脆或悦耳的声音，是黎明合唱中的先声之一，偶尔夜间也能听到。常见叫声为连续的'kee-kow'、'ee-aa-oo'或'ke-too, ke-too'，歌曲被描述为'ti-ti-tui-tui-tur-twee'或咕噜的哨声'churwee-churwee-churdle-twee-twur'。当遭遇捕食者如仓鸮时，会发出响亮的冒泡警报叫声。在面对飞行中的捕食者如鹰时，会发出柔和的液体吸吮音，当捕食者飞行时则发出响亮、滚动的钟铃般的叫声。其他叫声包括哨声'ki-ki-ki-ki-ki-ki'，各种音乐或尖叫哨声，责骂和啾啾声，短暂、中高音的'cheew'，以及觅食期间间歇性的沉闷'kluk'声。已报告有二重唱：鸟儿通常在同一树枝上，间隔最多1米，重复响亮、圆润、交替的模式。","habits":"广泛栖息于各类环境，包括红树林、沿海开放森林、松林、低地、丘陵和高海拔森林，森林边缘，以及城市、城镇和村庄的花园等人工景观。主要以花蜜为食，但也吃多种节肢动物，尤其是昆虫和蜘蛛，以及一些软果实和浆果；偶尔吃小型蜥蜴，包括壁虎。在开花植物中非常活跃，不断在开花树木和灌木之间飞舞，探查花朵，常倒挂采食；沿枝条搜索节肢动物；也会追逐飞行的节肢动物，包括蛾类。胆大显眼，通常3至4只小群体活动，但也可单独或成对出现，有时在开花植物中形成8至10只的小群，甚至更多，尤其是在非繁殖期。好斗，与同类和其他物种追逐打斗，经常驱赶或追逐Myzomela，尝试保卫花蜜来源免受黑喉红臀鹎侵扰；据报道，它会驱赶牛椋鸟和斑鸠。","breeding":"在萨摩亚全年繁殖，可能有5月至7月和10月至11月的高峰期，筑巢记录于1月至2月，依赖的幼鸟出现在6月中旬，幼鸟在2月和10月，有明确繁殖迹象的标本出现在4月、6月至7月和12月至1月；在汤加，8月有蛋，6月和8月有雏鸟，5月和11月有离巢幼鸟。繁殖季节领土性强，会驱赶大型鸟类远离巢区，并物理攻击小型鸟类，包括红嘴吸蜜鸟。巢穴脆弱而杯状，由细草、藤蔓须、松树针叶、其他纤维和根须编织而成，外部常覆盖蛛网，在湿润森林中有时重重覆盖着绿色苔藓状的苔藓；通常悬挂在1至15米高的树枝横叉处，隐藏在茂密的树叶中；在‘欧阿岛（汤加）的13个巢中，平均高度为3米，其中9个巢位于柑橘树中；有时会重复使用旧巢址，甚至在旧巢的残余之上重建新巢。一窝通常产一枚蛋，有时产两枚；孵化和育雏期未知；双亲共同喂养雏鸟和离巢幼鸟，后者依赖时间较长。","identification":"与卡达乌吸蜜鸟相似，但面部黄色程度远不及后者。可通过体型、鸣叫、行为和分布来辨别。在萨摩亚，不同小岛上的分布差异明显，例如在努乌特勒岛的高大、受保护的森林中最为丰富；在曼诺诺岛的成功森林中比在种植林森林中稍微丰富；而在纳穆阿岛的海滩上的椰子主导植被中较为稀缺。在斐济，最丰富的是在莱凯巴的沿海椰子种植园中。在萨摩亚，无论海拔高低都很丰富；在汤加的瓦瓦乌群岛中，成熟森林或次成熟/受干扰成熟森林中的数量远多于村庄、开阔种植园或木质种植园/早期演替森林。","protection":"IUCN：LC（无危）","distribution":"分布于太平洋中央岛屿，具体包括美国萨摩亚、斐济的劳群岛、萨摩亚的萨瓦伊岛、乌波卢岛及周边小岛，以及汤加群岛。在斐济东部的劳群岛、瓦利斯及富图纳群岛东北部、萨摩亚西部的萨瓦伊岛、乌波卢岛及周边小岛，以及汤加群岛的中南部波利尼西亚区域都有发现。","other":"尽管广泛分布且一般常见或丰富，但在其分布范围内存在一些岛屿上的分布和丰度变化不明，且在许多可能预期出现的岛屿上缺席，包括较大的岛屿，如斐济的瓦托阿岛和卡达乌岛（被取代），以及汤加的北部和南部边缘岛屿。"},{"name":"北肉垂吸蜜鸟","english_name":"Fiji Wattled Honeyeater","scientific_name":"Foulehaio taviunensis","overview":"北肉垂吸蜜鸟（英文名：Fiji Wattled Honeyeater，学名：Foulehaio taviunensis），是雀形目吸蜜鸟科肉垂吸蜜鸟属的鸟类。这种中等体型的吸蜜鸟主要分布在斐济的中北部岛屿，如Vanua Levu、Taveuni及周边小岛，其显著特征是橄榄色的翅膀和脸颊下方明亮的黄橙色肉垂。该物种在椰子种植园和次生林中罕见。","appearance":"成年北肉垂吸蜜鸟体长19至21厘米，上身呈暗橄榄色，头部、颈部、肩部和背部有模糊的黑色斑点。嘴基部有极窄的黄色裸皮，连接到下颚前侧的长而肉质的黄色肉垂。眼下方有一条起始于眼下的黄色羽毛条纹，向上绕过并位于后耳羽后面，包围一小块暗橄榄灰的上耳羽区域。臀部和上尾覆羽呈褐色到橄榄灰色。上翼和尾巴为深橄榄棕色到深棕色，翼覆羽和飞羽边缘为黄橄榄色，形成折叠翼上的对比鲜明的橄榄黄色区域，尾羽也有黄橄榄色边缘。下体颜色比上体略淡，为橄榄灰色带黄色调，下巴和喉咙处略显灰。","call":"发出响亮、悦耳的口哨声和钟铃般的叫声。","habits":"主要栖息于成熟的森林中，偏好热带湿润低地森林、红树林和山地森林。以花蜜为主食，同时也捕食多种节肢动物，尤其在繁殖季节，可能还会摄取软果和浆果，偶尔也会捕食小型蜥蜴。在树冠和次树冠层觅食，偶尔也会在地面活动。活跃的觅食方式包括在开花的树木和灌木间快速移动，探查花朵，有时会倒挂身体。会沿枝条搜索节肢动物，也会追逐飞行中的昆虫。通常以3至4只的小群体活动，但也会单独或成对出现，或在开花植物附近聚集8至10只的小群，甚至更多数量的鸟群，尤其是在非繁殖期。","identification":"与西肉垂吸蜜鸟和肉垂吸蜜鸟相比，北肉垂吸蜜鸟在形态上具有独特的肉垂和羽毛颜色模式。","protection":"IUCN：LC（无危）","distribution":"分布于太平洋的斐济中北部，具体包括Vanua Levu、Taveuni和相关小岛，如Macuata、Qamea、Rabi和Yaqaga。","other":"受到黑喉红臀鹎的攻击，但也会对该物种表现出攻击性。引入的物种似乎没有明显限制其分布。"},{"name":"西肉垂吸蜜鸟","english_name":"Kikau","scientific_name":"Foulehaio procerior","overview":"西肉垂吸蜜鸟（英文名：Kikau，学名：Foulehaio procerior），是雀形目吸蜜鸟科肉垂吸蜜鸟属的鸟类。体型中等，主色橄榄绿，喉部、腹部及脸颊带灰。拥有黑色髭纹及黄色肉垂，眼部淡色，是其显著特征。广泛分布于斐济群岛，海拔可达1450米，常见于热带湿润森林。","appearance":"体长19至21厘米，体重25.2至45.4克。较肉垂吸蜜鸟更暗，面部黄色限于狭窄的髭纹边缘，上覆黑色羽毛，耳羽橄榄灰色，后缘有小片黄绿色。背部深橄榄色，腹部暗色斑点明显。","call":"发出响亮、悦耳的哨声和钟铃般的鸣叫。","habits":"栖息于多种生境，以昆虫和花蜜为主食，偶尔捕食小型脊椎动物如蜥蜴和壁虎，也可能摄食软果和浆果。在树冠层活跃觅食，偶尔地面活动。通常以3至4只的小群体出现，有时单独或成对，非繁殖季节会形成多达数十只的喧闹群落。","breeding":"全年繁殖，每对每年可能抚育两窝以上幼鸟。筑巢于离地1至2.5米的树枝分叉处，巢呈杯状，由根须编织而成，通常含2至3枚白色带暗斑的蛋，双亲共同喂养巢中幼鸟和雏鸟。","identification":"与褐嘴裸吸蜜鸟相比，体型较小，颜色更偏橄榄绿而非黄色。","protection":"IUCN：LC（无危）","distribution":"分布于斐济西部和中部的Yasawa和Mamanuca群岛，Viti Levu岛，Vatulele，Beqa，Lomaiviti群岛（包括Ovalau），Yasayasa Moala群岛。","other":"与黑喉红臀鹎存在冲突，但也能对其发起攻击。"},{"name":"白耳吸蜜鸟","english_name":"White-eared Honeyeater","scientific_name":"Nesoptilotis leucotis","overview":"白耳吸蜜鸟（英文名：White-eared Honeyeater，学名：Nesoptilotis leucotis），是雀形目吸蜜鸟科白耳岩吸蜜鸟属的鸟类。这种中型吸蜜鸟以其橄榄绿的身体、黑色头部及醒目的白色耳斑而著称。分布于澳大利亚西南部、南部和东部，尤其偏好存在桉树的干燥森林和灌木丛生的环境。","appearance":"白耳吸蜜鸟拥有明亮的橄榄绿色上体和较浅的黄橄榄色下体，头部顶部呈灰色，黑色侧面延伸至颈部、下巴、喉咙和上胸，包围着显著的大型白色耳斑。幼鸟缺乏成年个体的灰顶冠和脸部黑色。成鸟翅膀边缘呈橄榄黄色，尾巴上部有淡黄橄榄色的侧边，下体有暗灰色斑点。雄鸟和雌鸟在外表上相似，但雄鸟体型较大。幼鸟比成鸟更暗淡和棕色，头部和后颈为深橄榄色，面部和围嘴处为暗褐色至棕灰色，耳羽强烈泛黄。","call":"白耳吸蜜鸟的叫声多样，最常见的是‘chwok，chwok，chwok-whit’和‘kwitchu，kwitchu’，声音深沉而略带金属质感，偶尔发出尖锐刮擦、金属般的‘chwik！’声。","habits":"白耳吸蜜鸟广泛栖息于存在桉树的干燥森林、灌木丛生的环境，偏好成熟植被与密集的下层植被。它们主要以昆虫为食，偶尔也吃花蜜，活跃于地面到树冠的高度，常在树皮下探查昆虫，也会在花朵中探取花蜜。","breeding":"繁殖期从七月持续至三月，巢通常建在低矮的灌木丛中，由干草、细茎、薄片状树皮编织而成，内部衬以柔软的植物材料、毛发或羽毛。每窝产卵2至3枚，由雌鸟单独孵化，父母双方共同喂养雏鸟。","identification":"白耳吸蜜鸟与其他吸蜜鸟种类的区别在于其独特的白色耳斑、橄榄绿色的上体和黑色头部。不同亚种之间主要在体型大小和颜色上有细微差异。","protection":"IUCN：LC（无危）","distribution":"白耳吸蜜鸟广泛分布于澳大利亚，主要见于西南部、南部和东部地区，包括维多利亚州、新南威尔士州、昆士兰州东部以及南澳大利亚东南部。在西澳大利亚州也有分布。","other":"该物种有两已知的亚种，其中N. l. novaenorciae分布在西澳大利亚和南澳大利亚的艾尔半岛，而N. l. leucotis则遍布东澳大利亚从维多利亚州至中央昆士兰州。"},{"name":"黄喉吸蜜鸟","english_name":"Yellow-throated Honeyeater","scientific_name":"Nesoptilotis flavicollis","overview":"黄喉吸蜜鸟（英文名：Yellow-throated Honeyeater，学名：Nesoptilotis flavicollis），是雀形目吸蜜鸟科白耳岩吸蜜鸟属的鸟类。拥有鲜亮的黄色喉部。背部呈橄榄绿色，头部和胸部为灰色，主要分布于澳大利亚塔斯马尼亚州及其周边岛屿，常见于各种森林和林地环境。曾被视为果园害鸟。","appearance":"体长20至23厘米，重18至40克。雄鸟和雌鸟的羽毛相似，但雄鸟体型更大。上体为鲜艳的橄榄绿色，头部和颈部呈暗银灰色，下巴和喉部明亮的黄色。眼后和下方有银色斑块，翅膀和尾羽边缘略带黄橄榄色。下体灰暗，腹部、臀部和两胁带有橄榄色晕染，全身散布着深色斑点。尾巴底面暗灰橄榄色，翼下呈淡黄色。虹膜红褐色，喙黑色，腿灰黑色。","call":"叫声响亮有力，主要有八种叫声。'Trill'和'Tonk song'全年皆可听到，尤其在非繁殖季节。'Breeding song'在繁殖季节响起。'Tonk song'为响亮的'吨克'声，有时像哨音；'Breeding song'为响亮的'de-witt'声或旋转的'churuk-churuk...'。","habits":"栖息于干燥和湿润的硬叶林，包括干硬叶林和湿硬叶林，偶尔出现在开阔的硬叶林或亚高山硬叶林中。常在城市公园、花园和保护区出现。以昆虫为主食，也吃花蜜和果实，偶尔食种子。觅食范围广泛，从树冠到地面，主要在大树上觅食，善于从树皮和叶片表面觅食，也会探查松散的树皮下的虫子。","breeding":"繁殖季为晚冬至仲夏，主要在9月至11月，巢由雌鸟建造，通常为小开口杯状，由草和树皮条构成，内部铺满毛发或细草。每窝产2至3枚蛋，孵化期15至17天，仅由雌鸟孵卵。幼鸟由雌鸟喂养，离巢期16天。雄鸟会在幼鸟离巢后至少3周继续喂养。","identification":"与白耳吸蜜鸟类似，但可以通过其特有的黄色喉部和橄榄绿色背部进行区分。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚塔斯马尼亚州和巴斯海峡的岛屿，包括金岛和福尔诺群岛。","other":"历史上，由于在果园中捕食小型水果，如樱桃和醋栗，曾被视为害鸟。"},{"name":"漠澳䳭","english_name":"Gibberbird","scientific_name":"Ashbyia lovensis","overview":"漠澳䳭（英文名：Gibberbird，学名：Ashbyia lovensis），是雀形目吸蜜鸟科漠澳䳭属的鸟类。色彩鲜艳、体型健壮的陆栖鸣禽。以直立的姿态栖息在澳大利亚中部干燥石质平原上。其灰色背部与黄色腹部形成鲜明对比，面部黄色，眼色淡黄至奶油色或白色，与其它种类的䳭不同。分布于澳大利亚南部北领地、昆士兰西南部、南澳大利亚东北部和新南威尔士州西北部。","appearance":"漠澳䳭体长11至14厘米，体重14至20克。雄鸟头顶、耳羽和颈部呈浅灰褐色，前额和耳羽泛黄，黄色的眼纹和眉线；背部粉红棕色带暗褐色斑点；翅膀深棕色，翼上覆羽具宽粉棕色边缘形成翼条；初级飞羽和次级飞羽边缘淡色，尖端有狭窄的白色边缘；尾羽深棕色，末端窄带淡色或白色，最外侧一对尾羽有明显的白色边缘；下颚、喉部和下体黄色，胸侧和胁部有淡粉色洗染；翼下覆羽和腋羽黄白色；虹膜淡黄色至奶油色或白色；喙和口裂黑色或深灰色；腿深灰色或棕色，常带粉色。雌鸟相似，但黄色区域较淡，头部顶部和背部粉红棕色，粉色洗染常延伸至胸部。幼鸟类似雌鸟，但脸颊和眉线较淡，下巴和喉部白色，口裂淡黄色或粉色。","call":"关于漠澳䳭的鸣叫特征，目前信息较少，已知其拥有甜美的歌声，被描述为‘音乐般的喋喋不休’，叫声为尖锐的‘weet-weet-weet’声。此外，它还有报警叫声，由5到6个高音刺耳音符组成，能引发附近漠澳䳭躲避。","habits":"漠澳䳭栖息于植被稀疏的石质或石砾沙漠，常见于非常开阔的灌木草甸和盐碱地，其中可能含有盐角草（Atriplex）、苦参（Sclerolaena）和米切尔草（Astrebla）。它可能部分游荡，一些地区在雨季之后较为常见，干旱期间则稀少。可能有能力进行长途移动，曾有记录在西澳大利亚南部的迷鸟距离最近的常规记录地点超过1000公里。主要食物为昆虫，包括甲虫、蝽象、蚂蚁和毛虫，也会食用草籽和其他植物物质。","breeding":"漠澳䳭的繁殖行为全年均可观察到，但在季节初雨后更为频繁。巢通常建在地面凹陷处或靠近一丛盐角草或草地上，巢材包括枝条、草、树皮和根须，有时含花部或异物如马毛。平均产卵数为2至4枚，蛋色淡粉至浅肉色，大端有红色斑点。雏鸟孵化时为无羽盲仔。","identification":"漠澳䳭与其它䳭属物种相比，具有独特的头部颜色模式，以及直立姿态和地面活动习性。雌雄之间差异不大，主要通过色彩的深浅辨别。幼鸟与雌鸟相似，但脸颊和眉线更淡。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部北领地极端南部、昆士兰西南部至南澳大利亚东北部和新南威尔士州西北部，主要栖息于澳大利亚中东部的干燥石质平原。"},{"name":"绯红澳䳭","english_name":"Crimson Chat","scientific_name":"Epthianura tricolor","overview":"绯红澳䳭（英文名：Crimson Chat，学名：Epthianura tricolor），是雀形目吸蜜鸟科澳䳭属的小型鸟类。其显著特征为鲜艳的红色头部与腹部，灰背黑面罩，白喉部，淡色眼睛，以及黑色带浅色翼条的翅膀。分布于澳大利亚内陆干旱地区，偶尔出现在沿海西部和南部澳大利亚。","appearance":"绯红澳䳭体长约11至13厘米，体重约9至14克。雄鸟繁殖羽时，前额、头顶、颈背鲜红，眼上方、面颊、颈侧暗棕色，上体棕色，尾上覆羽鲜红；上翼主要暗棕色，具窄白缘和宽白色端斑；尾黑色，外缘和端部白色；下体鲜红，下腹、大腿、尾下覆羽白色，有时有红色斑点；翅下覆羽和腋羽淡棕灰色。非繁殖羽雄鸟头顶部和下体红色减少，面部掩蔽色较淡。雌鸟似非繁殖羽雄鸟，但头部、颈部和上胸浅棕色，有时额头和头顶有淡橙色或粉红色。雏鸟类似雌鸟，但尾上覆羽淡橙色，下体缺乏红色或粉色，上翼羽具宽黄褐色缘。","call":"鸣叫声包括柔和的金属声“dik-it-dik-it”和高音哨声，类似“see”或“seet”。当受到惊扰时，会发出快速的“check-check”声。","habits":"栖息于开阔的盐生灌木丛、金合欢林、格里维尔亚、哈基亚和埃雷莫菲拉为主的干旱或半干旱地带，偶尔出现在温带或亚热带区域的草地上。以昆虫为主食，包括甲虫、蝗虫、蝽象、蝴蝶和蚂蚁，同时也吃蛛类、花蜜、果实和种子。通常在地面觅食或在低矮灌木中探查。以小群或最多30只的群体活动，有时与其他种类的䳭混群。","breeding":"繁殖期一般在7月至12月，雨量充沛时可能提前。成对繁殖，双方参与筑巢、保卫巢区、孵卵和育雏。巢呈杯状，由细草、细茎、树皮纤维、羽毛和根须构成，高度从地面0至120厘米（通常不超过40厘米），位于低矮灌木中。每窝产卵2至4枚，孵化期10至14天，雏鸟期9至11天。巢穴有时会被霍斯菲尔德青铜杜鹃寄生。孵化成功率约65%，雏鸟成功离巢率为20%至26%。","identification":"与绯红澳䳭容易混淆的是红头鸲鹟，但红头鸲鹟有黑色身躯、红色胸部和头部，白色翼斑和深色眼睛，而绯红澳䳭有红色冠部和下体、白色喉咙和黄色眼睛，嘴更细长。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚内陆，包括沿海西部和南部澳大利亚，从西海岸到大分水岭，从热带至南部海岸。","other":"绯红澳䳭会在雨量不足时迁移到湿润地带，这种游牧式移动有助于它们寻找最佳的花朵和花蜜资源。"},{"name":"橙澳䳭","english_name":"Orange Chat","scientific_name":"Epthianura aurifrons","overview":"橙澳䳭（英文名：Orange Chat，学名：Epthianura aurifrons），是雀形目吸蜜鸟科澳䳭属的特有种，主要分布在澳大利亚内陆干旱地区，具有鲜明的橙色头部和下体，雄鸟尤为夺目，雌鸟颜色较为柔和。在澳大利亚的干旱和半干旱地带广泛分布。","appearance":"雄性橙澳䳭拥有鲜艳的橙色头部和下体，背部略带黄绿色，尾羽黑色，尾端细白。雌鸟呈灰褐色，腹部偏黄色，喉部无黑色斑块。成鸟体长约10至12厘米，体重约8至13克。幼鸟类似雌鸟，但色彩更为柔和，翅膀和尾巴的边缘较宽。","call":"鸣叫包括清脆的金属声“twang tang”和柔和的“tchek tchek”，以及用于呼唤伴侣的软声“shu-shu-shu”。","habits":"生活在开放的盐碱地、灌木丛和干燥地带，以昆虫为主食，偶尔在低矮灌木上觅食。它们以群居形式活动，经常与其他种类的䳭混群。","breeding":"繁殖期随季节而变，主要在雨季进行，雌鸟筑巢，雄鸟守护领地，孵化期约11天，幼鸟离巢期为10天左右。","identification":"与黄色䳭和绯红䳭相似，但可通过橙色头部和黑色喉部（雄鸟）以及黄色上尾覆羽加以区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚内陆，包括干旱和半干旱地区，偶尔出现在北部热带和沿海地区。","other":"橙澳䳭的迁徙模式与其所在地区的食物供应和气候条件密切相关。"},{"name":"黄澳䳭","english_name":"Yellow Chat","scientific_name":"Epthianura crocea","overview":"黄澳䳭（英文名：Yellow Chat，学名：Epthianura crocea），是雀形目吸蜜鸟科澳䳭属的鸟类。广泛分布于澳大利亚的干旱和半干旱地区，从澳大利亚中北部至西澳大利亚北部，包括一些孤立的亚种群落。其最显著的特征是橄榄色上部与明亮的黄色下部，头部黄色，胸带黑色小斑块。雌鸟颜色较为平淡，下部黄色，面部灰白，眼圈浅色。","appearance":"黄澳䳭体型小巧，长度约11至12厘米，体重仅7至10克。雄鸟在繁殖季节呈现鲜明的颜色，头颈橙黄或亮黄，带有窄黑眉纹；背部橄榄黄色，具细褐条纹；翼羽暗棕，有黄色或黄白色边缘形成明显的翼斑；尾羽黑褐，中央对有黄边，其余有白尖和黄缘；腹部橙黄或亮黄，胸部有独特的黑色新月形标记。雌鸟更素淡，下部黄白，面部灰白，耳羽和窄眉线黄色，无黑胸斑。幼鸟类似雌鸟，虹膜灰色，喙基部较淡灰色或粉棕色。","call":"黄澳䳭的鸣唱高亢悦耳，通常由雄鸟发出，声似‘tee-tsu-tee’或‘pee-ee’，音调变化多端；金属质感的‘tee-tee-tee’在展示飞行时由雄鸟发出。其他叫声包括鼻音‘nang’，以及在断翅展示期间的颤音。","habits":"黄澳䳭栖息于低矮植被环绕的短暂湿地，包括盐沼和淡水沼泽、水井溢流、盐湖、污水处理池和泛滥平原，常见于干旱、半干旱和热带区域。食物主要为昆虫，如蚂蚁、甲虫、蛾类、毛虫和苍蝇，亦食蜘蛛。它们常在湿润地面觅食，也在小型灌木和草丛中活动，有时加入混合物种群体，与同属其他物种共同活动。","breeding":"繁殖记录显示，黄澳䳭在除二月、八月和九月之外的所有月份都有繁殖行为。巢穴为小型杯状，由草或细茎制成，有时含有蜘蛛卵囊或羽毛，内部铺以细根、羽毛、毛发和蜘蛛卵囊，置于距地面高达1.2米的草丛、灯芯草、低矮灌木或林木中，有时位于洪水区。每窝产卵3枚，孵化期未知；幼鸟由双亲喂养，离巢期为11至12天。","identification":"雄性黄澳䳭在繁殖季节的鲜艳色彩使其易于识别，而雌鸟则需通过其特有的黄色下部、灰白面部和缺乏黑胸斑来区分。与非常相似的雌性橙澳䳭主要区别在于淡色虹膜、白色（而非棕色）的翼羽边缘、橄榄灰（而非灰褐）的头顶、耳羽和大部分上部。","protection":"IUCN：LC（无危）。但在某些地区，如昆士兰州的指名亚种种被认为是‘脆弱’，南澳大利亚为‘稀少’；东部昆士兰的macgregori亚种为‘极危’；北领地的tunneyi亚种为‘濒危’。","distribution":"黄澳䳭分布于澳大利亚中北部，包括西澳大利亚北部、昆士兰州沿海附近Rockhampton地区，以及达尔文周边的孤立亚种群落。在西澳大利亚的金伯利地区，局部地区可能相当常见。","other":"黄澳䳭对栖息地的适应性和生存策略使它们能够在极端干旱环境中生存，包括降低代谢率和蒸发失水量的生理适应，以及利用刷舌摄取水分和薄水层的能力。"},{"name":"白额澳䳭","english_name":"White-fronted Chat","scientific_name":"Epthianura albifrons","overview":"白额澳䳭（英文名：White-fronted Chat，学名：Epthianura albifrons），是雀形目吸蜜鸟科澳䳭属的小型鸟类，主要分布于澳大利亚南部，包括西澳大利亚西南部至新南威尔士州中东部和塔斯马尼亚。其最显著的特征是雄鸟的白色脸部与黑色颈带形成鲜明对比。","appearance":"白额澳䳭体长11至13厘米，体重11至17克。雄鸟具有白色的脸部和胸部，与黑色颈带相连，延伸至后脑勺，上体银灰色，翅膀和尾羽上覆羽深棕色，腹部白色。雌鸟头部灰褐色，上体颜色较淡，下体白色或浅灰色，带有模糊的黑褐色胸带。幼鸟类似雌鸟，但头部和上体呈灰褐色或浅棕色，下体白色，胸部有不明显的棕色带纹。","call":"白额澳䳭发出独特的鼻音‘tang’声，类似斑胸草雀的叫声，通常在飞行中发出；有时会发出哀怨的哨声或尖锐的‘whit whit whit’展示飞行叫声。","habits":"栖息于澳大利亚南部的开阔地带，偏好低矮植被覆盖的盐沼生境，如草甸、低灌木丛和不超过1米高的低矮植被环绕的湿地。它们也出现在海滨沙丘、路边植被、农田、高尔夫球场等人类活动区域。主要以昆虫为食，偶尔摄取种子、花蜜或果实。","breeding":"繁殖期为6月至1月，有时会在其他月份繁殖，特别是在湿润条件适宜的情况下。雌鸟单独筑巢，巢为深杯状，由草、细茎、叶、根须等材料构成，一般位于地面1米以下的低矮灌木或草丛中。每窝产卵2至4枚，通常3枚，极少数5枚；双亲共同孵化，孵化期13至14天；幼鸟由双亲喂养，离巢期10至15天。巢穴偶尔被霍氏金鹃寄生。","identification":"雄性白额澳䳭的白色脸部和黑色颈带是其独特标识，雌鸟则头部灰褐色，胸带不明显。与同属物种的区别在于颜色模式和分布区域。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部，从西澳大利亚西南部经南澳大利亚、新南威尔士州到塔斯马尼亚。","other":"白额澳䳭可能因农业开垦而获益，但在新南威尔士州悉尼地区的城市和工业发展中遭受了数量下降。"},{"name":"巨嘴盗蜜鸟","english_name":"Long-billed Honeyeater","scientific_name":"Melilestes megarhynchus","overview":"巨嘴盗蜜鸟（英文名：Long-billed Honeyeater，学名：Melilestes megarhynchus），是雀形目吸蜜鸟科巨嘴盗蜜鸟属的唯一物种。分布于新几内亚和其西部卫星岛屿，栖息于森林内部，从低地至中海拔山区。拥有不成比例的长喙，上体呈棕色，下体灰白，头部带有红色眼睛。常隐秘行动，有时仅见于飞越道路。","appearance":"体型中等，长20-23厘米，体重介于36.3-57克。具有非常长而略重的弯曲喙，上体棕褐色，下体灰白带橄榄色，头部灰色带红眼。雌雄羽色相似，雄鸟体型较大。幼鸟喙较短，几乎直，羽色更暗淡，具亮黄色眼圈。","call":"发出鼻音、嘶哑的下滑音‘reeeeuuuuww！’。","habits":"栖息于原始雨林、河流边高大森林、次生林和其他受扰环境，偶尔出现在城镇和花园。活动范围从低地至海拔1500米的较低山区。主要以小节肢动物、小型蜥蜴、花蜜和偶尔的小果实为食。在植被各层活动，偏好在较低和中间树层觅食。","breeding":"繁殖季节似乎双峰型，从中旱季到早雨季，再次在雨季末。巢为深而厚壁的杯状，由苔藓、根须构成，内衬蕨类植物的叶片。一窝产2枚蛋，孵化期16-19天，雏鸟期14-17天。","identification":"与麦氏吮蜜鸟和茶胸吸蜜鸟相似，但具有更长更细的喙，红色而非暗色的眼睛，缺乏Tawny-breasted的面部条纹。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚和西部卫星岛屿，栖息于亚热带或热带湿润的低地森林和山地森林。"},{"name":"麦氏饮蜜鸟","english_name":"MacGregor's Honeyeater","scientific_name":"Macgregoria pulchra","overview":"麦氏饮蜜鸟（英文名：MacGregor's Honeyeater，学名：Macgregoria pulchra），是雀形目吸蜜鸟科麦氏饮蜜鸟属的鸟类。体型庞大的黑色鸟种，长度可达40厘米，拥有醒目的橙黄色眼囊和黑尖赭色初级飞羽。性别外观相似，雄鸟略大于雌鸟。麦氏饮蜜鸟属下的唯一物种，主要栖息于新几内亚的亚高山森林中。","appearance":"麦氏饮蜜鸟体长可达40厘米，雄鸟体重242至357克，雌鸟190至230克。全身几乎全黑，头部覆盖着显眼的黄色眼囊，额头和眼周的羽毛短而密集，柔软丝滑，身体下方有一层厚厚的绒毛。雌雄羽毛颜色相同，但雄鸟的体型和眼囊略大。幼鸟比成鸟暗淡且棕色更重，虹膜呈深棕色。","call":"麦氏饮蜜鸟发出的声音是快速重复的高音‘jeet’哨声，用于同伴间的联系和警报。还有一种‘pseer’声作为迎接伴侣回归时的问候，会连续多次发出，通常伴随翅膀拍打和尾巴竖起的动作。","habits":"麦氏饮蜜鸟主要栖息于亚高山地带的森林，包括由Dacrycarpus compactus和Libocedrus papuanus两种针叶树主导的环境。它们的活动范围从海拔2700米到4000米，最常见于3200至3500米之间。以果食为主，尤其依赖Dacrycarpus compactus的树脂丰富的果实，当主要食物不可得时，会转而食用其他种类的果实。","breeding":"麦氏饮蜜鸟的繁殖季节大约在7月至2月，筑巢周期与主要食物来源Dacrycarpus compactus的不可预测的结实周期相关联。巢穴为开放且体积较大的杯状，主要由苔藓、植物茎、地衣和少量树枝构成，内部衬有细茎和小叶片。已知一窝只产一枚蛋，孵化和育雏主要由雌鸟承担。","identification":"麦氏饮蜜鸟与烟色饮蜜鸟颜色模式相似，但体型远大于后者。其橙黄色眼囊和赭色翼羽在飞行中尤为明显。","protection":"IUCN：VU（易危）；CITES II级附录物种。在新几内亚的星山地区较为常见，但阿尔伯特爱德华山（Wharton山脉）自1933年后仅有一笔记录，显示其稀有性。","distribution":"麦氏饮蜜鸟分布于新几内亚岛的亚高山森林，从西新几内亚向东延伸至东南新几内亚，主要在海拔2800至4000米的云雾森林和Dacrycarpus森林中被发现。","other":"由于其数量小且持续下降，麦氏饮蜜鸟被IUCN红色名录评估为易危物种。"},{"name":"阿法饮蜜鸟","english_name":"Arfak Honeyeater","scientific_name":"Melipotes gymnops","overview":"阿法饮蜜鸟（英文名：Arfak Honeyeater，学名：Melipotes gymnops），是雀形目吸蜜鸟科饮蜜鸟属的鸟类。分布于印尼西巴布亚的鸟头半岛山区。其显著特征为头部、颈部、胸部及上腹部呈烟黑色至灰黑色，拥有一片环绕眼周的鲜亮黄色裸露皮肤，当鸟受到刺激时，面部斑块会变为鲜艳的红色。","appearance":"阿法饮蜜鸟体型中等，体长约21.5至22厘米，体重范围为48至61.5克。全身暗灰至灰黑色，头部、颈部、胸部及上腹部颜色一致，侧胸至腹部可见独特的奶油色至淡黄色条纹，逐渐过渡至下腹中央的浅赭色。背部颜色由黑灰色渐变为深灰褐色，尾羽上覆羽可能有较淡的尖端或边缘，至少在羽毛新鲜时如此。上尾羽灰黑色，边缘略浅，下尾羽呈浅棕灰色。虹膜颜色为深棕色至红棕色，喙色为黑色至灰黑色或黑褐色，腿色为灰黑色至带褐色或深蓝灰色。雌雄羽色相似，雄鸟平均体型略大于雌鸟。幼鸟特征未详述。","call":"发出连续的‘wee wee wee…’叫声，无论是在栖息还是飞行中均可听到。","habits":"生活在新几内亚的鸟头半岛山脉地区，海拔高度在1200至2700米之间，有时可达3680米。主要栖息于山地森林、森林边缘及本土农业园中。以果实为主食，但也摄取昆虫；曾在一胃中发现种子。在所有层次觅食，主要在树冠层，也会在农业园中的灌木和树木间活动。通常单独行动，或在食物丰富处形成小群。活跃、吵闹且显眼。","identification":"其最突出的特征是环绕眼睛的大型黄色裸露面部皮肤，当鸟受刺激时，面部斑块会变红。没有其他共生的吸蜜鸟具有这种颜色和形状的面部斑块。","protection":"IUCN：LC（无危）；属于限制分布物种，出现在西巴布亚高地EBA（Endemic Bird Area）。虽然了解不多，但在其分布范围内普遍被认为是常见或丰富的。","distribution":"分布于印尼西巴布亚的鸟头半岛（Tamrau Mts, Arfak Mts）和Wandammen Mts的山区，主要栖息于新几内亚西北部的山地森林。"},{"name":"烟色饮蜜鸟","english_name":"Common Smoky Honeyeater","scientific_name":"Melipotes fumigatus","overview":"烟色饮蜜鸟（英文名：Common Smoky Honeyeater，学名：Melipotes fumigatus），是雀形目吸蜜鸟科饮蜜鸟属的鸟类。广泛分布于中央山脉，主要在新几内亚中西部至东南部的山区。其显著特征为暗灰色的羽毛，喉咙和腹部颜色较浅，尤其是胸部边缘的羽毛呈淡色，形成吸引人的图案。最突出的是面部裸露的黄色斑块，形状略显不规则，可变为红色。主要以果实为食，不畏惧人类，常在开阔处栖息。","appearance":"烟色饮蜜鸟体型中等，长21.5-22厘米，雄鸟体重46-68克，雌鸟42-57克。额部、头顶和颈背黑色至棕黑色，逐渐过渡到深灰棕色的头部侧面和颈部以及上体，下巴和喉部颜色更浅的灰棕色；眼周有明亮的橙黄色皮肤斑块，下缘加厚，当鸟激动或倒挂时，斑块可变为鲜艳的红色；上翼和上尾呈烟灰色，翼覆羽有微弱的淡棕色灰色尖端，翼小羽和飞羽边缘橄榄棕色至灰橄榄色；下体深灰棕色至深橄榄棕色，与较浅的喉部形成对比，上胸有极微弱的赤褐色轴纹，下胸至腹部有模糊的淡灰色至浅灰棕色羽毛边缘，形成淡色斑点，大腿淡灰棕色；下尾深灰棕色；下翼粉红至浅黄色，覆羽基部淡灰棕色，飞羽边缘橄榄棕色；虹膜深棕色至红棕色；喙黑色，上颌前端偶尔奶油色；腿板岩灰色至深蓝灰色或棕色。雄鸟和雌鸟羽毛相似，雄鸟体型略大于雌鸟。幼鸟类似成鸟，但上体颜色更偏棕色，下体颜色更暗淡且均匀的灰色，下巴和喉部颜色最浅，缺乏明显的淡色斑点，腿部绿色至橄榄绿色。","call":"烟色饮蜜鸟的叫声包括两音节上扬的哨声“puu-wiii！”或不断重复的尖锐“wik！”音。","habits":"烟色饮蜜鸟栖息于中海拔至高山的原始森林，包括高海拔的苔藓林，森林边缘，二次生长林（尤其是在自然空地中的密集二次生长林），以及受干扰和改变的生境，包括花园。它们的活动范围从750米（奥克蒂迪地区）到4200米（雪山山脉），但很少低于1100米，主要在1400-3400米（物种分布范围内大部分为林线）之间；在东南部可达约2800米。在卡里穆伊山的海拔梯度上，仅幼鸟出现在1100-1370米，主要为雌鸟在2160-2490米，繁殖雄鸟不在1830米以下发现。","breeding":"繁殖季节至少在旱季晚期，产卵时间在9月底和10月初，雏鸟和离巢幼鸟出现时间为8月末至10月末，12月曾听到未见雏鸟的声音。筑巢高度通常为地面以上4.5-12米，位于小树分支末端附近的水平分叉处。巢为大型且略显笨重的悬挂杯状，由长而细的苔藓、少量叶子和其他植物材料构成，少量用长菌丝绑定，外部有时附着腐烂的兰花叶大块，内部铺有粗大的枯叶和蕨类植物或根须。","identification":"烟色饮蜜鸟与其他同属物种的区别在于其独特的羽毛色彩和眼周的橙黄色斑块。与相似物种相比，不存在共存现象。","protection":"IUCN：LC（无危）","distribution":"烟色饮蜜鸟主要分布在新几内亚中西部至东南部的山区。"},{"name":"红脸饮蜜鸟","english_name":"Wattled Smoky Honeyeater","scientific_name":"Melipotes carolae","overview":"红脸饮蜜鸟（英文名：Wattled Smoky Honeyeater，学名：Melipotes carolae），是雀形目吸蜜鸟科饮蜜鸟属的鸟类。以其独特的灰黑色羽毛和显著的红橙色面部裸皮而著称。这种鸟主要分布在新几内亚西部的Foja山脉高海拔森林中，是该地区特有种。","appearance":"红脸饮蜜鸟体型中等，羽毛呈深灰色，边缘略显淡色，腹部颜色稍浅。最引人注目的是其大面积的红橙色面部裸皮，延伸至下方形成垂挂的肉垂。喙部为黑色，与其它Melipotes属物种相比，其面部红色仅在特定情况下显现，且肉垂较小。","call":"红脸饮蜜鸟异常安静，尚未记录到其叫声，这与其它蜜雀有所不同。","habits":"这种鸟不特别羞涩，常在开阔处停栖。主要以果实为食，生活在Foja山脉的蒙特森林中，海拔高度超过1150米。","identification":"在Foja山脉中，没有与其相似的物种共同存在，因此通过其独特的红橙色面部裸皮和垂挂的肉垂可以轻易辨认。","protection":"IUCN：LC（无危）","distribution":"红脸饮蜜鸟仅分布于新几内亚西部的Foja山脉，这里是其唯一的栖息地。","other":"红脸饮蜜鸟是在2005年被国际科学家团队首次发现的新物种，由美国鸟类学家Bruce Beehler带领的队伍在新几内亚岛发现，以他的妻子Carol Beehler命名。"},{"name":"辉饮蜜鸟","english_name":"Spangled Honeyeater","scientific_name":"Melipotes ater","overview":"辉饮蜜鸟（英文名：Spangled Honeyeater，学名：Melipotes ater），是雀形目吸蜜鸟科饮蜜鸟属的鸟类。广泛分布在新几内亚东北部的休恩半岛山区。其显著特征为黑色外表，喉部颜色较浅，腹部点缀着半月形的白色斑点，拥有较大的黄色面部皮肤，受刺激时会变成红色。","appearance":"辉饮蜜鸟体型大，属于该属中最大型，体重约为同类的两倍以上。嘴短而略弯，尾部适中长度。全身羽毛呈缎黑色，眼周有一圈鲜亮的黄色皮肤，下颌和上喉部分灰暗。腹部有大量白色斑点，形状各异，从宽阔的楔形到小而圆的三角形不等。虹膜深棕色至红棕色，喙黑色或灰黑色，腿蓝灰色。雄鸟和雌鸟在外表上相似，但雄鸟可能体型更大。幼鸟特征未详述。","call":"通常较为安静，发出重复的深沉“chut chut”声。","habits":"栖息于海拔约1200米至3300米的山地森林和高大的次生林中，几乎全年居留。以果实为主食，主要在树冠层觅食，通常单独或成对出现，社交性比同类物种更强。","breeding":"关于繁殖的信息尚无报道。","identification":"与休恩寻蜜鸟相比，尽管体型相近，但面部特征有显著差异。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚东北部的休恩半岛山区，具体范围包括Adelbert和Huon山脉。"},{"name":"黄喉直嘴吸蜜鸟","english_name":"Olive Straightbill","scientific_name":"Timeliopsis fulvigula","overview":"黄喉直嘴吸蜜鸟（英文名：Olive Straightbill，学名：Timeliopsis fulvigula），是雀形目吸蜜鸟科直嘴吸蜜鸟属的鸟类。广泛分布在新几内亚的山区，偏好栖息于中海拔森林地带。其显著特征为橄榄色的羽毛与笔直的匕首状喙，拥有明亮的橙色眼睛。","appearance":"体长约13至15厘米，体重介于16至22克之间，性别间体型略有差异，雄鸟略大于雌鸟。全身覆盖着深橄榄色至灰橄榄色的羽毛，腹部颜色稍浅，头部顶部带有棕色调，脸颊和上喉部呈淡灰色，翅膀和尾羽更显橄榄褐色，展开的翅膀上有明显的橄榄黄色边缘。虹膜鲜艳的橙色至红棕色，喙黑灰色至黑色，下颌基部有时呈灰色，腿脚灰棕色。幼鸟羽毛色泽较成鸟更偏灰色，虹膜暗灰至深棕色。不同亚种在羽毛色泽上存在细微差别。","call":"发出持续不断的哀怨或斥责声，表现为‘sreed-sreed-sreed…’或响亮的‘scree scree’，后者在飞行中也会发出。","habits":"栖息于中海拔森林及其边缘，高度通常在1100至2450米之间，有时可达2700米。主要以昆虫为食，通过在低矮植被中搜寻和探查卷曲的叶子来觅食。性格羞怯，常单独活动，偶尔成对或形成由四只左右的小家庭群体，有时加入混合物种群。","breeding":"繁殖期跨越湿季和旱季，巢穴为开放式的杯状结构，外部由干枯的草叶构成，内部则用细根和其他纤维编织，衬以羽毛。确切的繁殖细节尚待研究。","identification":"与灌丛鹪鹩类相似，但黄喉直嘴吸蜜鸟体型略大，羽毛橄榄色而非棕色，眼色更明亮，喙型更为锐利。亚种间在羽毛色泽上存在微妙差异。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚的山区，包括东部高地的1760至2440米海拔区域，以及Gahavisuka省级公园附近高达2650米的地方。"},{"name":"灰喉直嘴吸蜜鸟","english_name":"Tawny Straightbill","scientific_name":"Timeliopsis griseigula","overview":"灰喉直嘴吸蜜鸟（英文名：Tawny Straightbill，学名：Timeliopsis griseigula），是雀形目吸蜜鸟科直嘴吸蜜鸟属的中等体型的鸟类。在新几内亚的低地森林中零星分布，以独特的直而尖锐的喙和暖棕色的外表著称。","appearance":"体长约18厘米，体重介于32至43克之间。雄鸟和雌鸟羽毛相似，上部橄榄棕色，尾羽覆羽带红褐色调，翼羽边缘呈淡白色至淡黄色，下部较淡的红褐色。幼鸟整体呈淡黄色，喙部颜色由深棕至黑色，逐渐向尖端变为奶油色或淡黄色。虹膜颜色从红色到红棕色不等。喙基部和下颌为暗棕色，腿粉色。亚种fulviventris比指名亚种更偏红褐色。","call":"鸣唱是一系列快速下降的升调哨音，叫声为“whip！”音。","habits":"栖息于低地和山脚的原始雨林，偶尔出现在森林边缘和高大的次生林中，海拔高度从海平面至800米。主要以昆虫、果实、花蜜和花朵为食，觅食范围从林下层至树冠层，通常在较低和中层林木中活动。在寻找食物时，会从树叶、树枝、藤蔓、棕榈叶、枯叶和花朵中拾取，也会倒挂探查。常单独或以家庭群（最多四只）活动，常见于混合物种群中，与锈色林鵙鹟或弯嘴鹛共同觅食。","breeding":"繁殖信息了解甚少，似乎在旱季至早雨季繁殖，可能持续至7月末至8月初。已知有幼鸟依赖期的记录。","identification":"与一些鵙鵙或绿褐吸蜜鸟相似，但灰喉直嘴吸蜜鸟的喙更细长且尖锐，眼睛为红色。在混群中通过其独特的叫声和觅食行为区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的低地和山脚地带，分布不连续，零星分布于该区域。"},{"name":"棕斑蚊蜜鸟","english_name":"Rufous-banded Honeyeater","scientific_name":"Conopophila albogularis","overview":"棕斑蚊蜜鸟（英文名：Rufous-banded Honeyeater，学名：Conopophila albogularis），是雀形目吸蜜鸟科蚊蜜鸟属的鸟类。分布于新几内亚南部、中南部、东北部和东南部，以及澳大利亚北部至约克角半岛北部和昆士兰东北部。达尔文郊区生态系统中最常见的小型鸟类之一，尤其在公园和花园中数量众多。","appearance":"体型较小，长约12-14.5厘米，体重9.2-14.5克。头部呈暗珍珠灰色，顶冠有细密的深色条纹，眼周有明显的淡白色环。上体棕色，翼上和尾上稍深，具淡黄色边缘。下体白色，有宽阔但模糊的棕色胸带，沿侧腹延伸。幼鸟缺乏锈色胸带，喙部有粉色。性别在外表上相似，但雄鸟略大于雌鸟。","call":"鸣声复杂而悦耳，包括一两个嘶哑的上滑音，随后是一系列5-8个音符的摇摆式模式。常见叫声为重复上升的'zzheep'或上滑的嘶哑'szweeit'。有时两鸟会交替呼叫，同时结束。","habits":"栖息于河岸纸皮树（Melaleuca）林地、季风雨林、红树林和城市环境。以昆虫和花蜜为食，偶尔食用种子的肉质部分。活动范围广泛，包括树冠、地面和水生植被。通常单独或成对活动，偶尔加入混群。","breeding":"繁殖期全年皆有，高峰期出现在干季中期至晚期和雨季后期。巢由双亲共同建造，形状为深杯状，主要由细条状树皮、草、蜘蛛网等构成。每窝产卵1-4枚，平均2枚，孵化期14-17天。幼鸟孵化后由双亲喂养，离巢期13-15天。一对成鸟一年最多可抚育五窝。","identification":"通过其白色的喉部、橙红色的胸带和灰头、棕色背部以及白色的腹部来辨认。幼鸟特征与成鸟显著不同，缺乏锈色胸带，喙部有粉色。","protection":"IUCN：LC（无危）","distribution":"分布在低地新几内亚，包括沃格尔角西部、塞皮克河、马克汉姆河、上穆萨河，以及从特里顿湾东至横跨弗莱河和弗莱河，以及从科雷马东至米尔恩湾的东南低地。也见于阿鲁群岛、托雷斯海峡的岛屿和澳大利亚北部，从梅尔维尔岛和北领地的顶端南至15°S，东至戈夫半岛，以及格罗特艾兰德岛，向东至昆士兰北部（约克角半岛）。","other":"在1980年代殖民了达尔文的郊区，到1985年已广泛分布且数量丰富。"},{"name":"红喉蚊蜜鸟","english_name":"Rufous-throated Honeyeater","scientific_name":"Conopophila rufogularis","overview":"红喉蚊蜜鸟（英文名：Rufous-throated Honeyeater，学名：Conopophila rufogularis），是雀形目吸蜜鸟科蚊蜜鸟属的鸟类。是澳大利亚北部特有的小型鸟类。其显著特征为红褐色喉咙斑块，白色下体，灰头，棕色背部和黄色翼斑。幼鸟缺乏锈色喉咙斑块，但可能有红色痕迹。红喉蚊蜜鸟通常栖息于河流或水源附近的森林和林地。","appearance":"体长11至14厘米，体重雄鸟8.5至13.9克，雌鸟8.2至13克。体型圆胖，尾巴短小。雄鸟上身淡灰褐色，头部和颈部略浅且更灰色，下体偏白；头部顶部有模糊的暗色条纹或斑点，下颌和喉咙中心呈红褐色，胸部和两侧有淡灰褐色，翅膀和尾部上侧比身体上部稍暗，三级飞羽边缘较窄且苍白，次级飞羽的大覆羽边缘狭窄而暗黄，尾羽和初级飞羽有细黄边；尾下覆羽淡灰色；下翼灰褐色，稍浅于覆羽和初级飞羽基部；虹膜橄榄灰至深棕色；喙黑色，下颚基部蓝灰色，有时喙裂处偏白；腿深灰色或黑色。雌鸟似雄鸟但体型较小，喉咙斑块颜色更淡红褐色且不均匀。幼鸟特征明显，有明显的薄白眼环，头顶无暗色条纹，下巴和喉咙偏白，缺乏红褐色斑块，喙灰色，边缘黄色或粉红色，下颚基部半部，喙裂初期肿胀且黄色；亚成体似成鸟，多数下巴和喉咙偏白或有散在的红褐色斑点，少数与成年雌鸟无法区分。","call":"发出嘈杂的鸣叫音，特别是在觅食或筑巢时；其他叫声包括尖锐、刺耳或烦人的‘zit-zit’声，作为联系或警报，还有沙哑的音调。单句的歌鸣未详细描述；也有飞行鸣叫（描述不完整），首次鸣叫在飞行中，其余在落地后。有时会二重唱。","habits":"栖息于开阔、草地覆盖的灌木林地，以桉树为主，下层散布着灌木和草类。也会出现在河岸的纸皮树或桉树-纸皮树林地，通常伴有金合欢、瓶子刷树和露兜树的灌木层。偶尔在城市公园和花园中出现。红喉蚊蜜鸟的食物主要是昆虫（尤其是蜘蛛）、花蜜（包括来自桉树、水胶树、黄花树、纸皮树）和果实（无花果）。在植被的所有层次中觅食，包括树冠和花朵中，空中，以及地面，尤其在长草丛中。通过从叶子或树枝上捕捉昆虫，或在空中捕捉，有时在水面附近。获取花蜜的方式是探入花朵。单独、成对或小群（最多30只）活动，经常与其他吸蜜鸟混合群或在开花的树木和灌木中出现。","breeding":"繁殖季节至少在7月至3月；记录到的孵化期为7月、9月底和11月至3月，早熟雏鸟在7月初。巢由雌鸟建造，可能仅由雌鸟完成，是一个精致而脆弱的袋子或钱包形状，由草、树皮碎片和枝条松散编织，用蜘蛛网加固，内部衬有草或根须，外部直径5.8至7.8厘米，深度5.2至7.6厘米，内部直径2.5至3.9厘米，深度4.5至6.4厘米；通常挂在树枝叶端的叉上，离地面1.2至10米（平均3.2米）。一窝产2或3枚卵，平均2.8枚；孵化可能仅由雌鸟完成，尽管有说法两性都参与孵化，孵化期13至15天；雏鸟前两天仅由雌鸟喂养，之后由两性共同喂养（雌鸟喂养更多），育雏期12天；双亲喂养离巢雏鸟。巢穴被灌丛杜鹃寄生。","identification":"与其他吸蜜鸟的区别在于其独特的红褐色喉咙斑块，以及在地面觅食的行为，这是吸蜜鸟中独一无二的。雌雄之间可以通过喉咙斑块的颜色和均匀度区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东北部至昆士兰州东南部，包括西澳大利亚州的金伯利地区，北领地的最顶端地区，以及卡奔塔利亚湾南部至昆士兰州北部和东部沿海地区。"},{"name":"灰蚊蜜鸟","english_name":"Grey Honeyeater","scientific_name":"Conopophila whitei","overview":"灰蚊蜜鸟（英文名：Grey Honeyeater，学名：Conopophila whitei），是雀形目吸蜜鸟科蚊蜜鸟属的鸟类。颜色低调、易于被忽视的澳洲内陆特有种，分布于西澳中部至南澳北部的干旱与半干旱地区。","appearance":"灰蚊蜜鸟体长约10.5-12厘米，体重7-11克。上体呈冷灰色，下体较淡，胸部和前侧腹部带棕色调。尾羽和飞羽黑色偏褐，眼周有淡灰色环，尾羽尖端白色，逐渐变为黄褐色。喙短而稍向下弯曲，颜色由灰色至黑色渐变。虹膜棕色，腿脚钢灰色。幼鸟眼周有淡黄色边缘，喉部羽毛浅灰色，带有黄绿色边缘。","call":"常见鸣声为尖锐金属质感的双音节‘chirra-wik-chirra-wik’或‘cre-seek’，类似白腹鹃鵙的叫声，也有微弱的高音颤音或连续的哀怨音符串‘troo-whee, troo-whee’。","habits":"栖息于低矮的金合欢林地和灌木丛，偏好成熟的金合欢群落。有时出现在城镇花园中。以昆虫为主食，也吃花蜜和寄生植物果实。在树冠和灌木丛中觅食，常与黄尾刺嘴莺和西噪刺莺混群。","breeding":"繁殖季节为8月至11月，有时延长至5月。巢为细小松散的杯状，由草茎、毛发和植物绒毛构成，用蜘蛛网固定。每窝产1或2枚卵，孵化和喂养由双亲共同承担。","identification":"与西噪刺莺、黄尾刺嘴莺等相似，但可通过体型、颜色和鸣声区分。红喉刺莺也可能混淆，需仔细辨别。","protection":"IUCN：LC（无危）；但在西澳列为Endangered（濒危）。可能受火灾和外来动物放牧威胁。","distribution":"分布于西澳中西部至北领地中部和南澳西北部，主要在澳洲内陆的干旱和半干旱地区。","other":"由F. Lawson Whitlock首次发现于1903年，正式描述由A. J. North于1910年发表。"},{"name":"斑胸胶蜜鸟","english_name":"Bar-breasted Honeyeater","scientific_name":"Ramsayornis fasciatus","overview":"斑胸胶蜜鸟（英文名：Bar-breasted Honeyeater，学名：Ramsayornis fasciatus），是雀形目吸蜜鸟科胶蜜鸟属的独特小鸟，主要分布于澳大利亚北部，从西澳大利亚东北部至昆士兰东南部。以鲜明的头胸黑色条纹和棕色白色相间的羽毛而著称。","appearance":"斑胸胶蜜鸟体长约13-14.5厘米，体重约12.5克，体型偏圆润，尾巴较短。头部顶部黑色，大胆地镶嵌着白色鳞片状花纹，眉线狭窄而白色，眼前后常带有细微的暗褐色斑点。侧面、下巴和喉咙白色，脸部有狭窄的黑褐色条纹。背部灰棕色，翅膀和尾巴颜色更深，有模糊的黑色条纹。腹部白色，胸部有显著的黑色断续条纹，逐渐变为前腹的黑棕色斑点。幼鸟的头部呈淡灰棕色，胸部条纹而非条块状，眼睛虹膜颜色较浅。两性羽毛相似，但雄鸟比雌鸟略大。","call":"发出金属质感、悦耳的叽叽喳喳声，主要叫声为柔和的喵喵声“shrr, shrr”或“zzzzzt”，频率和强度变化，用于联系；还有尖锐、急促的哨音在警报时发出，以及柔和的咕噜声和尖锐的叫声。","habits":"栖息于季节性泛滥的河流边纸皮树森林和湿地旁的林地，偶尔出现在桉树林或靠近湿地的开阔地带。以花蜜和昆虫为主食，通过探花取蜜和捕捉空中飞虫来觅食，经常在纸皮树中活动。通常单独或成对出现，有时会形成由10只左右的小群，甚至记录到30只以上的群体，常与其他吸蜜鸟种一起在开花的树木或灌木丛中觅食。","breeding":"繁殖季广泛，大致从晚春持续至冬季，记录显示筑巢活动发生在11月至7月，雏鸟期在2月至5月、7月和9月。在北领地几乎仅在雨季繁殖，主要集中在3月至4月，此时水塘水位最高。巢由两性共同建造，呈穹顶状，入口侧开，常用纸皮树皮条编织，内衬更细小的树皮碎片，悬挂在小型树木或灌木（通常是纸皮树）的细枝末端，高度0.3至7米，平均1.7米。一窝产1至3枚蛋，通常2枚，孵化和育雏期信息未知，两性都参与喂养。","identification":"斑胸胶蜜鸟最显著的特点是其独特的头部和胸部的黑色条纹，以及灰棕色的背部和白色的腹部，这有助于与其他吸蜜鸟种区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚北部，具体包括西澳大利亚的金伯利地区、梅尔维尔岛、北领地的最北端向东至卡奔塔利亚湾南部，以及昆士兰州的约克角半岛南至阿瑟顿，东海岸南至罗克汉普顿。","other":"斑胸胶蜜鸟的巢常被灌丛杜鹃寄生。"},{"name":"褐背胶蜜鸟","english_name":"Brown-backed Honeyeater","scientific_name":"Ramsayornis modestus","overview":"褐背胶蜜鸟（英文名：Brown-backed Honeyeater，学名：Ramsayornis modestus），是雀形目吸蜜鸟科胶蜜鸟属的鸟类。小型鸟类，主要分布在新几内亚海岸线和澳大利亚东北部的约克角半岛及其周边地区，常见于沿海地带的多种生境。","appearance":"这种小鸟体型较小，长约12至13厘米，雄鸟体重约11至14克，雌鸟稍轻，约8.5克。其上身呈褐色，下体白色，头部有黑色斑点，眼周有一条清晰的白线，下颚至耳羽处有白色斑块。翅膀和尾巴深褐色，胸部有淡褐色的斑纹，下腹部至两翼下方为灰暗色。喙和腿均为脏粉色，虹膜深红棕色。","call":"褐背胶蜜鸟的鸣声包括一系列短促的‘chit’音符，夹杂着柔和的颤音，还有‘mick-mick-mick’或干涩的‘chip’声，特别是在飞行时发出。此外，它们还会发出低沉的叽叽声、柔和的‘shee-shee-shee…’声，以及尖锐单调的叫声。","habits":"褐背胶蜜鸟偏好栖息在澳大利亚的河流边纸皮树丛或树林中，尤其是在临时湿地周围，也会出现在城市花园和公园中。在新几内亚，它们常见于红树林、草原桉树林或河流旁的纸皮树丛。它们主要以花蜜和昆虫为食，通常成对或小群活动，偶尔会形成多达18只的小群。","breeding":"繁殖期在澳大利亚为除六月外的所有月份，主要在九月至十月间产卵；在新几内亚全年均可繁殖，主要集中在八月至十一月。它们通常成小群体或独居筑巢，巢由双方共同建造，呈悬垂状，主要由纸皮树皮条制成，悬挂于树梢，离地面高度从0.6米到16米不等。每窝产卵1至3枚，通常为2枚，孵化期为14至16天，雏鸟喂养期为12至15天。","identification":"褐背胶蜜鸟与同类物种的区别在于其独特的褐色背部和白色的下体，以及眼下的白色线条。幼鸟与成鸟相似，但胸部有更明显的褐色条纹。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚海岸线、卫星岛屿、澳大利亚约克角半岛东北部以及昆士兰州东北部，包括一些离岸岛屿。","other":"褐背胶蜜鸟的分布范围在澳大利亚的某些地区是零星的，但在新几内亚则较为普遍。"},{"name":"刺颊垂蜜鸟","english_name":"Spiny-cheeked Honeyeater","scientific_name":"Acanthagenys rufogularis","overview":"刺颊垂蜜鸟（英文名：Spiny-cheeked Honeyeater，学名：Acanthagenys rufogularis），是雀形目吸蜜鸟科刺颊垂蜜鸟属的唯一物种，体长22至27厘米，重约52克。广泛分布于澳大利亚内陆，除塔斯马尼亚州、北部热带区及东南部海岸之外，以橄榄灰为主色，具显著的条纹和独特的粉红色喉咙斑块。","appearance":"刺颊垂蜜鸟体型中等至大，头部呈橄榄灰色，头顶有黑色细斑点，肩部、背部和翼上覆羽有黑色条纹，臀部有污白色斑块，尾羽黑色带明显白色尖端。脸部图案鲜明，喙基部粉红色，沿眼下方延伸至耳后，被黑色眼纹和浓密的白色颊纹所环绕。上翼黑色，边缘白色，次级飞羽边缘黄绿色。胸部粉色至橙色，腹部奶油色，下腹有深棕色条纹，尾下覆羽黑色带宽白尖。虹膜淡蓝至蓝灰色，喙黑色，基部粉红色，腿黑褐色。雌雄羽毛相似，雄鸟体型较大。幼鸟头部较棕，颊纹主要黄色，腹部稍暗，有更细的暗色条纹。","call":"发出响亮平滑的叫声，是澳大利亚内陆地区特有的声音。","habits":"生活在干旱和半干旱的灌木丛和林地，偏好由金合欢树主导的环境，如mulga（Acacia aneura）和鸸鹋灌木（Eremophila）。常见于mallee桉树林、灌木丛和灌木地，以及混合金合欢-桉树群落，通常有灌木层，如Eremophila。也会出现在干燥开阔的桉树林和森林，特别是在湿地或水道附近的平原上，如河红桉（Eucalyptus camaldulensis）林。偶尔在公园、花园、葡萄园或农田中发现。","breeding":"繁殖季节跨全年，主要集中在8月末至11月中旬。筑杯状巢，用柔韧的草、叶子、蜘蛛丝等材料，通常悬挂在离地面0.8至14米高的树枝间。每窝产2至3枚蛋，平均孵化期14至15天，雏鸟喂养期14天至19天。幼鸟出生后至少12天内由双亲喂养。","identification":"与其他吸蜜鸟相比，刺颊垂蜜鸟具有较大的体型、独特的脸颊条纹和粉红色的喉咙。与其他同属物种的区别在于其特有的面部标记和叫声。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚南部，从大约南纬19-20度线以南的地区，包括维多利亚州南部和大分水岭以东。在昆士兰州西北部、南澳大利亚州和维多利亚州东部至南澳大利亚州和维多利亚州的范围内，繁殖季节为8月至3月；在西澳大利亚州和北领地西部，繁殖季节为7月中旬至12月。","other":"刺颊垂蜜鸟可能因栖息地丧失而受到影响，在西澳大利亚州的小麦带可能已减少。有时被视为葡萄园中的害鸟。"},{"name":"灰颊垂蜜鸟","english_name":"Little Wattlebird","scientific_name":"Anthochaera chrysoptera","overview":"灰颊垂蜜鸟（英文名：Little Wattlebird，学名：Anthochaera chrysoptera），是雀形目吸蜜鸟科垂蜜鸟属的鸟类。又称刷子垂蜜鸟，是澳大利亚东南部特有的大型吸蜜鸟科鸟类。其最显著特征为头部、颈部及上体深棕色，细白条纹装饰全身，无粉色肉垂，下腹部亦无黄色。广泛分布于澳大利亚东南沿海地区，包括塔斯马尼亚州。","appearance":"体长27至35厘米，体重雄鸟57至95克，雌鸟44至63克（tasmanica亚种）。大型且修长的吸蜜鸟，尾部长而渐尖，喙长而微弯，无肉垂。头颈及上体主要呈暗褐色，顶部有细白条纹，侧面有银白色密集条纹，下腹中心泛乳黄，上翼深褐，初级飞羽基部有宽大的红褐色边缘，飞行时可见明显的红斑。羽毛随亚种有所不同，tasmanica亚种更大，颜色更偏向橄榄色。","call":"叫声粗犷响亮，有节奏的‘cookay-cookay’声，频率宽广，春季至夏季尤为喧闹。还有尖锐的‘yekop’声和粗糙的吠声。","habits":"栖息于硬叶灌木丛、干燥沿海林地，常见于开花的Banksia附近。全年活跃，春季至夏季最为喧闹。以花蜜为主食，偶尔食用果实、节肢动物和昆虫分泌物，偏好探入花朵取食花蜜。在维多利亚州，曾观察到其利用受损树木流出的树液取食。","breeding":"繁殖季节主要在春季至夏季，筑巢于小树或灌木丛中，巢由雌鸟搭建，呈浅开杯状，有时较深或略呈穹顶，通常用枝条、草茎、叶子等材料制成，内部铺垫碎皮、植物绒毛和羽毛。每巢产卵1至3枚，通常2枚，孵化期12至15天，双亲共同喂养幼鸟，离巢时间14至16天。","identification":"与红垂蜜鸟的区别在于无眼下的粉色肉垂和无黄色下腹部。tasmanica亚种比指名亚种大，颜色更偏向橄榄色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部、东南部，包括塔斯马尼亚州，主要在沿海和近海岸地区。","other":"在商业果园中被视为轻微害虫，因食用园中水果。"},{"name":"小垂蜜鸟","english_name":"Western Wattlebird","scientific_name":"Anthochaera lunulata","overview":"小垂蜜鸟（英文名：Western Wattlebird，学名：Anthochaera lunulata），是雀形目吸蜜鸟科垂蜜鸟属的鸟类。分布于澳大利亚西南部，包括西澳大利亚的西南地区。此鸟体型较大，身长约29至33厘米，体重65至78克，以暗灰褐色为主，具细白条纹，眼周无粉红色肉垂，腹部无黄色，与红垂蜜鸟显著不同。","appearance":"雄性小垂蜜鸟体长29至33厘米，重65至78克；雌鸟体长27至30厘米，重47至57克。整体呈长而修长的形状，尾羽渐长，喙适中，略向下弯曲，无肉垂。头部、颈部和背部主要为深褐灰色，饰以橄榄灰色细纹和点斑；眼部有黑色条纹，脸颊为淡色，密布银白色细纹，延伸至颈侧；下喉部有白色三角斑点；上体有细白条纹和斑点，尾羽覆羽有窄白鳞片，尾羽尖端明显白色；翅膀为深褐灰色，翼上有断续的白色翼带和细白横杠；腹面为灰褐色，比背部浅，胸腹部布满密集的细白条纹和斑点，腹部下方和臀部有更粗大的条纹和斑点，腹部中央为白色到奶油色，尾下覆羽宽白。","call":"叫声嘈杂而显眼，早晨最先鸣叫。最常见的是响亮的‘chwaak’声，被认为是雄鸟的领地叫声。雄鸟也有重复的节奏歌曲，开始时带有‘chok’音符和喙击声，逐渐发展成长而响亮的笑声和咕噜声，类似于Philemon的声音，常被重复。雌鸟的叫声通常更高，类似啾啾声，被认为也是领地叫声；觅食时发出‘weep’声。","habits":"栖息于开放的桉树为主的森林和灌木丛，偏好有Dryandra、Banksia和草树的复杂下层植被。常见于城市公园、未清理的路边植被和农田中的非本土桉树防护林带。以花蜜和昆虫为食，如蝽、膜翅目昆虫和蚂蚁。在特定季节，会频繁采食昆虫。在花蜜生产高峰期喂食植物。通常单独或成对出现，偶尔成群，最高可达50只。好斗，会攻击大小不同的鸟类，捍卫花蜜来源。","breeding":"繁殖期为6月至11月，有时延续至2月。独居筑巢。巢为浅杯状，由草、枝条、羊毛、羽毛等构成，直径10.2至15.2厘米，深度3.8至7.6厘米。巢通常位于高1.7至15米的树枝分叉处，多数在活的灌木或小树上。每窝产一枚卵，双亲共同喂养雏鸟和幼鸟。巢可能被苍白杜鹃寄生。","identification":"与红垂蜜鸟区别明显，无眼下的粉红色肉垂，腹部无黄色。雄鸟比雌鸟明显大。与灰颊垂蜜鸟相比，上体和下体的白色条纹较窄，喉部条纹更三角形，喉咙侧面无白色尖端，初级飞羽内网无白色尖端，喙较长。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚西南部沿海和近海地区，大致南至N Gairdner Range至Hopetoun，东至Cape Arid国家公园。","other":"由于大规模清除本地植被，导致其种群数量下降和分布范围缩小；20世纪上半叶，Perth周边的数量也有所减少。"},{"name":"红垂蜜鸟","english_name":"Red Wattlebird","scientific_name":"Anthochaera carunculata","overview":"红垂蜜鸟（英文名：Red Wattlebird，学名：Anthochaera carunculata），是雀形目吸蜜鸟科垂蜜鸟属的鸟类。大型的吸蜜鸟，体长31-39厘米，分布于澳大利亚南部和东南部。其特征为眼下的肉垂和灰褐色羽毛，腹部有明亮的黄色斑块。广泛栖息于各种干湿硬叶林和林地，以昆虫、浆果和花蜜为食。","appearance":"红垂蜜鸟体长33至37厘米，体重90至140克。成年鸟头部和颈部呈黑褐色，有密集的白色条纹，头顶深色，边缘有银白色面部斑块，下方有黑色条纹，耳羽后方挂着红色肉垂。上体暗褐色，有白色条纹，腹部黄色，下腹有大面积的黄色斑块。雌雄羽毛相似，但雌鸟通常比雄鸟略小。幼鸟颜色更均匀，棕色较深，面部肉垂较小，黄色斑块较淡。","call":"发出一系列响亮、粗糙、嘈杂的叫声，包括类似‘yak, yaak, yakyak’的吼叫和快速重复的单音节哨声‘pleu, pleu, pleu…’，以及强调的单音‘cook’、‘chock’或‘quok’。","habits":"栖息于多种干湿硬叶林和林地，常在农业土地残留的植被中发现，也出现在城市公园和花园中。以花蜜为主食，也会吃昆虫、果实、小型爬行动物等。具有领地性，会驱赶其他吸蜜鸟。","breeding":"繁殖季节从5月末到1月，通常在9月至11月。筑杯状巢，由两性共同建造，位于树叉处，高0.33至30米。每次产卵2枚，孵化期16至21天，双亲共同喂养雏鸟。","identification":"红垂蜜鸟以其显著的红色肉垂和黄色腹部斑块易于识别，与体型较小的西部和小垂蜜鸟区别明显。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部和东南部，包括东南昆士兰、新南威尔士州、维多利亚州、南澳大利亚州和西澳大利亚州西南部。","other":"尽管因土地清理而部分地区数量下降，但在某些城市环境中因花园的建立而受益。"},{"name":"黄垂蜜鸟","english_name":"Yellow Wattlebird","scientific_name":"Anthochaera paradoxa","overview":"黄垂蜜鸟（英文名：Yellow Wattlebird，学名：Anthochaera paradoxa），是雀形目吸蜜鸟科垂蜜鸟属的鸟类。是吸蜜鸟科中体型最大的物种，仅在澳大利亚塔斯马尼亚州发现。这种大型的吸蜜鸟以其黄色的长垂肉垂闻名，雄鸟平均重168克，雌鸟平均重123克，最大个体可达260克。栖息于多种森林环境，从沿海至亚高山地带。","appearance":"黄垂蜜鸟体长通常在37.5到45厘米之间，雄鸟体型显著大于雌鸟。成年鸟头部有黑白相间的条纹，灰色身躯，黄色腹部，最显著的特征是长而下垂的黄色至橙黄色面部肉垂，尤其是繁殖季节时颜色更为鲜艳。上体暗褐色，带有淡灰色条纹和斑点，尾巴长且尖端白色。下体主要为白色，胸部有深褐色条纹，腹部有一大块黄色至橙黄色斑块。幼鸟色彩较淡，缺乏长垂肉垂。","call":"黄垂蜜鸟的叫声粗犷而刺耳，被形容为类似人的咳嗽或打嗝声，伴有咕噜声和连续的'clok'音。","habits":"黄垂蜜鸟广泛分布于塔斯马尼亚东部和中部的多种生境，包括干湿森林、沿海灌木丛、公园、果园和花园。它们以桉树和班克斯花的花蜜、果实、昆虫、蜘蛛、蜜露、飞行中的蜜蜂和结晶植物汁液为食。由于桉树开花时间与地点的不确定性，造成黄垂蜜鸟的食物来源不稳定，可能对其生存构成威胁。","breeding":"繁殖期一般在8月至次年1月，筑巢由雌鸟单独完成，雄鸟偶尔提供材料。巢为开放的浅盘状，主要由细枝和树皮构成，内部铺垫羊毛和草。每窝产卵2-3枚，孵化期14-16天，幼鸟由双亲共同喂养，离巢期约18-21天。幼鸟依赖父母数周。","identification":"与灰颊垂蜜鸟和红垂蜜鸟相比，黄垂蜜鸟体型更大，具有更长的黄色肉垂。","protection":"IUCN：LC（无危）；然而，King岛的亚种（kingi）被认为是\"易危\"，受栖息地丧失影响，估计成熟个体不足1000只。过去曾因猎杀数量下降，现受法律保护。","distribution":"黄垂蜜鸟主要分布在澳大利亚塔斯马尼亚州的东部和中部，以及King岛（位于巴斯海峡西部）。在维多利亚州南部晨顿半岛的两个可能的观察记录缺乏实物证据。","other":"黄垂蜜鸟的种名paradoxa源自古希腊语，意为\"奇异的\"，反映了其独特的外观。"},{"name":"王吸蜜鸟","english_name":"Regent Honeyeater","scientific_name":"Anthochaera phrygia","overview":"王吸蜜鸟（英文名：Regent Honeyeater，学名：Anthochaera phrygia），是雀形目吸蜜鸟科垂蜜鸟属的鸟类。是澳大利亚东南部特有的标志性吸蜜鸟种，因其引人注目的外表和稀有状态而成为保护行动的焦点。以黑色头部、醒目的红眼圈和背部、翅膀及腹部复杂的白黄黑相间图案著称。分布范围从昆士兰东南部延伸至维多利亚东北部。","appearance":"王吸蜜鸟体长20.4-24厘米，体重41-45.5克（雄鸟），33-45克（雌鸟）。雄鸟整体黑色，头部显著，有大片脏黄色（偶尔带粉色）裸露皮肤环绕眼周，背部有明显的淡黄色斑纹。雌鸟较雄鸟小，颜色稍暗淡，面部裸露皮肤较小，喙略短。幼鸟比成鸟更暗淡，具灰色至蓝灰色面部裸皮，腹部呈奶油色渐变为淡黄色。","call":"其鸣声独特，由柔和穿透的颤音组成，带有滑音和轻微的颤动，重复2-3次，有时伴有气泡质感，音量和间隔复杂多变。此外，还发出高音急促的颤音、绵羊般的长音单或双音、'plick'或'plink'的单音，以及深沉的攻击性吠声。","habits":"栖息于干燥的硬叶林区，尤其偏好沿溪流、河谷和山脚的Eucalyptus树林。以花蜜为主食，同时食用昆虫、昆虫分泌物和果实。活跃且好斗，常在树冠中觅食，有时单独或结成3-50只的小到大群。","breeding":"繁殖季节主要在9月至11月，但记录显示全年除4月外都有繁殖行为。雌鸟筑巢，雄鸟守护，巢由软树皮条、干草、蜘蛛网等构成，位于1-30米高的树上。每窝通常产2枚蛋，孵化期12-15天，由雌鸟独自孵化，雏鸟由双亲共同喂养。","identification":"与同属其他种类相比，王吸蜜鸟具有独特的红眼圈和复杂的羽色图案，使其易于辨认。亚种间差异较小。","protection":"IUCN：CR（极危）","distribution":"分布于澳大利亚东南部，从昆士兰东南部至维多利亚东北部，主要集中在内陆斜坡的大分水岭附近。在维多利亚南部和昆士兰北部有零星记录。","other":"由于栖息地丧失和退化，王吸蜜鸟数量急剧减少，最近的保护努力集中在其关键栖息地的保护和恢复。"},{"name":"暗喉吸蜜鸟","english_name":"Bridled Honeyeater","scientific_name":"Bolemoreus frenatus","overview":"暗喉吸蜜鸟（英文名：Bridled Honeyeater，学名：Bolemoreus frenatus），是雀形目吸蜜鸟科波乐吸蜜鸟属的鸟类。以独特的马缰状面部标记而著称，是澳大利亚东北部昆士兰特有种。在较高海拔的热带雨林中发现，通常位于300米以上高度。冬季会迁至低海拔森林，包括红树林地带，偶尔可见于开阔生境。","appearance":"暗喉吸蜜鸟是一种中到大型的灰褐色吸蜜鸟，头部至背部为深灰褐色，逐渐变为黑色的面颊和耳羽，拥有显眼的白色眉纹和曲形的白色眼后纹，黄色耳羽尖，颈部侧面有大片淡灰色斑块，下腹部偏灰褐，下巴稍暗，腹部中央为泛白，尾下覆羽和翼下覆羽呈暗灰褐色。虹膜和眼眶环为蓝灰色，喙尖黑色，与明亮的黄色基部形成鲜明对比，腿色为深灰或棕灰色。雄鸟和雌鸟在外表上相似，但雄鸟体型较大。","call":"发出连贯的颤音啾啾声，通常下降，有时上升或起伏，'tchew-tchew-tchew...'。此外，还包括喂食时的严厉责骂声'chaaarh'，以及响亮的双音或三音符，例如'we-are'和'wachita-wachita'。","habits":"栖息于高海拔的热带雨林，偶尔出现在红树林等低地森林。在冬季，部分种群会迁至较低海拔。以昆虫、花蜜和果实为食，主要在树冠层觅食，偶尔在较低层次。会探访人类居住区，如城镇、果园和种植园。","breeding":"繁殖期大致在9月至12月间，巢为杯状，由攀援植物的长茎和蕨类植物的茎构成，内衬植物纤维，巢置于藤蔓丛或寄生植物中，离地面0.9米至8米之间。每窝产卵通常为2枚，幼鸟在离巢后仍被喂养一段时间。最长寿命记录为7年7个月，平均年存活率估计为64%-73%。","identification":"通过其独特的面部特征与同属其他物种相区分，特别是白色眼后纹和黄色耳羽尖。与Eungella吸蜜鸟（Bolemoreus leucogaster）相比，本种的分布更为北部。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东北部，从约克角半岛东南部至昆士兰东北部，包括阿瑟顿高原和内陆的温莎地区，以及沿海岛屿。在繁殖季节，主要分布在海拔600米至1500米的高海拔热带雨林。","other":"在分子系统发育分析后，暗喉吸蜜鸟和Eungella吸蜜鸟被从Lichenostomus属移至Bolemoreus属。"},{"name":"纹腹吸蜜鸟","english_name":"Eungella Honeyeater","scientific_name":"Bolemoreus hindwoodi","overview":"纹腹吸蜜鸟（英文名：Eungella Honeyeater，学名：Bolemoreus hindwoodi），是雀形目吸蜜鸟科波乐吸蜜鸟属的鸟类。以Keith Alfred Hindwood命名，他是皇家澳洲鸟类联盟的前主席。仅分布于澳大利亚中东部昆士兰州Clarke山脉的一小片高原雨林中。","appearance":"体型中等，长度介于17.2至19.7厘米之间，雄鸟体重20至27.2克，雌鸟19.7至24克。整体呈暗灰褐色，头部有细淡灰色鳞状斑点，背部有细淡灰色条纹。脸部黑色，带有窄而偏白的眼缘和髭纹，几乎与眼睛上方的小偏白斑块相连。耳羽后部有上扬的偏白色羽毛，边缘微黄，尾羽边缘为暗黄橄榄色。次级飞羽上有淡黄色橄榄色光泽，主翼羽有细白边。腹部比背部稍浅的灰褐色，有细白条纹。虹膜蓝灰色到蓝绿色，喙黑色，腿蓝色灰色。","call":"发出一系列尖锐、急促的哨声，叫声响亮有力且多样，包括开始时略带粗糙的金属音符的歌曲，以及柔和的‘chip’接触叫声，还有短促尖锐的‘chip’、‘tick’或‘churr’。","habits":"主要栖息于高海拔的雨林，偶尔出现在雨林边缘、低地桉树和松木森林、园林。通常活动在900米以上，但最低记录到150米。饮食以花蜜和果实为主，也会吃昆虫和花的部分。在树冠层和藤蔓植物中觅食，偶尔在下层树木和灌木丛中活动。单独或成对出现，有时在开花树上形成小群体。","breeding":"繁殖季节集中在春季，已知的筑巢时间从8月末至10月中旬，产卵期在10月，雏鸟孵化期在10月至11月。巢由双方共同建造，深度杯状，用细植物纤维编织，外覆苔藓，悬挂在4.2至20米高的地面，一般藏在树梢横枝上的密集叶丛中。每窝产2枚蛋，孵化可能由一方单独承担，孵化期大约13至14天，雏鸟由双方喂养，育雏期约为14至15天。","identification":"与暗喉吸蜜鸟相似，但可通过其特有的叫声、分布区域和形态细节加以区分。","protection":"IUCN：NT（近危）。依赖于Eungella国家公园内的保护，全球范围内不构成威胁，但在Clarke山脉二级保护区中属于受限制物种。","distribution":"分布于澳大利亚中东部的昆士兰州Clarke和Sarina山脉，主要在其西部的Mackay附近的高原雨林。","other":"曾被认为是暗喉吸蜜鸟的孤立种群，1983年被确认为独立物种。"},{"name":"黄脸吸蜜鸟","english_name":"Yellow-faced Honeyeater","scientific_name":"Caligavis chrysops","overview":"黄脸吸蜜鸟（英文名：Yellow-faced Honeyeater，学名：Caligavis chrysops），是雀形目吸蜜鸟科卡里吸蜜鸟属的鸟类。显著特征为头部两侧的黄色条纹，伴有黑色边框。广泛分布于澳大利亚东部和东南部的森林与灌木丛中，从沿海地带至高海拔亚高山区域。该鸟种以花蜜、昆虫、果实为食，能捕捉空中飞虫，活跃于树冠层。","appearance":"体长15-17.5厘米，体重12-20.5克，雄鸟略大于雌鸟。上体灰褐至橄榄褐色，头顶部有暗色斑点，两侧有黄色条纹，眼下方有宽大的黄色带延伸至耳羽，被黑色眼线和颊线框住。尾羽棕色，翼覆羽灰褐至橄榄褐色，具淡色尖端。下体淡灰褐色，胸部稍深，腹部更浅，尾下覆羽灰褐色。虹膜蓝灰色，嘴黑色，腿灰褐色。幼鸟相似于成鸟，但颜色较淡，上体无斑点，胸腹部颜色更浅。","call":"发出清晰响亮的'chick-up'声，常在黎明前开始鸣唱，持续约一小时，叫声变化丰富，包括重复的、略显哀婉的'chip'或'cheep'声。","habits":"栖息于多种生境，包括开阔的硬叶林、河流旁的树林及果园公园。日间迁徙，形成小至大群，最高记录为每小时数千只。食物来源广泛，包括花蜜、昆虫、果实等。","breeding":"繁殖季节为7月至翌年3月，筑精致的杯状巢，由雌鸟为主建造，通常位于灌木或小树中。每次产卵2-3枚，孵化期13-15天，雏鸟喂养期11-14天，双亲共同抚养。","identification":"与同属其他种类相比，黄脸吸蜜鸟具有独特的黄色面部条纹和黑色边框，且体型较小。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部和东部，从昆士兰远北区至南澳大利亚弗勒里厄半岛和洛夫提山脉。","other":"部分个体为留鸟，而大部分会迁徙至昆士兰州南部度过冬季，春季返回南方繁殖。"},{"name":"黑喉吸蜜鸟","english_name":"Black-throated Honeyeater","scientific_name":"Caligavis subfrenata","overview":"黑喉吸蜜鸟（英文名：Black-throated Honeyeater，学名：Caligavis subfrenata），是雀形目吸蜜鸟科卡里吸蜜鸟属的鸟类。在新几内亚山区常见的中等体型吸蜜鸟。其最显著的特征是灰褐色的身体，橄榄色的翅膀，橙色的腿，以及黑色脸部两侧的黄色簇毛和白色的耳斑。分布于新几内亚的上部山林和亚高山森林。","appearance":"成年黑喉吸蜜鸟体长20.5至22厘米，体重25至37克，雄鸟比雌鸟稍大。头部灰色，顶部和颈部带橄榄色调的灰棕色，面颊和颈侧黑色，带有独特的面部图案，由黄色肿胀的喙部与眼睛下方的金色裸皮相连，形成半月形的金黄色斑块，斑块后方有黑色、白色和金色条纹。颈侧有大的不规则白色斑块，下喉部有淡黄色斑点或细纹。上体橄榄棕色，翼上有黄绿色的边缘，尾羽也有类似的边缘。下体颜色较上体浅，腹部中心有斑驳的米色。虹膜灰至深棕色，眼环黑色，喙黑色，腿亮黄色至橄榄黄色。雌雄羽毛相似，幼鸟颜色略偏暖棕色。","call":"鸣声独特，是一系列下降且减速的泡泡音，更常被听到而非看到。","habits":"栖息于原始山地森林，尤其是中上部山地森林，包括苔藓森林、森林边缘、次生植被和亚高山灌木丛。活动范围从海拔1350米至3700米，常见于2000米以上，偶尔低至1070米。以花蜜、小节肢动物和果实为食，主要在树冠层觅食，偶尔降至地面附近。","breeding":"繁殖信息有限，已知在11月有成鸟喂养雏鸟的情况，4月至9月间观察到携带筑巢材料和雌鸟生殖器官增大的现象，以及单个繁殖期个体出现在10月和11月。","identification":"与橙颊吸蜜鸟相似，但黑喉吸蜜鸟体型较小，有明显的白色耳斑。不同亚种在羽毛色彩上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的山地地区，包括蒙塔涅山脉。","other":"2011年的分子系统发育分析显示，原属Lichenostomus的黑喉吸蜜鸟被归入Caligavis属。"},{"name":"暗吸蜜鸟","english_name":"Obscure Honeyeater","scientific_name":"Caligavis obscura","overview":"暗吸蜜鸟（英文名：Obscure Honeyeater，学名：Caligavis obscura），是雀形目吸蜜鸟科卡里吸蜜鸟属的鸟类。是新几内亚特有种。其最显著的外部特征是橄榄色的身体，脸部鲜黄色，眼睛下方有一条黑色线条，以明亮的黄色耳斑结束。分布于新几内亚的山地森林中。","appearance":"暗吸蜜鸟体型中等，长约18.5至19厘米，雄鸟体重24至31克，雌鸟体重24至27克。头部前额至头顶呈暗灰色，逐渐过渡到橄榄灰色，上嘴基部和眼上纹黄色，脸颊处有黄色三角形斑块，耳羽上方有黄色延伸至眼下的环状纹，耳后有白色大斑点。上体橄榄褐色，翼和尾羽边缘黄绿色，下体较上体淡，灰橄榄色，胸腹部略带橄榄褐色调，腹中部近白色。虹膜深灰褐至褐色，喙黑色，腿蓝色至灰色。幼鸟外观类似成鸟，但头部颜色更接近上体色调，缺乏成鸟的暗斑。","call":"其鸣唱为一系列通常五声的“chip”音符，先升后降。","habits":"栖息于新几内亚的原始森林中，尤其是山地森林，偶尔出现在次生林和受扰动的环境中，如花园。海拔高度主要在200米至1100米之间，有时高达1400米。主要在山地森林的较低和中层活动，特别偏爱下层林冠。饮食包括花蜜、小型节肢动物（昆虫）和果实，如无花果。在开花和结果的树木中觅食。","breeding":"已知有两个活跃的巢穴，分别在8月末和10月中旬被发现。巢杯状，一个倾斜，一侧较高形成部分穹顶，另一个由苔藓和小干枝构成，内衬细软材料，悬挂在离地面仅15厘米的小灌木水平分叉处。每巢产两枚卵。繁殖季节具体信息有限。","identification":"与黑喉吸蜜鸟相似，但体型较小，腿部为灰色而非橙色。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚（除东北部和中南部以外），在山地森林中较为常见。"},{"name":"黄冠吸蜜鸟","english_name":"Yellow-tufted Honeyeater","scientific_name":"Lichenostomus melanops","overview":"黄冠吸蜜鸟（英文名：Yellow-tufted Honeyeater，学名：Lichenostomus melanops），是雀形目吸蜜鸟科里奇吸蜜鸟属的鸟类。小型至中型的吸蜜鸟科鸟类，以明亮的黄色下巴和头顶，以及大胆的黑色脸颊为显著特征。通常成群出现，好斗，常在澳大利亚东南部的林地地区发现。","appearance":"体长17-23厘米，雄鸟体重16.6-40.2克，雌鸟体重14.2-36.7克。具有亮黄色的额头至颈背，宽阔的黑色面罩，以及黄色耳羽簇。上身主要为深橄榄褐色，下体橄榄灰色，泛黄，胸部有黄色条纹。幼鸟比成鸟更暗淡，棕黑色面罩，较淡的黄色耳羽簇，背部和臀部有棕色绒毛。","call":"叫声复杂多样，包括粗糙的‘tsup’、‘shup’或‘jik’，用于联系和警报，以及更柔和的社交鸣叫。","habits":"栖息于干燥开阔的硬叶林和林地，主要以昆虫和蜘蛛为食，偶尔食用蜗牛、树液、花蜜和果实。在高树冠层觅食，有时在地面。对大多数鸟类具有攻击性。","breeding":"繁殖期为7月至翌年3月，每季产卵1-2窝。巢由草、树皮碎片、蜘蛛网等材料编织，挂在密丛或再生枝条中。每窝产卵2枚，孵化期14-16天。","identification":"与其他吸蜜鸟相比，黄冠吸蜜鸟的黄色耳羽簇和黑色面罩是辨识要点。亚种之间在大小和颜色上有差异。","protection":"IUCN：LC（无危）。然而，黄披肩吸蜜鸟卡西迪亚种（L. m. cassidix）被列为华盛顿公约附录一的保护物种。","distribution":"分布于澳大利亚东部和东南部，主要在维多利亚州、新南威尔士州东部和昆士兰州南部。","other":"黄冠吸蜜鸟的四个亚种在大小和羽毛颜色上有所不同，其中黄披肩吸蜜鸟卡西迪亚种由于栖息地丧失而面临严重威胁。"},{"name":"紫颊纹吸蜜鸟","english_name":"Purple-gaped Honeyeater","scientific_name":"Lichenostomus cratitius","overview":"紫颊纹吸蜜鸟（英文名：Purple-gaped Honeyeater，学名：Lichenostomus cratitius），是雀形目吸蜜鸟科里奇吸蜜鸟属的鸟类。以灰橄榄色为主调，下体偏黄褐色，具有独特的头部图案，包括黑色眼纹和灰色顶冠，紫色口裂线以及黄色喉纹。分布于澳大利亚南部和西部的半干旱地区，主要栖息于马利灌木林、高草甸及相关的低矮桉树林。","appearance":"体长约16至19厘米，体重雄鸟19.5至24.7克，雌鸟15.5至22.5克（指名亚种）。头部有明显的暗灰色顶部和颈部，黑色眼纹延伸至耳羽后方，与灰色前耳羽融合，后耳羽处有黄色簇毛，紫色口裂线沿眼纹底部延伸，鲜黄色的须纹，橄榄黄色的颏和喉部。上体颜色较深，呈橄榄灰色，翅膀覆羽略带棕色，边缘稍淡；翅膀上有一片黄色橄榄色的外缘；尾羽棕色，边缘橄榄色，新鲜时有细白尖端；下体主要橄榄灰色，有模糊的黄橄榄色条纹，腹部中央呈淡黄色；尾巴下方橄榄灰色，翅膀下方偏白色到浅灰色，有宽的棕灰色边缘和尖端。虹膜深棕色；喙全黑，口裂和口裂线紫色（繁殖季节色彩更鲜艳）；腿灰黑色。两性羽毛相似，雄鸟略大于雌鸟。幼鸟与成鸟非常相似，但面部图案较暗淡，眼纹棕色，须纹淡黄色，上体带棕色，一些翅膀覆羽有黄色棕色边缘，下体淡黄色，喙较暗，基部黄色，口裂黄色而非紫色。指名亚种比occidentalis亚种更大、颜色更深。","call":"发出快速重复的响亮叽喳声“chuc-chuc-chuc-chuc-chuc”，在干扰展示中可能用于领地宣示和防御；对潜在威胁做出斥责反应（可能与叽喳声相同）；单个尖锐的“chirp”声；响亮的鞭状哨音；像鹦鹉般柔和的鸣叫声；飞行中的尖锐不悦耳的“twit-twit”声；据说还有悦耳的歌声和类似的声音，可能指的是上述声音之一。","habits":"常居住在马利桉树丛生的环境，偏好马利灌木草甸，但也出现在马利灌木林地和灌木丛，通常伴有密集的灌木下层，如扫帚灌木或偶尔的刺蓬。在某些地区，可以在非马利沙平原的灌木丛中发现它们，如西澳大利亚州，或在以桉树为主的干燥硬叶林或林地中，通常有草甸下层（如袋鼠岛），或在河流边的桉树或茶树群落中。主要以昆虫（如介壳虫和蚜虫）、蜘蛛和花蜜（如桉树、金合欢、腺花属或其它蛋白质科或山龙眼科灌木）为食，也吃树胶和蜜露，少量水果和种子。在一项研究中，花蜜和昆虫在饮食中的比例为38:62。通常单独、成双或小群体（最多10至12只）觅食，有时在丰富食物源如开花马利灌木时会形成多达30只以上的较大群体。对小型和中等大小的吸蜜鸟（如Acanthorhynchus和银眼莺）表现出攻击性。","breeding":"主要在春季和秋季繁殖，雨后也可能繁殖；记录的窝卵期为8月至11月、1月和3月至4月。巢由雌鸟单独建造，深而紧凑的小杯状巢，直径7至8.9厘米，深度7.6至10.1厘米，内部直径5.1至6.4厘米，深度5.1厘米，位于离地面0.5至3米（平均1.2米）的小灌木、小树或寄生植物上，通常悬挂在树叶、细枝或水平树枝的叉中，有时部分悬挂和部分支撑，或在垂直的枝叉中。通常产2枚卵；孵化期约为13至14天；雏鸟由两性共同喂养，没有关于巢雏期持续时间的信息。","identification":"与黄痣吸蜜鸟和歌吸蜜鸟相似，但可通过其独特的头部图案、紫色口裂线和黄色喉纹区分开来。","protection":"IUCN：LC（无危）","distribution":"分布在澳大利亚西南部和中南部，主要栖息于马利灌木林和相关低矮桉树林地带。在西澳大利亚州东部至南澳大利亚州，南澳大利亚州大部分地区以及维多利亚州南部有分布，新南威尔士州形成其东北极限分布范围。"},{"name":"矿吸蜜鸟","english_name":"Bell Miner","scientific_name":"Manorina melanophrys","overview":"矿吸蜜鸟（英文名：Bell Miner，学名：Manorina melanophrys），是雀形目吸蜜鸟科矿吸蜜鸟属的鸟类。其橄榄绿色的外表与橙黄的喙、腿和脸颊相映成趣。这种鸟以群居形式生活，展现出强烈的领地性和攻击性。主要分布在澳大利亚东南部沿海地区，偏爱茂密潮湿的桉树森林。矿吸蜜鸟的叫声独特，响亮的‘叮’声是其显著特征，也是其得名的由来。","appearance":"成年矿吸蜜鸟体长约18.5厘米，体重介于24.2到45克之间，雌雄差异不大。整体羽毛呈橄榄绿，上部稍深，腹部略显黄绿，冠部和耳羽带灰，前额和颊纹黑色，眼周有黄色斑块，眼后有橙红色裸露皮肤。翼覆羽和初级飞羽呈灰褐色，次级飞羽和三级飞羽边缘黄橄榄色，尾下覆羽灰橄榄绿，翅膀内侧灰褐色。虹膜深棕色，喙和腿橙黄色。幼鸟较暗淡，缺乏明亮的裸露面部皮肤，头部和颊纹颜色与冠部相近，翼覆羽褐色，下体橄榄色带灰色斑点。","call":"矿吸蜜鸟的主叫声为响亮纯净的钟铃般‘叮’声，音质清脆，穿透力强，是澳大利亚丛林的标志性声音之一。此外，它们还会发出多种短促尖锐的声音。","habits":"矿吸蜜鸟偏好开放的硬叶林和灌木丛生的林地，尤其集中在受粉虱侵扰的桉树林中，有时可见于退化林地。它们在固定区域内定居，很少离开领地边界。饮食以昆虫为主，辅以花蜜、甘露和偶尔的果实。觅食高度多在8米以上，偶尔会降至地面。它们会用喙舔舐树叶表面收集甘露。","breeding":"全年均可繁殖，高峰在8月和1月至4月。矿吸蜜鸟实行一夫一妻制，雌鸟独建巢穴，巢呈杯状，直径约7.6至10.2厘米，深度5.1厘米，通常悬挂在地面2.07至2.8米处的浓密灌木丛中。每窝产卵1至3枚，平均2枚，孵化期12至18天。雏鸟由双亲和辅助者共同喂养，离巢期10至15天。巢穴可能被苍白杜鹃寄生。","identification":"矿吸蜜鸟与其他同属物种的区别在于其橄榄绿色的羽毛、橙色的眼后裸露皮肤以及独特的叫声。幼鸟与成鸟相比，色彩较暗，无明显裸露皮肤。","protection":"IUCN：LC（无危）","distribution":"矿吸蜜鸟主要分布于澳大利亚东部和东南部，从昆士兰东南部向南延伸至维多利亚州中部，包括大分水岭以东的地区。","other":"矿吸蜜鸟与桉树大规模枯死现象紧密相关，被称为'Bell Miner-Associated Dieback'，这已成为商业林业关注的重大问题，同时也影响到生态多样性保护。"},{"name":"黑额矿吸蜜鸟","english_name":"Noisy Miner","scientific_name":"Manorina melanocephala","overview":"黑额矿吸蜜鸟（英文名：Noisy Miner，学名：Manorina melanocephala），是雀形目吸蜜鸟科矿吸蜜鸟属的鸟类。广泛分布在澳大利亚东部、东南部及塔斯马尼亚州。这中到大型的灰体吸蜜鸟，拥有黑色头部、黄色喙和脚，以及黄色的眼后斑。偏好在人类居住区及开放的桉树林中活动，以其嘈杂的鸣叫而闻名。","appearance":"黑额矿吸蜜鸟体长24至28厘米，翼展36至45厘米，体重70至80克。全身呈现灰色，背部、尾巴和胸部颜色较深，腹部白色，有白色的颈背纹路。额头和眼先部分为偏白色，头部顶部有一条宽阔的黑色带状标记，喙和脚橙黄至棕黄色，尾羽末端有明显的白色尖端。翼部可见橄榄绿边缘的飞羽。幼鸟与成鸟相似，但头部黑色部分带有褐色调，背部灰色更淡，眼后黄色皮肤斑点较为暗淡。","call":"黑额矿吸蜜鸟的鸣叫声丰富多样，包括刺耳的单音节声和复杂的歌曲。它们有用于警告空中捕食者的高频颤音，以及用于驱赶地面捕食者和其他鸟类的低频‘churr’音。此外，还有用于社群交流的低音调叫声。","habits":"这种鸟生活在干燥的开阔桉树森林中，尤其偏好少灌木的环境。它们在城市、农业地带和郊区公园也很常见。黑额矿吸蜜鸟是群居的，形成由数百只鸟组成的殖民地，积极保卫领地，排斥其他物种。它们以昆虫、花蜜、果实和偶尔的小型脊椎动物为食。","breeding":"全年繁殖，筑巢活动通常发生在冬季至春季。巢由雌鸟单独建造，是一个深而脆弱的杯状结构，由细枝、草或两者的组合构成。巢位于低枝或分叉处，离地面高度从0.2米到30米不等。每窝产卵2至4枚，孵化期15至18天，幼鸟由母鸟孵化，成年鸟共同喂养。","identification":"与黄喉矿吸蜜鸟和黑耳矿吸蜜鸟相比，黑额矿吸蜜鸟有更暗的头部和更加明显的黄色眼后斑。它们通过其独特的叫声和领地行为与其它鸟类区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部、东南部和塔斯马尼亚岛，包括内陆平原、丘陵地带和城市区域。","other":"黑额矿吸蜜鸟的高密度会对当地鸟类多样性产生负面影响，因为它们会排斥其他种类的鸟，导致生态平衡的破坏。"},{"name":"黄喉矿吸蜜鸟","english_name":"Yellow-throated Miner","scientific_name":"Manorina flavigula","overview":"黄喉矿吸蜜鸟（英文名：Yellow-throated Miner，学名：Manorina flavigula），是雀形目吸蜜鸟科矿吸蜜鸟属的鸟类。澳大利亚特有种。亦称为白臀矿吸蜜鸟。以灰身、黄色喉咙标记、腿和眼周裸露黄色皮肤为特征，拥有明显的白色臀部，这使它们在野外容易识别，与其它矿吸蜜鸟种类区分开来。其广泛分布在澳大利亚内陆地区，包括城镇和公园。","appearance":"成年黄喉矿吸蜜鸟体型中等，总长度22至28厘米，翼展12至13.8厘米，喙长25毫米，体重介于50至61克之间。头部顶部为浅灰色，额头橄榄黄色，逐渐过渡到灰色。具黑色面罩，下方有黄色嘴角线，眼后有小块裸露的黄色皮肤。显著的白色亚须纹，细长的橙黄色裸露颊纹；上体灰色，有不同程度的暗褐色斑点，尾羽深灰色，尖端白色，次级飞羽和三级飞羽灰色，与黑色翼部形成对比，有橄榄黄色边缘。下巴黄色（仅在良好视角下可见），喉咙和胸部为灰白色，胸部有暗灰色和白色斑点，上胸弥漫着黄色。腹部淡灰色，两胁和大腿非常淡灰色。下尾暗灰色，尖端白色至灰白色。下翼暗灰色，主翼基部有淡灰色斑块。虹膜棕色至深棕色，喙黄色至橙色，脚橙色至棕橙色。雌雄羽毛相同，雄鸟体型大于雌鸟。幼鸟与成鸟相似，但在良好视角下可由冠、颈和上体的淡粉色调、颈上无白色斑点、尾尖粉棕色、胸前有棕色色调（仅模糊斑点）、中覆羽和大覆羽末端有狭窄、模糊和断裂的淡粉色翼条、外侧主翼有更清晰的白色边缘、喙稍暗的黄色辨别。","call":"嘈杂，但叫声系列尚未研究。包括单音尖叫、惊恐时的尖叫和嘶喊，与黑额矿吸蜜鸟的叫声相同；缓慢的喵喵声“mew-mew-mew”，低沉的喉音“aarh”，悦耳的笑声。黎明时的歌唱最常在繁殖季节听到，是一群成员的吹哨音符合唱。","habits":"栖息于几乎所有的林木环境，尤其是金合欢树林和灌木丛，开阔的桉树林和森林。","breeding":"繁殖活动遍布整个分布区域，全年均有记录，但似乎高峰期在晚冬至夏季，集中在春季和初夏，大多数窝（87%）在8月至10月间。在松散的群体中筑巢，合作繁殖。巢是一个大型深杯状，偶尔呈碗状，通常由草、树枝和羊毛构成，通常用蜘蛛网或毛发绑定，内衬羊毛（较少使用的材料包括植物茎和根须、毛发、羽毛、花朵、茧壳、树皮、叶子、线、棉线、钓鱼线和纸张；在衬里中，有草、根须、植物绒毛、花、毛、毛发、羽毛、丝质纤维、种子荚中的丝、线、棉线、叶子，一次使用过trapdoor蜘蛛洞穴的盖子）。外部直径17.8至20.3厘米，深度9.5至10.2厘米，内部直径7.6至9.5厘米，深度4.1至7厘米；放置在离地1.2至16米（平均4.4米）的高度，通常位于浓密的树叶或灌木、树苗或小树的垂直分叉处，有时在桉树从中到上部树干水平的丛生生长处，位于槲寄生中，或靠近树干，有时悬挂在水平枝条上，一次在三个竖立的茎上。每窝产2至4枚蛋，罕见5枚（平均3.16枚）；由繁殖雌鸟孵卵，极少数情况下由繁殖雄鸟协助，孵化期约为15至16天；雏鸟由三只或更多的鸟喂养，可能是父母和辅助者，育雏期至少15至16天，一次雏鸟似乎在大约13天时提前离巢；离巢幼鸟由至少三只个体喂养。巢被太平洋噪鹃和淡色杜鹃寄生。从148枚蛋在55个已知结果的巢中，平均每巢有1.05只幼鸟离巢；在144个巢中，102个（71%）至少有一只幼鸟离巢；在半干旱地区的季节晚期巢往往由于高温而失败。","identification":"黄喉矿吸蜜鸟与其他矿吸蜜鸟属的区别在于其清洁的白色臀部，而不是像黑额矿吸蜜鸟和黑耳矿吸蜜鸟那样的连续灰色背部。此外，黄喉矿吸蜜鸟的上颌颜色较下颌浅，而纯种黑耳矿吸蜜鸟的下颌颜色比喉咙更深。与黑额矿吸蜜鸟相比，黄喉矿吸蜜鸟在喙上方和下方、前额和下巴上有不同程度的黄色高亮，而黑额矿吸蜜鸟的喙上方为白色，前额和颈部没有黄色高亮，但可以在下巴上有少量黄色。不同亚种的黄喉矿吸蜜鸟在颜色和大小上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚大部分地区，除了约克角半岛北部、澳大利亚东南部的塔斯马尼亚州和部分极端东南部地区。在西澳大利亚中部至昆士兰西部有广泛的分布。东部亚种M. f. flavigula覆盖了除约克角和昆士兰州海岸以外的大部分地区，向南延伸至新南威尔士州和维多利亚州内陆。M. f. lutea跨越西澳大利亚州和北领地的北部。M. f. obscura出现在西澳大利亚州西南部。M. f. melvillenis存在于北领地的非常北部。","other":"黄喉矿吸蜜鸟的范围已扩大，许多地区的数量有所增加，主要是对农业开垦的响应。然而，由于欧洲定居以来的改变，Swan Coastal Plain（西澳大利亚）的数量已经下降。"},{"name":"黑耳矿吸蜜鸟","english_name":"Black-eared Miner","scientific_name":"Manorina melanotis","overview":"黑耳矿吸蜜鸟（英文名：Black-eared Miner，学名：Manorina melanotis），是雀形目吸蜜鸟科矿吸蜜鸟属的鸟类。仅在澳大利亚东南部的半干旱地带，如Gluepot保护区等特定密集的完整灌木林中发现。是澳大利亚最稀有的鸟类之一。","appearance":"成鸟体长23至26厘米，体重43.5至60克。上身大部灰色，头部橄榄色渐变为灰色，面部有黑色面罩，下颚至胸部有黑白相间的斑点，腹部白色，侧翼和大腿灰洗。幼鸟外观与成鸟相似，但上体更淡，无颈部白斑，尾尖棕色，胸部灰度更均匀。","habits":"栖息于成熟完整的半干旱灌木林，偏好至少45年未经燃烧的环境。它们倾向于定居生活，形成小群体，通常在10公顷范围内活动，但在非繁殖季节会扩大活动范围。以昆虫和蜘蛛为主的无脊椎动物为食，偶尔摄取花蜜，通过探查和采集方式觅食。","breeding":"繁殖期记录在9月至12月，可能延续到春季。在松散的群体中繁殖，巢间距有时仅为25米。巢由树枝、草和蜘蛛网构成，位于地面1.5至4.5米高的树叉或浓密的枝叶中。每窝产2至3枚卵，至少由三个个体共同孵卵。巢可能被淡色杜鹃寄生。","identification":"与黄喉矿吸蜜鸟的区别在于：黑耳矿吸蜜鸟的颊斑全黑，髭纹比喉部颜色更深，而黄喉矿吸蜜鸟的髭纹较浅，颊斑有银色斑点。","protection":"IUCN：EN（濒危）","distribution":"分布于澳大利亚东南部，具体为维多利亚州西北部和南澳大利亚州东部的半干旱灌木林区。","other":"面临的主要威胁是与黄喉矿吸蜜鸟的杂交，导致遗传污染。"},{"name":"圣克里吸蜜鸟","english_name":"Makira Honeyeater","scientific_name":"Meliarchus sclateri","overview":"马基拉吸蜜鸟（英文名：Makira Honeyeater，学名：Meliarchus sclateri），是雀形目吸蜜鸟科圣克里吸蜜鸟属的鸟类。圣克里岛上特有种，分布于所罗门群岛的东部岛屿。","appearance":"体长约25至28厘米，雄鸟体重75.5至88克，雌鸟51.5至58.5克。头部和颈部顶部橄榄棕色，头顶有细腻的白色至淡奶油色条纹，逐渐稀疏至后颈，形成整洁的梳状效果。上背部深橄榄棕色，带橄榄绿光泽，背部中央有黑色斑点。翼上覆羽和尾上覆羽红棕色，尾羽具细而淡的橄榄边。下体白色，有模糊的黑色条纹，喉部至腹部橄榄棕色，胸部有明显的条纹。幼鸟颜色较淡，条纹更分散，臀部和尾上覆羽更红。","call":"声音包括一系列响亮尖锐的哨声、呼噜声、嘎嘎声和哀鸣。叫声有响亮的‘cheók cheók cheók’、清晰的双音节哨声‘tee woo’、高音的猫叫声‘chewéek’等。","habits":"栖息于原始森林，偶尔出现在高大的次生林边缘和椰子种植园。偏好山地森林，海拔高度从海平面至至少900米，主要分布在450米以上。在雨中会从暴露的栖木上发出‘wit...wit...wit...’的叫声。","breeding":"关于繁殖行为的信息缺失。","identification":"与其他吸蜜鸟的区别在于其特有的叫声和颜色模式，特别是在头颈部的条纹和下体的橄榄棕色。","protection":"IUCN：LC（无危）","distribution":"分布局限于所罗门群岛东部的马基拉岛（Makira）。","other":"在山地森林中最为丰富，每平方公里约220次遇见率；在蒙特森林中，每平方公里110次遇见率；在低地森林中，每平方公里24次遇见率。"},{"name":"暗寻蜜鸟","english_name":"Sooty Honeyeater","scientific_name":"Melionyx fuscus","overview":"暗寻蜜鸟（英文名：Sooty Honeyeater，学名：Melionyx fuscus），是雀形目吸蜜鸟科Melionyx的鸟类。主要分布在新几内亚高地的中西部至东南部。这中型、全身黑色的吸蜜鸟，具有细长的尾巴和蓝眼圈，眼后方有一小红点。栖息于上层山林和灌木地带。","appearance":"雄鸟成鸟全身暗棕色至黑色，翅膀和尾巴略显棕色，上身羽毛微淡，形成隐约的斑驳或鳞片效果。脸部尤其是额头可能因花粉而带色。下体黑色至深棕色，腹部和尾下覆羽较浅。幼鸟颜色更暗，下体斑点更多，尾下覆羽呈较丰富的棕色。喙黑色，腿蓝色。","call":"发出较为柔和的上扬双音节叫声，'schweep-schweep'。有两种歌曲类型：一种是高音的双音符重复，第二种是甜美、空灵的哨声系列，音调逐渐下降。","habits":"生活在新几内亚中部山脉的上层山林和高山森林，特别是在苔藓森林中，偶尔出现在草甸边缘的灌木丛。活跃于各种植被层级，以昆虫、花蜜、花粉和果实为食。","breeding":"繁殖期在10月到次年5月间，筑深杯状巢，通常靠近地面。巢由苔藓、细草和树蕨纤维制成，内衬暗色羽毛。每窝产一枚卵，由双亲共同喂养雏鸟。","identification":"与Short-bearded和Long-bearded Honeyeaters相似，但体型较小，没有白色胡须。幼鸟与成鸟在色泽上有细微差别。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚的中央山脉，从雪山西部的纳索山脉和奥兰治山脉向东延伸至东部高地，包括赫根山、威廉山和吉卢韦山等地。","other":"2019年基于分子系统发育研究，从Melidectes属中分离出来，归入复活的Melionyx属。"}];
